import React, { useState } from 'react';
import { PageId } from './domain/types';
import { Layout } from './components/Layout';
import { ArtistListPage } from './pages/ArtistListPage';
import { ConcertListPage } from './pages/ConcertListPage';
import { CalendarPage } from './pages/CalendarPage';

// Placeholder components for 2nd level pages to be implemented in detail next
const ArtistDetailPage = ({ onBack, onEdit }: any) => (
  <div>
    <button onClick={onBack}>⬅️ Back</button>
    <h1>Artist Detail</h1>
    <button onClick={onEdit}>Edit Artist</button>
  </div>
);

const ConcertHomePage = ({ onBack, onEdit }: any) => (
  <div>
    <button onClick={onBack}>⬅️ Back</button>
    <h1>Concert Home</h1>
    <button onClick={onEdit}>Edit Concert Info</button>
  </div>
);

const ArtistEditorPage = ({ onCancel }: any) => (
  <div>
    <h1>Artist Editor</h1>
    <button onClick={onCancel}>Cancel</button>
    <button onClick={onCancel}>Save</button>
  </div>
);

const ConcertEditorPage = ({ onCancel }: any) => (
  <div>
    <h1>Concert Editor</h1>
    <button onClick={onCancel}>Cancel</button>
    <button onClick={onCancel}>Save</button>
  </div>
);

export default function App() {
  const [currentPath, setCurrentPath] = useState<PageId>('ARTIST_LIST');

  const renderPage = () => {
    switch (currentPath) {
      case 'ARTIST_LIST':
        return <ArtistListPage onNavigate={setCurrentPath} />;
      case 'CONCERT_LIST':
        return <ConcertListPage onNavigate={setCurrentPath} />;
      case 'CALENDAR':
        return <CalendarPage />;
      case 'ARTIST_DETAIL':
        return <ArtistDetailPage onBack={() => setCurrentPath('ARTIST_LIST')} onEdit={() => setCurrentPath('ARTIST_EDITOR')} />;
      case 'CONCERT_HOME':
        return <ConcertHomePage onBack={() => setCurrentPath('CONCERT_LIST')} onEdit={() => setCurrentPath('ARTIST_EDITOR')} />;
      case 'ARTIST_EDITOR':
        return <ArtistEditorPage onCancel={() => setCurrentPath('ARTIST_DETAIL')} />;
      case 'CONCERT_EDITOR':
        return <ConcertEditorPage onCancel={() => setCurrentPath('CONCERT_HOME')} />;
      default:
        return <ArtistListPage onNavigate={setCurrentPath} />;
    }
  };

  return (
    <Layout currentPath={currentPath} onNavigate={setCurrentPath}>
      {renderPage()}
    </Layout>
  );
}

