import React from 'react';
import { theme } from './theme';

export type BadgeType = 'tour' | 'tracking' | 'untracked' | 'info' | 'success' | 'warning' | 'error';

interface StatusBadgeProps {
  label: string;
  type?: BadgeType;
  color?: string; // Optional direct color override
  subLabel?: string;
}

export const StatusBadge: React.FC<StatusBadgeProps> = ({ label, type = 'info', color: directColor, subLabel }) => {
  const getBaseColor = () => {
    if (directColor) return directColor;
    switch (type) {
      case 'tour': return theme.colors.status.tour;
      case 'tracking': return theme.colors.status.tracking;
      case 'untracked': return theme.colors.status.untracked;
      case 'success': return theme.colors.success;
      case 'warning': return theme.colors.warning;
      case 'error': return theme.colors.error;
      default: return theme.colors.primary;
    }
  };

  const color = getBaseColor();

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
      <div style={{ 
        display: 'inline-flex',
        alignItems: 'center',
        background: `${color}12`,
        color: color,
        padding: '3px 8px',
        borderRadius: theme.radius.badge,
        fontSize: '11px',
        fontWeight: 'bold',
        width: 'fit-content',
        border: `0.5px solid ${color}30`
      }}>
        <span style={{ 
          width: '5px', 
          height: '5px', 
          borderRadius: '50%', 
          background: color, 
          marginRight: '6px' 
        }} />
        {label}
      </div>
      {subLabel && (
        <span style={{ fontSize: '10px', color: theme.colors.textSecondary, marginLeft: '4px' }}>
          {subLabel}
        </span>
      )}
    </div>
  );
};

