export default function App() {
  const [currentPath, setCurrentPath] = useState<PageId>('ARTIST_LIST');
  const [selectedArtistId, setSelectedArtistId] = useState<string | undefined>();

  const handleNavigateToArtist = (id: string) => {
    setSelectedArtistId(id);
    setCurrentPath('ARTIST_DETAIL');
  };

  const renderPage = () => {
    switch (currentPath) {
      case 'ARTIST_LIST':
        return <ArtistListPage onNavigate={(path) => path === 'ARTIST_DETAIL' ? handleNavigateToArtist('mock-id') : setCurrentPath(path)} />;
      case 'CONCERT_LIST':
        return <ConcertListPage onNavigate={setCurrentPath} />;
      case 'CALENDAR':
        return <CalendarPage onNavigate={setCurrentPath} />;
      case 'ARTIST_DETAIL':
        return (
          <ArtistDetailPage 
            artistId={selectedArtistId} 
            onNavigate={setCurrentPath} 
            onBack={() => setCurrentPath('ARTIST_LIST')} 
          />
        );
      case 'CONCERT_HOME':
        return <ConcertHomePage onBack={() => setCurrentPath('CONCERT_LIST')} onEdit={() => setCurrentPath('ARTIST_EDITOR')} />;
      case 'ARTIST_EDITOR':
        return <ArtistEditorPage onCancel={() => setCurrentPath('ARTIST_DETAIL')} />;
      case 'CONCERT_EDITOR':
        return <ConcertEditorPage onCancel={() => setCurrentPath('CONCERT_HOME')} />;
      default:
        return <ArtistListPage onNavigate={setCurrentPath} />;
    }
  };

  return (
    <Layout currentPath={currentPath} onNavigate={setCurrentPath}>
      {renderPage()}
    </Layout>
  );
}

