interface GlassCardProps {
  children: React.ReactNode;
  className?: string;
  onClick?: () => void;
  padding?: string;
  // Fix: Added style property to allow parents to pass custom CSS styles
  style?: React.CSSProperties;
}

export const GlassCard: React.FC<GlassCardProps> = ({ children, className, onClick, padding = theme.spacing.md, style }) => {
  return (
    <div 
      onClick={onClick}
      className={className}
      style={{
        background: theme.glass.background,
        backdropFilter: theme.glass.blur,
        WebkitBackdropFilter: theme.glass.blur,
        border: theme.glass.border,
        borderRadius: theme.radius.card,
        boxShadow: theme.glass.shadow,
        padding: padding,
        cursor: onClick ? 'pointer' : 'default',
        transition: 'transform 0.2s ease, box-shadow 0.2s ease',
        // Fix: Spread the passed style to merge it with default glass styles
        ...style,
      }}
      onMouseDown={(e) => onClick && (e.currentTarget.style.transform = 'scale(0.98)')}
      onMouseUp={(e) => onClick && (e.currentTarget.style.transform = 'scale(1)')}
      onMouseLeave={(e) => onClick && (e.currentTarget.style.transform = 'scale(1)')}
    >
      {children}
    </div>
  );
};

