  name: string;
  url: string;
}

export interface Concert {
  id: string;
  date: string; // ISO or "TBD"
  venue: string;
  price: number;
  saleLink: string;
  status: Status;
  isParticipated: boolean;
  images: string[]; // URL list for album
  lotteryName?: string;
  lotteryResultDate?: string;
}

export interface Tour {
  id: string;
  name: string;
  imageUrl: string;
  memo?: string;
  concerts: Concert[];
}

export interface Artist {
  id: string;
  name: string;
  imageUrl: string;
  links: SiteLink[];
  autoTrackConcerts: boolean;
  autoTrackTickets: boolean;
  tours: Tour[];
  mainStatus: string;
  subLabel: string;
}

export type PageId = 
  | 'ARTIST_LIST' 
  | 'CONCERT_LIST' 
  | 'CALENDAR' 
  | 'ARTIST_DETAIL' 
  | 'CONCERT_HOME' 
  | 'ARTIST_EDITOR' 
  | 'CONCERT_EDITOR';

import React, { useState, useEffect } from 'react';
import { theme } from '../ui/theme';
import { GlassCard } from '../ui/GlassCard';
import { ConfirmDialog } from '../components/ConfirmDialog';
import { PageId, Tour, Concert, Status } from '../domain/types';

interface Props {
  tourId?: string;
  onSave: () => void;
  onCancel: () => void;
}

const statusOptions: { value: Status; label: string }[] = [
  { value: 'BEFORE_LOTTERY', label: '発売前' },
  { value: 'CONSIDERING', label: '検討中' },
  { value: 'LOTTERY_IN_PROGRESS', label: '抽選中' },
  { value: 'SKIPPED', label: '見送' },
  { value: 'PLANNING_TO_GO', label: '参戦予定' },
  { value: 'ATTENDED', label: '参戦済み' },
];

export const ConcertEditorPage: React.FC<Props> = ({ tourId, onSave, onCancel }) => {
  const initialTour: Tour = {
    id: tourId || 'new-tour',
    name: tourId ? '2024 WORLD TOUR [GATEWAY]' : '',
    imageUrl: tourId ? 'https://images.unsplash.com/photo-1470225620780-dba8ba36b745' : '',
    memo: '',
    concerts: tourId ? [
      { id: 'c1', date: '2024-08-20', venue: 'TOKYO DOME', price: 12000, saleLink: '', status: 'PLANNING_TO_GO', isParticipated: true, images: [] },
    ] : []
  };

  const [formData, setFormData] = useState<Tour>(initialTour);
  const [hasChanges, setHasChanges] = useState(false);
  const [expandedConcertId, setExpandedConcertId] = useState<string | null>(null);
  const [isDeleteTourModalOpen, setIsDeleteTourModalOpen] = useState(false);
  const [isDeleteConcertModalOpen, setIsDeleteConcertModalOpen] = useState<string | null>(null);

  useEffect(() => {
    setHasChanges(JSON.stringify(formData) !== JSON.stringify(initialTour));
  }, [formData]);

  const handleUpdateTour = (field: keyof Tour, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleAddConcert = () => {
    const newConcert: Concert = {
      id: `new-${Date.now()}`,
      date: 'TBD',
      venue: '',
      price: 0,
      saleLink: '',
      status: 'BEFORE_LOTTERY',
      isParticipated: false,
      images: []
    };
    setFormData(prev => ({ ...prev, concerts: [...prev.concerts, newConcert] }));
    setExpandedConcertId(newConcert.id);
  };

  const handleUpdateConcert = (id: string, updates: Partial<Concert>) => {
    setFormData(prev => ({
      ...prev,
      concerts: prev.concerts.map(c => c.id === id ? { ...c, ...updates } : c)
    }));
  };

  const handleDeleteConcert = (id: string) => {
    setFormData(prev => ({
      ...prev,
      concerts: prev.concerts.filter(c => c.id !== id)
    }));
    setIsDeleteConcertModalOpen(null);
  };

  const handleDeleteTour = () => {
    console.log('Deleting tour:', formData.id);
    onCancel();
  };

  const showLotteryFields = (status: Status) => {
    return ['LOTTERY_IN_PROGRESS', 'PLANNING_TO_GO', 'SKIPPED'].includes(status);
  };

  return (
    <div style={{ paddingBottom: '120px' }}>
      {/* Header */}
      <header style={headerStyle}>
        <button onClick={onCancel} style={navButtonStyle}>キャンセル</button>
        <h2 style={{ fontSize: '17px', margin: 0, fontWeight: 'bold' }}>ツアー・公演編集</h2>
        <button 
          disabled={!hasChanges || !formData.name}
          onClick={onSave}
          style={{ ...navButtonStyle, color: (!hasChanges || !formData.name) ? theme.colors.textSecondary : theme.colors.primary, fontWeight: 'bold' }}
        >
          保存
        </button>
      </header>

      {/* Tour Info Section */}
      <section style={{ marginBottom: theme.spacing.xl }}>
        <h3 style={sectionTitleStyle}>ツアー情報</h3>
        <GlassCard padding={theme.spacing.md}>
          <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.md }}>
            <Field label="ツアー名 (必須)">
              <input 
                type="text" 
                value={formData.name} 
                onChange={e => handleUpdateTour('name', e.target.value)}
                placeholder="名称を入力"
                style={inputStyle}
              />
            </Field>
            <Field label="ツアー画像URL">
              <input 
                type="url" 
                value={formData.imageUrl} 
                onChange={e => handleUpdateTour('imageUrl', e.target.value)}
                placeholder="https://..."
                style={inputStyle}
              />
            </Field>
            <Field label="メモ">
              <textarea 
                value={formData.memo}
                onChange={e => handleUpdateTour('memo', e.target.value)}
                placeholder="自由入力..."
                style={{ ...inputStyle, minHeight: '60px', resize: 'none' }}
              />
            </Field>
          </div>
        </GlassCard>
      </section>

      {/* Concert List Section */}
      <section style={{ marginBottom: theme.spacing.xl }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: theme.spacing.sm }}>
          <h3 style={{ ...sectionTitleStyle, marginBottom: 0 }}>公演一覧 (場次)</h3>
          <button onClick={handleAddConcert} style={actionButtonStyle}>＋ 公演を追加</button>
        </div>

        {formData.concerts.length === 0 ? (
          <GlassCard padding={theme.spacing.lg} style={{ textAlign: 'center', color: theme.colors.textSecondary }}>
            まだ公演が登録されていません
          </GlassCard>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.sm }}>
            {formData.concerts.map(concert => {
              const isExpanded = expandedConcertId === concert.id;
              return (
                <GlassCard key={concert.id} padding="0">
                  <div 
                    onClick={() => setExpandedConcertId(isExpanded ? null : concert.id)}
                    style={{ padding: theme.spacing.md, cursor: 'pointer', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}
                  >
                    <div>
                      <div style={{ fontWeight: '700', fontSize: '15px' }}>{concert.date}</div>
                      <div style={{ fontSize: '12px', color: theme.colors.textSecondary }}>{concert.venue || '会場未入力'}</div>
                    </div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                      <span style={{ fontSize: '13px', fontWeight: '600', color: theme.colors.primary }}>
                        {statusOptions.find(o => o.value === concert.status)?.label}
                      </span>
                      <span style={{ transform: isExpanded ? 'rotate(180deg)' : 'none', transition: 'transform 0.2s' }}>▼</span>
                    </div>
                  </div>

                  {isExpanded && (
                    <div style={{ padding: `0 ${theme.spacing.md} ${theme.spacing.md} ${theme.spacing.md}`, display: 'flex', flexDirection: 'column', gap: theme.spacing.md, borderTop: '0.5px solid rgba(0,0,0,0.05)', paddingTop: theme.spacing.md }}>
                      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                        <Field label="日付 (YYYY-MM-DD or TBD)">
                          <input type="text" value={concert.date} onChange={e => handleUpdateConcert(concert.id, { date: e.target.value })} style={inputStyle} />
                        </Field>
                        <Field label="会場">
                          <input type="text" value={concert.venue} onChange={e => handleUpdateConcert(concert.id, { venue: e.target.value })} style={inputStyle} />
                        </Field>
                        <Field label="チケット価格">
                          <input type="number" value={concert.price} onChange={e => handleUpdateConcert(concert.id, { price: Number(e.target.value) })} style={inputStyle} />
                        </Field>
                        <Field label="販売リンク">
                          <input type="url" value={concert.saleLink} onChange={e => handleUpdateConcert(concert.id, { saleLink: e.target.value })} style={inputStyle} />
                        </Field>
                      </div>

                      <Field label="状態">
                        <select 
                          value={concert.status} 
                          onChange={e => handleUpdateConcert(concert.id, { status: e.target.value as Status })}
                          style={inputStyle}
                        >
                          {statusOptions.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                        </select>
                      </Field>

                      {showLotteryFields(concert.status) && (
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', background: 'rgba(0,0,0,0.02)', padding: '12px', borderRadius: '12px' }}>
                          <Field label="抽選名">
                            <input type="text" value={concert.lotteryName || ''} onChange={e => handleUpdateConcert(concert.id, { lotteryName: e.target.value })} placeholder="例: FC先行" style={inputStyle} />
                          </Field>
                          <Field label="抽選結果日時">
                            <input type="text" value={concert.lotteryResultDate || ''} onChange={e => handleUpdateConcert(concert.id, { lotteryResultDate: e.target.value })} placeholder="2024.08.01 18:00" style={inputStyle} />
                          </Field>
                        </div>
                      )}

                      <button 
                        onClick={(e) => { e.stopPropagation(); setIsDeleteConcertModalOpen(concert.id); }}
                        style={{ alignSelf: 'flex-start', border: 'none', background: 'none', color: theme.colors.error, fontSize: '13px', fontWeight: 'bold', padding: '8px 0' }}
                      >
                        🗑️ 公演を削除
                      </button>
                    </div>
                  )}
                </GlassCard>
              );
            })}
          </div>
        )}
      </section>

      {/* Dangerous Operations */}
      <section style={{ marginTop: '40px' }}>
        <button 
          onClick={() => setIsDeleteTourModalOpen(true)}
          style={{ 
            width: '100%', 
            padding: '16px', 
            borderRadius: theme.radius.card, 
            background: 'rgba(255, 59, 48, 0.08)', 
            color: theme.colors.error, 
            border: 'none', 
            fontWeight: 'bold',
            fontSize: '15px',
            cursor: 'pointer'
          }}
        >
          ツアーを削除
        </button>
      </section>

      {/* Confirm Dialogs */}
      <ConfirmDialog 
        isOpen={isDeleteTourModalOpen}
        title="ツアーを削除"
        message="このツアーと、それに紐づくすべての公演データが削除されます。よろしいですか？"
        confirmLabel="削除する"
        isDestructive
        onClose={() => setIsDeleteTourModalOpen(false)}
        onConfirm={handleDeleteTour}
      />

      <ConfirmDialog 
        isOpen={!!isDeleteConcertModalOpen}
        title="公演を削除"
        message="この公演データを削除します。よろしいですか？"
        confirmLabel="削除する"
        isDestructive
        onClose={() => setIsDeleteConcertModalOpen(null)}
        onConfirm={() => isDeleteConcertModalOpen && handleDeleteConcert(isDeleteConcertModalOpen)}
      />
    </div>
  );
};

