import React, { useState } from 'react';
import { PageId } from './domain/types';
import { Layout } from './components/Layout';
import { ArtistListPage } from './pages/ArtistListPage';
import { ConcertListPage } from './pages/ConcertListPage';
import { CalendarPage } from './pages/CalendarPage';
import { ArtistDetailPage } from './pages/ArtistDetailPage';
import { ConcertHomePage } from './pages/ConcertHomePage';
import { ArtistEditorPage } from './pages/ArtistEditorPage';
import { ConcertEditorPage } from './pages/ConcertEditorPage';

export default function App() {
  const [currentPath, setCurrentPath] = useState<PageId>('ARTIST_LIST');
  const [selectedArtistId, setSelectedArtistId] = useState<string | undefined>();
  const [selectedTourId, setSelectedTourId] = useState<string | undefined>();

  const handleNavigateToArtist = (id: string) => {
    setSelectedArtistId(id);
    setCurrentPath('ARTIST_DETAIL');
  };

  const handleNavigateToConcertEdit = (tourId?: string) => {
    setSelectedTourId(tourId);
    setCurrentPath('CONCERT_EDITOR');
  };

  const renderPage = () => {
    switch (currentPath) {
      case 'ARTIST_LIST':
        return <ArtistListPage onNavigate={(path) => path === 'ARTIST_DETAIL' ? handleNavigateToArtist('mock-id') : setCurrentPath(path)} />;
      case 'CONCERT_LIST':
        return <ConcertListPage onNavigate={setCurrentPath} />;
      case 'CALENDAR':
        return <CalendarPage onNavigate={setCurrentPath} />;
      case 'ARTIST_DETAIL':
        return (
          <ArtistDetailPage 
            artistId={selectedArtistId} 
            onNavigate={(id) => id === 'CONCERT_EDITOR' ? handleNavigateToConcertEdit('t1') : setCurrentPath(id)} 
            onBack={() => setCurrentPath('ARTIST_LIST')} 
          />
        );
      case 'CONCERT_HOME':
        return <ConcertHomePage onNavigate={setCurrentPath} onBack={() => setCurrentPath('CONCERT_LIST')} />;
      case 'ARTIST_EDITOR':
        return (
          <ArtistEditorPage 
            artistId={selectedArtistId}
            onSave={() => setCurrentPath('ARTIST_DETAIL')}
            onCancel={() => setCurrentPath('ARTIST_DETAIL')}
            onNavigate={(id) => id === 'CONCERT_EDITOR' ? handleNavigateToConcertEdit() : setCurrentPath(id)}
          />
        );
      case 'CONCERT_EDITOR':
        return (
          <ConcertEditorPage 
            tourId={selectedTourId}
            onSave={() => setCurrentPath('ARTIST_DETAIL')}
            onCancel={() => setCurrentPath('ARTIST_DETAIL')}
          />
        );
      default:
        return <ArtistListPage onNavigate={setCurrentPath} />;
    }
  };

  return (
    <div className="app-root">
      <Layout currentPath={currentPath} onNavigate={setCurrentPath}>
        {renderPage()}
      </Layout>
    </div>
  );
}

