import React from 'react';
import { theme } from './theme';

// Status color mapping per Spec v2
const getStatusStyles = (label: string) => {
  if (['発売前', '検討中', '抽選中'].includes(label)) return theme.colors.badges.processing;
  if (['見送'].includes(label)) return theme.colors.badges.skipped;
  if (['落選'].includes(label)) return theme.colors.badges.failed;
  if (['参戦予定', '当選'].includes(label)) return theme.colors.badges.confirmed;
  if (['参戦済み'].includes(label)) return theme.colors.badges.completed;
  return theme.colors.badges.skipped; // fallback
};

interface StatusBadgeProps {
  label: string;
  subLabel?: string;
  isMainStatus?: boolean; // If true, render as primary text without pill per spec v2
}

export const StatusBadge: React.FC<StatusBadgeProps> = ({ label, subLabel, isMainStatus }) => {
  if (isMainStatus) {
    return (
      <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
        <span style={{ 
          fontSize: '15px', 
          fontWeight: '500', 
          color: theme.colors.primary 
        }}>
          {label}
        </span>
        {subLabel && (
          <span style={{ fontSize: '13px', color: theme.colors.textSecondary }}>
            {subLabel}
          </span>
        )}
      </div>
    );
  }

  const styles = getStatusStyles(label);

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
      <div style={{ 
        display: 'inline-flex',
        alignItems: 'center',
        background: styles.bg,
        color: styles.text,
        padding: '2px 10px',
        borderRadius: theme.radius.badge,
        fontSize: '11px',
        fontWeight: '600',
        width: 'fit-content',
        border: `1px solid ${styles.border}`
      }}>
        {label}
      </div>
      {subLabel && (
        <span style={{ fontSize: '10px', color: theme.colors.textSecondary, marginLeft: '4px' }}>
          {subLabel}
        </span>
      )}
    </div>
  );
};

import React from 'react';
import { theme } from './theme';

interface GlassCardProps {
  children: React.ReactNode;
  className?: string;
  onClick?: () => void;
  padding?: string;
  style?: React.CSSProperties;
  isSheet?: boolean;
}

export const GlassCard: React.FC<GlassCardProps> = ({ 
  children, 
  className, 
  onClick, 
  padding = theme.spacing.md, 
  style,
  isSheet = false
}) => {
  return (
    <div 
      onClick={onClick}
      className={className}
      style={{
        background: theme.glass.background,
        backdropFilter: theme.glass.blur,
        WebkitBackdropFilter: theme.glass.blur,
        border: theme.glass.border,
        borderRadius: isSheet ? theme.radius.dialog : theme.radius.card,
        boxShadow: isSheet ? theme.shadows.xxl : theme.shadows.sm,
        padding: padding,
        cursor: onClick ? 'pointer' : 'default',
        transition: 'transform 0.15s ease, box-shadow 0.15s ease',
        ...style,
      }}
      onMouseDown={(e) => onClick && (e.currentTarget.style.transform = 'scale(0.985)')}
      onMouseUp={(e) => onClick && (e.currentTarget.style.transform = 'scale(1)')}
      onMouseLeave={(e) => onClick && (e.currentTarget.style.transform = 'scale(1)')}
    >
      {children}
    </div>
  );
};

import React from 'react';
import { theme } from '../ui/theme';
import { PageId } from '../domain/types';

interface LayoutProps {
  children: React.ReactNode;
  currentPath: PageId;
