    { id: 'ARTIST_LIST', label: 'アーティスト', icon: '👤' },
    { id: 'CONCERT_LIST', label: '公演', icon: '🎫' },
    { id: 'CALENDAR', label: 'カレンダー', icon: '📅' },
  ];

  const isMainTab = tabs.some(tab => tab.id === currentPath);

  return (
    <div style={{ 
      minHeight: '100vh', 
      backgroundColor: theme.colors.background,
      color: theme.colors.text,
      paddingBottom: isMainTab ? '90px' : '0',
      fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif'
    }}>
      <main style={{ padding: `0 ${theme.spacing.lg} ${theme.spacing.md} ${theme.spacing.lg}` }}>
        <div style={{ paddingTop: theme.spacing.pageTop }}>
          {children}
        </div>
      </main>

      {isMainTab && (
        <nav style={{
          position: 'fixed',
          bottom: 0,
          left: 0,
          right: 0,
          height: '70px',
          background: 'rgba(255, 255, 255, 0.8)',
          backdropFilter: 'blur(20px)',
          WebkitBackdropFilter: 'blur(20px)',
          borderTop: '0.5px solid rgba(0,0,0,0.1)',
          display: 'flex',
          justifyContent: 'space-around',
          alignItems: 'center',
          paddingBottom: 'env(safe-area-inset-bottom)',
          zIndex: 100,
        }}>
          {tabs.map((tab) => (
            <button
              key={tab.id}
              onClick={() => onNavigate(tab.id)}
              style={{
                border: 'none',
                background: 'none',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                gap: '4px',
                color: currentPath === tab.id ? theme.colors.primary : theme.colors.textSecondary,
                fontSize: '10px',
                cursor: 'pointer',
              }}
            >
              <span style={{ 
                fontSize: '20px',
                color: currentPath === tab.id ? theme.colors.primary : theme.colors.textWeak,
                transition: 'color 0.2s'
              }}>{tab.icon}</span>
              <span style={{ fontWeight: currentPath === tab.id ? '600' : '400' }}>{tab.label}</span>
            </button>
          ))}
        </nav>
      )}
    </div>
  );
};

