import React, { useState, useMemo } from 'react';
import { GlassCard } from '../ui/GlassCard';
import { StatusBadge } from '../ui/StatusBadge';
import { CalendarMenu } from '../components/CalendarMenu';
import { theme } from '../ui/theme';
import { PageId, Status } from '../domain/types';

interface Props {
  onNavigate: (id: PageId) => void;
}

// Priority mapping for dots (higher number = higher priority)
const priorityMap: Record<Status, number> = {
  'PLANNING_TO_GO': 6,
  'LOTTERY_IN_PROGRESS': 5,
  'CONSIDERING': 4,
  'BEFORE_LOTTERY': 3,
  'ATTENDED': 2,
  'SKIPPED': 1,
  'WON': 0, // Not explicitly in the calendar dot list but for safety
  'LOST': 0,
};

const colorMap: Record<Status, string> = {
  'PLANNING_TO_GO': theme.colors.primary,
  'LOTTERY_IN_PROGRESS': '#5856D6',
  'CONSIDERING': '#FF9500',
  'BEFORE_LOTTERY': '#8E8E93',
  'ATTENDED': theme.colors.success,
  'SKIPPED': theme.colors.error,
  'WON': theme.colors.success,
  'LOST': theme.colors.error,
};

const statusLabelMap: Record<Status, string> = {
  'PLANNING_TO_GO': '参戦予定',
  'LOTTERY_IN_PROGRESS': '抽選中',
  'CONSIDERING': '検討中',
  'BEFORE_LOTTERY': '発売前',
  'ATTENDED': '参戦済み',
  'SKIPPED': '見送',
  'WON': '当選',
  'LOST': '落選',
};

export const CalendarPage: React.FC<Props> = ({ onNavigate }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<string | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [weekStart, setWeekStart] = useState<'sun' | 'mon'>('sun');

  // Mock data - In a real app, this would come from a global state/hook
  const mockConcerts = useMemo(() => [
    { id: '1', date: '2024-08-15', artist: 'Artist Beta', tour: 'Summer Fest', status: 'ATTENDED' as Status },
    { id: '2', date: '2024-08-20', artist: 'Artist Alpha', tour: 'Gateway Tour', status: 'PLANNING_TO_GO' as Status },
    { id: '3', date: '2024-08-20', artist: 'Artist Gamma', tour: 'Groove Night', status: 'CONSIDERING' as Status },
    { id: '4', date: '2024-08-28', artist: 'Artist Alpha', tour: 'Acoustic Journey', status: 'LOTTERY_IN_PROGRESS' as Status },
  ], []);

  const daysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
  const firstDayOfMonth = (year: number, month: number) => new Date(year, month, 1).getDay();

  const handlePrevMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
    setSelectedDate(null);
  };

  const handleNextMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
    setSelectedDate(null);
  };

  const handleRefresh = () => {
    console.log('Refreshing calendar data...');
  };

  const calendarDays = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const count = daysInMonth(year, month);
    let startDay = firstDayOfMonth(year, month);

    // Adjust for Monday start
    if (weekStart === 'mon') {
      startDay = startDay === 0 ? 6 : startDay - 1;
    }

    const days = [];
    // Padding
    for (let i = 0; i < startDay; i++) {
      days.push(null);
    }
    // Days
    for (let i = 1; i <= count; i++) {
      days.push(i);
    }
    return days;
  }, [currentDate, weekStart]);

  const getDayConcerts = (day: number) => {
    const dateStr = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    return mockConcerts.filter(c => c.date === dateStr);
  };

  const getPriorityStatus = (day: number): Status | null => {
    const dayConcerts = getDayConcerts(day);
    if (dayConcerts.length === 0) return null;
    return dayConcerts.reduce((prev, curr) => 
      (priorityMap[curr.status] > priorityMap[prev.status]) ? curr : prev
    ).status;
  };

  const handleDayClick = (day: number) => {
    const dateStr = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSelectedDate(dateStr === selectedDate ? null : dateStr);
  };

  const selectedConcerts = useMemo(() => {
    if (!selectedDate) return [];
    return mockConcerts.filter(c => c.date === selectedDate);
  }, [selectedDate, mockConcerts]);

  const weekLabels = weekStart === 'sun' 
    ? ['日', '月', '火', '水', '木', '金', '土']
    : ['月', '火', '水', '木', '金', '土', '日'];

  return (
    <div style={{ paddingBottom: '120px' }}>
      {/* Top Header Refresh */}
      <div style={{ position: 'fixed', top: theme.spacing.md, right: theme.spacing.md, zIndex: 10 }}>
        <button 
          onClick={handleRefresh}
          style={{ 
            border: 'none', 
            background: 'rgba(255,255,255,0.8)', 
            backdropFilter: 'blur(10px)',
            width: '40px',
            height: '40px',
            borderRadius: '20px',
            fontSize: '18px',
            boxShadow: '0 2px 8px rgba(0,0,0,0.05)',
            cursor: 'pointer'
          }}
        >
          🔄
        </button>
      </div>

      <header style={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center', 
        marginBottom: theme.spacing.lg,
        paddingTop: '40px'
      }}>
        <div style={{ fontSize: '22px', fontWeight: '800' }}>
          {currentDate.getFullYear()}年 {currentDate.getMonth() + 1}月
        </div>
        <div style={{ display: 'flex', gap: '12px' }}>
          <button onClick={handlePrevMonth} style={{ border: 'none', background: 'rgba(0,0,0,0.05)', borderRadius: '50%', width: '32px', height: '32px', cursor: 'pointer' }}>◀</button>
          <button onClick={handleNextMonth} style={{ border: 'none', background: 'rgba(0,0,0,0.05)', borderRadius: '50%', width: '32px', height: '32px', cursor: 'pointer' }}>▶</button>
        </div>
      </header>

      <GlassCard padding="12px">
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '4px' }}>
          {weekLabels.map((label, idx) => (
            <div key={label} style={{ 
              textAlign: 'center', 
              fontSize: '11px', 
              color: (idx === 0 && weekStart === 'sun') || (idx === 6 && weekStart === 'mon') ? theme.colors.error : theme.colors.textSecondary,
              paddingBottom: '8px',
              fontWeight: '600'
            }}>
              {label}
            </div>
          ))}
          {calendarDays.map((day, idx) => {
            if (day === null) return <div key={`empty-${idx}`} />;

            const priorityStatus = getPriorityStatus(day);
            const dateStr = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
            const isSelected = selectedDate === dateStr;

            return (
              <div 
                key={day} 
                onClick={() => handleDayClick(day)}
                style={{
                  aspectRatio: '1/1',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'center',
                  borderRadius: '12px',
                  background: isSelected ? 'rgba(0,122,255,0.1)' : 'transparent',
                  border: isSelected ? `1.5px solid ${theme.colors.primary}` : '1.5px solid transparent',
                  cursor: 'pointer',
                  position: 'relative',
                  transition: 'all 0.1s ease'
                }}
              >
                <span style={{ 
                  fontSize: '15px', 
                  fontWeight: '500',
                  color: theme.colors.text 
                }}>
                  {day}
                </span>
                {priorityStatus && (
                  <div style={{ 
                    position: 'absolute',
                    bottom: '6px',
                    width: '4px',
                    height: '4px',
                    borderRadius: '50%',
                    background: colorMap[priorityStatus]
                  }} />
                )}
              </div>
            );
          })}
        </div>
      </GlassCard>

      {/* Selected Day Concerts */}
      {selectedDate && (
        <div style={{ marginTop: theme.spacing.lg }} className="fade-in">
          <h3 style={{ fontSize: '15px', fontWeight: 'bold', marginBottom: theme.spacing.md, color: theme.colors.textSecondary }}>
            {selectedDate.replace(/-/g, '.')} の公演
          </h3>
          <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.sm }}>
            {selectedConcerts.length > 0 ? (
              selectedConcerts.map(concert => (
                <GlassCard 
                  key={concert.id}
                  padding={theme.spacing.sm}
                  onClick={() => {
                    const status = priorityMap[concert.status];
                    // Logic: Planning (6) or Attended (2) goes to HOME, others to DETAIL
                    if (status === 6 || status === 2) {
                      onNavigate('CONCERT_HOME');
                    } else {
                      onNavigate('ARTIST_DETAIL');
                    }
                  }}
                >
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <div>
                      <div style={{ fontSize: '12px', color: theme.colors.textSecondary }}>{concert.artist}</div>
                      <div style={{ fontWeight: '700', fontSize: '15px' }}>{concert.tour}</div>
                    </div>
                    {/* Fixed: StatusBadge does not accept a color prop. It manages color internally via getStatusStyles */}
                    <StatusBadge label={statusLabelMap[concert.status]} />
                  </div>
                </GlassCard>
              ))
            ) : (
              <div style={{ textAlign: 'center', padding: '20px', color: theme.colors.textSecondary, fontSize: '14px' }}>
                予定はありません
              </div>
            )}
          </div>
        </div>
      )}

      {/* Bottom Left Menu */}
      <div style={{ position: 'fixed', left: theme.spacing.md, bottom: '100px', zIndex: 90 }}>
        <button 
          onClick={() => setIsMenuOpen(!isMenuOpen)}
          style={{ 
            border: theme.glass.border, 
            background: theme.glass.background,
            backdropFilter: 'blur(10px)',
            padding: '10px 16px', 
            borderRadius: '20px', 
            fontSize: '14px',
            display: 'flex',
            alignItems: 'center',
            gap: '6px',
            boxShadow: theme.glass.shadow,
            cursor: 'pointer'
          }}
        >
          <span style={{ fontSize: '16px' }}>☰</span> メニュー
        </button>
      </div>

      <CalendarMenu 
        isOpen={isMenuOpen} 
        onClose={() => setIsMenuOpen(false)}
        weekStart={weekStart}
        setWeekStart={setWeekStart}
      />
    </div>
  );
};

