export type Status = 
  | 'BEFORE_LOTTERY' 
  | 'CONSIDERING' 
  | 'LOTTERY_IN_PROGRESS' 
  | 'WON' 
  | 'LOST' 
  | 'PLANNING_TO_GO' 
  | 'ATTENDED' 
  | 'SKIPPED';

export type TrackingStatus = 'success' | 'failed';

export interface SiteLink {
  name: string;
  url: string;
  autoTrack: boolean;
  lastCheckedAt?: string;
  lastSuccessAt?: string;
  trackingStatus?: TrackingStatus;
  errorMessage?: string; // 「接続できませんでした」など
}

export interface Concert {
  id: string;
  date: string; // ISO (YYYY-MM-DD) or "TBD"
  venue: string;
  price: number;
  saleLink: string;
  status: Status;
  isParticipated: boolean;
  images: string[]; 
  lotteryName?: string;
  lotteryResultDate?: string;
}

export interface Tour {
  id: string;
  name: string;
  imageUrl: string;
  memo?: string;
  concerts: Concert[];
}

export interface Artist {
  id: string;
  name: string;
  imageUrl: string;
  links: SiteLink[];
  autoTrackConcerts: boolean;
  autoTrackTickets: boolean;
  tours: Tour[];
  mainStatus: string;
  subLabel: string;
}

export type PageId = 
  | 'ARTIST_LIST' 
  | 'CONCERT_LIST' 
  | 'CALENDAR' 
  | 'ARTIST_DETAIL' 
  | 'CONCERT_HOME' 
  | 'ARTIST_EDITOR' 
  | 'CONCERT_EDITOR';

