import React, { useState } from 'react';
import { theme } from '../ui/theme';
import { GlassCard } from '../ui/GlassCard';
import { ImageDialog } from '../components/ImageDialog';
import { PageId, Concert, Tour } from '../domain/types';

interface Props {
  onNavigate: (id: PageId) => void;
  onBack: () => void;
}

export const ConcertHomePage: React.FC<Props> = ({ onNavigate, onBack }) => {
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [fullscreenImage, setFullscreenImage] = useState<string | null>(null);
  const [failedImages, setFailedImages] = useState<Set<string>>(new Set());

  // Mock data
  const tour: Tour = {
    id: 't1',
    name: '2024 WORLD TOUR [GATEWAY]',
    imageUrl: 'https://images.unsplash.com/photo-1470225620780-dba8ba36b745?auto=format&fit=crop&w=800&q=80',
    concerts: []
  };

  const [images, setImages] = useState<string[]>([
    'https://images.unsplash.com/photo-1459749411177-042180ce673c?auto=format&fit=crop&w=400&q=80',
    'https://broken-link-example.com/img.jpg', // 失敗例
  ]);

  const handleAddImage = (url: string) => {
    setImages([...images, url]);
  };

  const handleImageError = (url: string) => {
    setFailedImages(prev => new Set([...prev, url]));
  };

  const handleRemoveImage = (url: string) => {
    setImages(images.filter(i => i !== url));
  };

  return (
    <div style={{ minHeight: '100vh', position: 'relative' }}>
      <div style={{ position: 'fixed', inset: 0, zIndex: -1, backgroundImage: `url(${tour.imageUrl})`, backgroundSize: 'cover', backgroundPosition: 'center', filter: 'blur(40px) brightness(0.7)', transform: 'scale(1.2)' }} />

      <div style={{ padding: `${theme.spacing.lg} ${theme.spacing.md} 120px ${theme.spacing.md}` }}>
        <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '32px' }}>
          <button onClick={onBack} style={{ border: 'none', background: 'rgba(255,255,255,0.2)', color: 'white', width: '36px', height: '36px', borderRadius: '18px', fontSize: '18px' }}>←</button>
          <div style={{ display: 'flex', gap: '12px' }}>
            <button onClick={() => onNavigate('ARTIST_EDITOR')} style={{ border: 'none', background: 'rgba(255,255,255,0.2)', color: 'white', padding: '8px 16px', borderRadius: '18px', fontSize: '13px', fontWeight: '600' }}>編集</button>
          </div>
        </header>

        <div style={{ color: 'white', marginBottom: '24px' }}>
          <h1 style={{ fontSize: '28px', fontWeight: '900', margin: '0 0 4px 0', textShadow: '0 2px 10px rgba(0,0,0,0.3)' }}>{tour.name}</h1>
          <div style={{ fontSize: '16px', opacity: 0.9, fontWeight: '500' }}>アーティスト A</div>
        </div>

        <section>
          <h2 style={{ color: 'white', fontSize: '18px', fontWeight: 'bold', marginBottom: '16px', paddingLeft: '4px' }}>アルバム</h2>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '12px' }}>
            {images.map((img, idx) => {
              const isFailed = failedImages.has(img);
              return (
                <div key={idx} style={{ position: 'relative', aspectRatio: '1/1', borderRadius: '12px', overflow: 'hidden', background: '#333' }}>
                  {isFailed ? (
                    <div style={{ width: '100%', height: '100%', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', color: '#999', fontSize: '12px', padding: '10px', textAlign: 'center' }}>
                      <span style={{ fontSize: '20px', marginBottom: '4px' }}>📷</span>
                      読み込めません
                      <button 
                        onClick={() => handleRemoveImage(img)}
                        style={{ marginTop: '8px', border: 'none', background: 'rgba(255,255,255,0.1)', color: 'white', fontSize: '10px', padding: '4px 8px', borderRadius: '4px' }}
                      >削除</button>
                    </div>
                  ) : (
                    <img 
                      src={img} 
                      alt="" 
                      onError={() => handleImageError(img)} 
                      onClick={() => setFullscreenImage(img)}
                      style={{ width: '100%', height: '100%', objectFit: 'cover', cursor: 'pointer' }} 
                    />
                  )}
                </div>
              );
            })}
          </div>
        </section>
      </div>

      <button onClick={() => setIsDialogOpen(true)} style={{ position: 'fixed', right: theme.spacing.md, bottom: theme.spacing.lg, width: '56px', height: '56px', borderRadius: '28px', backgroundColor: theme.colors.primary, color: 'white', border: 'none', fontSize: '28px', zIndex: 90 }}>＋</button>

      {fullscreenImage && (
        <div onClick={() => setFullscreenImage(null)} style={{ position: 'fixed', inset: 0, zIndex: 3000, background: 'black', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <img src={fullscreenImage} alt="" style={{ maxWidth: '100%', maxHeight: '100%', objectFit: 'contain' }} />
        </div>
      )}

      <ImageDialog isOpen={isDialogOpen} onClose={() => setIsDialogOpen(false)} onAdd={handleAddImage} />
    </div>
  );
};

