import React, { useState, useMemo } from 'react';
import { PageShell } from '../ui/PageShell';
import { theme } from '../ui/theme';
import { PageId, Status } from '../domain/types';
import { CalendarMenu } from '../components/CalendarMenu';

interface Props {
  onNavigate: (id: PageId) => void;
}

const colorMap: Record<Status, string> = {
  'PLANNING_TO_GO': theme.colors.primary,
  'LOTTERY_IN_PROGRESS': '#9CA3AF',
  'CONSIDERING': '#9CA3AF',
  'BEFORE_LOTTERY': '#9CA3AF',
  'ATTENDED': theme.colors.primary,
  'SKIPPED': '#9CA3AF',
  'WON': theme.colors.primary,
  'LOST': '#9CA3AF',
};

const statusLabelMap: Record<Status, string> = {
  'PLANNING_TO_GO': '参戦予定',
  'LOTTERY_IN_PROGRESS': '抽選中',
  'CONSIDERING': '検討中',
  'BEFORE_LOTTERY': '発売前',
  'ATTENDED': '参戦済み',
  'SKIPPED': '見送',
  'WON': '当選',
  'LOST': '落選',
};

export const CalendarPage: React.FC<Props> = ({ onNavigate }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<string | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [weekStart, setWeekStart] = useState<'sun' | 'mon'>('sun');

  const mockConcerts = useMemo(() => [
    { id: '1', date: '2024-08-15', artist: 'Artist Beta', tour: 'Summer Fest', status: 'ATTENDED' as Status },
    { id: '2', date: '2024-08-20', artist: 'Artist Alpha', tour: 'Gateway Tour', status: 'PLANNING_TO_GO' as Status },
    { id: '4', date: '2024-08-28', artist: 'Artist Alpha', tour: 'Acoustic Journey', status: 'LOTTERY_IN_PROGRESS' as Status },
  ], []);

  const daysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
  const firstDayOfMonth = (year: number, month: number) => new Date(year, month, 1).getDay();

  const calendarDays = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const count = daysInMonth(year, month);
    let startDay = firstDayOfMonth(year, month);
    if (weekStart === 'mon') startDay = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < startDay; i++) days.push(null);
    for (let i = 1; i <= count; i++) days.push(i);
    return days;
  }, [currentDate, weekStart]);

  const getDayConcerts = (day: number) => {
    const dateStr = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    return mockConcerts.filter(c => c.date === dateStr);
  };

  const handleDayClick = (day: number) => {
    const dateStr = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSelectedDate(dateStr === selectedDate ? null : dateStr);
  };

  return (
    <PageShell
      header={
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingBottom: '8px' }}>
          <h1 style={{ fontSize: '32px', fontWeight: '900', color: '#111827', margin: 0, letterSpacing: '-0.025em' }}>
            LiveTrack <span style={{ color: '#53BEE8' }}>JP</span>
          </h1>
          <button style={{ padding: '12px', borderRadius: '9999px', background: 'white', border: '1px solid #F3F4F6', color: '#9CA3AF', cursor: 'pointer' }}>
            <svg style={{ width: '24px', height: '24px' }} fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path>
            </svg>
          </button>
        </div>
      }
    >
      <div style={{ paddingBottom: '120px' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
          <div style={{ fontSize: '24px', fontWeight: '900' }}>{currentDate.getFullYear()}年 {currentDate.getMonth() + 1}月</div>
          <div style={{ display: 'flex', gap: '8px' }}>
            <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1))} style={{ width: '40px', height: '40px', borderRadius: '50%', border: 'none', background: '#F3F4F6', cursor: 'pointer' }}>◀</button>
            <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1))} style={{ width: '40px', height: '40px', borderRadius: '50%', border: 'none', background: '#F3F4F6', cursor: 'pointer' }}>▶</button>
          </div>
        </div>

        <div style={{ background: 'white', borderRadius: '32px', padding: '24px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 12px rgba(0,0,0,0.03)' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '8px' }}>
            {(weekStart === 'sun' ? ['日', '月', '火', '水', '木', '金', '土'] : ['月', '火', '水', '木', '金', '土', '日']).map(l => <div key={l} style={{ textAlign: 'center', fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary }}>{l}</div>)}
            {calendarDays.map((day, idx) => {
              if (day === null) return <div key={idx} />;
              const concerts = getDayConcerts(day);
              const isSelected = selectedDate === `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
              return (
                <div key={day} onClick={() => handleDayClick(day)} style={{ aspectRatio: '1/1', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', borderRadius: '16px', background: isSelected ? 'rgba(83, 190, 232, 0.1)' : 'transparent', border: isSelected ? '2px solid #53BEE8' : 'none', cursor: 'pointer', position: 'relative' }}>
                  <span style={{ fontSize: '16px', fontWeight: '600' }}>{day}</span>
                  {concerts.length > 0 && <div style={{ position: 'absolute', bottom: '6px', width: '5px', height: '5px', borderRadius: '50%', background: colorMap[concerts[0].status] }} />}
                </div>
              );
            })}
          </div>
        </div>

        {selectedDate && (
          <div style={{ marginTop: '32px' }}>
            <h3 style={{ fontSize: '14px', fontWeight: '700', color: theme.colors.textSecondary, marginBottom: '16px', textTransform: 'uppercase', letterSpacing: '0.05em' }}>{selectedDate.replace(/-/g, '.')}</h3>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
              {mockConcerts.filter(c => c.date === selectedDate).map(c => (
                <div key={c.id} style={{ background: 'white', borderRadius: '24px', padding: '20px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 12px rgba(0,0,0,0.03)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <div>
                    <div style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: '700' }}>{c.artist}</div>
                    <div style={{ fontSize: '17px', fontWeight: '800' }}>{c.tour}</div>
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: colorMap[c.status] }} />
                    <span style={{ fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary }}>{statusLabelMap[c.status]}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      <div style={{ position: 'fixed', left: '32px', bottom: '100px', zIndex: 90 }}>
        <button onClick={() => setIsMenuOpen(!isMenuOpen)} style={{ width: '64px', height: '64px', borderRadius: '9999px', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'white', border: '1px solid #F3F4F6', color: '#9CA3AF', boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.1)', cursor: 'pointer' }}>
          <svg style={{ width: '32px', height: '32px' }} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
        </button>
      </div>
      <CalendarMenu isOpen={isMenuOpen} onClose={() => setIsMenuOpen(false)} weekStart={weekStart} setWeekStart={setWeekStart} />
    </PageShell>
  );
};

