import { Artist, Concert, Status, TICKET_TRACK_STATUSES, TOUR_ACTIVE_STATUSES } from './types';

/**
 * Calculates Artist status based on their tours and concerts.
 * Rules:
 * - main: 'ツアー中' if any active tour status. '公演追跡中' if concerts exist but no active tour. '未追跡' otherwise.
 * - sub: 'チケット追跡中' ONLY IF autoTrackTickets is ON AND there is at least one concert in unhandled status.
 */
export const calcArtistStatus = (artist: Artist): {
  main: 'ツアー中' | '公演追跡中' | '未追跡';
  sub: 'チケット追跡中' | null;
} => {
  const allConcerts = artist.tours.flatMap(t => t.concerts);

  const hasActiveTour = allConcerts.some(c => TOUR_ACTIVE_STATUSES.includes(c.status));
  const hasUnhandledConcerts = allConcerts.some(c => TICKET_TRACK_STATUSES.includes(c.status));

  let main: 'ツアー中' | '公演追跡中' | '未追跡' = '未追跡';
  if (hasActiveTour) {
    main = 'ツアー中';
  } else if (allConcerts.length > 0) {
    main = '公演追跡中';
  }

  // Rule: Sub label appears only if auto tracking is ON AND unhandled concerts exist
  const sub = (artist.autoTrackTickets && hasUnhandledConcerts) ? 'チケット追跡中' : null;

  return { main, sub };
};

/**
 * Priority for sorting artists (Status Sort):
 * 1. ツアー中 (sub 'チケット追跡中' first)
 * 2. 公演追跡中
 * 3. 未追跡
 */
const getArtistPriority = (artist: Artist): number => {
  const status = calcArtistStatus(artist);
  if (status.main === 'ツアー中') {
    return status.sub === 'チケット追跡中' ? 1 : 2;
  }
  if (status.main === '公演追跡中') return 3;
  return 4;
};

export const sortArtistsForDisplay = (artists: Artist[], sortMode: 'manual' | 'status'): Artist[] => {
  if (sortMode === 'manual') {
    return [...artists]; // Assumes array order is the manual order
  }

  return [...artists].sort((a, b) => {
    const prioA = getArtistPriority(a);
    const prioB = getArtistPriority(b);
    if (prioA !== prioB) return prioA - prioB;
    // Tie-break by name
    return a.name.localeCompare(b.name);
  });
};

/**
 * Priority for sorting concerts:
 * 1. (発売前 / 検討中 / 抽選中)
 * 2. 参戦予定
 * 3. 参戦済み
 * 4. 見送
 */
const getConcertStatusPriority = (status: Status): number => {
  if (TICKET_TRACK_STATUSES.includes(status)) return 1;
  if (status === '参戦予定') return 2;
  if (status === '参戦済み') return 3;
  if (status === '見送') return 4;
  return 99;
};

export const sortPerformancesForDisplay = (concerts: Concert[]): Concert[] => {
  return [...concerts].sort((a, b) => {
    const prioA = getConcertStatusPriority(a.status);
    const prioB = getConcertStatusPriority(b.status);

    if (prioA !== prioB) return prioA - prioB;

    // Within same priority, Sort by Date (Specific Date > TBD)
    if (a.date !== 'TBD' && b.date === 'TBD') return -1;
    if (a.date === 'TBD' && b.date !== 'TBD') return 1;
    if (a.date !== 'TBD' && b.date !== 'TBD') return a.date.localeCompare(b.date);

    return 0;
  });
};

/**
 * Checks for date conflicts (YYYY-MM-DD). Only targets '参戦予定' and '参戦済み'.
 */
export const checkDateConflicts = (concerts: Concert[]): string[] => {
  const targetConcerts = concerts.filter(c => 
    (c.status === '参戦予定' || c.status === '参戦済み') && c.date !== 'TBD'
  );

  const dates = targetConcerts.map(c => c.date);
  const conflicts = dates.filter((date, index) => dates.indexOf(date) !== index);
  return Array.from(new Set(conflicts));
};

export type Status = 
  | '発売前' 
  | '検討中' 
  | '抽選中' 
  | '参戦予定' 
  | '参戦済み' 
  | '見送';

export const TOUR_ACTIVE_STATUSES: Status[] = ['発売前', '検討中', '抽選中', '参戦予定', '見送'];
export const TICKET_TRACK_STATUSES: Status[] = ['発売前', '検討中', '抽選中'];

