import { Artist, Concert, Status, TICKET_TRACK_STATUSES, TOUR_ACTIVE_STATUSES, PageId } from './types';

/**
 * Calculates Artist status based on their tours and concerts.
 */
export const calcArtistStatus = (artist: Artist): {
  main: 'ツアー中' | '公演追跡中' | '未追跡';
  sub: 'チケット追跡中' | null;
} => {
  const allConcerts = artist.tours.flatMap(t => t.concerts);

  const hasActiveTour = allConcerts.some(c => TOUR_ACTIVE_STATUSES.includes(c.status));
  const hasUnhandledConcerts = allConcerts.some(c => TICKET_TRACK_STATUSES.includes(c.status));

  let main: 'ツアー中' | '公演追跡中' | '未追跡' = '未追跡';
  if (hasActiveTour) {
    main = 'ツアー中';
  } else if (allConcerts.length > 0) {
    main = '公演追跡中';
  }

  // Rule: Sub label appears only if auto tracking is ON AND unhandled concerts exist
  const sub = (artist.autoTrackTickets && hasUnhandledConcerts) ? 'チケット追跡中' : null;

  return { main, sub };
};

/**
 * Priority for sorting artists (Status Sort):
 */
const getArtistPriority = (artist: Artist): number => {
  const status = calcArtistStatus(artist);
  if (status.main === 'ツアー中') {
    return status.sub === 'チケット追跡中' ? 1 : 2;
  }
  if (status.main === '公演追跡中') return 3;
  return 4;
};

export const sortArtistsForDisplay = (artists: Artist[], sortMode: 'manual' | 'status'): Artist[] => {
  if (sortMode === 'manual') {
    return [...artists];
  }

  return [...artists].sort((a, b) => {
    const prioA = getArtistPriority(a);
    const prioB = getArtistPriority(b);
    if (prioA !== prioB) return prioA - prioB;
    return a.name.localeCompare(b.name);
  });
};

/**
 * Priority for sorting concerts:
 */
const getConcertStatusPriority = (status: Status): number => {
  if (TICKET_TRACK_STATUSES.includes(status)) return 1;
  if (status === '参戦予定') return 2;
  if (status === '参戦済み') return 3;
  if (status === '見送') return 4;
  return 99;
};

/**
 * Priority for Calendar dot status (Higher to Lower):
 * 参戦予定 > 抽選中 > 検討中 > 発売前 > 参戦済み > 見送
 */
const getCalendarStatusWeight = (status: Status): number => {
  switch (status) {
    case '参戦予定': return 100;
    case '抽選中': return 90;
    case '検討中': return 80;
    case '発売前': return 70;
    case '参戦済み': return 60;
    case '見送': return 50;
    default: return 0;
  }
};

/**
 * Determine the best status to represent a list of concerts on the calendar.
 */
export const getBestStatusForDay = (concerts: Concert[]): Status | null => {
  if (concerts.length === 0) return null;
  return [...concerts].sort((a, b) => getCalendarStatusWeight(b.status) - getCalendarStatusWeight(a.status))[0].status;
};

/**
 * Centralized navigation rule for concert cards.
 */
export const getConcertNavigationTarget = (status: Status): PageId => {
  if (status === '参戦予定' || status === '参戦済み') {
    return 'CONCERT_HOME';
  }
  return 'ARTIST_DETAIL';
};

/**
 * Sort performances by Status -> Date.
 */
export const sortPerformancesForDisplay = (concerts: Concert[]): Concert[] => {
  return [...concerts].sort((a, b) => {
    const prioA = getConcertStatusPriority(a.status);
    const prioB = getConcertStatusPriority(b.status);

    if (prioA !== prioB) return prioA - prioB;

    if (a.date !== 'TBD' && b.date === 'TBD') return -1;
    if (a.date === 'TBD' && b.date !== 'TBD') return 1;
    if (a.date !== 'TBD' && b.date !== 'TBD') return a.date.localeCompare(b.date);

    return 0;
  });
};

/**
 * Sort performances by Lottery Result Date.
 */
export const sortPerformancesByLotteryDate = (concerts: Concert[]): Concert[] => {
  const targets: Status[] = ['抽選中', '参戦予定', '見送'];
  return [...concerts].sort((a, b) => {
    const isTargetA = targets.includes(a.status) && !!a.lotteryResultDate;
    const isTargetB = targets.includes(b.status) && !!b.lotteryResultDate;

    if (isTargetA && !isTargetB) return -1;
    if (!isTargetA && isTargetB) return 1;
    if (isTargetA && isTargetB) {
      return (a.lotteryResultDate || '').localeCompare(b.lotteryResultDate || '');
    }
    return 0;
  });
};

/**
 * Checks for date conflicts (YYYY-MM-DD). Only targets '参戦予定' and '参戦済み'.
 */
export const checkDateConflicts = (concerts: Concert[]): string[] => {
  const targetConcerts = concerts.filter(c => 
    (c.status === '参戦予定' || c.status === '参戦済み') && c.date !== 'TBD'
  );

  const dates = targetConcerts.map(c => c.date);
  const conflicts = dates.filter((date, index) => dates.indexOf(date) !== index);
  return Array.from(new Set(conflicts));
};

import React, { useState, useMemo, useEffect } from 'react';
import { PageShell } from '../ui/PageShell';
import { theme } from '../ui/theme';
import { PageId, Status } from '../domain/types';
import { CalendarMenu } from '../components/CalendarMenu';
import { 
  getBestStatusForDay, 
  sortPerformancesForDisplay, 
  getConcertNavigationTarget 
} from '../domain/logic';

interface Props {
  onNavigate: (id: PageId) => void;
}

// Visual indicator mapping for dots
const colorMap: Record<Status, string> = {
  '参戦予定': theme.colors.primary,
  '抽選中': '#F59E0B', // Amber 500
  '検討中': '#9CA3AF',
  '発売前': '#10B981', // Emerald 500
  '参戦済み': theme.colors.primary,
  '見送': '#D1D5DB',
};

export const CalendarPage: React.FC<Props> = ({ onNavigate }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<string | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [weekStart, setWeekStart] = useState<'sun' | 'mon'>('sun');

  // Local filter states (sync with storage in real app)
  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);

  // Clear selected date when month/year changes
  useEffect(() => {
    setSelectedDate(null);
  }, [currentDate.getFullYear(), currentDate.getMonth()]);

  // Mock data - Updated to include lotteryResultDate if needed and ensure Japanese status strings
  const rawMockConcerts = useMemo(() => [
    { id: '1', date: '2024-08-15', artist: 'Artist Beta', tour: 'Summer Fest', status: '参戦済み' as Status },
    { id: '2', date: '2024-08-20', artist: 'Artist Alpha', tour: 'Gateway Tour', status: '参戦予定' as Status },
    { id: '3', date: '2024-08-20', artist: 'Artist Gamma', tour: 'Club Night', status: '検討中' as Status },
    { id: '4', date: '2024-08-28', artist: 'Artist Alpha', tour: 'Acoustic Journey', status: '抽選中' as Status },
    { id: '5', date: 'TBD', artist: 'Secret Artist', tour: 'Hidden Tour', status: '検討中' as Status },
  ], []);

  // Filter concerts based on status visibility and exclude TBD
  const filteredConcerts = useMemo(() => {
    return rawMockConcerts.filter(c => {
      if (c.date === 'TBD') return false; // Exclusion Rule 3
      if (!showAttended && c.status === '参戦済み') return false; // Exclusion Rule 6
      if (!showSkipped && c.status === '見送') return false; // Exclusion Rule 6
      return true;
    });
  }, [rawMockConcerts, showAttended, showSkipped]);

  const daysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
  const firstDayOfMonth = (year: number, month: number) => new Date(year, month, 1).getDay();

  const calendarDays = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const count = daysInMonth(year, month);
    let startDay = firstDayOfMonth(year, month);
    if (weekStart === 'mon') startDay = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < startDay; i++) days.push(null);
    for (let i = 1; i <= count; i++) days.push(i);
    return days;
  }, [currentDate, weekStart]);

  const getDayConcerts = (day: number) => {
    const dateStr = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    const dayConcerts = filteredConcerts.filter(c => c.date === dateStr);
    return sortPerformancesForDisplay(dayConcerts as any); // Requirement 4
  };

  const handleDayClick = (day: number) => {
    const dateStr = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSelectedDate(dateStr === selectedDate ? null : dateStr);
  };

  const handleConcertClick = (status: Status) => {
    const target = getConcertNavigationTarget(status); // Requirement 7
    onNavigate(target);
  };

  return (
    <PageShell
      header={
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingBottom: '8px' }}>
