          </h1>
          <button style={{ padding: '12px', borderRadius: '9999px', background: 'white', border: '1px solid #F3F4F6', color: '#9CA3AF', cursor: 'pointer' }}>
            <svg style={{ width: '24px', height: '24px' }} fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path>
            </svg>
          </button>
        </div>
      }
    >
      <div style={{ paddingBottom: '120px' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
          <div style={{ fontSize: '24px', fontWeight: '900' }}>{currentDate.getFullYear()}年 {currentDate.getMonth() + 1}月</div>
          <div style={{ display: 'flex', gap: '8px' }}>
            <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1))} style={{ width: '40px', height: '40px', borderRadius: '50%', border: 'none', background: '#F3F4F6', cursor: 'pointer' }}>◀</button>
            <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1))} style={{ width: '40px', height: '40px', borderRadius: '50%', border: 'none', background: '#F3F4F6', cursor: 'pointer' }}>▶</button>
          </div>
        </div>

        <div style={{ background: 'white', borderRadius: '32px', padding: '24px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 12px rgba(0,0,0,0.03)' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '8px' }}>
            {(weekStart === 'sun' ? ['日', '月', '火', '水', '木', '金', '土'] : ['月', '火', '水', '木', '金', '土', '日']).map(l => (
              <div key={l} style={{ textAlign: 'center', fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary }}>{l}</div>
            ))}
            {calendarDays.map((day, idx) => {
              if (day === null) return <div key={idx} />;
              const concerts = getDayConcerts(day);
              const bestStatus = getBestStatusForDay(concerts as any); // Requirement 1
              const isSelected = selectedDate === `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
              return (
                <div 
                  key={day} 
                  onClick={() => handleDayClick(day)} 
                  style={{ 
                    aspectRatio: '1/1', 
                    display: 'flex', 
                    flexDirection: 'column', 
                    alignItems: 'center', 
                    justifyContent: 'center', 
                    borderRadius: '16px', 
                    background: isSelected ? 'rgba(83, 190, 232, 0.1)' : 'transparent', 
                    border: isSelected ? '2px solid #53BEE8' : 'none', 
                    cursor: 'pointer', 
                    position: 'relative' 
                  }}
                >
                  <span style={{ fontSize: '16px', fontWeight: '600' }}>{day}</span>
                  {/* Requirement 2: dot marker only */}
                  {bestStatus && (
                    <div style={{ 
                      position: 'absolute', 
                      bottom: '6px', 
                      width: '6px', 
                      height: '6px', 
                      borderRadius: '50%', 
                      background: colorMap[bestStatus] 
