              );
            })}
          </div>
        </div>

        {selectedDate && (
          <div style={{ marginTop: '32px' }} className="fade-in">
            <h3 style={{ fontSize: '14px', fontWeight: '700', color: theme.colors.textSecondary, marginBottom: '16px', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
              {selectedDate.replace(/-/g, '.')}
            </h3>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
              {/* Requirement 4: using common sort logic within day list */}
              {sortPerformancesForDisplay(filteredConcerts.filter(c => c.date === selectedDate) as any).map((c: any) => (
                <div 
                  key={c.id} 
                  onClick={() => handleConcertClick(c.status)}
                  style={{ 
                    background: 'white', 
                    borderRadius: '24px', 
                    padding: '20px', 
                    border: '1px solid rgba(0,0,0,0.04)', 
                    boxShadow: '0 4px 12px rgba(0,0,0,0.03)', 
                    display: 'flex', 
                    justifyContent: 'space-between', 
                    alignItems: 'center',
                    cursor: 'pointer'
                  }}
                >
                  <div>
                    <div style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: '700' }}>{c.artist}</div>
                    <div style={{ fontSize: '17px', fontWeight: '800' }}>{c.tour}</div>
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: colorMap[c.status] }} />
                    <span style={{ fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary }}>{c.status}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      <div style={{ position: 'fixed', left: '32px', bottom: '100px', zIndex: 90 }}>
        <button 
          onClick={() => setIsMenuOpen(!isMenuOpen)} 
          style={{ 
            width: '64px', height: '64px', borderRadius: '9999px', display: 'flex', alignItems: 'center', justifyContent: 'center', 
            background: 'white', border: '1px solid #F3F4F6', color: '#9CA3AF', boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.1)', cursor: 'pointer' 
          }}
        >
          <svg style={{ width: '32px', height: '32px' }} fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z"></path>
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path>
          </svg>
        </button>
      </div>
      <CalendarMenu 
        isOpen={isMenuOpen} 
