  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);

  // Mock artist data
  const artist: Artist = {
    id: 'a1',
    name: 'Artist Alpha',
    imageUrl: '',
    links: [{ name: 'Official', url: '#', autoTrack: true }],
    autoTrackConcerts: true,
    autoTrackTickets: true,
    tours: [
      {
        id: 't1',
        name: '2024 WORLD TOUR [GATEWAY]',
        imageUrl: '',
        concerts: [
          { id: 'c1', date: '2024.08.20', venue: 'TOKYO DOME', status: '参戦予定', isParticipated: true, images: [], price: 12000, saleLink: '' },
          { id: 'c2', date: '2024.08.21', venue: 'TOKYO DOME', status: '参戦済み', isParticipated: true, images: [], price: 12000, saleLink: '' },
          { id: 'c3', date: 'TBD', venue: 'OSAKA', status: '発売前', isParticipated: false, images: [], price: 0, saleLink: '' },
          { id: 'c4', date: '2024.12.01', venue: 'NAGOYA', status: '見送', isParticipated: false, images: [], price: 0, saleLink: '' },
        ]
      }
    ]
  };

  // Rule 1: Always use centralized logic for status calculation
  const status = calcArtistStatus(artist);

  // Rule 2, 3 & 5: Filter and Sort concerts, hide empty tours
  const processedTours = useMemo(() => {
    return artist.tours
      .map(tour => {
        const filteredConcerts = tour.concerts.filter(c => {
          if (!showAttended && c.status === '参戦済み') return false;
          if (!showSkipped && c.status === '見送') return false;
          return true;
        });

        return {
          ...tour,
          concerts: sortPerformancesForDisplay(filteredConcerts)
        };
      })
      .filter(tour => tour.concerts.length > 0);
  }, [artist.tours, showAttended, showSkipped]);

  const handleAddConcert = () => {
    // Rule 7: Directly add to current artist (skipping selection)
    // In a real app, this would pass the artistId via routing or state
    onNavigate('CONCERT_EDITOR');
  };

  return (
    <PageShell
      header={
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <button onClick={onBack} style={{ border: 'none', background: 'none', color: '#9CA3AF', cursor: 'pointer', padding: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Icons.ChevronLeft />
          </button>
          {/* Rule 6: Edit path only via this button - Updated to Icon Style */}
          <IconButton 
            icon={<Icons.Edit />} 
            onClick={() => onNavigate('ARTIST_EDITOR')}
            size={40}
            style={{ 
              borderRadius: '16px', 
              color: theme.colors.primary, 
              borderColor: '#F3F4F6' 
            }}
          />
        </div>
      }
    >
      <div style={{ paddingBottom: '120px' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '24px', marginBottom: '32px' }}>
          <div style={{ width: '88px', height: '88px', borderRadius: '50%', background: '#F3F4F6', border: '3px solid white', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }} />
          <div>
            <h1 style={{ fontSize: '32px', fontWeight: '900', margin: 0 }}>{artist.name}</h1>
            <div style={{ display: 'flex', gap: '8px', marginTop: '10px' }}>
              {artist.links.map(l => <span key={l.name} style={{ fontSize: '11px', fontWeight: '700', color: theme.colors.primary, background: 'rgba(83, 190, 232, 0.08)', padding: '4px 10px', borderRadius: '8px' }}>{l.name}</span>)}
            </div>
          </div>
        </div>

        <div style={{ background: 'white', borderRadius: '32px', padding: '24px', border: '1px solid rgba(0, 0, 0, 0.04)', marginBottom: '32px' }}>
          <div style={{ fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary, textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '4px' }}>Status</div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
            <span style={{ fontSize: '24px', fontWeight: '900', color: theme.colors.primary }}>{status.main}</span>
            {status.sub && <span style={{ fontSize: '14px', color: theme.colors.textSecondary, fontWeight: '500' }}>/ {status.sub}</span>}
          </div>
        </div>

        {processedTours.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '40px', color: theme.colors.textWeak }}>
            表示可能な公演がありません
          </div>
        ) : (
          processedTours.map(tour => (
            <div key={tour.id} style={{ marginBottom: '32px' }}>
              <h3 style={{ fontSize: '18px', fontWeight: '900', marginBottom: '12px', paddingLeft: '4px' }}>{tour.name}</h3>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                {tour.concerts.map(c => (
                  <ConcertItem 
                    key={c.id} 
                    concert={c} 
                    onClick={() => onNavigate('CONCERT_HOME')} 
                  />
                ))}
              </div>
            </div>
          ))
        )}
      </div>

      <IconButton 
        icon={<Icons.Plus />} 
        primary 
        size={64} 
        onClick={handleAddConcert} 
        style={{ position: 'fixed', right: '32px', bottom: '100px', zIndex: 90 }} 
      />
      <div style={{ position: 'fixed', left: '32px', bottom: '100px', zIndex: 90 }}>
        <button onClick={() => setIsMenuOpen(!isMenuOpen)} style={{ width: '64px', height: '64px', borderRadius: '9999px', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'white', border: '1px solid #F3F4F6', color: '#9CA3AF', boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.1)', cursor: 'pointer' }}>
          <Icons.Menu />
        </button>
      </div>
      <ArtistDetailMenu 
        isOpen={isMenuOpen} 
        onClose={() => setIsMenuOpen(false)}
        showAttended={showAttended}
        onToggleAttended={() => setShowAttended(!showAttended)}
        showSkipped={showSkipped}
        onToggleSkipped={() => setShowSkipped(!showSkipped)}
      />
    </PageShell>
  );
};

import React, { useState, useEffect } from 'react';
