interface Props {
  artistId?: string;
  onSave: () => void;
  onCancel: () => void;
  onNavigate: (id: PageId) => void;
}

export const ArtistEditorPage: React.FC<Props> = ({ artistId, onSave, onCancel, onNavigate }) => {
  // Requirement 1: Main status and sub labels are calculation-only, hidden from editor.
  const initialArtist: Artist = {
    id: artistId || 'new',
    name: artistId ? 'アーティスト A' : '',
    imageUrl: artistId ? 'https://via.placeholder.com/150' : '',
    links: artistId ? [
      { name: 'Official Site', url: 'https://example.com', autoTrack: true, trackingStatus: 'success', lastCheckedAt: '2024/05/10 12:00' },
      { name: 'X (Twitter)', url: 'https://x.com/artist', autoTrack: false, trackingStatus: 'failed', errorMessage: 'ページの内容が変わりました', lastCheckedAt: '2024/05/10 11:30' }
    ] : [],
    autoTrackConcerts: true,
    autoTrackTickets: true,
    tours: artistId ? [{ id: 't1', name: '2024 WORLD TOUR [GATEWAY]', imageUrl: '', concerts: [{}, {}] as any }] : [],
  };

  const [formData, setFormData] = useState<Artist>(initialArtist);
  const [hasChanges, setHasChanges] = useState(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [activeFailure, setActiveFailure] = useState<SiteLink | null>(null);

  useEffect(() => {
    setHasChanges(JSON.stringify(formData) !== JSON.stringify(initialArtist));
  }, [formData]);

  const handleUpdateField = (field: keyof Artist, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleAddLink = () => {
    // Requirement 4: Default autoTrack = OFF for new items
    const newLink: SiteLink = {
      name: '',
      url: '',
      autoTrack: false
    };
    handleUpdateField('links', [...formData.links, newLink]);
  };

  const handleRemoveLink = (index: number) => {
    // Requirement 5: Removal discards info, doesn't affect others
    const newLinks = [...formData.links];
    newLinks.splice(index, 1);
    handleUpdateField('links', newLinks);
  };

  const handleUpdateLink = (index: number, updates: Partial<SiteLink>) => {
    const newLinks = [...formData.links];
    newLinks[index] = { ...newLinks[index], ...updates };
    handleUpdateField('links', newLinks);
  };

  return (
    <div style={{ paddingBottom: '120px' }}>
      <header style={headerStyle}>
        {/* Requirement 8: Cancel vs Save model - Updated to Icons */}
        <IconButton 
          icon={<Icons.X />} 
          onClick={onCancel}
          size={40}
          style={{ 
            color: theme.colors.textSecondary, 
            borderColor: 'transparent', 
            background: 'transparent',
            boxShadow: 'none'
          }}
        />
        <h2 style={{ fontSize: '17px', margin: 0, fontWeight: 'bold' }}>アーティスト編集</h2>
        <IconButton 
          icon={<Icons.Check />} 
          onClick={onSave}
          disabled={!hasChanges || !formData.name}
          size={40}
          style={{ 
            color: theme.colors.primary, 
            borderColor: 'transparent', 
            background: 'transparent',
            boxShadow: 'none'
          }}
        />
      </header>

      <section style={{ marginBottom: theme.spacing.xl }}>
        <h3 style={sectionTitleStyle}>基本情報</h3>
        <GlassCard padding={theme.spacing.md}>
          <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.md }}>
            <Field label="アーティスト名 (必須)">
              <input type="text" value={formData.name} onChange={e => handleUpdateField('name', e.target.value)} placeholder="名称を入力" style={inputStyle} />
            </Field>
            <Field label="画像URL">
              <input type="url" value={formData.imageUrl} onChange={e => handleUpdateField('imageUrl', e.target.value)} placeholder="https://..." style={inputStyle} />
            </Field>
          </div>
        </GlassCard>
      </section>

      {/* Requirement 2: Explicit auto-tracking toggles with mandatory notes */}
      <section style={{ marginBottom: theme.spacing.xl }}>
        <h3 style={sectionTitleStyle}>追跡設定</h3>
        <GlassCard padding={theme.spacing.md}>
          <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.lg }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div>
                <div style={{ fontWeight: '600', fontSize: '15px' }}>公演自動追跡</div>
                <div style={{ fontSize: '12px', color: theme.colors.textSecondary }}>新規ツアー・公演情報を自動取得します</div>
              </div>
              <Toggle active={formData.autoTrackConcerts} onToggle={() => handleUpdateField('autoTrackConcerts', !formData.autoTrackConcerts)} />
            </div>

            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div>
                <div style={{ fontWeight: '600', fontSize: '15px' }}>チケット自動追跡</div>
                <div style={{ fontSize: '12px', color: theme.colors.textSecondary }}>販売・抽選情報を自動更新します</div>
                <div style={{ fontSize: '11px', color: theme.colors.error, marginTop: '4px', fontWeight: 'bold' }}>
                  ※ 当選後はチケット追跡は行われません
                </div>
              </div>
              <Toggle active={formData.autoTrackTickets} onToggle={() => handleUpdateField('autoTrackTickets', !formData.autoTrackTickets)} />
            </div>
          </div>
        </GlassCard>
      </section>

      {/* Requirement 3: Flat Site List (No categories) */}
      <section style={{ marginBottom: theme.spacing.xl }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: theme.spacing.sm }}>
          <h3 style={{ ...sectionTitleStyle, marginBottom: 0 }}>追跡サイト一覧</h3>
          <button onClick={handleAddLink} style={actionButtonStyle}>＋ 追加</button>
        </div>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
          {formData.links.map((link, idx) => (
            <GlassCard key={idx} padding={theme.spacing.md}>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                  <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '8px' }}>
                    <input 
                      type="text" 
                      value={link.name} 
                      onChange={e => handleUpdateLink(idx, { name: e.target.value })} 
                      placeholder="サイト名" 
                      style={inputStyle} 
                    />
                    <input 
                      type="url" 
                      value={link.url} 
                      onChange={e => handleUpdateLink(idx, { url: e.target.value })} 
                      placeholder="URL" 
                      style={inputStyle} 
                    />
                  </div>
                  <button 
                    onClick={() => handleRemoveLink(idx)}
                    style={{ border: 'none', background: 'none', padding: '8px', cursor: 'pointer', color: theme.colors.textLabel }}
                  >
                    🗑️
                  </button>
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderTop: '0.5px solid rgba(0,0,0,0.05)', paddingTop: '12px' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <span style={{ fontSize: '13px', fontWeight: '600' }}>自動追跡</span>
                    {link.trackingStatus === 'failed' && (
                      <button 
                        onClick={() => setActiveFailure(link)}
                        style={{ border: 'none', background: 'none', fontSize: '14px', cursor: 'pointer', padding: 0 }}
                      >⚠️</button>
                    )}
                  </div>
                  <Toggle active={link.autoTrack} onToggle={() => handleUpdateLink(idx, { autoTrack: !link.autoTrack })} />
                </div>
              </div>
            </GlassCard>
          ))}
        </div>
      </section>

      {/* Requirement 6: Tour list with direct "Edit" button to Concert Editor */}
      {formData.tours.length > 0 && (
        <section style={{ marginBottom: theme.spacing.xl }}>
          <h3 style={sectionTitleStyle}>登録済みツアー</h3>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
            {formData.tours.map(tour => (
              <GlassCard key={tour.id} padding={theme.spacing.md}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <div style={{ fontWeight: '700', fontSize: '15px' }}>{tour.name}</div>
                  <button 
                    onClick={() => onNavigate('CONCERT_EDITOR')}
                    style={{ 
                      padding: '8px 16px', 
                      borderRadius: '12px', 
                      background: 'rgba(83, 190, 232, 0.1)', 
                      color: theme.colors.primary, 
                      border: 'none', 
                      fontWeight: 'bold', 
                      fontSize: '13px',
                      cursor: 'pointer' 
                    }}
                  >
                    編集
                  </button>
                </div>
              </GlassCard>
            ))}
          </div>
        </section>
      )}

      {/* Requirement 7: Destructive action with confirmation */}
      <section style={{ marginTop: '40px' }}>
        <button onClick={() => setIsDeleteModalOpen(true)} style={deleteButtonStyle}>アーティストを削除</button>
      </section>

      {/* Error Details */}
      {activeFailure && (
        <ConfirmDialog 
          isOpen={!!activeFailure}
          title="追跡エラー詳細"
          message={`最終確認：${activeFailure.lastCheckedAt}\nエラー：${activeFailure.errorMessage || '不明なエラー'}`}
          confirmLabel="閉じる"
          onClose={() => setActiveFailure(null)}
          onConfirm={() => setActiveFailure(null)}
        />
      )}

      <ConfirmDialog 
        isOpen={isDeleteModalOpen} 
        title="アーティストを削除しますか？" 
        message="このアーティストに紐づくすべてのツアー、公演、思い出アルバムのデータが完全に削除されます。この操作は取り消せません。" 
        confirmLabel="削除する" 
        isDestructive 
        onClose={() => setIsDeleteModalOpen(false)} 
        onConfirm={() => onCancel()} 
      />
    </div>
  );
};

// Styles
const headerStyle: React.CSSProperties = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: theme.spacing.xl, position: 'sticky', top: 0, zIndex: 100, background: theme.colors.background, padding: `${theme.spacing.sm} 0` };
const sectionTitleStyle: React.CSSProperties = { fontSize: '13px', color: theme.colors.textSecondary, fontWeight: 'bold', marginBottom: theme.spacing.sm, paddingLeft: '4px' };
const inputStyle: React.CSSProperties = { width: '100%', padding: '10px 12px', borderRadius: '10px', border: '1px solid rgba(0,0,0,0.08)', background: 'rgba(255,255,255,0.4)', fontSize: '15px', outline: 'none' };
const actionButtonStyle: React.CSSProperties = { border: 'none', background: 'none', color: theme.colors.primary, fontSize: '14px', fontWeight: '600', cursor: 'pointer' };
const deleteButtonStyle: React.CSSProperties = { width: '100%', padding: '16px', borderRadius: theme.radius.card, background: 'rgba(255, 59, 48, 0.08)', color: theme.colors.error, border: 'none', fontWeight: 'bold', fontSize: '15px', cursor: 'pointer' };
const Field = ({ label, children }: any) => (<div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}><label style={{ fontSize: '12px', color: theme.colors.textSecondary, marginLeft: '4px' }}>{label}</label>{children}</div>);
const Toggle = ({ active, onToggle }: any) => (<div onClick={onToggle} style={{ width: '46px', height: '26px', borderRadius: '13px', background: active ? theme.colors.primary : '#E9E9EB', position: 'relative', cursor: 'pointer' }}><div style={{ position: 'absolute', top: '2px', left: active ? '22px' : '2px', width: '22px', height: '22px', borderRadius: '11px', background: 'white', transition: 'left 0.2s' }} /></div>);

import React, { useState, useEffect, useMemo } from 'react';
import { theme } from '../ui/theme';
import { GlassCard } from '../ui/GlassCard';
import { ConfirmDialog } from '../components/ConfirmDialog';
import { PageId, Tour, Concert, Status } from '../domain/types';
import { Icons, IconButton } from '../ui/IconButton';
import { sortPerformancesForDisplay, checkDateConflicts } from '../domain/logic';

const Field = ({ label, children, description }: { label: string; children: any; description?: string }) => (
  <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
    <label style={{ fontSize: '12px', color: theme.colors.textSecondary, marginLeft: '4px', fontWeight: 'bold' }}>{label}</label>
    {children}
    {description && <div style={{ fontSize: '10px', color: theme.colors.textWeak, marginLeft: '4px' }}>{description}</div>}
  </div>
);

interface Props {
  tourId?: string;
  onSave: () => void;
  onCancel: () => void;
}

const statusOptions: { value: Status; label: string }[] = [
  { value: '発売前', label: '発売前' },
  { value: '検討中', label: '検討中' },
  { value: '抽選中', label: '抽選中' },
  { value: '参戦予定', label: '参戦予定' },
  { value: '参戦済み', label: '参戦済み' },
  { value: '見送', label: '見送' },
];

export const ConcertEditorPage: React.FC<Props> = ({ tourId, onSave, onCancel }) => {
  const initialTour: Tour = {
    id: tourId || 'new-tour',
    name: tourId ? '2024 WORLD TOUR [GATEWAY]' : '',
    imageUrl: tourId ? 'https://images.unsplash.com/photo-1470225620780-dba8ba36b745' : '',
    memo: '',
    concerts: tourId ? [
      { id: 'c1', date: '2024-08-20', venue: 'TOKYO DOME', price: 12000, saleLink: '', status: '参戦予定', isParticipated: true, images: [] },
    ] : []
  };

  const [formData, setFormData] = useState<Tour>(initialTour);
  const [hasChanges, setHasChanges] = useState(false);
  const [expandedConcertId, setExpandedConcertId] = useState<string | null>(null);
  const [isDeleteTourModalOpen, setIsDeleteTourModalOpen] = useState(false);
  const [isDeleteConcertModalOpen, setIsDeleteConcertModalOpen] = useState<string | null>(null);
  const [isConflictDialogOpen, setIsConflictDialogOpen] = useState(false);

  useEffect(() => {
    // Basic change detection for the "Save" button state
    setHasChanges(JSON.stringify(formData) !== JSON.stringify(initialTour));
  }, [formData]);

  const sortedConcerts = useMemo(() => {
    // Requirement 5: Sorting depends on common logic, even for TBD dates
    return sortPerformancesForDisplay(formData.concerts);
  }, [formData.concerts]);

  const handleSave = () => {
    // Requirement 4: Duplicate date check on Save
    const conflicts = checkDateConflicts(formData.concerts);
    if (conflicts.length > 0) {
      setIsConflictDialogOpen(true);
      return;
    }
    // Logic to actually persist data would go here
    onSave();
  };

  const handleUpdateTour = (field: keyof Tour, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleAddConcert = () => {
    const newConcert: Concert = {
      id: `new-${Date.now()}`,
      date: 'TBD', // Requirement 5: TBD is allowed
      venue: '',
      price: 0,
      saleLink: '',
      status: '発売前',
      isParticipated: false,
      images: []
    };
    setFormData(prev => ({ ...prev, concerts: [...prev.concerts, newConcert] }));
    setExpandedConcertId(newConcert.id);
  };

  const handleUpdateConcert = (id: string, updates: Partial<Concert>) => {
    setFormData(prev => ({
      ...prev,
      concerts: prev.concerts.map(c => c.id === id ? { ...c, ...updates } : c)
    }));
  };

  const handleDeleteConcert = (id: string) => {
    setFormData(prev => ({
      ...prev,
      concerts: prev.concerts.filter(c => c.id !== id)
    }));
    setIsDeleteConcertModalOpen(null);
  };

  return (
    <div style={{ paddingBottom: '160px' }}>
      <header style={headerStyle}>
        {/* Requirement 8: Cancel discards everything - Updated to Icons */}
        <IconButton 
          icon={<Icons.X />} 
          onClick={onCancel}
          size={40}
          style={{ 
            color: theme.colors.textSecondary, 
            borderColor: 'transparent', 
            background: 'transparent',
            boxShadow: 'none'
          }}
        />
        <h2 style={{ fontSize: '17px', margin: 0, fontWeight: 'bold' }}>ツアー・公演編集</h2>
        {/* Requirement 8: Save commits everything - Updated to Icons */}
        <IconButton 
          icon={<Icons.Check />} 
          onClick={handleSave}
          disabled={!hasChanges || !formData.name}
          size={40}
          style={{ 
            color: theme.colors.primary, 
            borderColor: 'transparent', 
            background: 'transparent',
            boxShadow: 'none'
          }}
        />
      </header>

      {/* Requirement 1: Upper section - Tour Information */}
      <section style={{ marginBottom: theme.spacing.xl }}>
        <h3 style={sectionTitleStyle}>ツアー情報 (共通)</h3>
        <GlassCard padding={theme.spacing.md}>
          <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.md }}>
            <Field label="ツアー名 (必須)">
              <input type="text" value={formData.name} onChange={e => handleUpdateTour('name', e.target.value)} placeholder="名称を入力" style={inputStyle} />
            </Field>
            <Field label="ツアー画像URL">
              <input type="url" value={formData.imageUrl} onChange={e => handleUpdateTour('imageUrl', e.target.value)} placeholder="https://..." style={inputStyle} />
            </Field>
            <Field label="メモ">
              <textarea 
                value={formData.memo} 
                onChange={e => handleUpdateTour('memo', e.target.value)} 
                placeholder="ツアーに関する全体メモ" 
                style={{ ...inputStyle, minHeight: '80px', resize: 'none' }} 
              />
            </Field>
          </div>
        </GlassCard>
      </section>

      {/* Requirement 1: Lower section - Concert List (Field) */}
      <section style={{ marginBottom: theme.spacing.xl }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: theme.spacing.sm }}>
          <h3 style={{ ...sectionTitleStyle, marginBottom: 0 }}>公演一覧 (場次)</h3>
          <button onClick={handleAddConcert} style={actionButtonStyle}>＋ 公演を追加</button>
        </div>

        {sortedConcerts.length === 0 ? (
          <GlassCard padding={theme.spacing.lg} style={{ textAlign: 'center', color: theme.colors.textSecondary }}>まだ公演が登録されていません</GlassCard>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.sm }}>
            {sortedConcerts.map(concert => {
              const isExpanded = expandedConcertId === concert.id;
              // Requirement 3: Lottery info display condition
              const showLotteryInfo = ['抽選中', '参戦予定', '見送'].includes(concert.status);

              return (
                <GlassCard key={concert.id} padding="0">
                  <div onClick={() => setExpandedConcertId(isExpanded ? null : concert.id)} style={{ padding: theme.spacing.md, cursor: 'pointer', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <div>
                      <div style={{ fontWeight: '700', fontSize: '15px' }}>{concert.date}</div>
                      <div style={{ fontSize: '12px', color: theme.colors.textSecondary }}>{concert.venue || '会場未入力'}</div>
                    </div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                      <span style={{ fontSize: '13px', fontWeight: '600', color: theme.colors.primary }}>
                        {concert.status}
                      </span>
                      <span style={{ 
                        transform: isExpanded ? 'rotate(180deg)' : 'none', 
                        transition: 'transform 0.2s',
                        fontSize: '10px'
                      }}>▼</span>
                    </div>
                  </div>
                  {isExpanded && (
                    <div style={{ padding: `0 ${theme.spacing.md} ${theme.spacing.md} ${theme.spacing.md}`, display: 'flex', flexDirection: 'column', gap: theme.spacing.md, borderTop: '0.5px solid rgba(0,0,0,0.05)', paddingTop: theme.spacing.md }}>
                      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                        <Field label="日付" description="YYYY-MM-DD or TBD">
                          <input type="text" value={concert.date} onChange={e => handleUpdateConcert(concert.id, { date: e.target.value })} style={inputStyle} />
                        </Field>
                        <Field label="会場">
                          <input type="text" value={concert.venue} onChange={e => handleUpdateConcert(concert.id, { venue: e.target.value })} style={inputStyle} />
                        </Field>
                      </div>

                      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                        <Field label="状態">
                          <select value={concert.status} onChange={e => handleUpdateConcert(concert.id, { status: e.target.value as Status })} style={inputStyle}>
                            {statusOptions.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                          </select>
                        </Field>
                        <Field label="チケット価格">
                          <input type="number" value={concert.price} onChange={e => handleUpdateConcert(concert.id, { price: Number(e.target.value) })} style={inputStyle} />
                        </Field>
                      </div>

                      {/* Requirement 3: Lottery fields visible only for specific statuses */}
                      {showLotteryInfo && (
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', padding: '12px', background: 'rgba(0,0,0,0.02)', borderRadius: '12px' }}>
                          <Field label="抽選名">
                            <input 
                              type="text" 
                              value={concert.lotteryName || ''} 
                              onChange={e => handleUpdateConcert(concert.id, { lotteryName: e.target.value })} 
                              placeholder="FC先行、一般など"
                              style={inputStyle} 
                            />
                          </Field>
                          <Field label="抽選結果日時">
                            <input 
                              type="text" 
                              value={concert.lotteryResultDate || ''} 
                              onChange={e => handleUpdateConcert(concert.id, { lotteryResultDate: e.target.value })} 
                              placeholder="YYYY/MM/DD HH:MM"
                              style={inputStyle} 
                            />
                          </Field>
                        </div>
                      )}

                      <Field label="販売ページURL">
                        <input type="url" value={concert.saleLink} onChange={e => handleUpdateConcert(concert.id, { saleLink: e.target.value })} placeholder="https://..." style={inputStyle} />
                      </Field>

                      <button 
                        onClick={(e) => { e.stopPropagation(); setIsDeleteConcertModalOpen(concert.id); }} 
                        style={{ alignSelf: 'flex-start', border: 'none', background: 'none', color: theme.colors.error, fontSize: '13px', fontWeight: 'bold', cursor: 'pointer', padding: '8px 0' }}
                      >
                        🗑️ この公演を削除
                      </button>
                    </div>
                  )}
                </GlassCard>
              );
            })}
          </div>
        )}
      </section>

      {/* Requirement 7: Tour deletion at the bottom, red, with confirmation */}
      <section style={{ marginTop: '64px', padding: '0 4px' }}>
        <button 
          onClick={() => setIsDeleteTourModalOpen(true)}
          style={{ 
            width: '100%', 
            padding: '16px', 
            borderRadius: theme.radius.button, 
            background: 'rgba(255, 59, 48, 0.08)', 
            color: theme.colors.error, 
            border: 'none', 
            fontWeight: 'bold', 
            fontSize: '15px',
            cursor: 'pointer'
          }}
        >
          ツアーを削除
        </button>
        <div style={{ fontSize: '11px', color: theme.colors.textSecondary, textAlign: 'center', marginTop: '12px' }}>
          ※ ツアー配下の全公演および思い出アルバムも削除されます
        </div>
      </section>

      {/* Dialogs */}
      <ConfirmDialog 
        isOpen={isConflictDialogOpen} 
        title="日付の重複" 
        message="参戦予定または参戦済みの公演が同じ日に複数存在します。日付を変更してください。" 
        confirmLabel="確認" 
        onClose={() => setIsConflictDialogOpen(false)} 
        onConfirm={() => setIsConflictDialogOpen(false)} 
      />

      <ConfirmDialog 
        isOpen={isDeleteTourModalOpen} 
        title="ツアーを完全に削除しますか？" 
        message="このツアー、配下の全公演、およびアルバム画像がすべて削除されます。この操作は取り消せません。" 
        confirmLabel="ツアーを削除" 
        isDestructive 
        onClose={() => setIsDeleteTourModalOpen(false)} 
        onConfirm={() => onCancel()} 
      />

      <ConfirmDialog 
        isOpen={!!isDeleteConcertModalOpen} 
        title="公演を削除しますか？" 
        message="この公演に関連する抽選情報やアルバム画像もすべて破棄されます。" 
        confirmLabel="公演を削除" 
        isDestructive 
        onClose={() => setIsDeleteConcertModalOpen(null)} 
        onConfirm={() => isDeleteConcertModalOpen && handleDeleteConcert(isDeleteConcertModalOpen)} 
      />
    </div>
  );
};

const headerStyle: React.CSSProperties = { 
  display: 'flex', 
  justifyContent: 'space-between', 
  alignItems: 'center', 
  marginBottom: theme.spacing.xl, 
  position: 'sticky', 
