            onClick={onBack} 
            style={{ 
              border: 'none', 
              background: 'rgba(255,255,255,0.15)', 
              backdropFilter: 'blur(10px)',
              color: 'white', 
              width: '44px', 
              height: '44px', 
              borderRadius: '22px', 
              display: 'flex', 
              alignItems: 'center', 
              justifyContent: 'center', 
              cursor: 'pointer' 
            }}
          >
            <Icons.ChevronLeft />
          </button>

          {/* Requirement 3: Edit button navigates to Artist Editor only - Updated to Icon */}
          <IconButton 
            icon={<Icons.Edit />} 
            onClick={() => onNavigate('ARTIST_EDITOR')}
            size={44}
            style={{ 
              background: 'rgba(255,255,255,0.15)', 
              backdropFilter: 'blur(10px)',
              border: 'none',
              color: 'white',
              boxShadow: 'none'
            }}
          />
        </header>

        <div style={{ color: 'white', marginBottom: '32px', textAlign: 'center' }}>
          {/* Requirement 7: No status or tracking info displayed here */}
          <h1 style={{ 
            fontSize: '32px', 
            fontWeight: '900', 
            margin: '0 0 8px 0', 
            textShadow: '0 4px 12px rgba(0,0,0,0.4)',
            letterSpacing: '-0.02em'
          }}>
