  primary?: boolean;
  size?: number;
  style?: React.CSSProperties;
  disabled?: boolean;
}

export const IconButton: React.FC<IconButtonProps> = ({ 
  icon, 
  onClick, 
  primary = false, 
  size = 44,
  style,
  disabled = false
}) => {
  return (
    <button
      onClick={onClick}
      disabled={disabled}
      style={{
        width: `${size}px`,
        height: `${size}px`,
        borderRadius: '9999px',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
