        {/* Delete button moved to header (Right) */}
        <IconButton 
          icon={<Icons.Trash />} 
          onClick={() => setIsDeleteModalOpen(true)}
          size={40}
          style={{ 
            color: theme.colors.error, 
            borderColor: 'transparent', 
            background: 'transparent',
            boxShadow: 'none'
          }}
        />
