        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
          <div style={{
            width: '8px',
            height: '8px',
            borderRadius: '50%',
            background: dotColor,
          }} />
          <div style={{
            fontSize: '11px',
            fontWeight: '700',
            color: theme.colors.textSecondary,
            letterSpacing: '0.05em',
            textTransform: 'uppercase'
          }}>
            {concert.status}
          </div>
        </div>
      </div>
    </div>
  );
};

export const ConcertListPage: React.FC<Props> = ({ artists, onOpenArtist, onOpenConcert, onCreateConcert, onRefreshAll }) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isArtistPickerOpen, setIsArtistPickerOpen] = useState(false);
  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);
  const [sortMode, setSortMode] = useState<'status' | 'lottery'>('status');

  // Flatten all concerts from all artists
  const allConcerts = useMemo(() => {
    const list: ConcertWithMetadata[] = [];
    artists.forEach(artist => {
      artist.tours.forEach(tour => {
        tour.concerts.forEach(concert => {
          list.push({
            ...concert,
            artistName: artist.name,
            artistId: artist.id,
            tourName: tour.name,
            tourId: tour.id
          });
        });
      });
    });
    return list;
  }, [artists]);

  // Filter -> Sort -> Display
  const processedConcerts = useMemo(() => {
    // 1. Filter
    let list = allConcerts.filter(c => {
      if (!showAttended && c.status === '参戦済み') return false;
      if (!showSkipped && c.status === '見送') return false;
      return true;
    });

    // 2. Sort
    if (sortMode === 'lottery') {
      return sortPerformancesByLotteryDate(list as any) as ConcertWithMetadata[];
    }
    return sortPerformancesForDisplay(list as any) as ConcertWithMetadata[];
  }, [allConcerts, showAttended, showSkipped, sortMode]);

  const handleCardClick = (concert: ConcertWithMetadata) => {
    // Instruction 2: ID-based navigation rules
    if (concert.status === '参戦予定' || concert.status === '参戦済み') {
      onOpenConcert(concert.id, concert.tourId, concert.artistId);
    } else {
      onOpenArtist(concert.artistId);
    }
  };

  return (
    <PageShell
      header={
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingBottom: '8px' }}>
          <h1 style={{ fontSize: '32px', fontWeight: '900', color: '#111827', margin: 0, letterSpacing: '-0.025em' }}>
            LiveTrack <span style={{ color: '#53BEE8' }}>JP</span>
          </h1>
          <button 
            onClick={onRefreshAll}
            style={{
              padding: '12px',
              borderRadius: '9999px',
              background: 'white',
              border: '1px solid #F3F4F6',
              color: '#9CA3AF',
              boxShadow: '0 1px 2px 0 rgba(0, 0, 0, 0.05)',
              cursor: 'pointer',
              outline: 'none'
            }}
          >
            <Icons.Refresh />
          </button>
        </div>
      }
    >
      <div style={{ display: 'flex', flexDirection: 'column', gap: '16px', paddingBottom: '120px' }}>
        {processedConcerts.length === 0 ? (
          <div style={{ 
            padding: '80px 20px', 
            textAlign: 'center', 
            color: theme.colors.textWeak,
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            gap: '24px'
          }}>
            <div style={{ fontSize: '48px', opacity: 0.5 }}>🎟️</div>
            <div style={{ fontSize: '15px', fontWeight: '600' }}>表示可能な公演がありません</div>
            <button 
              onClick={() => setIsArtistPickerOpen(true)}
              style={{
                padding: '12px 24px',
                borderRadius: '12px',
                background: theme.colors.primary,
                color: 'white',
                border: 'none',
                fontWeight: 'bold',
                cursor: 'pointer'
              }}
            >
              ＋ 公演を追加
            </button>
          </div>
        ) : (
          processedConcerts.map((concert) => (
            <ConcertRowCard 
              key={concert.id} 
              concert={concert} 
              onClick={() => handleCardClick(concert)} 
            />
          ))
        )}
      </div>

      <IconButton 
        icon={<Icons.Plus />} 
        primary 
        size={64}
        onClick={() => setIsArtistPickerOpen(true)}
        style={{ position: 'fixed', right: '32px', bottom: '100px', zIndex: 90, boxShadow: '0 12px 24px -6px rgba(83, 190, 232, 0.5)' }}
      />

      <div style={{ position: 'fixed', left: '32px', bottom: '100px', zIndex: 90 }}>
        <button 
          onClick={() => setIsMenuOpen(!isMenuOpen)}
          style={{ 
            width: '64px', height: '64px', borderRadius: '9999px', display: 'flex', alignItems: 'center', justifyContent: 'center', 
            background: 'white', border: '1px solid #F3F4F6', color: '#9CA3AF', boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.1)', cursor: 'pointer', outline: 'none'
          }}
        >
          <Icons.Menu />
        </button>
      </div>

      <ConcertMenu 
        isOpen={isMenuOpen} 
        onClose={() => setIsMenuOpen(false)} 
        showAttended={showAttended}
        onToggleAttended={() => setShowAttended(!showAttended)}
        showSkipped={showSkipped}
        onToggleSkipped={() => setShowSkipped(!showSkipped)}
        sortMode={sortMode}
        onSetSort={setSortMode}
      />

      {/* Artist Picker Overlay for Requirement 3 */}
      {isArtistPickerOpen && (
        <div style={{
          position: 'fixed',
          inset: 0,
          zIndex: 2000,
          background: 'rgba(0,0,0,0.4)',
          backdropFilter: 'blur(8px)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          padding: '24px'
        }}>
          <div style={{ position: 'fixed', inset: 0 }} onClick={() => setIsArtistPickerOpen(false)} />
          <GlassCard padding="24px" style={{ width: '100%', maxWidth: '360px', position: 'relative', display: 'flex', flexDirection: 'column', gap: '20px' }}>
            <h3 style={{ margin: 0, fontSize: '18px', fontWeight: '800' }}>公演を追加するアーティストを選択</h3>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '10px', maxHeight: '300px', overflowY: 'auto' }}>
              {artists.length === 0 ? (
                <div style={{ fontSize: '13px', color: theme.colors.textSecondary, textAlign: 'center', padding: '20px' }}>
                  アーティストを先に登録してください
                </div>
              ) : (
                artists.map(artist => (
                  <button 
                    key={artist.id}
                    onClick={() => {
                      onCreateConcert(artist.id);
                      setIsArtistPickerOpen(false);
                    }}
                    style={{
                      padding: '16px',
                      borderRadius: '16px',
                      border: '1px solid rgba(0,0,0,0.05)',
                      background: 'white',
                      textAlign: 'left',
                      fontWeight: '700',
                      fontSize: '15px',
                      cursor: 'pointer'
                    }}
                  >
                    {artist.name}
                  </button>
                ))
              )}
            </div>
            <button 
              onClick={() => setIsArtistPickerOpen(false)}
              style={{
                padding: '12px',
                borderRadius: '12px',
                border: 'none',
                background: 'rgba(0,0,0,0.05)',
                fontWeight: '700',
                cursor: 'pointer'
              }}
            >
              閉じる
            </button>
          </GlassCard>
        </div>
      )}
    </PageShell>
  );
};

import React from 'react';
import { GlassCard } from '../ui/GlassCard';
import { theme } from '../ui/theme';

interface ConcertMenuProps {
  isOpen: boolean;
  onClose: () => void;
  showAttended: boolean;
  onToggleAttended: () => void;
  showSkipped: boolean;
  onToggleSkipped: () => void;
  sortMode: 'status' | 'lottery';
  onSetSort: (mode: 'status' | 'lottery') => void;
}

export const ConcertMenu: React.FC<ConcertMenuProps> = ({ 
  isOpen, 
  onClose,
  showAttended,
  onToggleAttended,
  showSkipped,
  onToggleSkipped,
  sortMode,
  onSetSort
}) => {
  if (!isOpen) return null;

  return (
    <div style={{
      position: 'fixed',
      bottom: '160px',
      left: theme.spacing.md,
      zIndex: 1000,
      width: '260px',
    }}>
      <div 
        style={{ position: 'fixed', inset: 0, background: 'transparent' }} 
        onClick={onClose} 
      />
      <GlassCard className="fade-in">
        <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.md }}>
          <section>
            <h4 style={{ fontSize: '12px', color: theme.colors.textSecondary, marginBottom: theme.spacing.sm, fontWeight: 'bold' }}>並び替え</h4>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
              <MenuButton 
                label="状態順 (優先)" 
