            <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
              <MenuButton 
                label="参戦済みを表示" 
                toggle 
                active={showAttended} 
                onClick={onToggleAttended}
              />
              <MenuButton 
                label="見送を表示" 
                toggle 
                active={showSkipped} 
                onClick={onToggleSkipped}
              />
            </div>
          </section>
        </div>
      </GlassCard>
    </div>
  );
};

const MenuButton = ({ label, active, toggle, onClick, small }: any) => (
  <button 
    onClick={onClick}
    style={{
      width: '100%',
      textAlign: 'left',
      padding: small ? '6px 8px' : '8px 12px',
      borderRadius: '8px',
      border: 'none',
      background: active ? 'rgba(0,122,255,0.1)' : 'transparent',
      color: active ? theme.colors.primary : theme.colors.text,
      fontSize: small ? '12px' : '14px',
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center',
      cursor: 'pointer'
    }}
  >
    <span>{label}</span>
    {toggle && <span style={{ fontSize: '10px', fontWeight: 'bold' }}>{active ? 'ON' : 'OFF'}</span>}
  </button>
);

