import { Artist, Concert, DisplaySettings } from '../domain/types';
import { ArtistDetailMenu } from '../components/ArtistDetailMenu';
import { calcArtistStatus, sortPerformancesForDisplay } from '../domain/logic';

interface Props {
  artistId: string;
  artist: Artist;
  settings: DisplaySettings;
  onOpenArtistEditor: (artistId: string) => void;
  onOpenConcertEditor: (artistId: string) => void;
  onOpenConcertHome: (artistId: string, tourId: string, concertId: string) => void;
  onChangeSettings: (settings: Partial<DisplaySettings>) => void;
  onBack: () => void;
}

const ConcertItem = ({ concert, onClick }: { concert: Concert; onClick?: () => void }) => {
  const isSpecial = concert.status === '参戦予定' || concert.status === '参戦済み';
  const dotColor = isSpecial ? theme.colors.primary : '#9CA3AF';

  const canNavigate = !!onClick;

  return (
    <div 
      onClick={onClick}
      style={{
        background: 'white',
        borderRadius: '24px',
        padding: '16px 20px',
        border: '1px solid rgba(0, 0, 0, 0.04)',
        boxShadow: '0 4px 12px rgba(0,0,0,0.03)',
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        cursor: canNavigate ? 'pointer' : 'default'
      }}
    >
      <div>
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
          <span style={{ fontWeight: '800', fontSize: '16px' }}>{concert.date}</span>
          <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
            <div style={{ width: '6px', height: '6px', borderRadius: '50%', background: dotColor }} />
            <span style={{ fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary }}>{concert.status}</span>
          </div>
        </div>
        <div style={{ fontSize: '13px', color: theme.colors.textSecondary, marginTop: '2px' }}>{concert.venue || '会場未定'}</div>
      </div>
      {canNavigate && (
        <div style={{ color: '#D1D5DB' }}>
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <polyline points="9 18 15 12 9 6"></polyline>
          </svg>
        </div>
      )}
    </div>
  );
};

export const ArtistDetailPage: React.FC<Props> = ({ 
  artistId, 
  artist, 
  settings, 
  onOpenArtistEditor, 
  onOpenConcertEditor, 
  onOpenConcertHome,
  onChangeSettings,
  onBack 
}) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  // Rule 1: Always use centralized logic for status calculation
  const status = calcArtistStatus(artist);

  // Filter and Sort concerts, hide empty tours
  const processedTours = useMemo(() => {
    return artist.tours
      .map(tour => {
        const filteredConcerts = tour.concerts.filter(c => {
          if (!settings.showAttended && c.status === '参戦済み') return false;
          if (!settings.showSkipped && c.status === '見送') return false;
          return true;
        });

        return {
          ...tour,
          concerts: sortPerformancesForDisplay(filteredConcerts)
        };
      })
      .filter(tour => tour.concerts.length > 0);
  }, [artist.tours, settings]);

  return (
    <PageShell
      header={
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <button onClick={onBack} style={{ border: 'none', background: 'none', color: '#9CA3AF', cursor: 'pointer', padding: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Icons.ChevronLeft />
          </button>
          <IconButton 
            icon={<Icons.Edit />} 
            onClick={() => onOpenArtistEditor(artistId)}
            size={40}
            style={{ 
              borderRadius: '16px', 
              color: theme.colors.primary, 
              borderColor: '#F3F4F6' 
            }}
          />
        </div>
      }
    >
      <div style={{ paddingBottom: '120px' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '24px', marginBottom: '32px' }}>
          <div style={{ 
            width: '88px', 
            height: '88px', 
            borderRadius: '50%', 
            background: '#F3F4F6', 
            border: '3px solid white', 
            boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
            overflow: 'hidden',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center'
          }}>
            {artist.imageUrl ? (
              <img src={artist.imageUrl} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
            ) : (
              <span style={{ fontSize: '32px', opacity: 0.2 }}>👤</span>
            )}
          </div>
          <div>
            <h1 style={{ fontSize: '32px', fontWeight: '900', margin: 0 }}>{artist.name}</h1>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px', marginTop: '10px' }}>
              {artist.links.map(l => (
                <span key={l.name} style={{ fontSize: '11px', fontWeight: '700', color: theme.colors.primary, background: 'rgba(83, 190, 232, 0.08)', padding: '4px 10px', borderRadius: '8px' }}>
                  {l.name}
                </span>
              ))}
            </div>
          </div>
        </div>

        <div style={{ background: 'white', borderRadius: '32px', padding: '24px', border: '1px solid rgba(0, 0, 0, 0.04)', marginBottom: '32px' }}>
          <div style={{ fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary, textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '4px' }}>ステータス</div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
            <span style={{ fontSize: '24px', fontWeight: '900', color: theme.colors.primary }}>{status.main}</span>
            {status.sub && <span style={{ fontSize: '14px', color: theme.colors.textSecondary, fontWeight: '500' }}>/ {status.sub}</span>}
          </div>
        </div>

        {processedTours.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '40px', color: theme.colors.textWeak }}>
            表示可能な公演がありません
          </div>
        ) : (
          processedTours.map(tour => (
            <div key={tour.id} style={{ marginBottom: '32px' }}>
              <h3 style={{ fontSize: '18px', fontWeight: '900', marginBottom: '12px', paddingLeft: '4px' }}>{tour.name}</h3>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                {tour.concerts.map(c => {
                  const isNavigable = c.status === '参戦予定' || c.status === '参戦済み';
                  return (
                    <ConcertItem 
                      key={c.id} 
                      concert={c} 
                      onClick={isNavigable ? () => onOpenConcertHome(artistId, tour.id, c.id) : undefined} 
                    />
                  );
                })}
              </div>
            </div>
          ))
        )}
      </div>

      <IconButton 
        icon={<Icons.Plus />} 
        primary 
        size={64} 
        onClick={() => onOpenConcertEditor(artistId)} 
        style={{ position: 'fixed', right: '32px', bottom: '100px', zIndex: 90 }} 
      />
      <div style={{ position: 'fixed', left: '32px', bottom: '100px', zIndex: 90 }}>
        <button onClick={() => setIsMenuOpen(!isMenuOpen)} style={{ width: '64px', height: '64px', borderRadius: '9999px', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'white', border: '1px solid #F3F4F6', color: '#9CA3AF', boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.1)', cursor: 'pointer', outline: 'none' }}>
