import React, { useState } from 'react';
import { PageId, Artist, DisplaySettings } from './domain/types';
import { Layout } from './components/Layout';
import { ArtistListPage } from './pages/ArtistListPage';
import { ConcertListPage } from './pages/ConcertListPage';
import { CalendarPage } from './pages/CalendarPage';
import { ArtistDetailPage } from './pages/ArtistDetailPage';
import { ConcertHomePage } from './pages/ConcertHomePage';
import { ArtistEditorPage } from './pages/ArtistEditorPage';
import { ConcertEditorPage } from './pages/ConcertEditorPage';

export default function App() {
  const [currentPath, setCurrentPath] = useState<PageId>('ARTIST_LIST');
  const [selectedArtistId, setSelectedArtistId] = useState<string | undefined>();
  const [selectedTourId, setSelectedTourId] = useState<string | undefined>();
  const [selectedConcertId, setSelectedConcertId] = useState<string | undefined>();

  // Global display settings
  const [displaySettings, setDisplaySettings] = useState<DisplaySettings>({
    showAttended: true,
    showSkipped: true,
  });

  // Real data state
  const [artists, setArtists] = useState<Artist[]>([
    { 
      id: '1', name: 'アーティスト A', imageUrl: '', links: [], autoTrackConcerts: true, autoTrackTickets: true, order: 0,
      tours: [{ id: 't1', name: 'Tour A', imageUrl: '', concerts: [{ id: 'c1', status: '参戦予定', date: '2024-10-01', venue: 'TOKYO DOME', price: 0, saleLink: '', isParticipated: false, images: [] }] }]
    },
    { 
      id: '2', name: 'アーティスト B', imageUrl: '', links: [], autoTrackConcerts: false, autoTrackTickets: true, order: 1,
      tours: [{ id: 't2', name: 'Tour B', imageUrl: '', concerts: [{ id: 'c2', status: '参戦済み', date: '2023-01-01', venue: 'OSAKA HALL', price: 0, saleLink: '', isParticipated: false, images: [] }] }]
    },
  ]);

  const handleOpenArtist = (id: string) => {
    setSelectedArtistId(id);
    setCurrentPath('ARTIST_DETAIL');
  };

  const handleOpenConcert = (concertId: string, tourId: string, artistId: string) => {
    setSelectedConcertId(concertId);
    setSelectedTourId(tourId);
    setSelectedArtistId(artistId);
    setCurrentPath('CONCERT_HOME');
  };

  const handleCreateConcert = (artistId: string) => {
    setSelectedArtistId(artistId);
    setSelectedTourId(undefined); // New tour or select existing inside editor
    setCurrentPath('CONCERT_EDITOR');
  };

  const handleRefreshAll = () => {
    console.log('Refreshing all artist data from external sources...');
  };

  const handleUpdateDisplaySettings = (updates: Partial<DisplaySettings>) => {
    setDisplaySettings(prev => ({ ...prev, ...updates }));
  };

  const renderPage = () => {
    switch (currentPath) {
      case 'ARTIST_LIST':
        return (
          <ArtistListPage 
            artists={artists}
            onOpenArtist={handleOpenArtist} 
            onOpenArtistEditor={() => {
              setSelectedArtistId(undefined);
              setCurrentPath('ARTIST_EDITOR');
            }}
            onRefreshAll={handleRefreshAll}
          />
        );
      case 'CONCERT_LIST':
        return (
          <ConcertListPage 
            artists={artists}
            onOpenArtist={handleOpenArtist}
            onOpenConcert={handleOpenConcert}
            onCreateConcert={handleCreateConcert}
            onRefreshAll={handleRefreshAll} 
          />
        );
      case 'CALENDAR':
        return (
          <CalendarPage 
            artists={artists}
            onOpenArtist={handleOpenArtist}
            onOpenConcert={handleOpenConcert}
            onRefreshAll={handleRefreshAll}
          />
        );
      case 'ARTIST_DETAIL':
        const artist = artists.find(a => a.id === selectedArtistId);
        if (!artist) return null;
        return (
          <ArtistDetailPage 
            artistId={selectedArtistId!} 
            artist={artist}
            settings={displaySettings}
            onOpenArtistEditor={(id) => { setSelectedArtistId(id); setCurrentPath('ARTIST_EDITOR'); }}
            onOpenConcertEditor={handleCreateConcert}
            onOpenConcertHome={handleOpenConcert}
            onChangeSettings={handleUpdateDisplaySettings}
            onBack={() => setCurrentPath('ARTIST_LIST')} 
          />
        );
      case 'CONCERT_HOME':
        return <ConcertHomePage onNavigate={(id) => { if(id === 'ARTIST_EDITOR') { setCurrentPath('ARTIST_EDITOR'); } else { setCurrentPath(id); } }} onBack={() => setCurrentPath('ARTIST_DETAIL')} />;
      case 'ARTIST_EDITOR':
        return (
          <ArtistEditorPage 
            artistId={selectedArtistId}
            onSave={() => setCurrentPath(selectedArtistId ? 'ARTIST_DETAIL' : 'ARTIST_LIST')}
            onCancel={() => setCurrentPath(selectedArtistId ? 'ARTIST_DETAIL' : 'ARTIST_LIST')}
            onNavigate={(id) => setCurrentPath(id)}
          />
        );
      case 'CONCERT_EDITOR':
        return (
          <ConcertEditorPage 
            tourId={selectedTourId}
            onSave={() => setCurrentPath('ARTIST_DETAIL')}
            onCancel={() => setCurrentPath('ARTIST_DETAIL')}
          />
        );
      default:
        return (
          <ArtistListPage 
            artists={artists} 
            onOpenArtist={handleOpenArtist} 
            onOpenArtistEditor={() => setCurrentPath('ARTIST_EDITOR')} 
            onRefreshAll={handleRefreshAll} 
          />
        );
    }
  };

  return (
    <div className="app-root">
      <Layout currentPath={currentPath} onNavigate={setCurrentPath}>
        {renderPage()}
      </Layout>
    </div>
  );
}

import React, { useState, useRef } from 'react';
import { theme } from '../ui/theme';
import { ImageDialog } from '../components/ImageDialog';
import { Artist, Tour, Concert } from '../domain/types';
import { Icons, IconButton } from '../ui/IconButton';

interface Props {
  artistId: string;
  concertId: string;
  artist: Artist;
  tour: Tour;
  concert: Concert;
  onBack: () => void;
  onOpenArtistEditor: (artistId: string) => void;
  onUpdateConcertAlbum: (artistId: string, tourId: string, concertId: string, images: string[]) => void;
}

export const ConcertHomePage: React.FC<Props> = ({ 
  artistId, 
  concertId, 
  artist, 
  tour, 
  concert, 
  onBack, 
  onOpenArtistEditor,
  onUpdateConcertAlbum 
}) => {
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingImageUrl, setEditingImageUrl] = useState<{ url: string; index: number } | null>(null);
  const [fullscreenImage, setFullscreenImage] = useState<string | null>(null);
  const [failedImages, setFailedImages] = useState<Set<string>>(new Set());

  // Drag and Drop state
  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);

  const images = concert.images || [];

  const handleAddImage = (url: string) => {
    if (editingImageUrl !== null) {
      const newImages = [...images];
      newImages[editingImageUrl.index] = url;
      onUpdateConcertAlbum(artistId, tour.id, concertId, newImages);
      setFailedImages(prev => {
        const next = new Set(prev);
        next.delete(editingImageUrl.url);
        return next;
      });
      setEditingImageUrl(null);
    } else {
      onUpdateConcertAlbum(artistId, tour.id, concertId, [...images, url]);
    }
  };

  const handleImageError = (url: string) => {
    setFailedImages(prev => new Set([...prev, url]));
  };

  const handleRemoveImage = (url: string) => {
    onUpdateConcertAlbum(artistId, tour.id, concertId, images.filter(i => i !== url));
  };

  const handleReplaceImage = (url: string, index: number) => {
    setEditingImageUrl({ url, index });
    setIsDialogOpen(true);
  };

  // Drag and Drop Handlers
  const handleDragStart = (index: number) => {
    dragItem.current = index;
  };

  const handleDragEnter = (index: number) => {
    dragOverItem.current = index;
  };

  const handleDragEnd = () => {
    if (dragItem.current !== null && dragOverItem.current !== null && dragItem.current !== dragOverItem.current) {
      const newList = [...images];
      const draggedItemContent = newList[dragItem.current];
      newList.splice(dragItem.current, 1);
      newList.splice(dragOverItem.current, 0, draggedItemContent);

      onUpdateConcertAlbum(artistId, tour.id, concertId, newList);
    }
    dragItem.current = null;
    dragOverItem.current = null;
  };

  return (
    <div style={{ minHeight: '100vh', position: 'relative', overflowX: 'hidden' }}>
      {/* Background from Tour Image */}
      <div style={{ 
        position: 'fixed', 
        inset: 0, 
        zIndex: -1, 
        backgroundImage: tour.imageUrl ? `url(${tour.imageUrl})` : 'none', 
        backgroundColor: '#111',
        backgroundSize: 'cover', 
        backgroundPosition: 'center', 
        filter: 'blur(40px) brightness(0.6)', 
        transform: 'scale(1.2)' 
      }} />

      <div style={{ padding: `${theme.spacing.lg} ${theme.spacing.md} 140px ${theme.spacing.md}`, maxWidth: '600px', margin: '0 auto' }}>
        <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' }}>
          <button 
            onClick={onBack} 
            style={{ 
              border: 'none', 
              background: 'rgba(255,255,255,0.15)', 
              backdropFilter: 'blur(10px)',
              color: 'white', 
              width: '44px', 
              height: '44px', 
              borderRadius: '22px', 
              display: 'flex', 
              alignItems: 'center', 
              justifyContent: 'center', 
              cursor: 'pointer' 
            }}
          >
            <Icons.ChevronLeft />
          </button>

          <IconButton 
            icon={<Icons.Edit />} 
            onClick={() => onOpenArtistEditor(artistId)}
            size={44}
            style={{ 
              background: 'rgba(255,255,255,0.15)', 
              backdropFilter: 'blur(10px)',
              border: 'none',
              color: 'white',
              boxShadow: 'none'
            }}
          />
        </header>

        <div style={{ color: 'white', marginBottom: '32px', textAlign: 'center' }}>
          <h1 style={{ 
            fontSize: '32px', 
            fontWeight: '900', 
            margin: '0 0 8px 0', 
            textShadow: '0 4px 12px rgba(0,0,0,0.4)',
            letterSpacing: '-0.02em'
          }}>
            {tour.name}
          </h1>
          <div style={{ fontSize: '18px', opacity: 0.8, fontWeight: '600', textShadow: '0 2px 4px rgba(0,0,0,0.3)' }}>
            {artist.name}
          </div>
          <div style={{ fontSize: '14px', opacity: 0.6, marginTop: '4px' }}>
            {concert.date} @ {concert.venue}
          </div>
        </div>

        <section>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px', padding: '0 4px' }}>
            <h2 style={{ color: 'white', fontSize: '20px', fontWeight: '800', margin: 0 }}>アルバム</h2>
            <span style={{ fontSize: '13px', color: 'rgba(255,255,255,0.6)', fontWeight: '600' }}>
              {images.length} 枚の思い出
            </span>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '16px' }}>
            {images.map((img, idx) => {
              const isFailed = failedImages.has(img);
              return (
                <div 
                  key={`${img}-${idx}`} 
                  draggable
                  onDragStart={() => handleDragStart(idx)}
                  onDragEnter={() => handleDragEnter(idx)}
                  onDragEnd={handleDragEnd}
                  onDragOver={(e) => e.preventDefault()}
                  style={{ 
                    position: 'relative', 
                    aspectRatio: '1/1', 
                    borderRadius: '24px', 
                    overflow: 'hidden', 
                    background: 'rgba(0,0,0,0.2)',
                    boxShadow: '0 8px 24px rgba(0,0,0,0.2)',
                    border: '1px solid rgba(255,255,255,0.1)',
                    cursor: 'grab'
                  }}
                >
                  {isFailed ? (
                    <div style={{ 
                      width: '100%', 
                      height: '100%', 
                      display: 'flex', 
                      flexDirection: 'column', 
                      alignItems: 'center', 
                      justifyContent: 'center', 
                      color: 'rgba(255,255,255,0.5)', 
                      fontSize: '12px', 
                      padding: '16px', 
                      textAlign: 'center' 
                    }}>
                      <div style={{ fontSize: '24px', marginBottom: '8px', opacity: 0.5 }}>📷</div>
                      <div style={{ fontWeight: '600', marginBottom: '12px' }}>読み込めません</div>

                      <div style={{ display: 'flex', gap: '8px' }}>
                        <button 
                          onClick={() => handleReplaceImage(img, idx)}
                          style={{ border: 'none', background: 'rgba(255,255,255,0.15)', color: 'white', fontSize: '11px', padding: '6px 12px', borderRadius: '8px', fontWeight: 'bold' }}
                        >
                          置換
                        </button>
                        <button 
                          onClick={() => handleRemoveImage(img)}
                          style={{ border: 'none', background: 'rgba(255, 59, 48, 0.2)', color: '#FF3B30', fontSize: '11px', padding: '6px 12px', borderRadius: '8px', fontWeight: 'bold' }}
                        >
                          削除
                        </button>
                      </div>
                    </div>
                  ) : (
                    <>
                      <img 
                        src={img} 
                        alt="" 
                        loading="lazy"
                        onError={() => handleImageError(img)} 
                        onClick={() => setFullscreenImage(img)}
                        style={{ width: '100%', height: '100%', objectFit: 'cover', cursor: 'pointer' }} 
                      />
                      <button 
                        onClick={(e) => {
                          e.stopPropagation();
                          handleRemoveImage(img);
                        }}
                        style={{
                          position: 'absolute',
                          top: '12px',
                          right: '12px',
                          width: '24px',
                          height: '24px',
                          borderRadius: '12px',
                          background: 'rgba(0,0,0,0.5)',
                          border: 'none',
                          color: 'white',
                          fontSize: '14px',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          cursor: 'pointer'
                        }}
                      >
                        ×
                      </button>
                    </>
                  )}
                </div>
              );
            })}
          </div>
        </section>
      </div>

      <IconButton 
        icon={<Icons.Plus />} 
        primary 
        size={64} 
        onClick={() => {
          setEditingImageUrl(null);
          setIsDialogOpen(true);
        }} 
        style={{ 
          position: 'fixed', 
          right: '32px', 
          bottom: '40px', 
          zIndex: 90
        }}
      />

      {fullscreenImage && (
        <div 
          onClick={() => setFullscreenImage(null)} 
          className="fade-in"
          style={{ 
            position: 'fixed', 
            inset: 0, 
            zIndex: 3000, 
            background: 'rgba(0,0,0,0.95)', 
            display: 'flex', 
            alignItems: 'center', 
            justifyContent: 'center',
            padding: '20px'
          }}
        >
          <img src={fullscreenImage} alt="" style={{ maxWidth: '100%', maxHeight: '100%', objectFit: 'contain', borderRadius: '8px' }} />
          <button 
            style={{ position: 'absolute', top: '24px', right: '24px', background: 'none', border: 'none', color: 'white', fontSize: '32px', cursor: 'pointer' }}
            onClick={() => setFullscreenImage(null)}
          >
            ×
          </button>
        </div>
      )}

      <ImageDialog 
        isOpen={isDialogOpen} 
        onClose={() => {
          setIsDialogOpen(false);
          setEditingImageUrl(null);
        }} 
        onAdd={handleAddImage}
        title={editingImageUrl ? "画像のURLを更新" : "思い出の写真を追加"}
      />
    </div>
  );
};

