      tours: [{ id: 't1', name: 'Tour A', imageUrl: 'https://images.unsplash.com/photo-1470225620780-dba8ba36b745', concerts: [{ id: 'c1', status: '参戦予定', date: '2024-10-01', venue: 'TOKYO DOME', price: 0, saleLink: '', isParticipated: false, images: ['https://images.unsplash.com/photo-1459749411177-042180ce673c'] }] }]
    },
    { 
      id: '2', name: 'アーティスト B', imageUrl: '', links: [], autoTrackConcerts: false, autoTrackTickets: true, order: 1,
      tours: [{ id: 't2', name: 'Tour B', imageUrl: '', concerts: [{ id: 'c2', status: '参戦済み', date: '2023-01-01', venue: 'OSAKA HALL', price: 0, saleLink: '', isParticipated: false, images: [] }] }]
    },
  ]);

  const handleOpenArtist = (id: string) => {
    setSelectedArtistId(id);
    setCurrentPath('ARTIST_DETAIL');
  };

  const handleOpenConcert = (concertId: string, tourId: string, artistId: string) => {
    setSelectedConcertId(concertId);
    setSelectedTourId(tourId);
    setSelectedArtistId(artistId);
    setCurrentPath('CONCERT_HOME');
  };

  const handleCreateConcert = (artistId: string) => {
    setSelectedArtistId(artistId);
    setSelectedTourId(undefined); // New tour or select existing inside editor
    setCurrentPath('CONCERT_EDITOR');
  };

  const handleRefreshAll = () => {
    console.log('Refreshing all artist data from external sources...');
  };

  const handleUpdateDisplaySettings = (updates: Partial<DisplaySettings>) => {
    setDisplaySettings(prev => ({ ...prev, ...updates }));
  };

  const handleUpdateConcertAlbum = (artistId: string, tourId: string, concertId: string, images: string[]) => {
    setArtists(prevArtists => prevArtists.map(artist => {
      if (artist.id !== artistId) return artist;
      return {
        ...artist,
        tours: artist.tours.map(tour => {
          if (tour.id !== tourId) return tour;
          return {
            ...tour,
            concerts: tour.concerts.map(concert => {
              if (concert.id !== concertId) return concert;
              return { ...concert, images };
            })
          };
        })
      };
    }));
  };

  const renderPage = () => {
    switch (currentPath) {
      case 'ARTIST_LIST':
        return (
          <ArtistListPage 
            artists={artists}
            onOpenArtist={handleOpenArtist} 
            onOpenArtistEditor={() => {
              setSelectedArtistId(undefined);
              setCurrentPath('ARTIST_EDITOR');
            }}
            onRefreshAll={handleRefreshAll}
          />
        );
      case 'CONCERT_LIST':
        return (
          <ConcertListPage 
            artists={artists}
            onOpenArtist={handleOpenArtist}
            onOpenConcert={handleOpenConcert}
            onCreateConcert={handleCreateConcert}
            onRefreshAll={handleRefreshAll} 
          />
        );
      case 'CALENDAR':
        return (
          <CalendarPage 
            artists={artists}
            onOpenArtist={handleOpenArtist}
            onOpenConcert={handleOpenConcert}
            onRefreshAll={handleRefreshAll}
          />
        );
      case 'ARTIST_DETAIL': {
        const artist = artists.find(a => a.id === selectedArtistId);
        if (!artist) return null;
        return (
          <ArtistDetailPage 
            artistId={selectedArtistId!} 
            artist={artist}
            settings={displaySettings}
            onOpenArtistEditor={(id) => { setSelectedArtistId(id); setCurrentPath('ARTIST_EDITOR'); }}
            onOpenConcertEditor={handleCreateConcert}
            onOpenConcertHome={handleOpenConcert}
            onChangeSettings={handleUpdateDisplaySettings}
            onBack={() => setCurrentPath('ARTIST_LIST')} 
          />
        );
      }
      case 'CONCERT_HOME': {
        const artist = artists.find(a => a.id === selectedArtistId);
        const tour = artist?.tours.find(t => t.id === selectedTourId);
        const concert = tour?.concerts.find(c => c.id === selectedConcertId);

        if (!artist || !tour || !concert) return null;

        // Ensure navigation condition: Only allow '参戦予定' or '参戦済み'
        if (concert.status !== '参戦予定' && concert.status !== '参戦済み') {
          setCurrentPath('ARTIST_DETAIL');
          return null;
        }

        return (
          <ConcertHomePage 
            artistId={artist.id}
            concertId={concert.id}
            artist={artist}
            tour={tour}
            concert={concert}
            onBack={() => setCurrentPath('ARTIST_DETAIL')}
            onOpenArtistEditor={(id) => { setSelectedArtistId(id); setCurrentPath('ARTIST_EDITOR'); }}
            onUpdateConcertAlbum={handleUpdateConcertAlbum}
          />
        );
      }
      case 'ARTIST_EDITOR':
        return (
          <ArtistEditorPage 
            artistId={selectedArtistId}
            onSave={() => setCurrentPath(selectedArtistId ? 'ARTIST_DETAIL' : 'ARTIST_LIST')}
            onCancel={() => setCurrentPath(selectedArtistId ? 'ARTIST_DETAIL' : 'ARTIST_LIST')}
            onNavigate={(id) => setCurrentPath(id)}
          />
        );
      case 'CONCERT_EDITOR':
        return (
          <ConcertEditorPage 
            tourId={selectedTourId}
            onSave={() => setCurrentPath('ARTIST_DETAIL')}
            onCancel={() => setCurrentPath('ARTIST_DETAIL')}
          />
        );
      default:
        return (
          <ArtistListPage 
            artists={artists} 
            onOpenArtist={handleOpenArtist} 
            onOpenArtistEditor={() => setCurrentPath('ARTIST_EDITOR')} 
            onRefreshAll={handleRefreshAll} 
          />
        );
    }
  };

  return (
    <div className="app-root">
      <Layout currentPath={currentPath} onNavigate={setCurrentPath}>
        {renderPage()}
      </Layout>
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { theme } from '../ui/theme';
import { GlassCard } from '../ui/GlassCard';
import { ConfirmDialog } from '../components/ConfirmDialog';
import { PageId, Artist, SiteLink, TrackingErrorType } from '../domain/types';
import { Icons, IconButton } from '../ui/IconButton';

interface Props {
  artistId?: string;
  artist?: Artist;
  onSave: (updated: Artist) => void;
  onCancel: () => void;
  onOpenConcertEditor: (artistId: string, tourId?: string) => void;
  onDeleteArtist: (artistId: string) => void;
}

const generateId = () => Math.random().toString(36).substr(2, 9);

export const ArtistEditorPage: React.FC<Props> = ({ 
  artistId, 
  artist, 
  onSave, 
  onCancel, 
  onOpenConcertEditor,
  onDeleteArtist
}) => {
  // Instruction 1: Initialize from props or create a new one
  const getInitialData = (): Artist => {
    if (artistId && artist) return { ...artist };
    return {
      id: generateId(),
      name: '',
      imageUrl: '',
      links: [],
      autoTrackConcerts: true,
      autoTrackTickets: true,
      tours: [],
      order: 0
    };
  };

  const [formData, setFormData] = useState<Artist>(getInitialData());
  const originalArtistRef = useRef<string>(JSON.stringify(getInitialData()));
  const [hasChanges, setHasChanges] = useState(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [activeFailure, setActiveFailure] = useState<SiteLink | null>(null);

  // Instruction 5: Stable change detection using stringified initial snapshot
  useEffect(() => {
    setHasChanges(JSON.stringify(formData) !== originalArtistRef.current);
  }, [formData]);

  const handleUpdateField = (field: keyof Artist, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleAddLink = () => {
    const newLink: SiteLink = {
      name: '',
      url: '',
      autoTrack: false
    };
    handleUpdateField('links', [...formData.links, newLink]);
  };

  const handleRemoveLink = (index: number) => {
    const newLinks = [...formData.links];
    newLinks.splice(index, 1);
    handleUpdateField('links', newLinks);
  };

  const handleUpdateLink = (index: number, updates: Partial<SiteLink>) => {
    const newLinks = [...formData.links];
    newLinks[index] = { ...newLinks[index], ...updates };
    handleUpdateField('links', newLinks);
  };

  // Instruction 4: Fix error detail labels to align with 4 categories
  const getErrorLabel = (link: SiteLink): TrackingErrorType => {
    return link.errorMessage ?? '情報を取得できませんでした';
  };

  return (
    <div style={{ paddingBottom: '160px' }}>
      <header style={headerStyle}>
        <IconButton 
          icon={<Icons.X />} 
          onClick={onCancel}
          size={40}
          style={{ 
            color: theme.colors.textSecondary, 
            borderColor: 'transparent', 
            background: 'transparent',
            boxShadow: 'none'
          }}
        />
        <h2 style={{ fontSize: '17px', margin: 0, fontWeight: 'bold' }}>
          {artistId ? 'アーティスト編集' : 'アーティスト追加'}
        </h2>
        {artistId ? (
          <IconButton 
            icon={<Icons.Trash />} 
            onClick={() => setIsDeleteModalOpen(true)}
            size={40}
            style={{ 
              color: theme.colors.error, 
              borderColor: 'transparent', 
              background: 'transparent',
              boxShadow: 'none'
            }}
          />
        ) : <div style={{ width: 40 }} />}
      </header>

      <section style={{ marginBottom: theme.spacing.xl }}>
        <h3 style={sectionTitleStyle}>基本情報</h3>
        <GlassCard padding={theme.spacing.md}>
          <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.md }}>
            <Field label="アーティスト名 (必須)">
              <input type="text" value={formData.name} onChange={e => handleUpdateField('name', e.target.value)} placeholder="名称を入力" style={inputStyle} />
            </Field>
            <Field label="画像URL">
              <input type="url" value={formData.imageUrl} onChange={e => handleUpdateField('imageUrl', e.target.value)} placeholder="https://..." style={inputStyle} />
            </Field>
          </div>
        </GlassCard>
      </section>

      <section style={{ marginBottom: theme.spacing.xl }}>
        <h3 style={sectionTitleStyle}>追跡設定</h3>
        <GlassCard padding={theme.spacing.md}>
          <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.lg }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div>
                <div style={{ fontWeight: '600', fontSize: '15px' }}>公演自動追跡</div>
                <div style={{ fontSize: '12px', color: theme.colors.textSecondary }}>新規ツアー・公演情報を自動取得します</div>
              </div>
              <Toggle active={formData.autoTrackConcerts} onToggle={() => handleUpdateField('autoTrackConcerts', !formData.autoTrackConcerts)} />
            </div>

            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div>
                <div style={{ fontWeight: '600', fontSize: '15px' }}>チケット自動追跡</div>
                <div style={{ fontSize: '12px', color: theme.colors.textSecondary }}>販売・抽選情報を自動更新します</div>
                <div style={{ fontSize: '11px', color: theme.colors.error, marginTop: '4px', fontWeight: 'bold' }}>
                  ※ 当選後はチケット追跡は行われません
                </div>
              </div>
              <Toggle active={formData.autoTrackTickets} onToggle={() => handleUpdateField('autoTrackTickets', !formData.autoTrackTickets)} />
            </div>
          </div>
        </GlassCard>
      </section>

      <section style={{ marginBottom: theme.spacing.xl }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: theme.spacing.sm }}>
          <h3 style={{ ...sectionTitleStyle, marginBottom: 0 }}>追跡サイト一覧</h3>
          <button onClick={handleAddLink} style={actionButtonStyle}>＋ 追加</button>
        </div>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
          {formData.links.map((link, idx) => (
            <GlassCard key={idx} padding={theme.spacing.md}>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                  <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '8px' }}>
                    <input 
                      type="text" 
                      value={link.name} 
                      onChange={e => handleUpdateLink(idx, { name: e.target.value })} 
                      placeholder="サイト名" 
                      style={inputStyle} 
                    />
                    <input 
                      type="url" 
                      value={link.url} 
                      onChange={e => handleUpdateLink(idx, { url: e.target.value })} 
                      placeholder="URL" 
                      style={inputStyle} 
                    />
                  </div>
                  <button 
                    onClick={() => handleRemoveLink(idx)}
                    style={{ border: 'none', background: 'none', padding: '8px', cursor: 'pointer', color: theme.colors.textLabel }}
                  >
                    🗑️
                  </button>
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderTop: '0.5px solid rgba(0,0,0,0.05)', paddingTop: '12px' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <span style={{ fontSize: '13px', fontWeight: '600' }}>自動追跡</span>
                    {link.trackingStatus === 'failed' && (
                      <button 
                        onClick={() => setActiveFailure(link)}
                        style={{ border: 'none', background: 'none', fontSize: '14px', cursor: 'pointer', padding: 0 }}
                      >⚠️</button>
                    )}
                  </div>
                  <Toggle active={link.autoTrack} onToggle={() => handleUpdateLink(idx, { autoTrack: !link.autoTrack })} />
                </div>
              </div>
            </GlassCard>
          ))}
        </div>
      </section>

      {/* Instruction 2: Pass ID when editing tours */}
      {formData.tours.length > 0 && (
        <section style={{ marginBottom: theme.spacing.xl }}>
          <h3 style={sectionTitleStyle}>登録済みツアー</h3>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
            {formData.tours.map(tour => (
              <GlassCard key={tour.id} padding={theme.spacing.md}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <div style={{ fontWeight: '700', fontSize: '15px' }}>{tour.name}</div>
                  <button 
                    onClick={() => onOpenConcertEditor(formData.id, tour.id)}
                    style={{ 
                      padding: '8px 16px', 
                      borderRadius: '12px', 
                      background: 'rgba(83, 190, 232, 0.1)', 
                      color: theme.colors.primary, 
                      border: 'none', 
                      fontWeight: 'bold', 
                      fontSize: '13px',
                      cursor: 'pointer' 
                    }}
                  >
                    編集
                  </button>
                </div>
              </GlassCard>
            ))}
          </div>
        </section>
      )}

      <section style={{ marginTop: '40px' }}>
        <button 
          disabled={!hasChanges || !formData.name}
          onClick={() => onSave(formData)} 
          style={{ 
            width: '100%', 
            padding: '16px', 
            borderRadius: theme.radius.button, 
            background: (!hasChanges || !formData.name) ? 'rgba(0,0,0,0.05)' : theme.colors.primary, 
            color: (!hasChanges || !formData.name) ? theme.colors.textWeak : 'white', 
            border: 'none', 
            fontWeight: 'bold', 
            fontSize: '16px', 
            cursor: (!hasChanges || !formData.name) ? 'default' : 'pointer',
            transition: 'all 0.2s'
          }}
        >
          保存
        </button>
      </section>

      {activeFailure && (
        <ConfirmDialog 
          isOpen={!!activeFailure}
          title="追跡エラー詳細"
          message={`最終確認：${activeFailure.lastCheckedAt || '---'}\nエラー：${getErrorLabel(activeFailure)}`}
          confirmLabel="閉じる"
          onClose={() => setActiveFailure(null)}
          onConfirm={() => setActiveFailure(null)}
        />
      )}

      <ConfirmDialog 
        isOpen={isDeleteModalOpen} 
        title="アーティストを削除しますか？" 
        message="このアーティストに紐づくすべてのツアー、公演、思い出アルバムのデータが完全に削除されます。この操作は取り消せません。" 
        confirmLabel="削除する" 
        isDestructive 
        onClose={() => setIsDeleteModalOpen(false)} 
        // Instruction 3: Real deletion callback
        onConfirm={() => onDeleteArtist(formData.id)} 
      />
    </div>
  );
};

const headerStyle: React.CSSProperties = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: theme.spacing.xl, position: 'sticky', top: 0, zIndex: 100, background: theme.colors.background, padding: `${theme.spacing.sm} 0` };
const sectionTitleStyle: React.CSSProperties = { fontSize: '13px', color: theme.colors.textSecondary, fontWeight: 'bold', marginBottom: theme.spacing.sm, paddingLeft: '4px' };
const inputStyle: React.CSSProperties = { width: '100%', padding: '10px 12px', borderRadius: '10px', border: '1px solid rgba(0,0,0,0.08)', background: 'rgba(255,255,255,0.4)', fontSize: '15px', outline: 'none' };
const actionButtonStyle: React.CSSProperties = { border: 'none', background: 'none', color: theme.colors.primary, fontSize: '14px', fontWeight: '600', cursor: 'pointer' };
const Field = ({ label, children }: any) => (<div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}><label style={{ fontSize: '12px', color: theme.colors.textSecondary, marginLeft: '4px' }}>{label}</label>{children}</div>);
const Toggle = ({ active, onToggle }: any) => (<div onClick={onToggle} style={{ width: '46px', height: '26px', borderRadius: '13px', background: active ? theme.colors.primary : '#E9E9EB', position: 'relative', cursor: 'pointer' }}><div style={{ position: 'absolute', top: '2px', left: active ? '22px' : '2px', width: '22px', height: '22px', borderRadius: '11px', background: 'white', transition: 'left 0.2s' }} /></div>);

import React, { useState } from 'react';
import { PageId, Artist, DisplaySettings } from './domain/types';
import { Layout } from './components/Layout';
import { ArtistListPage } from './pages/ArtistListPage';
import { ConcertListPage } from './pages/ConcertListPage';
import { CalendarPage } from './pages/CalendarPage';
import { ArtistDetailPage } from './pages/ArtistDetailPage';
import { ConcertHomePage } from './pages/ConcertHomePage';
import { ArtistEditorPage } from './pages/ArtistEditorPage';
import { ConcertEditorPage } from './pages/ConcertEditorPage';

export default function App() {
  const [currentPath, setCurrentPath] = useState<PageId>('ARTIST_LIST');
  const [selectedArtistId, setSelectedArtistId] = useState<string | undefined>();
  const [selectedTourId, setSelectedTourId] = useState<string | undefined>();
  const [selectedConcertId, setSelectedConcertId] = useState<string | undefined>();

  // Global display settings
  const [displaySettings, setDisplaySettings] = useState<DisplaySettings>({
    showAttended: true,
    showSkipped: true,
  });

  // Real data state
  const [artists, setArtists] = useState<Artist[]>([
    { 
      id: '1', name: 'アーティスト A', imageUrl: '', links: [], autoTrackConcerts: true, autoTrackTickets: true, order: 0,
      tours: [{ id: 't1', name: 'Tour A', imageUrl: 'https://images.unsplash.com/photo-1470225620780-dba8ba36b745', concerts: [{ id: 'c1', status: '参戦予定', date: '2024-10-01', venue: 'TOKYO DOME', price: 0, saleLink: '', isParticipated: false, images: ['https://images.unsplash.com/photo-1459749411177-042180ce673c'] }] }]
    },
    { 
      id: '2', name: 'アーティスト B', imageUrl: '', links: [], autoTrackConcerts: false, autoTrackTickets: true, order: 1,
      tours: [{ id: 't2', name: 'Tour B', imageUrl: '', concerts: [{ id: 'c2', status: '参戦済み', date: '2023-01-01', venue: 'OSAKA HALL', price: 0, saleLink: '', isParticipated: false, images: [] }] }]
    },
  ]);

  const handleOpenArtist = (id: string) => {
    setSelectedArtistId(id);
    setCurrentPath('ARTIST_DETAIL');
  };

  const handleOpenConcert = (concertId: string, tourId: string, artistId: string) => {
    setSelectedConcertId(concertId);
    setSelectedTourId(tourId);
    setSelectedArtistId(artistId);
    setCurrentPath('CONCERT_HOME');
  };

  const handleCreateConcert = (artistId: string) => {
    setSelectedArtistId(artistId);
    setSelectedTourId(undefined);
    setCurrentPath('CONCERT_EDITOR');
  };

  const handleOpenConcertEditor = (artistId: string, tourId?: string) => {
    setSelectedArtistId(artistId);
    setSelectedTourId(tourId);
    setCurrentPath('CONCERT_EDITOR');
  };

  const handleRefreshAll = () => {
    console.log('Refreshing all artist data from external sources...');
  };

  const handleUpdateDisplaySettings = (updates: Partial<DisplaySettings>) => {
    setDisplaySettings(prev => ({ ...prev, ...updates }));
  };

  const handleUpdateConcertAlbum = (artistId: string, tourId: string, concertId: string, images: string[]) => {
    setArtists(prevArtists => prevArtists.map(artist => {
      if (artist.id !== artistId) return artist;
      return {
        ...artist,
        tours: artist.tours.map(tour => {
          if (tour.id !== tourId) return tour;
          return {
            ...tour,
            concerts: tour.concerts.map(concert => {
              if (concert.id !== concertId) return concert;
              return { ...concert, images };
            })
          };
        })
      };
    }));
  };

  const handleSaveArtist = (updatedArtist: Artist) => {
    setArtists(prev => {
      const exists = prev.some(a => a.id === updatedArtist.id);
      if (exists) {
        return prev.map(a => a.id === updatedArtist.id ? updatedArtist : a);
      }
      return [...prev, updatedArtist];
    });
    setSelectedArtistId(updatedArtist.id);
    setCurrentPath('ARTIST_DETAIL');
  };

  const handleDeleteArtist = (artistId: string) => {
    setArtists(prev => prev.filter(a => a.id !== artistId));
    setCurrentPath('ARTIST_LIST');
  };

  const renderPage = () => {
    switch (currentPath) {
      case 'ARTIST_LIST':
        return (
          <ArtistListPage 
            artists={artists}
            onOpenArtist={handleOpenArtist} 
            onOpenArtistEditor={() => {
              setSelectedArtistId(undefined);
              setCurrentPath('ARTIST_EDITOR');
            }}
            onRefreshAll={handleRefreshAll}
          />
        );
      case 'CONCERT_LIST':
        return (
          <ConcertListPage 
            artists={artists}
            onOpenArtist={handleOpenArtist}
            onOpenConcert={handleOpenConcert}
            onCreateConcert={handleCreateConcert}
            onRefreshAll={handleRefreshAll} 
          />
        );
      case 'CALENDAR':
        return (
          <CalendarPage 
            artists={artists}
            onOpenArtist={handleOpenArtist}
            onOpenConcert={handleOpenConcert}
            onRefreshAll={handleRefreshAll}
          />
        );
      case 'ARTIST_DETAIL': {
        const artist = artists.find(a => a.id === selectedArtistId);
        if (!artist) return null;
        return (
          <ArtistDetailPage 
            artistId={selectedArtistId!} 
            artist={artist}
            settings={displaySettings}
            onOpenArtistEditor={(id) => { setSelectedArtistId(id); setCurrentPath('ARTIST_EDITOR'); }}
            onOpenConcertEditor={handleCreateConcert}
            onOpenConcertHome={handleOpenConcert}
            onChangeSettings={handleUpdateDisplaySettings}
            onBack={() => setCurrentPath('ARTIST_LIST')} 
          />
        );
      }
      case 'CONCERT_HOME': {
        const artist = artists.find(a => a.id === selectedArtistId);
        const tour = artist?.tours.find(t => t.id === selectedTourId);
        const concert = tour?.concerts.find(c => c.id === selectedConcertId);

        if (!artist || !tour || !concert) return null;

        if (concert.status !== '参戦予定' && concert.status !== '参戦済み') {
          setCurrentPath('ARTIST_DETAIL');
          return null;
        }

        return (
          <ConcertHomePage 
            artistId={artist.id}
            concertId={concert.id}
            artist={artist}
            tour={tour}
            concert={concert}
            onBack={() => setCurrentPath('ARTIST_DETAIL')}
            onOpenArtistEditor={(id) => { setSelectedArtistId(id); setCurrentPath('ARTIST_EDITOR'); }}
            onUpdateConcertAlbum={handleUpdateConcertAlbum}
          />
        );
      }
      case 'ARTIST_EDITOR': {
        const artist = artists.find(a => a.id === selectedArtistId);
        return (
          <ArtistEditorPage 
            artistId={selectedArtistId}
            artist={artist}
            onSave={handleSaveArtist}
            onCancel={() => setCurrentPath(selectedArtistId ? 'ARTIST_DETAIL' : 'ARTIST_LIST')}
            onOpenConcertEditor={handleOpenConcertEditor}
            onDeleteArtist={handleDeleteArtist}
          />
        );
      }
      case 'CONCERT_EDITOR':
        return (
          <ConcertEditorPage 
            tourId={selectedTourId}
            onSave={() => setCurrentPath('ARTIST_DETAIL')}
            onCancel={() => setCurrentPath('ARTIST_DETAIL')}
          />
        );
      default:
        return (
          <ArtistListPage 
            artists={artists} 
            onOpenArtist={handleOpenArtist} 
            onOpenArtistEditor={() => setCurrentPath('ARTIST_EDITOR')} 
            onRefreshAll={handleRefreshAll} 
          />
        );
    }
  };

  return (
    <div className="app-root">
      <Layout currentPath={currentPath} onNavigate={setCurrentPath}>
        {renderPage()}
      </Layout>
    </div>
  );
}

