import React, { useState, useMemo } from 'react';
import { PageId, Artist, Tour, DisplaySettings, Status } from './domain/types';
import { Layout } from './components/Layout';
import { ArtistListPage } from './pages/ArtistListPage';
import { ConcertListPage } from './pages/ConcertListPage';
import { CalendarPage } from './pages/CalendarPage';
import { ArtistDetailPage } from './pages/ArtistDetailPage';
import { ConcertHomePage } from './pages/ConcertHomePage';
import { ArtistEditorPage } from './pages/ArtistEditorPage';
import { ConcertEditorPage } from './pages/ConcertEditorPage';
import { GlassCard } from './ui/GlassCard';
import { theme } from './ui/theme';

// Requirement 1: Unified Navigation Context
type NavContext = {
  path: PageId;
  artistId?: string;
  tourId?: string;
  concertId?: string;
};

export default function App() {
  const [nav, setNav] = useState<NavContext>({ path: 'ARTIST_LIST' });
  const [isArtistPickerOpen, setIsArtistPickerOpen] = useState(false);

  // Global display settings
  const [displaySettings, setDisplaySettings] = useState<DisplaySettings>({
    showAttended: true,
    showSkipped: true,
  });

  // Requirement 2: Single Data Source
  const [artists, setArtists] = useState<Artist[]>([
    { 
      id: '1', name: 'アーティスト A', imageUrl: '', links: [], autoTrackConcerts: true, autoTrackTickets: true, order: 0,
      tours: [{ id: 't1', name: 'Tour A', imageUrl: 'https://images.unsplash.com/photo-1470225620780-dba8ba36b745', memo: 'メモ', concerts: [{ id: 'c1', status: '参戦予定', date: '2024-10-01', venue: 'TOKYO DOME', price: 0, saleLink: '', isParticipated: false, images: ['https://images.unsplash.com/photo-1459749411177-042180ce673c'] }] }]
    },
    { 
      id: '2', name: 'アーティスト B', imageUrl: '', links: [], autoTrackConcerts: false, autoTrackTickets: true, order: 1,
      tours: [{ id: 't2', name: 'Tour B', imageUrl: '', concerts: [{ id: 'c2', status: '参戦済み', date: '2023-01-01', venue: 'OSAKA HALL', price: 0, saleLink: '', isParticipated: false, images: [] }] }]
    },
  ]);

  // --- Navigation Handlers ---

  const navigateToArtistList = () => setNav({ path: 'ARTIST_LIST' });

  const navigateToArtistDetail = (artistId: string) => 
    setNav({ path: 'ARTIST_DETAIL', artistId });

  const navigateToArtistEditor = (artistId?: string) => 
    setNav({ path: 'ARTIST_EDITOR', artistId });

  const navigateToConcertEditor = (artistId: string, tourId?: string) => 
    setNav({ path: 'CONCERT_EDITOR', artistId, tourId });

  const navigateToConcertHome = (artistId: string, tourId: string, concertId: string) => {
    // Requirement 5: Guard for status access
    const artist = artists.find(a => a.id === artistId);
    const tour = artist?.tours.find(t => t.id === tourId);
    const concert = tour?.concerts.find(c => c.id === concertId);

    if (concert && (concert.status === '参戦予定' || concert.status === '参戦済み')) {
      setNav({ path: 'CONCERT_HOME', artistId, tourId, concertId });
    } else {
      navigateToArtistDetail(artistId);
    }
  };

  // --- CRUD API (Unified) ---

  const upsertArtist = (updated: Artist) => {
    setArtists(prev => {
      const exists = prev.some(a => a.id === updated.id);
      return exists ? prev.map(a => a.id === updated.id ? updated : a) : [...prev, updated];
    });
    navigateToArtistDetail(updated.id);
  };

  const deleteArtist = (artistId: string) => {
    setArtists(prev => prev.filter(a => a.id !== artistId));
    navigateToArtistList();
  };

  const upsertTour = (artistId: string, updatedTour: Tour) => {
    setArtists(prev => prev.map(artist => {
      if (artist.id !== artistId) return artist;
      const tourExists = artist.tours.some(t => t.id === updatedTour.id);
      return {
        ...artist,
        tours: tourExists 
          ? artist.tours.map(t => t.id === updatedTour.id ? updatedTour : t)
          : [...artist.tours, updatedTour]
      };
    }));
    navigateToArtistDetail(artistId);
  };

  const deleteTour = (artistId: string, tourId: string) => {
    setArtists(prev => prev.map(artist => {
      if (artist.id !== artistId) return artist;
      return { ...artist, tours: artist.tours.filter(t => t.id !== tourId) };
    }));
    navigateToArtistDetail(artistId);
  };

  const updateConcertAlbum = (artistId: string, tourId: string, concertId: string, images: string[]) => {
    setArtists(prev => prev.map(artist => {
      if (artist.id !== artistId) return artist;
      return {
        ...artist,
        tours: artist.tours.map(tour => {
          if (tour.id !== tourId) return tour;
          return {
            ...tour,
            concerts: tour.concerts.map(concert => 
              concert.id === concertId ? { ...concert, images } : concert
            )
          };
        })
      };
    }));
  };

  // --- External Actions ---

  const handleRefreshAll = () => {
    console.log('Refreshing data...');
  };

  // Requirement 6: Reset logic for import
  const handleImportData = (newArtists: Artist[]) => {
    setArtists(newArtists);
    setNav({ path: 'ARTIST_LIST' });
  };

  const handleUpdateDisplaySettings = (updates: Partial<DisplaySettings>) => {
    setDisplaySettings(prev => ({ ...prev, ...updates }));
  };

  // Requirement 4: Artist Selection for Global "+" 
  const openGlobalConcertPicker = () => setIsArtistPickerOpen(true);

  // --- Page Rendering ---

  const renderPage = () => {
    switch (nav.path) {
      case 'ARTIST_LIST':
        return (
          <ArtistListPage 
            artists={artists}
            onOpenArtist={navigateToArtistDetail} 
            onOpenArtistEditor={() => navigateToArtistEditor()}
            onRefreshAll={handleRefreshAll}
          />
        );
      case 'CONCERT_LIST':
        return (
          <ConcertListPage 
            artists={artists}
            onOpenArtist={navigateToArtistDetail}
            onOpenConcert={navigateToConcertHome}
            onCreateConcert={openGlobalConcertPicker}
            onRefreshAll={handleRefreshAll} 
          />
        );
      case 'CALENDAR':
        return (
          <CalendarPage 
            artists={artists}
            onOpenArtist={navigateToArtistDetail}
            onOpenConcert={navigateToConcertHome}
            onRefreshAll={handleRefreshAll}
          />
        );
      case 'ARTIST_DETAIL': {
        const artist = artists.find(a => a.id === nav.artistId);
        if (!artist) return null;
        return (
          <ArtistDetailPage 
            artistId={nav.artistId!} 
            artist={artist}
            settings={displaySettings}
            onOpenArtistEditor={navigateToArtistEditor}
            onOpenConcertEditor={(aid) => navigateToConcertEditor(aid)}
            onOpenConcertHome={navigateToConcertHome}
            onChangeSettings={handleUpdateDisplaySettings}
            onBack={navigateToArtistList} 
          />
        );
      }
      case 'CONCERT_HOME': {
        const artist = artists.find(a => a.id === nav.artistId);
        const tour = artist?.tours.find(t => t.id === nav.tourId);
        const concert = tour?.concerts.find(c => c.id === nav.concertId);

        if (!artist || !tour || !concert) {
          // Guard redirect
          navigateToArtistList();
          return null;
        }

        return (
          <ConcertHomePage 
            artistId={artist.id}
            concertId={concert.id}
            artist={artist}
            tour={tour}
            concert={concert}
            onBack={() => navigateToArtistDetail(artist.id)}
            onOpenArtistEditor={navigateToArtistEditor}
            onUpdateConcertAlbum={updateConcertAlbum}
          />
        );
      }
      case 'ARTIST_EDITOR': {
        const artist = artists.find(a => a.id === nav.artistId);
        return (
          <ArtistEditorPage 
            artistId={nav.artistId}
            artist={artist}
            onSave={upsertArtist}
            onCancel={() => nav.artistId ? navigateToArtistDetail(nav.artistId) : navigateToArtistList()}
            onOpenConcertEditor={navigateToConcertEditor}
            onDeleteArtist={deleteArtist}
          />
        );
      }
      case 'CONCERT_EDITOR': {
        const artist = artists.find(a => a.id === nav.artistId);
        if (!artist) return null;
        const tour = artist.tours.find(t => t.id === nav.tourId);
        return (
          <ConcertEditorPage 
            artistId={artist.id}
            tourId={nav.tourId}
            tour={tour}
            allArtists={artists}
            onSave={(updated) => upsertTour(artist.id, updated)}
            onCancel={() => navigateToArtistDetail(artist.id)}
            onDeleteTour={deleteTour}
          />
        );
      }
      default:
        return null;
    }
  };

  return (
    <div className="app-root">
      <Layout currentPath={nav.path} onNavigate={(path) => setNav({ path })}>
        {renderPage()}
      </Layout>

      {/* Requirement 4: Global Artist Picker Sheet */}
      {isArtistPickerOpen && (
        <div style={overlayStyle}>
          <div style={backdropStyle} onClick={() => setIsArtistPickerOpen(false)} />
          <GlassCard padding="24px" style={pickerCardStyle}>
            <h3 style={{ margin: 0, fontSize: '18px', fontWeight: '800' }}>公演を追加するアーティストを選択</h3>
            <div style={pickerListStyle}>
              {artists.length === 0 ? (
                <div style={emptyPickerStyle}>
                  アーティストを先に登録してください
                </div>
              ) : (
                artists.map(artist => (
                  <button 
                    key={artist.id}
                    onClick={() => {
                      navigateToConcertEditor(artist.id);
                      setIsArtistPickerOpen(false);
                    }}
                    style={pickerButtonStyle}
                  >
                    {artist.name}
                  </button>
                ))
              )}
            </div>
            <button onClick={() => setIsArtistPickerOpen(false)} style={closeButtonStyle}>
              閉じる
            </button>
          </GlassCard>
        </div>
      )}
    </div>
  );
}

// --- Styles ---
const overlayStyle: React.CSSProperties = { position: 'fixed', inset: 0, zIndex: 2000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '24px' };
const backdropStyle: React.CSSProperties = { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)', backdropFilter: 'blur(8px)' };
const pickerCardStyle: React.CSSProperties = { width: '100%', maxWidth: '360px', position: 'relative', display: 'flex', flexDirection: 'column', gap: '20px' };
const pickerListStyle: React.CSSProperties = { display: 'flex', flexDirection: 'column', gap: '10px', maxHeight: '300px', overflowY: 'auto' };
const emptyPickerStyle: React.CSSProperties = { fontSize: '13px', color: theme.colors.textSecondary, textAlign: 'center', padding: '20px' };
const pickerButtonStyle: React.CSSProperties = { padding: '16px', borderRadius: '16px', border: '1px solid rgba(0,0,0,0.05)', background: 'white', textAlign: 'left', fontWeight: '700', fontSize: '15px', cursor: 'pointer' };
const closeButtonStyle: React.CSSProperties = { padding: '12px', borderRadius: '12px', border: 'none', background: 'rgba(0,0,0,0.05)', fontWeight: '700', cursor: 'pointer' };

import React, { useState, useMemo } from 'react';
import { PageShell } from '../ui/PageShell';
import { IconButton, Icons } from '../ui/IconButton';
import { theme } from '../ui/theme';
import { PageId, Concert, Status, Artist } from '../domain/types';
import { ConcertMenu } from '../components/ConcertMenu';
import { sortPerformancesForDisplay, sortPerformancesByLotteryDate } from '../domain/logic';

interface Props {
  artists: Artist[];
  onOpenArtist: (artistId: string) => void;
  onOpenConcert: (concertId: string, tourId: string, artistId: string) => void;
  onCreateConcert: () => void;
  onRefreshAll: () => void;
}

interface ConcertWithMetadata extends Concert {
  artistName: string;
  artistId: string;
  tourName: string;
  tourId: string;
}

const ConcertRowCard = ({ concert, onClick }: { concert: ConcertWithMetadata; onClick: () => void }) => {
  const [isHovered, setIsHovered] = useState(false);
  const isSpecial = concert.status === '参戦予定' || concert.status === '参戦済み';
  const dotColor = isSpecial ? theme.colors.primary : theme.colors.textWeak;

  return (
    <div
      onClick={onClick}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      style={{
        background: 'white',
        borderRadius: theme.radius.card,
        border: '1px solid rgba(0, 0, 0, 0.04)',
        padding: '20px 24px',
        display: 'flex',
        flexDirection: 'column',
        gap: '8px',
        cursor: 'pointer',
        boxShadow: isHovered 
          ? '0 10px 20px -5px rgba(0, 0, 0, 0.06)' 
          : '0 4px 12px -2px rgba(0, 0, 0, 0.03)',
        transform: isHovered ? 'scale(1.015)' : 'scale(1)',
        transition: 'all 0.3s cubic-bezier(0.16, 1, 0.3, 1)',
      }}
    >
      <div style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: '700', letterSpacing: '0.05em' }}>
        {concert.artistName}
      </div>
      <div style={{ 
        fontWeight: '800', 
        fontSize: '18px', 
        color: isHovered ? theme.colors.primary : theme.colors.text,
        transition: 'color 0.2s'
      }}>
        {concert.tourName}
      </div>

      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '4px' }}>
        <div style={{ fontSize: '13px', color: theme.colors.textSecondary }}>
          {concert.date}
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
          <div style={{
            width: '8px',
            height: '8px',
            borderRadius: '50%',
            background: dotColor,
          }} />
          <div style={{
            fontSize: '11px',
            fontWeight: '700',
            color: theme.colors.textSecondary,
            letterSpacing: '0.05em',
            textTransform: 'uppercase'
          }}>
            {concert.status}
          </div>
        </div>
      </div>
    </div>
  );
};

export const ConcertListPage: React.FC<Props> = ({ artists, onOpenArtist, onOpenConcert, onCreateConcert, onRefreshAll }) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);
  const [sortMode, setSortMode] = useState<'status' | 'lottery'>('status');

  const allConcerts = useMemo(() => {
    const list: ConcertWithMetadata[] = [];
    artists.forEach(artist => {
      artist.tours.forEach(tour => {
        tour.concerts.forEach(concert => {
          list.push({
            ...concert,
            artistName: artist.name,
            artistId: artist.id,
            tourName: tour.name,
            tourId: tour.id
          });
        });
      });
    });
    return list;
  }, [artists]);

  const processedConcerts = useMemo(() => {
    let list = allConcerts.filter(c => {
      if (!showAttended && c.status === '参戦済み') return false;
      if (!showSkipped && c.status === '見送') return false;
      return true;
    });

    if (sortMode === 'lottery') {
      return sortPerformancesByLotteryDate(list as any) as ConcertWithMetadata[];
    }
    return sortPerformancesForDisplay(list as any) as ConcertWithMetadata[];
  }, [allConcerts, showAttended, showSkipped, sortMode]);

  const handleCardClick = (concert: ConcertWithMetadata) => {
    if (concert.status === '参戦予定' || concert.status === '参戦済み') {
      onOpenConcert(concert.artistId, concert.tourId, concert.id);
    } else {
      onOpenArtist(concert.artistId);
    }
  };

  return (
    <PageShell
      header={
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingBottom: '8px' }}>
          <h1 style={{ fontSize: '32px', fontWeight: '900', color: '#111827', margin: 0, letterSpacing: '-0.025em' }}>
            LiveTrack <span style={{ color: '#53BEE8' }}>JP</span>
          </h1>
          <button 
            onClick={onRefreshAll}
            style={{
              padding: '12px',
              borderRadius: '9999px',
              background: 'white',
              border: '1px solid #F3F4F6',
              color: '#9CA3AF',
              boxShadow: '0 1px 2px 0 rgba(0, 0, 0, 0.05)',
              cursor: 'pointer',
              outline: 'none'
            }}
          >
            <Icons.Refresh />
          </button>
        </div>
      }
    >
      <div style={{ display: 'flex', flexDirection: 'column', gap: '16px', paddingBottom: '120px' }}>
        {processedConcerts.length === 0 ? (
          <div style={{ 
            padding: '80px 20px', 
            textAlign: 'center', 
            color: theme.colors.textWeak,
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            gap: '24px'
          }}>
            <div style={{ fontSize: '48px', opacity: 0.5 }}>🎟️</div>
            <div style={{ fontSize: '15px', fontWeight: '600' }}>表示可能な公演がありません</div>
            <button 
              onClick={onCreateConcert}
              style={{
                padding: '12px 24px',
                borderRadius: '12px',
                background: theme.colors.primary,
                color: 'white',
                border: 'none',
                fontWeight: 'bold',
                cursor: 'pointer'
              }}
            >
              ＋ 公演を追加
            </button>
          </div>
        ) : (
          processedConcerts.map((concert) => (
            <ConcertRowCard 
              key={concert.id} 
              concert={concert} 
              onClick={() => handleCardClick(concert)} 
            />
          ))
        )}
      </div>

      <IconButton 
        icon={<Icons.Plus />} 
        primary 
        size={64}
        onClick={onCreateConcert}
        style={{ position: 'fixed', right: '32px', bottom: '100px', zIndex: 90, boxShadow: '0 12px 24px -6px rgba(83, 190, 232, 0.5)' }}
      />

      <div style={{ position: 'fixed', left: '32px', bottom: '100px', zIndex: 90 }}>
        <button 
          onClick={() => setIsMenuOpen(!isMenuOpen)}
          style={{ 
            width: '64px', height: '64px', borderRadius: '9999px', display: 'flex', alignItems: 'center', justifyContent: 'center', 
            background: 'white', border: '1px solid #F3F4F6', color: '#9CA3AF', boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.1)', cursor: 'pointer', outline: 'none'
          }}
        >
          <Icons.Menu />
        </button>
      </div>

      <ConcertMenu 
        isOpen={isMenuOpen} 
        onClose={() => setIsMenuOpen(false)} 
        showAttended={showAttended}
        onToggleAttended={() => setShowAttended(!showAttended)}
        showSkipped={showSkipped}
        onToggleSkipped={() => setShowSkipped(!showSkipped)}
        sortMode={sortMode}
        onSetSort={setSortMode}
      />
    </PageShell>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { theme } from '../ui/theme';
import { GlassCard } from '../ui/GlassCard';
import { ConfirmDialog } from '../components/ConfirmDialog';
import { Artist, Tour, Concert, Status } from '../domain/types';
import { Icons, IconButton } from '../ui/IconButton';
import { sortPerformancesForDisplay, checkGlobalDateConflicts } from '../domain/logic';
import { PageShell } from '../ui/PageShell';

const generateId = () => Math.random().toString(36).substr(2, 9);

const Field = ({ label, children, description }: { label: string; children: any; description?: string }) => (
  <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
    <label style={{ fontSize: '12px', color: theme.colors.textSecondary, marginLeft: '4px', fontWeight: 'bold' }}>{label}</label>
    {children}
    {description && <div style={{ fontSize: '10px', color: theme.colors.textWeak, marginLeft: '4px' }}>{description}</div>}
  </div>
);

interface Props {
  artistId: string;
  tourId?: string;
  tour?: Tour;
  allArtists: Artist[];
  onSave: (updatedTour: Tour) => void;
  onCancel: () => void;
  onDeleteTour: (artistId: string, tourId: string) => void;
}

const statusOptions: { value: Status; label: string; color: string }[] = [
  { value: '発売前', label: '発売前', color: '#10B981' },
  { value: '検討中', label: '検討中', color: '#9CA3AF' },
  { value: '抽選中', label: '抽選中', color: '#F59E0B' },
  { value: '参戦予定', label: '参戦予定', color: theme.colors.primary },
  { value: '参戦済み', label: '参戦済み', color: theme.colors.primary },
  { value: '見送', label: '見送', color: '#D1D5DB' },
];

// --- Custom Components for the Editor ---

const StatusPicker = ({ value, onChange }: { value: Status; onChange: (s: Status) => void }) => {
  const [isOpen, setIsOpen] = useState(false);
  const current = statusOptions.find(o => o.value === value) || statusOptions[0];

  return (
    <div style={{ position: 'relative' }}>
      <div 
        onClick={() => setIsOpen(!isOpen)}
        style={{ ...inputStyle, cursor: 'pointer', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
          <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: current.color }} />
          {current.label}
        </div>
        <span style={{ fontSize: '10px', opacity: 0.5 }}>{isOpen ? '▲' : '▼'}</span>
      </div>
      {isOpen && (
        <>
          <div style={{ position: 'fixed', inset: 0, zIndex: 100 }} onClick={() => setIsOpen(false)} />
          <GlassCard padding="8px" style={{ position: 'absolute', top: '100%', left: 0, right: 0, zIndex: 101, marginTop: '4px', display: 'flex', flexDirection: 'column', gap: '2px' }}>
            {statusOptions.map(opt => (
              <div 
                key={opt.value}
                onClick={() => { onChange(opt.value); setIsOpen(false); }}
                style={{ 
                  padding: '10px 12px', 
                  borderRadius: '8px', 
                  fontSize: '14px', 
                  fontWeight: '600',
                  cursor: 'pointer',
                  background: value === opt.value ? 'rgba(83, 190, 232, 0.1)' : 'transparent',
                  color: value === opt.value ? theme.colors.primary : theme.colors.textMain,
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px'
                }}
              >
                <div style={{ width: '6px', height: '6px', borderRadius: '50%', background: opt.color }} />
                {opt.label}
              </div>
            ))}
          </GlassCard>
        </>
      )}
    </div>
  );
};

const CustomDatePicker = ({ value, onChange }: { value: string; onChange: (val: string) => void }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [viewDate, setViewDate] = useState(value === 'TBD' ? new Date() : new Date(value));

  const daysInMonth = (y: number, m: number) => new Date(y, m + 1, 0).getDate();
  const firstDay = (y: number, m: number) => new Date(y, m, 1).getDay();

  const calendarDays = useMemo(() => {
    const y = viewDate.getFullYear();
    const m = viewDate.getMonth();
    const days = [];
    const first = firstDay(y, m);
    for (let i = 0; i < first; i++) days.push(null);
    for (let i = 1; i <= daysInMonth(y, m); i++) days.push(i);
    return days;
  }, [viewDate]);

  const handleSelectDay = (day: number) => {
    const y = viewDate.getFullYear();
    const m = String(viewDate.getMonth() + 1).padStart(2, '0');
    const d = String(day).padStart(2, '0');
    onChange(`${y}-${m}-${d}`);
    setIsOpen(false);
  };

  return (
    <div style={{ position: 'relative' }}>
      <div 
        onClick={() => setIsOpen(!isOpen)}
        style={{ ...inputStyle, cursor: 'pointer', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}
      >
        <span>{value === 'TBD' ? '未定 (TBD)' : value}</span>
        <Icons.Calendar />
      </div>
      {isOpen && (
        <>
          <div style={{ position: 'fixed', inset: 0, zIndex: 100 }} onClick={() => setIsOpen(false)} />
          <GlassCard padding="16px" style={{ position: 'absolute', top: '100%', left: 0, width: '280px', zIndex: 101, marginTop: '4px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px' }}>
              <button onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() - 1, 1))} style={navBtnStyle}>◀</button>
              <div style={{ fontWeight: 'bold', fontSize: '14px' }}>{viewDate.getFullYear()}年 {viewDate.getMonth() + 1}月</div>
              <button onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 1))} style={navBtnStyle}>▶</button>
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '4px', textAlign: 'center' }}>
              {['日','月','火','水','木','金','土'].map(d => <div key={d} style={{ fontSize: '10px', color: theme.colors.textWeak }}>{d}</div>)}
              {calendarDays.map((day, i) => (
                <div 
                  key={i} 
                  onClick={() => day && handleSelectDay(day)}
                  style={{ 
                    padding: '8px 0', 
                    fontSize: '13px', 
                    borderRadius: '8px', 
                    cursor: day ? 'pointer' : 'default',
                    background: day && value === `${viewDate.getFullYear()}-${String(viewDate.getMonth()+1).padStart(2,'0')}-${String(day).padStart(2,'0')}` ? theme.colors.primary : 'transparent',
                    color: day && value === `${viewDate.getFullYear()}-${String(viewDate.getMonth()+1).padStart(2,'0')}-${String(day).padStart(2,'0')}` ? 'white' : theme.colors.textMain,
                    opacity: day ? 1 : 0
                  }}
                >
                  {day}
                </div>
              ))}
            </div>
            <button 
              onClick={() => { onChange('TBD'); setIsOpen(false); }}
              style={{ width: '100%', marginTop: '12px', padding: '8px', border: 'none', background: 'rgba(0,0,0,0.05)', borderRadius: '8px', fontSize: '12px', fontWeight: 'bold', cursor: 'pointer' }}
            >
              日付未定 (TBD)
            </button>
          </GlassCard>
        </>
      )}
    </div>
  );
};

const navBtnStyle = { border: 'none', background: 'none', padding: '4px 8px', cursor: 'pointer', fontSize: '12px' };

// --- Main Page Component ---

export const ConcertEditorPage: React.FC<Props> = ({ 
  artistId, 
  tourId, 
  tour, 
  allArtists, 
  onSave, 
  onCancel,
  onDeleteTour 
}) => {
  const getInitialData = (): Tour => {
    if (tourId && tour) return { ...tour };
    return {
      id: generateId(),
      name: '',
      imageUrl: '',
      memo: '',
      concerts: []
    };
  };

  const [formData, setFormData] = useState<Tour>(getInitialData());
  const initialSnapshotRef = useRef<string>(JSON.stringify(getInitialData()));

  const [imageUrlDraft, setImageUrlDraft] = useState(formData.imageUrl);
  const [hasChanges, setHasChanges] = useState(false);
  const [expandedConcertId, setExpandedConcertId] = useState<string | null>(null);
  const [isDeleteTourModalOpen, setIsDeleteTourModalOpen] = useState(false);
  const [isDeleteConcertModalOpen, setIsDeleteConcertModalOpen] = useState<string | null>(null);
  const [isConflictDialogOpen, setIsConflictDialogOpen] = useState(false);

  useEffect(() => {
    if (tour) {
      setFormData({ ...tour });
      setImageUrlDraft(tour.imageUrl);
      initialSnapshotRef.current = JSON.stringify(tour);
    }
  }, [tourId]);

  useEffect(() => {
    setHasChanges(JSON.stringify(formData) !== initialSnapshotRef.current);
  }, [formData]);

  const sortedConcerts = useMemo(() => {
    return sortPerformancesForDisplay(formData.concerts);
  }, [formData.concerts]);

  const handleSave = () => {
    const conflicts = checkGlobalDateConflicts(allArtists, formData.id, formData.concerts);
    if (conflicts.length > 0) {
      setIsConflictDialogOpen(true);
      return;
    }
    onSave(formData);
  };

  const handleUpdateTourField = (field: keyof Tour, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleLoadImage = () => {
    if (imageUrlDraft.trim()) {
      handleUpdateTourField('imageUrl', imageUrlDraft.trim());
    }
  };

  const handleAddConcert = () => {
    const newConcert: Concert = {
      id: generateId(),
      date: 'TBD',
      venue: '',
      price: 0,
      saleLink: '',
      status: '発売前',
      isParticipated: false,
      images: []
    };
    setFormData(prev => ({ ...prev, concerts: [...prev.concerts, newConcert] }));
    setExpandedConcertId(newConcert.id);
  };

  const handleUpdateConcert = (id: string, updates: Partial<Concert>) => {
    setFormData(prev => ({
      ...prev,
      concerts: prev.concerts.map(c => c.id === id ? { ...c, ...updates } : c)
    }));
  };

  const handleDeleteConcert = (id: string) => {
    setFormData(prev => ({
      ...prev,
      concerts: prev.concerts.filter(c => c.id !== id)
    }));
    setIsDeleteConcertModalOpen(null);
  };

  return (
    <PageShell
      header={
        <header style={headerStyle}>
          <IconButton 
            icon={<Icons.X />} 
            onClick={onCancel}
            size={40}
            style={{ 
              color: theme.colors.textSecondary, 
              borderColor: 'transparent', 
              background: 'transparent',
              boxShadow: 'none'
            }}
          />
          <h2 style={{ fontSize: '17px', margin: 0, fontWeight: 'bold' }}>ツアー・公演編集</h2>
          {tourId ? (
            <IconButton 
              icon={<Icons.Trash />} 
              onClick={() => setIsDeleteTourModalOpen(true)}
              size={40}
              style={{ 
                color: theme.colors.error, 
                borderColor: 'transparent', 
                background: 'transparent',
                boxShadow: 'none'
              }}
            />
          ) : <div style={{ width: 40 }} />}
        </header>
      }
    >
      <div style={{ paddingBottom: '160px' }}>
        <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '24px' }}>
          <div style={{ 
            width: '120px', 
            height: '160px', 
            borderRadius: '16px', 
            background: '#F3F4F6', 
            border: '4px solid white', 
            boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
            overflow: 'hidden',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center'
          }}>
            {formData.imageUrl ? (
              <img 
                src={formData.imageUrl} 
                style={{ width: '100%', height: '100%', objectFit: 'cover' }} 
                onError={(e) => {
                  (e.target as HTMLImageElement).src = 'https://via.placeholder.com/150?text=Error';
                }}
              />
            ) : (
              <span style={{ fontSize: '32px', opacity: 0.2 }}>🎸</span>
            )}
          </div>
        </div>

        <section style={{ marginBottom: theme.spacing.xl }}>
          <h3 style={sectionTitleStyle}>ツアー情報 (共通)</h3>
          <GlassCard padding={theme.spacing.md}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.md }}>
              <Field label="ツアー名 (必須)">
                <input type="text" value={formData.name} onChange={e => handleUpdateTourField('name', e.target.value)} placeholder="名称を入力" style={inputStyle} />
              </Field>
              <Field label="ツアー画像URL">
                <div style={{ display: 'flex', gap: '8px' }}>
                  <input 
                    type="url" 
                    value={imageUrlDraft} 
                    onChange={e => setImageUrlDraft(e.target.value)} 
                    placeholder="https://..." 
                    style={inputStyle} 
                  />
                  <button 
                    onClick={handleLoadImage}
                    style={loadButtonStyle}
                    onMouseEnter={(e) => e.currentTarget.style.color = theme.colors.primary}
                    onMouseLeave={(e) => e.currentTarget.style.color = theme.colors.textSecondary}
                  >
                    読み込み
                  </button>
                </div>
              </Field>
              <Field label="メモ">
                <textarea 
                  value={formData.memo} 
                  onChange={e => handleUpdateTourField('memo', e.target.value)} 
                  placeholder="ツアーに関する全体メモ" 
                  style={{ ...inputStyle, minHeight: '80px', resize: 'none' }} 
                />
              </Field>
            </div>
          </GlassCard>
        </section>

        <section style={{ marginBottom: theme.spacing.xl }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: theme.spacing.sm }}>
            <h3 style={{ ...sectionTitleStyle, marginBottom: 0 }}>公演一覧 (場次)</h3>
            <button onClick={handleAddConcert} style={actionButtonStyle}>＋ 公演を追加</button>
          </div>

          {sortedConcerts.length === 0 ? (
            <GlassCard padding={theme.spacing.lg} style={{ textAlign: 'center', color: theme.colors.textWeak }}>まだ公演が登録されていません</GlassCard>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.sm }}>
              {sortedConcerts.map(concert => {
                const isExpanded = expandedConcertId === concert.id;
                const showLotteryInfo = ['抽選中', '参戦予定', '見送'].includes(concert.status);

                return (
                  <GlassCard key={concert.id} padding="0">
                    <div onClick={() => setExpandedConcertId(isExpanded ? null : concert.id)} style={{ padding: theme.spacing.md, cursor: 'pointer', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <div>
                        <div style={{ fontWeight: '700', fontSize: '15px' }}>{concert.date === 'TBD' ? '日付未定' : concert.date}</div>
                        <div style={{ fontSize: '12px', color: theme.colors.textSecondary }}>{concert.venue || '会場未入力'}</div>
                      </div>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <span style={{ fontSize: '13px', fontWeight: '600', color: theme.colors.primary }}>
                          {concert.status}
                        </span>
                        <span style={{ 
                          transform: isExpanded ? 'rotate(180deg)' : 'none', 
                          transition: 'transform 0.2s',
                          fontSize: '10px'
                        }}>▼</span>
                      </div>
                    </div>
                    {isExpanded && (
                      <div style={{ padding: `0 ${theme.spacing.md} ${theme.spacing.md} ${theme.spacing.md}`, display: 'flex', flexDirection: 'column', gap: theme.spacing.md, borderTop: '0.5px solid rgba(0,0,0,0.05)', paddingTop: theme.spacing.md }}>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                          <Field label="日付">
                            <CustomDatePicker 
                              value={concert.date} 
                              onChange={(val) => handleUpdateConcert(concert.id, { date: val })} 
                            />
                          </Field>
                          <Field label="会場">
                            <input type="text" value={concert.venue} onChange={e => handleUpdateConcert(concert.id, { venue: e.target.value })} placeholder="会場名" style={inputStyle} />
                          </Field>
                        </div>

                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                          <Field label="状態">
                            <StatusPicker 
                              value={concert.status} 
                              onChange={(val) => handleUpdateConcert(concert.id, { status: val })} 
                            />
                          </Field>
                          <Field label="チケット価格">
                            <input 
                              type="text" 
                              value={concert.price || ''} 
                              onChange={e => handleUpdateConcert(concert.id, { price: Number(e.target.value.replace(/[^0-9]/g, '')) })} 
                              placeholder="金額を入力" 
                              style={inputStyle} 
                            />
                          </Field>
                        </div>

                        {showLotteryInfo && (
                          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', padding: '12px', background: 'rgba(0,0,0,0.02)', borderRadius: '12px' }}>
                            <Field label="抽選名">
                              <input 
                                type="text" 
                                value={concert.lotteryName || ''} 
                                onChange={e => handleUpdateConcert(concert.id, { lotteryName: e.target.value })} 
                                placeholder="FC先行、一般など"
                                style={inputStyle} 
                              />
                            </Field>
                            <Field label="抽選結果日時">
                              <input 
                                type="text" 
                                value={concert.lotteryResultDate || ''} 
                                onChange={e => handleUpdateConcert(concert.id, { lotteryResultDate: e.target.value })} 
                                placeholder="YYYY/MM/DD HH:MM"
                                style={inputStyle} 
                              />
                            </Field>
                          </div>
                        )}

                        <Field label="販売ページURL">
                          <input type="url" value={concert.saleLink} onChange={e => handleUpdateConcert(concert.id, { saleLink: e.target.value })} placeholder="https://..." style={inputStyle} />
                        </Field>

                        <button 
                          onClick={(e) => { e.stopPropagation(); setIsDeleteConcertModalOpen(concert.id); }} 
                          style={{ alignSelf: 'flex-start', border: 'none', background: 'none', color: theme.colors.error, fontSize: '13px', fontWeight: 'bold', cursor: 'pointer', padding: '8px 0' }}
                        >
                          🗑️ この公演を削除
                        </button>
                      </div>
                    )}
                  </GlassCard>
                );
              })}
            </div>
          )}
        </section>

        <section style={{ marginTop: '40px', padding: '0 4px' }}>
          <button 
            disabled={!hasChanges || !formData.name}
            onClick={handleSave}
            style={{ 
              width: '100%', 
              padding: '16px', 
              borderRadius: theme.radius.button, 
              background: (!hasChanges || !formData.name) ? 'rgba(0,0,0,0.05)' : theme.colors.primary, 
              color: (!hasChanges || !formData.name) ? theme.colors.textWeak : 'white', 
              border: 'none', 
              fontWeight: 'bold', 
              fontSize: '16px', 
              cursor: (!hasChanges || !formData.name) ? 'default' : 'pointer',
              transition: 'all 0.2s'
            }}
          >
            ツアー情報を保存
          </button>
        </section>

        <ConfirmDialog 
          isOpen={isConflictDialogOpen} 
          title="日付の重複" 
          message="参戦予定または参戦済みの公演が他アーティストも含め同日に存在します。日付を変更してください。" 
          confirmLabel="確認" 
          onClose={() => setIsConflictDialogOpen(false)} 
          onConfirm={() => setIsConflictDialogOpen(false)} 
        />

        <ConfirmDialog 
          isOpen={isDeleteTourModalOpen} 
          title="ツアーを完全に削除しますか？" 
          message="このツアー、配下の全公演、およびアルバム画像がすべて削除されます。この操作は取り消せません。" 
          confirmLabel="ツアーを削除" 
          isDestructive 
          onClose={() => setIsDeleteTourModalOpen(false)} 
          onConfirm={() => onDeleteTour(artistId, formData.id)} 
        />

        <ConfirmDialog 
          isOpen={!!isDeleteConcertModalOpen} 
          title="公演を削除しますか？" 
          message="この公演に関連する抽選情報やアルバム画像もすべて破棄されます。" 
          confirmLabel="公演を削除" 
          isDestructive 
          onClose={() => setIsDeleteConcertModalOpen(null)} 
          onConfirm={() => isDeleteConcertModalOpen && handleDeleteConcert(isDeleteConcertModalOpen)} 
        />
      </div>
    </PageShell>
  );
};

