import { calcArtistStatus, sortPerformancesForDisplay } from '../domain/logic';

interface Props {
  artistId: string;
  artist: Artist;
  settings: DisplaySettings;
  onOpenArtistEditor: (artistId: string) => void;
  onOpenConcertEditor: (artistId: string) => void;
  onOpenConcertHome: (artistId: string, tourId: string, concertId: string) => void;
  onChangeSettings: (settings: Partial<DisplaySettings>) => void;
  onBack: () => void;
}

const ConcertItem = ({ concert, onClick }: { concert: Concert; onClick?: () => void }) => {
  const isSpecial = concert.status === '参戦予定' || concert.status === '参戦済み';
  const dotColor = isSpecial ? theme.colors.primary : '#9CA3AF';
  const canNavigate = !!onClick;
  const isLottery = concert.status === '抽選中';

  const displayImage = concert.images && concert.images.length > 0 ? concert.images[0] : null;

  return (
    <div 
      onClick={onClick}
      style={{
        background: 'white',
        borderRadius: '28px',
        padding: '16px 20px',
        border: '1px solid rgba(0, 0, 0, 0.04)',
        boxShadow: '0 4px 12px rgba(0,0,0,0.03)',
        display: 'flex',
        gap: '16px',
        alignItems: 'center',
        cursor: canNavigate ? 'pointer' : 'default',
        position: 'relative'
      }}
    >
      {/* Concert Thumbnail */}
      <div style={{
        width: '52px',
        height: '52px',
        borderRadius: '16px',
        background: '#F3F4F6',
        flexShrink: 0,
        overflow: 'hidden',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        border: '1px solid rgba(0,0,0,0.05)'
      }}>
        {displayImage ? (
          <img src={displayImage} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
        ) : (
          <span style={{ fontSize: '20px', opacity: 0.2 }}>🎟️</span>
        )}
      </div>

      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px', flexWrap: 'wrap' }}>
          <span style={{ fontWeight: '800', fontSize: '16px' }}>{concert.date}</span>
          <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
            <div style={{ width: '6px', height: '6px', borderRadius: '50%', background: dotColor }} />
            <span style={{ fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary }}>{concert.status}</span>
          </div>
        </div>

        <div style={{ fontSize: '13px', color: theme.colors.textSecondary, marginTop: '2px', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
          {concert.venue || '会場未定'}
        </div>

        {isLottery && (
          <div style={{ marginTop: '8px', display: 'flex', flexDirection: 'column', gap: '2px' }}>
            {concert.lotteryName && (
              <div style={{ fontSize: '12px', fontWeight: '800', color: theme.colors.primary }}>{concert.lotteryName}</div>
            )}
            <div style={{ display: 'flex', gap: '12px', alignItems: 'center' }}>
              {concert.lotteryResultDate && (
                <div style={{ fontSize: '12px', color: theme.colors.textMain, fontWeight: '600' }}>
                  {concert.lotteryResultDate}
                </div>
              )}
              {concert.price > 0 && (
                <div style={{ fontSize: '12px', color: theme.colors.textSecondary }}>
                  ¥{concert.price.toLocaleString()}
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
        {concert.saleLink && (
          <a 
            href={concert.saleLink} 
            target="_blank" 
            rel="noopener noreferrer"
            onClick={(e) => e.stopPropagation()}
            style={{ 
              display: 'flex', 
              color: theme.colors.textWeak, 
              padding: '8px',
              borderRadius: '12px',
              background: '#F9FAFB',
              transition: 'color 0.2s'
            }}
            onMouseEnter={(e) => (e.currentTarget.style.color = theme.colors.primary)}
            onMouseLeave={(e) => (e.currentTarget.style.color = theme.colors.textWeak)}
          >
            <Icons.Globe />
          </a>
        )}
        {canNavigate && (
          <div style={{ color: '#D1D5DB' }}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <polyline points="9 18 15 12 9 6"></polyline>
            </svg>
          </div>
        )}
      </div>
    </div>
  );
};

