import React, { useState, useMemo, useEffect } from 'react';
import { PageShell } from '../ui/PageShell';
import { theme } from '../ui/theme';
import { PageId, Status, Artist, Concert } from '../domain/types';
import { CalendarMenu } from '../components/CalendarMenu';
import { 
  getBestStatusForDay, 
  sortPerformancesForDisplay, 
  getConcertNavigationTarget 
} from '../domain/logic';
import { Icons } from '../ui/IconButton';

interface Props {
  artists: Artist[];
  onOpenArtist: (artistId: string) => void;
  onOpenConcert: (artistId: string, tourId: string, concertId: string) => void;
  onRefreshAll: () => void;
}

// Visual indicator mapping for dots
const colorMap: Record<Status, string> = {
  '参戦予定': theme.colors.primary,
  '抽選中': '#F59E0B', // Amber 500
  '検討中': '#9CA3AF',
  '発売前': '#10B981', // Emerald 500
  '参戦済み': theme.colors.primary,
  '見送': '#D1D5DB',
};

interface ConcertWithMetadata extends Concert {
  artistName: string;
  artistId: string;
  tourName: string;
  tourId: string;
}

export const CalendarPage: React.FC<Props> = ({ artists, onOpenArtist, onOpenConcert, onRefreshAll }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<string | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [weekStart, setWeekStart] = useState<'sun' | 'mon'>('sun');

  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);

  // Instruction 2: Reset selected date when month/year changes
  useEffect(() => {
    setSelectedDate(null);
  }, [currentDate.getFullYear(), currentDate.getMonth()]);

  // Flatten and unify data source
  const allConcerts = useMemo(() => {
    const list: ConcertWithMetadata[] = [];
    artists.forEach(artist => {
      artist.tours.forEach(tour => {
        tour.concerts.forEach(concert => {
          list.push({
            ...concert,
            artistName: artist.name,
            artistId: artist.id,
            tourName: tour.name,
            tourId: tour.id
          });
        });
      });
    });
    return list;
  }, [artists]);

  // Instruction 4 & 5: Apply filters and exclude TBD globally for calendar logic
  const visibleConcerts = useMemo(() => {
    return allConcerts.filter(c => {
      if (c.date === 'TBD') return false;
      if (!showAttended && c.status === '参戦済み') return false;
      if (!showSkipped && c.status === '見送') return false;
      return true;
    });
  }, [allConcerts, showAttended, showSkipped]);

  const daysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
  const firstDayOfMonth = (year: number, month: number) => new Date(year, month, 1).getDay();

  const calendarDays = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const count = daysInMonth(year, month);
    let startDay = firstDayOfMonth(year, month);
    if (weekStart === 'mon') startDay = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < startDay; i++) days.push(null);
    for (let i = 1; i <= count; i++) days.push(i);
    return days;
  }, [currentDate, weekStart]);

  const getDayConcerts = (day: number) => {
    const dateStr = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    // Instruction 1: Filter specifically by date string
    return visibleConcerts.filter(c => c.date === dateStr);
  };

  const handleDayClick = (day: number) => {
    const dateStr = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSelectedDate(dateStr === selectedDate ? null : dateStr);
  };

  const handleConcertClick = (concert: ConcertWithMetadata) => {
    // ID-based navigation consistency
    if (concert.status === '参戦予定' || concert.status === '参戦済み') {
      // Fix: Correct argument order (artistId, tourId, concertId)
      onOpenConcert(concert.artistId, concert.tourId, concert.id);
    } else {
      onOpenArtist(concert.artistId);
    }
  };

  const dayConcerts = useMemo(() => {
    if (!selectedDate) return [];
    const filtered = visibleConcerts.filter(c => c.date === selectedDate);
    return sortPerformancesForDisplay(filtered as any) as ConcertWithMetadata[];
  }, [selectedDate, visibleConcerts]);

  return (
    <PageShell
      header={
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingBottom: '8px' }}>
          <h1 style={{ fontSize: '32px', fontWeight: '900', color: '#111827', margin: 0, letterSpacing: '-0.025em' }}>
            LiveTrack <span style={{ color: '#53BEE8' }}>JP</span>
          </h1>
          <button 
            onClick={onRefreshAll}
            style={{ padding: '12px', borderRadius: '9999px', background: 'white', border: '1px solid #F3F4F6', color: '#9CA3AF', cursor: 'pointer', outline: 'none' }}
          >
            <Icons.Refresh />
          </button>
        </div>
      }
    >
      <div style={{ paddingBottom: '120px' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
          <div style={{ fontSize: '24px', fontWeight: '900' }}>{currentDate.getFullYear()}年 {currentDate.getMonth() + 1}月</div>
          <div style={{ display: 'flex', gap: '8px' }}>
            <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1))} style={{ width: '40px', height: '40px', borderRadius: '50%', border: 'none', background: '#F3F4F6', cursor: 'pointer', fontWeight: 'bold' }}>◀</button>
            <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1))} style={{ width: '40px', height: '40px', borderRadius: '50%', border: 'none', background: '#F3F4F6', cursor: 'pointer', fontWeight: 'bold' }}>▶</button>
          </div>
        </div>

        <div style={{ background: 'white', borderRadius: '32px', padding: '24px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 12px rgba(0,0,0,0.03)' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '8px' }}>
            {(weekStart === 'sun' ? ['日', '月', '火', '水', '木', '金', '土'] : ['月', '火', '水', '木', '金', '土', '日']).map(l => (
              <div key={l} style={{ textAlign: 'center', fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary }}>{l}</div>
            ))}
            {calendarDays.map((day, idx) => {
              if (day === null) return <div key={idx} />;
              const concerts = getDayConcerts(day);
              // Instruction 3: Dot is at most 1, based on weighted priority logic
              const bestStatus = getBestStatusForDay(concerts as any);
              const isSelected = selectedDate === `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;

              return (
                <div 
                  key={day} 
                  onClick={() => handleDayClick(day)} 
                  style={{ 
                    aspectRatio: '1/1', 
                    display: 'flex', 
                    flexDirection: 'column', 
                    alignItems: 'center', 
                    justifyContent: 'center', 
                    borderRadius: '16px', 
                    background: isSelected ? 'rgba(83, 190, 232, 0.1)' : 'transparent', 
                    border: isSelected ? '2px solid #53BEE8' : 'none', 
                    cursor: 'pointer', 
                    position: 'relative',
                    transition: 'all 0.2s'
                  }}
                >
                  <span style={{ fontSize: '16px', fontWeight: '600' }}>{day}</span>
                  {bestStatus && (
                    <div style={{ 
                      position: 'absolute', 
                      bottom: '6px', 
                      width: '6px', 
                      height: '6px', 
                      borderRadius: '50%', 
                      background: colorMap[bestStatus] 
                    }} />
                  )}
                </div>
              );
            })}
          </div>
        </div>

        {selectedDate && dayConcerts.length > 0 && (
          <div style={{ marginTop: '32px' }} className="fade-in">
            <h3 style={{ fontSize: '14px', fontWeight: '700', color: theme.colors.textSecondary, marginBottom: '16px', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
              {selectedDate.replace(/-/g, '.')}
            </h3>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
              {dayConcerts.map((c) => (
                <div 
                  key={c.id} 
                  onClick={() => handleConcertClick(c)}
                  style={{ 
                    background: 'white', 
                    borderRadius: '24px', 
                    padding: '20px', 
                    border: '1px solid rgba(0,0,0,0.04)', 
                    boxShadow: '0 4px 12px rgba(0,0,0,0.03)', 
                    display: 'flex', 
                    justifyContent: 'space-between', 
                    alignItems: 'center',
                    cursor: 'pointer'
                  }}
                >
                  <div>
                    <div style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: '700' }}>{c.artistName}</div>
                    <div style={{ fontSize: '17px', fontWeight: '800' }}>{c.tourName}</div>
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: colorMap[c.status] }} />
                    <span style={{ fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary }}>{c.status}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      <div style={{ position: 'fixed', left: '32px', bottom: '100px', zIndex: 90 }}>
        <button 
          onClick={() => setIsMenuOpen(!isMenuOpen)} 
          style={{ 
            width: '64px', height: '64px', borderRadius: '9999px', display: 'flex', alignItems: 'center', justifyContent: 'center', 
            background: 'white', border: '1px solid #F3F4F6', color: '#9CA3AF', boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.1)', cursor: 'pointer', outline: 'none'
          }}
        >
          <Icons.Menu />
        </button>
      </div>
      <CalendarMenu 
        isOpen={isMenuOpen} 
        onClose={() => setIsMenuOpen(false)} 
        weekStart={weekStart} 
        setWeekStart={setWeekStart}
        showAttended={showAttended}
        setShowAttended={setShowAttended}
        showSkipped={showSkipped}
        setShowSkipped={setShowSkipped}
      />
    </PageShell>
  );
};

import React, { useState, useRef } from 'react';
import { theme } from '../ui/theme';
import { ImageDialog } from '../components/ImageDialog';
import { Artist, Tour, Concert } from '../domain/types';
import { Icons, IconButton } from '../ui/IconButton';

interface Props {
  artistId: string;
  concertId: string;
  artist: Artist;
  tour: Tour;
  concert: Concert;
  onBack: () => void;
  onOpenArtistEditor: (artistId: string) => void;
  onUpdateConcertAlbum: (artistId: string, tourId: string, concertId: string, images: string[]) => void;
}

export const ConcertHomePage: React.FC<Props> = ({ 
  artistId, 
  concertId, 
  artist, 
  tour, 
  concert, 
  onBack, 
  onOpenArtistEditor,
  onUpdateConcertAlbum 
}) => {
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingImageUrl, setEditingImageUrl] = useState<{ url: string; index: number } | null>(null);
  const [fullscreenImage, setFullscreenImage] = useState<string | null>(null);
  const [failedImages, setFailedImages] = useState<Set<string>>(new Set());

  // Drag and Drop state
  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);

  const images = concert.images || [];

  // Requirement Fix: Determine the best background image (Concert Album > Tour Poster > Artist Profile)
  const backgroundUrl = (images.length > 0) 
    ? images[0] 
    : (tour.imageUrl || artist.imageUrl || '');

  const handleAddImage = (url: string) => {
    if (editingImageUrl !== null) {
      const newImages = [...images];
      newImages[editingImageUrl.index] = url;
      onUpdateConcertAlbum(artistId, tour.id, concertId, newImages);
      setFailedImages(prev => {
        const next = new Set(prev);
        next.delete(editingImageUrl.url);
        return next;
      });
      setEditingImageUrl(null);
    } else {
      onUpdateConcertAlbum(artistId, tour.id, concertId, [...images, url]);
    }
  };

  const handleImageError = (url: string) => {
    setFailedImages(prev => new Set([...prev, url]));
  };

  const handleRemoveImage = (url: string) => {
    onUpdateConcertAlbum(artistId, tour.id, concertId, images.filter(i => i !== url));
  };

  const handleReplaceImage = (url: string, index: number) => {
    setEditingImageUrl({ url, index });
    setIsDialogOpen(true);
  };

  // Drag and Drop Handlers
  const handleDragStart = (index: number) => {
    dragItem.current = index;
  };

  const handleDragEnter = (index: number) => {
    dragOverItem.current = index;
  };

  const handleDragEnd = () => {
    if (dragItem.current !== null && dragOverItem.current !== null && dragItem.current !== dragOverItem.current) {
      const newList = [...images];
      const draggedItemContent = newList[dragItem.current];
      newList.splice(dragItem.current, 1);
      newList.splice(dragOverItem.current, 0, draggedItemContent);

      onUpdateConcertAlbum(artistId, tour.id, concertId, newList);
    }
    dragItem.current = null;
    dragOverItem.current = null;
  };

  return (
    <div style={{ minHeight: '100vh', position: 'relative', overflowX: 'hidden' }}>
      {/* 
        Requirement Fix: Dynamic background 
        We use double quotes and encodeURI for safety. 
        referrerPolicy="no-referrer" is used on images below, but for CSS background, browser behavior varies.
      */}
      <div style={{ 
        position: 'fixed', 
        inset: 0, 
        zIndex: -1, 
        backgroundImage: backgroundUrl ? `url("${encodeURI(backgroundUrl)}")` : 'none', 
        backgroundColor: '#111',
        backgroundSize: 'cover', 
        backgroundPosition: 'center', 
        filter: 'blur(40px) brightness(0.6)', 
        transform: 'scale(1.2)',
        transition: 'background-image 0.5s ease-in-out'
      }} />

      <div style={{ padding: `${theme.spacing.lg} ${theme.spacing.md} 140px ${theme.spacing.md}`, maxWidth: '600px', margin: '0 auto' }}>
        <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' }}>
          <button 
            onClick={onBack} 
            style={{ 
              border: 'none', 
              background: 'rgba(255,255,255,0.15)', 
              backdropFilter: 'blur(10px)',
              color: 'white', 
              width: '44px', 
              height: '44px', 
              borderRadius: '22px', 
              display: 'flex', 
              alignItems: 'center', 
              justifyContent: 'center', 
              cursor: 'pointer' 
            }}
          >
            <Icons.ChevronLeft />
          </button>

          <IconButton 
            icon={<Icons.Edit />} 
            onClick={() => onOpenArtistEditor(artistId)}
            size={44}
            style={{ 
              background: 'rgba(255,255,255,0.15)', 
              backdropFilter: 'blur(10px)',
              border: 'none',
              color: 'white',
              boxShadow: 'none'
            }}
          />
        </header>

        <div style={{ color: 'white', marginBottom: '32px', textAlign: 'center' }}>
          <h1 style={{ 
            fontSize: '32px', 
            fontWeight: '900', 
            margin: '0 0 8px 0', 
            textShadow: '0 4px 12px rgba(0,0,0,0.4)',
            letterSpacing: '-0.02em'
          }}>
            {tour.name}
          </h1>
          <div style={{ fontSize: '18px', opacity: 0.8, fontWeight: '600', textShadow: '0 2px 4px rgba(0,0,0,0.3)' }}>
            {artist.name}
          </div>
          <div style={{ fontSize: '14px', opacity: 0.6, marginTop: '4px' }}>
            {concert.date} @ {concert.venue}
          </div>
        </div>

        <section>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px', padding: '0 4px' }}>
            <h2 style={{ color: 'white', fontSize: '20px', fontWeight: '800', margin: 0 }}>アルバム</h2>
            <span style={{ fontSize: '13px', color: 'rgba(255,255,255,0.6)', fontWeight: '600' }}>
              {images.length} 枚の思い出
            </span>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '16px' }}>
            {images.map((img, idx) => {
              const isFailed = failedImages.has(img);
              return (
                <div 
                  key={`${img}-${idx}`} 
                  draggable
                  onDragStart={() => handleDragStart(idx)}
                  onDragEnter={() => handleDragEnter(idx)}
                  onDragEnd={handleDragEnd}
                  onDragOver={(e) => e.preventDefault()}
                  style={{ 
                    position: 'relative', 
                    aspectRatio: '1/1', 
                    borderRadius: '24px', 
                    overflow: 'hidden', 
                    background: 'rgba(0,0,0,0.2)',
                    boxShadow: '0 8px 24px rgba(0,0,0,0.2)',
                    border: '1px solid rgba(255,255,255,0.1)',
                    cursor: 'grab'
                  }}
                >
                  {isFailed ? (
                    <div style={{ 
                      width: '100%', 
                      height: '100%', 
                      display: 'flex', 
                      flexDirection: 'column', 
                      alignItems: 'center', 
                      justifyContent: 'center', 
                      color: 'rgba(255,255,255,0.5)', 
                      fontSize: '12px', 
                      padding: '16px', 
                      textAlign: 'center' 
                    }}>
                      <div style={{ fontSize: '24px', marginBottom: '8px', opacity: 0.5 }}>📷</div>
                      <div style={{ fontWeight: '600', marginBottom: '12px' }}>読み込めません</div>

                      <div style={{ display: 'flex', gap: '8px' }}>
                        <button 
                          onClick={() => handleReplaceImage(img, idx)}
                          style={{ border: 'none', background: 'rgba(255,255,255,0.15)', color: 'white', fontSize: '11px', padding: '6px 12px', borderRadius: '8px', fontWeight: 'bold' }}
                        >
                          置換
                        </button>
                        <button 
                          onClick={() => handleRemoveImage(img)}
                          style={{ border: 'none', background: 'rgba(255, 59, 48, 0.2)', color: '#FF3B30', fontSize: '11px', padding: '6px 12px', borderRadius: '8px', fontWeight: 'bold' }}
                        >
                          削除
                        </button>
                      </div>
                    </div>
                  ) : (
                    <>
                      <img 
                        src={img} 
                        referrerPolicy="no-referrer"
                        alt="" 
                        loading="lazy"
                        onError={() => handleImageError(img)} 
                        onClick={() => setFullscreenImage(img)}
                        style={{ width: '100%', height: '100%', objectFit: 'cover', cursor: 'pointer' }} 
                      />
                      <button 
                        onClick={(e) => {
                          e.stopPropagation();
                          handleRemoveImage(img);
                        }}
                        style={{
                          position: 'absolute',
                          top: '12px',
                          right: '12px',
                          width: '24px',
                          height: '24px',
                          borderRadius: '12px',
                          background: 'rgba(0,0,0,0.5)',
                          border: 'none',
                          color: 'white',
                          fontSize: '14px',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          cursor: 'pointer'
                        }}
                      >
                        ×
                      </button>
                    </>
                  )}
                </div>
              );
            })}
          </div>
        </section>
      </div>

      <IconButton 
        icon={<Icons.Plus />} 
        primary 
        size={64} 
        onClick={() => {
          setEditingImageUrl(null);
          setIsDialogOpen(true);
        }} 
        style={{ 
          position: 'fixed', 
          right: '32px', 
          bottom: '40px', 
          zIndex: 90
        }}
      />

      {fullscreenImage && (
        <div 
          onClick={() => setFullscreenImage(null)} 
          className="fade-in"
          style={{ 
            position: 'fixed', 
            inset: 0, 
            zIndex: 3000, 
            background: 'rgba(0,0,0,0.95)', 
            display: 'flex', 
            alignItems: 'center', 
            justifyContent: 'center',
            padding: '20px'
          }}
        >
          <img src={fullscreenImage} referrerPolicy="no-referrer" alt="" style={{ maxWidth: '100%', maxHeight: '100%', objectFit: 'contain', borderRadius: '8px' }} />
          <button 
            style={{ position: 'absolute', top: '24px', right: '24px', background: 'none', border: 'none', color: 'white', fontSize: '32px', cursor: 'pointer' }}
            onClick={() => setFullscreenImage(null)}
          >
            ×
          </button>
        </div>
      )}

      <ImageDialog 
        isOpen={isDialogOpen} 
        onClose={() => {
          setIsDialogOpen(false);
          setEditingImageUrl(null);
        }} 
        onAdd={handleAddImage}
        title={editingImageUrl ? "画像のURLを更新" : "思い出の写真を追加"}
      />
    </div>
  );
};

import React from 'react';
import { theme } from './theme';
import { Status } from '../domain/types';

const getStatusStyles = (label: string) => {
  switch (label as Status) {
    case '発売前': return theme.colors.badges.processing;
    case '検討中': return theme.colors.badges.considering;
    case '抽選中': return theme.colors.badges.lottery;
    case '参戦予定': return theme.colors.badges.confirmed;
    case '参戦済み': return theme.colors.badges.completed;
    case '見送': return theme.colors.badges.skipped;
    default: return theme.colors.badges.skipped;
  }
};

interface StatusBadgeProps {
  label: string;
  subLabel?: string | null;
  isMainStatus?: boolean;
}

export const StatusBadge: React.FC<StatusBadgeProps> = ({ label, subLabel, isMainStatus }) => {
  if (isMainStatus) {
    const mainColor = theme.colors.status[label as Status] || theme.colors.primary;
    return (
      <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
        <span style={{ 
          fontSize: '15px', 
          fontWeight: '800', 
          color: mainColor 
        }}>
          {label}
        </span>
        {subLabel && (
          <span style={{ fontSize: '13px', color: theme.colors.textSecondary }}>
            {subLabel}
          </span>
        )}
      </div>
    );
  }

  const styles = getStatusStyles(label);

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
      <div style={{ 
        display: 'inline-flex',
        alignItems: 'center',
        background: styles.bg,
        color: styles.text,
        padding: '4px 12px',
        borderRadius: theme.radius.badge,
        fontSize: '11px',
        fontWeight: '700',
        width: 'fit-content',
        border: `1px solid ${styles.border}`
      }}>
        {label}
      </div>
      {subLabel && (
        <span style={{ fontSize: '10px', color: theme.colors.textSecondary, marginLeft: '4px' }}>
          {subLabel}
        </span>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { PageShell } from '../ui/PageShell';
import { theme } from '../ui/theme';
import { PageId, Status, Artist, Concert } from '../domain/types';
import { CalendarMenu } from '../components/CalendarMenu';
import { 
  getBestStatusForDay, 
  sortPerformancesForDisplay, 
  getConcertNavigationTarget 
} from '../domain/logic';
import { Icons } from '../ui/IconButton';

interface Props {
  artists: Artist[];
  onOpenArtist: (artistId: string) => void;
  onOpenConcert: (artistId: string, tourId: string, concertId: string) => void;
  onRefreshAll: () => void;
}

// Unified Color Map using theme definitions
const colorMap: Record<Status, string> = {
  '参戦予定': theme.colors.status['参戦予定'],
  '抽選中': theme.colors.status['抽選中'],
  '検討中': theme.colors.status['検討中'],
  '発売前': theme.colors.status['発売前'],
  '参戦済み': theme.colors.status['参戦済み'],
  '見送': theme.colors.status['見送'],
};

interface ConcertWithMetadata extends Concert {
  artistName: string;
  artistId: string;
  tourName: string;
  tourId: string;
}

export const CalendarPage: React.FC<Props> = ({ artists, onOpenArtist, onOpenConcert, onRefreshAll }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<string | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [weekStart, setWeekStart] = useState<'sun' | 'mon'>('sun');

  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);

  useEffect(() => {
    setSelectedDate(null);
  }, [currentDate.getFullYear(), currentDate.getMonth()]);

  const allConcerts = useMemo(() => {
    const list: ConcertWithMetadata[] = [];
    artists.forEach(artist => {
      artist.tours.forEach(tour => {
        tour.concerts.forEach(concert => {
          list.push({
            ...concert,
            artistName: artist.name,
            artistId: artist.id,
            tourName: tour.name,
            tourId: tour.id
          });
        });
      });
    });
    return list;
  }, [artists]);

  const visibleConcerts = useMemo(() => {
    return allConcerts.filter(c => {
      if (c.date === 'TBD') return false;
      if (!showAttended && c.status === '参戦済み') return false;
      if (!showSkipped && c.status === '見送') return false;
      return true;
    });
  }, [allConcerts, showAttended, showSkipped]);

  const daysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
  const firstDayOfMonth = (year: number, month: number) => new Date(year, month, 1).getDay();

  const calendarDays = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const count = daysInMonth(year, month);
    let startDay = firstDayOfMonth(year, month);
    if (weekStart === 'mon') startDay = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < startDay; i++) days.push(null);
    for (let i = 1; i <= count; i++) days.push(i);
    return days;
  }, [currentDate, weekStart]);

  const getDayConcerts = (day: number) => {
    const dateStr = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    return visibleConcerts.filter(c => c.date === dateStr);
  };

  const handleDayClick = (day: number) => {
    const dateStr = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSelectedDate(dateStr === selectedDate ? null : dateStr);
  };

  const handleConcertClick = (concert: ConcertWithMetadata) => {
    if (concert.status === '参戦予定' || concert.status === '参戦済み') {
      onOpenConcert(concert.artistId, concert.tourId, concert.id);
    } else {
      onOpenArtist(concert.artistId);
    }
  };

  const dayConcerts = useMemo(() => {
    if (!selectedDate) return [];
    const filtered = visibleConcerts.filter(c => c.date === selectedDate);
    return sortPerformancesForDisplay(filtered as any) as ConcertWithMetadata[];
  }, [selectedDate, visibleConcerts]);

  return (
    <PageShell
      header={
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingBottom: '8px' }}>
          <h1 style={{ fontSize: '32px', fontWeight: '900', color: '#111827', margin: 0, letterSpacing: '-0.025em' }}>
            LiveTrack <span style={{ color: '#53BEE8' }}>JP</span>
          </h1>
          <button 
            onClick={onRefreshAll}
            style={{ padding: '12px', borderRadius: '9999px', background: 'white', border: '1px solid #F3F4F6', color: '#9CA3AF', cursor: 'pointer', outline: 'none' }}
          >
            <Icons.Refresh />
          </button>
        </div>
      }
    >
      <div style={{ paddingBottom: '120px' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
          <div style={{ fontSize: '24px', fontWeight: '900' }}>{currentDate.getFullYear()}年 {currentDate.getMonth() + 1}月</div>
          <div style={{ display: 'flex', gap: '8px' }}>
            <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1))} style={{ width: '40px', height: '40px', borderRadius: '50%', border: 'none', background: '#F3F4F6', cursor: 'pointer', fontWeight: 'bold' }}>◀</button>
            <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1))} style={{ width: '40px', height: '40px', borderRadius: '50%', border: 'none', background: '#F3F4F6', cursor: 'pointer', fontWeight: 'bold' }}>▶</button>
          </div>
        </div>

        <div style={{ background: 'white', borderRadius: '32px', padding: '24px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 12px rgba(0,0,0,0.03)' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '8px' }}>
            {(weekStart === 'sun' ? ['日', '月', '火', '水', '木', '金', '土'] : ['月', '火', '水', '木', '金', '土', '日']).map(l => (
              <div key={l} style={{ textAlign: 'center', fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary }}>{l}</div>
            ))}
            {calendarDays.map((day, idx) => {
              if (day === null) return <div key={idx} />;
              const concerts = getDayConcerts(day);
              const bestStatus = getBestStatusForDay(concerts as any);
              const isSelected = selectedDate === `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;

              return (
                <div 
                  key={day} 
                  onClick={() => handleDayClick(day)} 
                  style={{ 
                    aspectRatio: '1/1', 
                    display: 'flex', 
                    flexDirection: 'column', 
                    alignItems: 'center', 
                    justifyContent: 'center', 
                    borderRadius: '16px', 
                    background: isSelected ? 'rgba(83, 190, 232, 0.1)' : 'transparent', 
                    border: isSelected ? '2px solid #53BEE8' : 'none', 
                    cursor: 'pointer', 
                    position: 'relative',
                    transition: 'all 0.2s'
                  }}
                >
                  <span style={{ fontSize: '16px', fontWeight: '600' }}>{day}</span>
                  {bestStatus && (
                    <div style={{ 
                      position: 'absolute', 
                      bottom: '6px', 
                      width: '6px', 
                      height: '6px', 
                      borderRadius: '50%', 
                      background: colorMap[bestStatus] 
                    }} />
                  )}
                </div>
              );
            })}
          </div>
        </div>

        {selectedDate && dayConcerts.length > 0 && (
          <div style={{ marginTop: '32px' }} className="fade-in">
            <h3 style={{ fontSize: '14px', fontWeight: '700', color: theme.colors.textSecondary, marginBottom: '16px', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
              {selectedDate.replace(/-/g, '.')}
            </h3>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
              {dayConcerts.map((c) => (
                <div 
                  key={c.id} 
                  onClick={() => handleConcertClick(c)}
                  style={{ 
                    background: 'white', 
                    borderRadius: '24px', 
                    padding: '20px', 
                    border: '1px solid rgba(0,0,0,0.04)', 
                    boxShadow: '0 4px 12px rgba(0,0,0,0.03)', 
                    display: 'flex', 
                    justifyContent: 'space-between', 
                    alignItems: 'center',
                    cursor: 'pointer'
                  }}
                >
                  <div>
                    <div style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: '700' }}>{c.artistName}</div>
                    <div style={{ fontSize: '17px', fontWeight: '800' }}>{c.tourName}</div>
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: colorMap[c.status] }} />
                    <span style={{ fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary }}>{c.status}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      <div style={{ position: 'fixed', left: '32px', bottom: '100px', zIndex: 90 }}>
        <button 
          onClick={() => setIsMenuOpen(!isMenuOpen)} 
          style={{ 
            width: '64px', height: '64px', borderRadius: '9999px', display: 'flex', alignItems: 'center', justifyContent: 'center', 
            background: 'white', border: '1px solid #F3F4F6', color: '#9CA3AF', boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.1)', cursor: 'pointer', outline: 'none'
          }}
        >
          <Icons.Menu />
        </button>
      </div>
      <CalendarMenu 
        isOpen={isMenuOpen} 
        onClose={() => setIsMenuOpen(false)} 
        weekStart={weekStart} 
        setWeekStart={setWeekStart}
        showAttended={showAttended}
        setShowAttended={setShowAttended}
        showSkipped={showSkipped}
        setShowSkipped={setShowSkipped}
      />
    </PageShell>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { theme } from '../ui/theme';
import { GlassCard } from '../ui/GlassCard';
import { ConfirmDialog } from '../components/ConfirmDialog';
import { Artist, Tour, Concert, Status } from '../domain/types';
