const CustomDatePicker = ({ value, onChange, showTime = false }: { value: string; onChange: (val: string) => void; showTime?: boolean }) => {
  const [isOpen, setIsOpen] = useState(false);
  const initialDateStr = value === 'TBD' || !value ? '' : value.split(' ')[0];
  const initialTimeStr = (showTime && value && value.includes(' ')) ? value.split(' ')[1] : '10:00';
  const [viewDate, setViewDate] = useState(initialDateStr ? new Date(initialDateStr) : new Date());
  const [selectedTime, setSelectedTime] = useState(initialTimeStr);

  const daysInMonth = (y: number, m: number) => new Date(y, m + 1, 0).getDate();
  const firstDay = (y: number, m: number) => new Date(y, m, 1).getDay();

  const calendarDays = useMemo(() => {
    const y = viewDate.getFullYear();
    const m = viewDate.getMonth();
    const days = [];
    const first = firstDay(y, m);
    for (let i = 0; i < first; i++) days.push(null);
    for (let i = 1; i <= daysInMonth(y, m); i++) days.push(i);
    return days;
  }, [viewDate]);

  const handleSelectDay = (day: number) => {
    const y = viewDate.getFullYear();
    const m = String(viewDate.getMonth() + 1).padStart(2, '0');
    const d = String(day).padStart(2, '0');
    const datePart = `${y}-${m}-${d}`;
    if (showTime) {
      onChange(`${datePart} ${selectedTime}`);
    } else {
      onChange(datePart);
      setIsOpen(false);
    }
  };

  const handleTimeChange = (type: 'h' | 'm', val: string) => {
    const [h, m] = selectedTime.split(':');
    const newTime = type === 'h' ? `${val}:${m}` : `${h}:${val}`;
    setSelectedTime(newTime);
    if (initialDateStr) {
      onChange(`${initialDateStr} ${newTime}`);
    }
  };

  const hours = Array.from({ length: 24 }, (_, i) => String(i).padStart(2, '0'));
  const minutes = Array.from({ length: 12 }, (_, i) => String(i * 5).padStart(2, '0'));

  return (
    <div style={{ position: 'relative' }}>
      <div 
        onClick={() => setIsOpen(!isOpen)}
        style={{ ...inputStyle, cursor: 'pointer', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}
      >
        <span style={{ fontSize: '14px' }}>{value === 'TBD' || !value ? '未定 (TBD)' : value}</span>
        {showTime ? <Icons.Clock /> : <Icons.Calendar />}
      </div>
      {isOpen && (
        <>
          <div style={{ position: 'fixed', inset: 0, zIndex: 100 }} onClick={() => setIsOpen(false)} />
          <GlassCard padding="16px" style={{ position: 'absolute', top: '100%', left: 0, width: showTime ? '320px' : '280px', zIndex: 101, marginTop: '4px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px' }}>
              <button onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() - 1, 1))} style={navBtnStyle}>◀</button>
              <div style={{ fontWeight: 'bold', fontSize: '14px' }}>{viewDate.getFullYear()}年 {viewDate.getMonth() + 1}月</div>
              <button onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 1))} style={navBtnStyle}>▶</button>
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '4px', textAlign: 'center', marginBottom: showTime ? '16px' : '0' }}>
              {['日','月','火','水','木','金','土'].map(d => <div key={d} style={{ fontSize: '10px', color: theme.colors.textWeak }}>{d}</div>)}
              {calendarDays.map((day, i) => {
                const isSelected = day && initialDateStr === `${viewDate.getFullYear()}-${String(viewDate.getMonth()+1).padStart(2,'0')}-${String(day).padStart(2,'0')}`;
                return (
                  <div key={i} onClick={() => day && handleSelectDay(day)} style={{ padding: '8px 0', fontSize: '13px', borderRadius: '8px', cursor: day ? 'pointer' : 'default', background: isSelected ? theme.colors.primary : 'transparent', color: isSelected ? 'white' : theme.colors.textMain, opacity: day ? 1 : 0 }}>{day}</div>
                );
              })}
            </div>
            {showTime && (
              <div style={{ borderTop: '0.5px solid rgba(0,0,0,0.05)', paddingTop: '16px' }}>
                <div style={{ fontSize: '11px', color: theme.colors.textSecondary, marginBottom: '8px', fontWeight: 'bold' }}>時間設定</div>
                <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                  <select value={selectedTime.split(':')[0]} onChange={e => handleTimeChange('h', e.target.value)} style={selectTimeStyle}>{hours.map(h => <option key={h} value={h}>{h}時</option>)}</select>
                  <span style={{ fontWeight: 'bold' }}>:</span>
                  <select value={selectedTime.split(':')[1]} onChange={e => handleTimeChange('m', e.target.value)} style={selectTimeStyle}>{minutes.map(m => <option key={m} value={m}>{m}分</option>)}</select>
                </div>
              </div>
            )}
            <div style={{ display: 'flex', gap: '8px', marginTop: '16px' }}>
              <button onClick={() => { onChange('TBD'); setIsOpen(false); }} style={{ flex: 1, padding: '10px', border: 'none', background: 'rgba(0,0,0,0.05)', borderRadius: '10px', fontSize: '12px', fontWeight: 'bold', cursor: 'pointer' }}>未定</button>
              <button onClick={() => setIsOpen(false)} style={{ flex: 1, padding: '10px', border: 'none', background: theme.colors.primary, color: 'white', borderRadius: '10px', fontSize: '12px', fontWeight: 'bold', cursor: 'pointer' }}>確定</button>
            </div>
          </GlassCard>
        </>
      )}
    </div>
  );
};

const navBtnStyle = { border: 'none', background: 'none', padding: '4px 8px', cursor: 'pointer', fontSize: '12px' };
const selectTimeStyle = { flex: 1, padding: '10px', borderRadius: '10px', border: '1px solid rgba(0,0,0,0.08)', fontSize: '13px', background: 'rgba(255,255,255,0.7)', outline: 'none', cursor: 'pointer', appearance: 'none', WebkitAppearance: 'none', textAlign: 'center' } as React.CSSProperties;

export const ConcertEditorPage: React.FC<Props> = ({ artistId, tourId, tour, allArtists, onSave, onCancel, onDeleteTour }) => {
  const getInitialData = (): Tour => {
    if (tourId && tour) return { ...tour };
    return { id: generateId(), name: '', imageUrl: '', memo: '', concerts: [] };
  };
  const [formData, setFormData] = useState<Tour>(getInitialData());
  const initialSnapshotRef = useRef<string>(JSON.stringify(getInitialData()));
  const [imageUrlDraft, setImageUrlDraft] = useState(formData.imageUrl);
  const [hasChanges, setHasChanges] = useState(false);
  const [expandedConcertId, setExpandedConcertId] = useState<string | null>(null);
  const [isDeleteTourModalOpen, setIsDeleteTourModalOpen] = useState(false);
  const [isDeleteConcertModalOpen, setIsDeleteConcertModalOpen] = useState<string | null>(null);
  const [isConflictDialogOpen, setIsConflictDialogOpen] = useState(false);

  useEffect(() => {
    if (tour) {
      setFormData({ ...tour });
      setImageUrlDraft(tour.imageUrl);
      initialSnapshotRef.current = JSON.stringify(tour);
    }
  }, [tourId]);

  useEffect(() => {
    setHasChanges(JSON.stringify(formData) !== initialSnapshotRef.current);
  }, [formData]);

  const sortedConcerts = useMemo(() => sortPerformancesForDisplay(formData.concerts), [formData.concerts]);

  const handleSave = () => {
    const conflicts = checkGlobalDateConflicts(allArtists, formData.id, formData.concerts);
    if (conflicts.length > 0) {
      setIsConflictDialogOpen(true);
      return;
    }
    onSave(formData);
  };

  const handleUpdateTourField = (field: keyof Tour, value: any) => setFormData(prev => ({ ...prev, [field]: value }));
  const handleLoadImage = () => imageUrlDraft.trim() && handleUpdateTourField('imageUrl', imageUrlDraft.trim());
  const handleAddConcert = () => {
    const newConcert: Concert = { id: generateId(), date: 'TBD', venue: '', price: 0, saleLink: '', status: '発売前', isParticipated: false, images: [] };
    setFormData(prev => ({ ...prev, concerts: [...prev.concerts, newConcert] }));
    setExpandedConcertId(newConcert.id);
  };
  const handleUpdateConcert = (id: string, updates: Partial<Concert>) => setFormData(prev => ({ ...prev, concerts: prev.concerts.map(c => c.id === id ? { ...c, ...updates } : c) }));
  const handleDeleteConcert = (id: string) => { setFormData(prev => ({ ...prev, concerts: prev.concerts.filter(c => c.id !== id) })); setIsDeleteConcertModalOpen(null); };

  return (
    <PageShell
      header={
        <header style={headerStyle}>
          <IconButton icon={<Icons.X />} onClick={onCancel} size={40} style={{ color: theme.colors.textSecondary, borderColor: 'transparent', background: 'transparent', boxShadow: 'none' }} />
          <h2 style={{ fontSize: '17px', margin: 0, fontWeight: 'bold' }}>ツアー・公演編集</h2>
          {tourId ? <IconButton icon={<Icons.Trash />} onClick={() => setIsDeleteTourModalOpen(true)} size={40} style={{ color: theme.colors.error, borderColor: 'transparent', background: 'transparent', boxShadow: 'none' }} /> : <div style={{ width: 40 }} />}
        </header>
      }
    >
      <div style={{ paddingBottom: '160px' }}>
        <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '24px' }}>
          <div style={{ width: '120px', height: '160px', borderRadius: '16px', background: '#F3F4F6', border: '4px solid white', boxShadow: '0 4px 12px rgba(0,0,0,0.1)', overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            {formData.imageUrl ? <img src={formData.imageUrl} style={{ width: '100%', height: '100%', objectFit: 'cover' }} onError={(e) => { (e.target as HTMLImageElement).src = 'https://via.placeholder.com/150?text=Error'; }} /> : <span style={{ fontSize: '32px', opacity: 0.2 }}>🎸</span>}
          </div>
        </div>
        <section style={{ marginBottom: theme.spacing.xl }}>
          <h3 style={sectionTitleStyle}>ツアー情報 (共通)</h3>
          <GlassCard padding={theme.spacing.md}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.md }}>
              <Field label="ツアー名 (必須)"><input type="text" value={formData.name} onChange={e => handleUpdateTourField('name', e.target.value)} placeholder="名称を入力" style={inputStyle} /></Field>
              <Field label="ツアー画像URL"><div style={{ display: 'flex', gap: '8px' }}><input type="url" value={imageUrlDraft} onChange={e => setImageUrlDraft(e.target.value)} placeholder="https://..." style={inputStyle} /><button onClick={handleLoadImage} style={loadButtonStyle}>読み込み</button></div></Field>
              <Field label="メモ"><textarea value={formData.memo} onChange={e => handleUpdateTourField('memo', e.target.value)} placeholder="ツアーに関する全体メモ" style={{ ...inputStyle, minHeight: '80px', resize: 'none' }} /></Field>
            </div>
          </GlassCard>
        </section>
        <section style={{ marginBottom: theme.spacing.xl }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: theme.spacing.sm }}><h3 style={{ ...sectionTitleStyle, marginBottom: 0 }}>公演一覧 (場次)</h3><button onClick={handleAddConcert} style={actionButtonStyle}>＋ 公演を追加</button></div>
          {sortedConcerts.length === 0 ? <GlassCard padding={theme.spacing.lg} style={{ textAlign: 'center', color: theme.colors.textWeak }}>まだ公演が登録されていません</GlassCard> : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.sm }}>
              {sortedConcerts.map(concert => {
                const isExpanded = expandedConcertId === concert.id;
                const showLotteryInfo = ['抽選中', '参戦予定', '見送'].includes(concert.status);
                const statusColor = theme.colors.status[concert.status as Status] || theme.colors.primary;
                return (
                  <GlassCard key={concert.id} padding="0">
                    <div onClick={() => setExpandedConcertId(isExpanded ? null : concert.id)} style={{ padding: theme.spacing.md, cursor: 'pointer', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <div style={{ flex: 1 }}><div style={{ fontWeight: '700', fontSize: '15px' }}>{concert.date === 'TBD' ? '日付未定' : concert.date}</div><div style={{ fontSize: '12px', color: theme.colors.textSecondary }}>{concert.venue || '会場未入力'}</div></div>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}><span style={{ fontSize: '13px', fontWeight: '800', color: statusColor }}>{concert.status}</span><IconButton icon={<Icons.X />} onClick={(e) => { e.stopPropagation(); setIsDeleteConcertModalOpen(concert.id); }} size={28} style={{ background: 'rgba(190, 18, 60, 0.05)', color: theme.colors.error, border: 'none', boxShadow: 'none' }} /><span style={{ transform: isExpanded ? 'rotate(180deg)' : 'none', transition: 'transform 0.2s', fontSize: '10px' }}>▼</span></div>
                    </div>
                    {isExpanded && (
                      <div style={{ padding: `0 ${theme.spacing.md} ${theme.spacing.md} ${theme.spacing.md}`, display: 'flex', flexDirection: 'column', gap: theme.spacing.md, borderTop: '0.5px solid rgba(0,0,0,0.05)', paddingTop: theme.spacing.md }}>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}><Field label="日付"><CustomDatePicker value={concert.date} onChange={(val) => handleUpdateConcert(concert.id, { date: val })} /></Field><Field label="会場"><input type="text" value={concert.venue} onChange={e => handleUpdateConcert(concert.id, { venue: e.target.value })} placeholder="会場名" style={inputStyle} /></Field></div>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}><Field label="状態"><StatusPicker value={concert.status} onChange={(val) => handleUpdateConcert(concert.id, { status: val })} /></Field><Field label="チケット価格"><input type="text" value={concert.price || ''} onChange={e => handleUpdateConcert(concert.id, { price: Number(e.target.value.replace(/[^0-9]/g, '')) })} placeholder="金额を入力" style={inputStyle} /></Field></div>
                        {showLotteryInfo && (<div style={{ display: 'flex', flexDirection: 'column', gap: '12px', padding: '16px', background: 'rgba(0,0,0,0.02)', borderRadius: '16px' }}><Field label="抽選名"><input type="text" value={concert.lotteryName || ''} onChange={e => handleUpdateConcert(concert.id, { lotteryName: e.target.value })} placeholder="FC先行、一般など" style={inputStyle} /></Field><Field label="抽選結果日時"><CustomDatePicker showTime value={concert.lotteryResultDate || ''} onChange={(val) => handleUpdateConcert(concert.id, { lotteryResultDate: val })} /></Field></div>)}
                        <Field label="販売ページURL"><input type="url" value={concert.saleLink} onChange={e => handleUpdateConcert(concert.id, { saleLink: e.target.value })} placeholder="https://..." style={inputStyle} /></Field>
                      </div>
                    )}
                  </GlassCard>
                );
              })}
            </div>
          )}
        </section>
        <section style={{ marginTop: '40px', padding: '0 4px' }}><button disabled={!hasChanges || !formData.name} onClick={handleSave} style={{ width: '100%', padding: '16px', borderRadius: theme.radius.button, background: (!hasChanges || !formData.name) ? 'rgba(0,0,0,0.05)' : theme.colors.primary, color: (!hasChanges || !formData.name) ? theme.colors.textWeak : 'white', border: 'none', fontWeight: 'bold', fontSize: '16px', cursor: (!hasChanges || !formData.name) ? 'default' : 'pointer', transition: 'all 0.2s' }}>ツアー情報を保存</button></section>
        <ConfirmDialog isOpen={isConflictDialogOpen} title="日付の重複" message="参戦予定または参戦済みの公演が他アーティストも含め同日に存在します。日付を変更してください。" confirmLabel="確認" onClose={() => setIsConflictDialogOpen(false)} onConfirm={() => setIsConflictDialogOpen(false)} />
        <ConfirmDialog isOpen={isDeleteTourModalOpen} title="ツアーを完全に削除しますか？" message="このツアー、配下の全公演、およびアルバム画像がすべて削除されます。この操作は取り消せません。" confirmLabel="ツアーを削除" isDestructive onClose={() => setIsDeleteTourModalOpen(false)} onConfirm={() => onDeleteTour(artistId, formData.id)} />
        <ConfirmDialog isOpen={!!isDeleteConcertModalOpen} title="公演を削除しますか？" message="この公演に関連する抽選情報やアルバム画像もすべて破棄されます。" confirmLabel="公演を削除" isDestructive onClose={() => setIsDeleteConcertModalOpen(null)} onConfirm={() => isDeleteConcertModalOpen && handleDeleteConcert(isDeleteConcertModalOpen)} />
      </div>
    </PageShell>
  );
};

const headerStyle: React.CSSProperties = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', position: 'sticky', top: 0, zIndex: 100, background: theme.colors.background, padding: `${theme.spacing.sm} 0`, borderBottom: '1px solid rgba(0,0,0,0.05)' };
const sectionTitleStyle: React.CSSProperties = { fontSize: '13px', color: theme.colors.textSecondary, fontWeight: 'bold', marginBottom: theme.spacing.sm, paddingLeft: '4px', textTransform: 'uppercase', letterSpacing: '0.05em' };
const actionButtonStyle: React.CSSProperties = { border: 'none', background: 'none', color: theme.colors.primary, fontSize: '14px', fontWeight: '600', cursor: 'pointer' };
const loadButtonStyle: React.CSSProperties = { padding: '0 16px', borderRadius: '12px', border: '1px solid rgba(0,0,0,0.08)', background: 'white', color: theme.colors.textSecondary, fontSize: '13px', fontWeight: 'bold', cursor: 'pointer', whiteSpace: 'nowrap', transition: 'all 0.2s' };
const inputStyle: React.CSSProperties = { width: '100%', padding: '12px', borderRadius: '12px', border: '1px solid rgba(0,0,0,0.08)', background: 'rgba(255,255,255,0.6)', fontSize: '15px', outline: 'none', fontFamily: 'inherit', minHeight: '44px' };

import React, { useState, useMemo } from 'react';
import { PageShell } from '../ui/PageShell';
import { IconButton, Icons } from '../ui/IconButton';
import { theme } from '../ui/theme';
import { PageId, Concert, Status, Artist } from '../domain/types';
import { ConcertMenu } from '../components/ConcertMenu';
import { sortPerformancesForDisplay, sortPerformancesByLotteryDate } from '../domain/logic';

interface Props {
  artists: Artist[];
  onOpenArtist: (artistId: string) => void;
  onOpenConcert: (artistId: string, tourId: string, concertId: string) => void;
  onCreateConcert: () => void;
  onRefreshAll: () => void;
}

interface ConcertWithMetadata extends Concert {
  artistName: string;
  artistId: string;
  artistImageUrl: string;
  tourName: string;
  tourId: string;
  tourImageUrl: string;
}

const ConcertRowCard = ({ concert, onClick }: { concert: ConcertWithMetadata; onClick: () => void }) => {
  const [isHovered, setIsHovered] = useState(false);
  const [imgError, setImgError] = useState(false);

  const statusColor = theme.colors.status[concert.status as Status] || theme.colors.primary;

  const displayImage = concert.tourImageUrl || (concert.images && concert.images.length > 0 ? concert.images[0] : null) || concert.artistImageUrl;

  return (
    <div
      onClick={onClick}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      style={{
        background: 'white',
        borderRadius: theme.radius.card,
        border: '1px solid rgba(0, 0, 0, 0.04)',
        padding: '20px 24px',
        display: 'flex',
        alignItems: 'center',
        gap: '20px',
        cursor: 'pointer',
        boxShadow: isHovered 
          ? '0 10px 20px -5px rgba(0, 0, 0, 0.06)' 
          : '0 4px 12px -2px rgba(0, 0, 0, 0.03)',
        transform: isHovered ? 'scale(1.015)' : 'scale(1)',
        transition: 'all 0.3s cubic-bezier(0.16, 1, 0.3, 1)',
      }}
    >
      <div style={{
        width: '68px',
        height: '68px',
        borderRadius: '50%',
        background: '#F3F4F6',
        flexShrink: 0,
        border: '3px solid white',
        boxShadow: '0 2px 8px rgba(0,0,0,0.08)',
        overflow: 'hidden',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center'
      }}>
        {displayImage && !imgError ? (
          <img 
            src={displayImage} 
            referrerPolicy="no-referrer"
            alt={concert.tourName}
            style={{ width: '100%', height: '100%', objectFit: 'cover' }} 
            onError={() => setImgError(true)}
          />
        ) : (
          <span style={{ fontSize: '24px', opacity: 0.2 }}>🎟️</span>
        )}
      </div>

      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{ 
          fontSize: '12px', 
          color: theme.colors.textSecondary, 
          fontWeight: '700', 
          letterSpacing: '0.05em', 
          marginBottom: '2px',
          whiteSpace: 'nowrap',
          overflow: 'hidden',
          textOverflow: 'ellipsis'
        }}>
          {concert.artistName}
        </div>
        <div style={{ 
          fontWeight: '800', 
          fontSize: '18px', 
          color: isHovered ? theme.colors.primary : theme.colors.text,
          transition: 'color 0.2s',
          whiteSpace: 'nowrap',
          overflow: 'hidden',
          textOverflow: 'ellipsis',
          marginBottom: '4px'
        }}>
          {concert.tourName}
        </div>

        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div style={{ fontSize: '13px', color: theme.colors.textSecondary }}>
            {concert.date}
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <div style={{
              width: '8px',
              height: '8px',
              borderRadius: '50%',
              background: statusColor,
            }} />
            <div style={{
              fontSize: '11px',
              fontWeight: '800',
              color: statusColor,
              letterSpacing: '0.05em',
              textTransform: 'uppercase'
            }}>
              {concert.status}
            </div>
          </div>
        </div>
      </div>

      <div style={{ color: theme.colors.textLabel, flexShrink: 0 }}>
        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <polyline points="9 18 15 12 9 6"></polyline>
        </svg>
      </div>
    </div>
  );
};

export const ConcertListPage: React.FC<Props> = ({ artists, onOpenArtist, onOpenConcert, onCreateConcert, onRefreshAll }) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);
  const [sortMode, setSortMode] = useState<'status' | 'lottery'>('status');

  const allConcerts = useMemo(() => {
    const list: ConcertWithMetadata[] = [];
    artists.forEach(artist => {
      artist.tours.forEach(tour => {
        tour.concerts.forEach(concert => {
          list.push({
            ...concert,
            artistName: artist.name,
            artistId: artist.id,
            artistImageUrl: artist.imageUrl || '',
            tourName: tour.name,
            tourId: tour.id,
            tourImageUrl: tour.imageUrl || ''
          });
        });
      });
    });
    return list;
  }, [artists]);

  const processedConcerts = useMemo(() => {
    let list = allConcerts.filter(c => {
      if (!showAttended && c.status === '参戦済み') return false;
      if (!showSkipped && c.status === '見送') return false;
      return true;
    });

    if (sortMode === 'lottery') {
      return sortPerformancesByLotteryDate(list as any) as ConcertWithMetadata[];
    }
    return sortPerformancesForDisplay(list as any) as ConcertWithMetadata[];
  }, [allConcerts, showAttended, showSkipped, sortMode]);

  const handleCardClick = (concert: ConcertWithMetadata) => {
    if (concert.status === '参戦予定' || concert.status === '参戦済み') {
      onOpenConcert(concert.artistId, concert.tourId, concert.id);
    } else {
      onOpenArtist(concert.artistId);
    }
  };

  return (
    <PageShell
      header={
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingBottom: '8px' }}>
          <h1 style={{ fontSize: '32px', fontWeight: '900', color: '#111827', margin: 0, letterSpacing: '-0.025em' }}>
            LiveTrack <span style={{ color: '#53BEE8' }}>JP</span>
          </h1>
          <button 
            onClick={onRefreshAll}
            style={{
              padding: '12px',
              borderRadius: '9999px',
              background: 'white',
              border: '1px solid #F3F4F6',
              color: '#9CA3AF',
              boxShadow: '0 1px 2px 0 rgba(0, 0, 0, 0.05)',
              cursor: 'pointer',
              outline: 'none',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center'
            }}
          >
            <Icons.Refresh />
          </button>
        </div>
      }
    >
      <div style={{ display: 'flex', flexDirection: 'column', gap: '16px', paddingBottom: '120px' }}>
        {processedConcerts.length === 0 ? (
          <div style={{ 
            padding: '80px 20px', 
            textAlign: 'center', 
            color: theme.colors.textWeak,
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            gap: '24px'
          }}>
            <div style={{ fontSize: '48px', opacity: 0.5 }}>🎟️</div>
            <div style={{ fontSize: '15px', fontWeight: '600' }}>表示可能な公演がありません</div>
            <button 
              onClick={onCreateConcert}
              style={{
                padding: '12px 24px',
                borderRadius: '12px',
                background: theme.colors.primary,
                color: 'white',
                border: 'none',
                fontWeight: 'bold',
                cursor: 'pointer'
              }}
            >
              ＋ 公演を追加
            </button>
          </div>
        ) : (
          processedConcerts.map((concert) => (
            <ConcertRowCard 
              key={concert.id} 
              concert={concert} 
              onClick={() => handleCardClick(concert)} 
            />
          ))
        )}
      </div>

      <IconButton 
        icon={<Icons.Plus />} 
        primary 
        size={64}
        onClick={onCreateConcert}
        style={{ position: 'fixed', right: '32px', bottom: '100px', zIndex: 90, boxShadow: '0 12px 24px -6px rgba(83, 190, 232, 0.5)' }}
      />

      <div style={{ position: 'fixed', left: '32px', bottom: '100px', zIndex: 90 }}>
        <button 
          onClick={() => setIsMenuOpen(!isMenuOpen)}
          style={{ 
            width: '64px', height: '64px', borderRadius: '9999px', display: 'flex', alignItems: 'center', justifyContent: 'center', 
            background: 'white', border: '1px solid #F3F4F6', color: '#9CA3AF', boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.1)', cursor: 'pointer', outline: 'none'
          }}
        >
          <Icons.Menu />
        </button>
      </div>

      <ConcertMenu 
        isOpen={isMenuOpen} 
        onClose={() => setIsMenuOpen(false)} 
        showAttended={showAttended}
        onToggleAttended={() => setShowAttended(!showAttended)}
        showSkipped={showSkipped}
        onToggleSkipped={() => setShowSkipped(!showSkipped)}
        sortMode={sortMode}
        onSetSort={setSortMode}
      />
    </PageShell>
  );
};

payload.text:
【公演ページ背景が出ない原因＆修正指示】

原因（主に2つ）：
1) 背景URLの優先順位が不適切
- 現在：backgroundUrl = (images[0]) → tour.imageUrl → artist.imageUrl
- アルバム先頭(images[0])が未設定/無効/403/直リンクでない場合、背景が常に失敗し、tour.imageUrlへフォールバックしない

2) CSS background-image は referrerPolicy を指定できない
- 画像ホストがホットリンク制限（Referer必須/拒否）していると、<img referrerPolicy="no-referrer"> は表示できても、
  CSS background-image は失敗することがある
- その場合「サムネは出るのに背景だけ出ない」現象が起きる

---

修正指示（確定）：

A) 背景はアルバム(images)を使わない（ツアー画像を最優先）
- 背景URLは以下に固定：
  1) tour.imageUrl
  2) artist.imageUrl
  3) なし

例：
const preferredBg = tour.imageUrl || artist.imageUrl || '';

B) 背景は CSS background-image ではなく「背面に <img> を敷く」方式に変更（重要）
- referrerPolicy="no-referrer" を効かせるため
- ぼかしは <img> に filter を適用する

実装例（置き換え）：

// state
const [bgUrl, setBgUrl] = useState<string>('');

// 有効URLだけ採用（プリロードで失敗したらフォールバック）
useEffect(() => {
  const candidates = [tour.imageUrl, artist.imageUrl].filter(Boolean) as string[];
  let canceled = false;

  const tryLoad = (i: number) => {
    if (i >= candidates.length) {
      if (!canceled) setBgUrl('');
      return;
    }
    const url = candidates[i];
    const img = new Image();
    img.onload = () => { if (!canceled) setBgUrl(url); };
    img.onerror = () => tryLoad(i + 1);
    img.src = url;
  };

  tryLoad(0);
  return () => { canceled = true; };
}, [tour.imageUrl, artist.imageUrl]);

// JSX（background div を消して、これを最背面に入れる）
<div style={{ position:'fixed', inset:0, zIndex:-1, overflow:'hidden', background:'#111' }}>
  {bgUrl ? (
    <img
      src={bgUrl}
      referrerPolicy="no-referrer"
      alt=""
      style={{
        width:'100%',
        height:'100%',
        objectFit:'cover',
        filter:'blur(40px) brightness(0.6)',
        transform:'scale(1.2)'
      }}
    />
  ) : null}
</div>

C) encodeURI は不要（<img> なら基本OK）。必要なら encodeURI(bgUrl) を src に適用しても良い

D) 画像URLが「直リンク画像」ではない場合は表示できない
- その場合は占位表示にし、ツアー編集の「読み込み」ボタンでプレビュー確認できるようにする

---


最終ルール：
- 公演ページ背景＝ tour.imageUrl（失敗したら artist.imageUrl にフォールバック）
- アルバム(images)は背景に使わない
- CSS background-image は使わず、背面 <img> + blur で実装する

