            <polyline points="9 18 15 12 9 6"></polyline>
          </svg>
        </div>
      </div>
    </div>
  );
};

export const ConcertListPage: React.FC<Props> = ({ artists, onOpenArtist, onOpenConcert, onCreateConcert, onRefreshAll }) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);
  const [sortMode, setSortMode] = useState<'status' | 'lottery'>('status');

  const allConcerts = useMemo(() => {
    const list: ConcertWithMetadata[] = [];
    artists.forEach(artist => {
      artist.tours.forEach(tour => {
        tour.concerts.forEach(concert => {
          list.push({
            ...concert,
            artistName: artist.name,
            artistId: artist.id,
            artistImageUrl: artist.imageUrl || '',
            tourName: tour.name,
            tourId: tour.id,
            tourImageUrl: tour.imageUrl || '',
            tourOfficialUrl: tour.officialUrl
          });
        });
      });
    });
    return list;
  }, [artists]);

  const processedConcerts = useMemo(() => {
    let list = allConcerts.filter(c => {
      if (!showAttended && c.status === '参戦済み') return false;
      if (!showSkipped && c.status === '見送') return false;
      return true;
    });

    if (sortMode === 'lottery') {
      return sortPerformancesByLotteryDate(list as any) as ConcertWithMetadata[];
    }
    return sortPerformancesForDisplay(list as any) as ConcertWithMetadata[];
  }, [allConcerts, showAttended, showSkipped, sortMode]);

  const handleCardClick = (concert: ConcertWithMetadata) => {
    if (concert.status === '参戦予定' || concert.status === '参戦済み') {
      onOpenConcert(concert.artistId, concert.tourId, concert.id);
    } else {
      onOpenArtist(concert.artistId);
    }
  };

  return (
    <PageShell
      header={
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingBottom: '8px' }}>
          <h1 style={{ fontSize: '32px', fontWeight: '900', color: '#111827', margin: 0, letterSpacing: '-0.025em' }}>
            LiveTrack <span style={{ color: '#53BEE8' }}>JP</span>
          </h1>
          <button 
            onClick={onRefreshAll}
            style={{
              padding: '12px',
              borderRadius: '9999px',
              background: 'white',
              border: '1px solid #F3F4F6',
              color: '#9CA3AF',
              boxShadow: '0 1px 2px 0 rgba(0, 0, 0, 0.05)',
              cursor: 'pointer',
              outline: 'none',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center'
            }}
          >
            <Icons.Refresh />
          </button>
        </div>
      }
    >
      <div style={{ display: 'flex', flexDirection: 'column', gap: '16px', paddingBottom: '120px' }}>
        {processedConcerts.length === 0 ? (
          <div style={{ 
            padding: '80px 20px', 
            textAlign: 'center', 
            color: theme.colors.textWeak,
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            gap: '24px'
          }}>
            <div style={{ fontSize: '48px', opacity: 0.5 }}>🎟️</div>
            <div style={{ fontSize: '15px', fontWeight: '600' }}>表示可能な公演がありません</div>
            <button 
              onClick={onCreateConcert}
              style={{
                padding: '12px 24px',
                borderRadius: '12px',
                background: theme.colors.primary,
                color: 'white',
                border: 'none',
                fontWeight: 'bold',
                cursor: 'pointer'
              }}
            >
              ＋ 公演を追加
            </button>
          </div>
        ) : (
          processedConcerts.map((concert) => (
            <ConcertRowCard 
              key={concert.id} 
              concert={concert} 
              onClick={() => handleCardClick(concert)} 
            />
          ))
        )}
      </div>

      <IconButton 
        icon={isMenuOpen ? <Icons.X /> : <Icons.Plus />} 
        primary 
        size={64}
        onClick={() => setIsMenuOpen(!isMenuOpen)}
        style={{ 
          position: 'fixed', 
          right: '16px', 
          bottom: 'calc(16px + env(safe-area-inset-bottom))', 
          zIndex: 110, 
          boxShadow: '0 8px 24px -6px rgba(83, 190, 232, 0.5)' 
        }}
      />

      <ConcertMenu 
        isOpen={isMenuOpen} 
        onClose={() => setIsMenuOpen(false)} 
        onAddConcert={onCreateConcert}
        showAttended={showAttended}
        onToggleAttended={() => setShowAttended(!showAttended)}
        showSkipped={showSkipped}
        onToggleSkipped={() => setShowSkipped(!showSkipped)}
        sortMode={sortMode}
        onSetSort={setSortMode}
      />
    </PageShell>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { PageShell } from '../ui/PageShell';
import { theme } from '../ui/theme';
import { PageId, Status, Artist, Concert } from '../domain/types';
import { CalendarMenu } from '../components/CalendarMenu';
import { 
  getBestStatusForDay, 
  sortPerformancesForDisplay, 
} from '../domain/logic';
import { Icons, IconButton } from '../ui/IconButton';

interface Props {
  artists: Artist[];
  onOpenArtist: (artistId: string) => void;
  onOpenConcert: (artistId: string, tourId: string, concertId: string) => void;
  onRefreshAll: () => void;
}

const colorMap: Record<Status, string> = {
  '参戦予定': theme.colors.status['参戦予定'],
  '抽選中': theme.colors.status['抽選中'],
  '検討中': theme.colors.status['検討中'],
  '発売前': theme.colors.status['発売前'],
  '参戦済み': theme.colors.status['参戦済み'],
  '見送': theme.colors.status['見送'],
};

interface ConcertWithMetadata extends Concert {
  artistName: string;
  artistId: string;
  tourName: string;
  tourId: string;
}

export const CalendarPage: React.FC<Props> = ({ artists, onOpenArtist, onOpenConcert, onRefreshAll }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<string | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [weekStart, setWeekStart] = useState<'sun' | 'mon'>('sun');

  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);

  useEffect(() => {
    setSelectedDate(null);
  }, [currentDate.getFullYear(), currentDate.getMonth()]);

  const allConcerts = useMemo(() => {
    const list: ConcertWithMetadata[] = [];
    artists.forEach(artist => {
      artist.tours.forEach(tour => {
        tour.concerts.forEach(concert => {
          list.push({
            ...concert,
            artistName: artist.name,
            artistId: artist.id,
            tourName: tour.name,
            tourId: tour.id
          });
        });
      });
    });
    return list;
  }, [artists]);

  const visibleConcerts = useMemo(() => {
    return allConcerts.filter(c => {
      if (c.date === 'TBD') return false;
      if (!showAttended && c.status === '参戦済み') return false;
      if (!showSkipped && c.status === '見送') return false;
      return true;
    });
  }, [allConcerts, showAttended, showSkipped]);

  const daysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
  const firstDayOfMonth = (year: number, month: number) => new Date(year, month, 1).getDay();

  const calendarDays = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const count = daysInMonth(year, month);
    let startDay = firstDayOfMonth(year, month);
    if (weekStart === 'mon') startDay = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < startDay; i++) days.push(null);
    for (let i = 1; i <= count; i++) days.push(i);
    return days;
  }, [currentDate, weekStart]);

  const getDayConcerts = (day: number) => {
    const dateStr = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    return visibleConcerts.filter(c => c.date === dateStr);
  };

  const handleDayClick = (day: number) => {
    const dateStr = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSelectedDate(dateStr === selectedDate ? null : dateStr);
  };

  const handleConcertClick = (concert: ConcertWithMetadata) => {
    if (concert.status === '参戦予定' || concert.status === '参戦済み') {
      onOpenConcert(concert.artistId, concert.tourId, concert.id);
    } else {
      onOpenArtist(concert.artistId);
    }
  };

  const dayConcerts = useMemo(() => {
    if (!selectedDate) return [];
    const filtered = visibleConcerts.filter(c => c.date === selectedDate);
    return sortPerformancesForDisplay(filtered as any) as ConcertWithMetadata[];
  }, [selectedDate, visibleConcerts]);

  return (
    <PageShell
      header={
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingBottom: '8px' }}>
          <h1 style={{ fontSize: '32px', fontWeight: '900', color: '#111827', margin: 0, letterSpacing: '-0.025em' }}>
            LiveTrack <span style={{ color: '#53BEE8' }}>JP</span>
          </h1>
          <button 
            onClick={onRefreshAll}
            style={{ padding: '12px', borderRadius: '9999px', background: 'white', border: '1px solid #F3F4F6', color: '#9CA3AF', cursor: 'pointer', outline: 'none' }}
          >
            <Icons.Refresh />
          </button>
        </div>
      }
    >
      <div style={{ paddingBottom: '120px' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
          <div style={{ fontSize: '24px', fontWeight: '900' }}>{currentDate.getFullYear()}年 {currentDate.getMonth() + 1}月</div>
          <div style={{ display: 'flex', gap: '8px' }}>
            <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1))} style={{ width: '40px', height: '40px', borderRadius: '50%', border: 'none', background: '#F3F4F6', cursor: 'pointer', fontWeight: 'bold' }}>◀</button>
            <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1))} style={{ width: '40px', height: '40px', borderRadius: '50%', border: 'none', background: '#F3F4F6', cursor: 'pointer', fontWeight: 'bold' }}>▶</button>
          </div>
        </div>

        <div style={{ background: 'white', borderRadius: '32px', padding: '24px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 12px rgba(0,0,0,0.03)' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '8px' }}>
            {(weekStart === 'sun' ? ['日', '月', '火', '水', '木', '金', '土'] : ['月', '火', '水', '木', '金', '土', '日']).map(l => (
              <div key={l} style={{ textAlign: 'center', fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary }}>{l}</div>
            ))}
            {calendarDays.map((day, idx) => {
              if (day === null) return <div key={idx} />;
              const concerts = getDayConcerts(day);
              const bestStatus = getBestStatusForDay(concerts as any);
              const isSelected = selectedDate === `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;

              return (
                <div 
                  key={day} 
                  onClick={() => handleDayClick(day)} 
                  style={{ 
                    aspectRatio: '1/1', 
                    display: 'flex', 
                    flexDirection: 'column', 
                    alignItems: 'center', 
                    justifyContent: 'center', 
                    borderRadius: '16px', 
                    background: isSelected ? 'rgba(83, 190, 232, 0.1)' : 'transparent', 
                    border: isSelected ? '2px solid #53BEE8' : 'none', 
                    cursor: 'pointer', 
                    position: 'relative',
                    transition: 'all 0.2s'
                  }}
                >
                  <span style={{ fontSize: '16px', fontWeight: '600' }}>{day}</span>
                  {bestStatus && (
                    <div style={{ 
                      position: 'absolute', 
                      bottom: '6px', 
                      width: '6px', 
                      height: '6px', 
                      borderRadius: '50%', 
                      background: colorMap[bestStatus] 
                    }} />
                  )}
                </div>
              );
            })}
          </div>
        </div>

        {selectedDate && dayConcerts.length > 0 && (
          <div style={{ marginTop: '32px' }} className="fade-in">
            <h3 style={{ fontSize: '14px', fontWeight: '700', color: theme.colors.textSecondary, marginBottom: '16px', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
              {selectedDate.replace(/-/g, '.')}
            </h3>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
              {dayConcerts.map((c) => (
                <div 
                  key={c.id} 
                  onClick={() => handleConcertClick(c)}
                  style={{ 
                    background: 'white', 
                    borderRadius: '24px', 
                    padding: '20px', 
                    border: '1px solid rgba(0,0,0,0.04)', 
                    boxShadow: '0 4px 12px rgba(0,0,0,0.03)', 
                    display: 'flex', 
                    justifyContent: 'space-between', 
                    alignItems: 'center',
                    cursor: 'pointer'
                  }}
                >
                  <div>
                    <div style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: '700' }}>{c.artistName}</div>
                    <div style={{ fontSize: '17px', fontWeight: '800' }}>{c.tourName}</div>
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: colorMap[c.status] }} />
                    <span style={{ fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary }}>{c.status}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      <IconButton 
        icon={isMenuOpen ? <Icons.X /> : <Icons.Plus />} 
        primary 
        size={64}
        onClick={() => setIsMenuOpen(!isMenuOpen)}
        style={{ 
          position: 'fixed', 
          right: '16px', 
          bottom: 'calc(16px + env(safe-area-inset-bottom))', 
          zIndex: 110, 
          boxShadow: '0 8px 24px -6px rgba(83, 190, 232, 0.5)' 
        }}
      />

      <CalendarMenu 
        isOpen={isMenuOpen} 
        onClose={() => setIsMenuOpen(false)} 
        weekStart={weekStart} 
        setWeekStart={setWeekStart}
        showAttended={showAttended}
        setShowAttended={setShowAttended}
        showSkipped={showSkipped}
        setShowSkipped={setShowSkipped}
      />
    </PageShell>
  );
};

import React, { useState, useMemo } from 'react';
import { PageShell } from '../ui/PageShell';
import { theme } from '../ui/theme';
import { IconButton, Icons } from '../ui/IconButton';
import { Artist, Concert, DisplaySettings } from '../domain/types';
import { ArtistDetailMenu } from '../components/ArtistDetailMenu';
import { calcArtistStatus, sortPerformancesForDisplay } from '../domain/logic';

interface Props {
  artistId: string;
  artist: Artist;
  settings: DisplaySettings;
  onOpenArtistEditor: (artistId: string) => void;
  onOpenConcertEditor: (artistId: string) => void;
  onOpenConcertHome: (artistId: string, tourId: string, concertId: string) => void;
  onChangeSettings: (settings: Partial<DisplaySettings>) => void;
  onBack: () => void;
}

const ConcertItem = ({ concert, tourImageUrl, tourOfficialUrl, onClick }: { concert: Concert; tourImageUrl: string; tourOfficialUrl?: string; onClick?: () => void }) => {
  const [imgError, setImgError] = useState(false);
  const isSpecial = concert.status === '参戦予定' || concert.status === '参戦済み';
  const dotColor = isSpecial ? theme.colors.primary : '#9CA3AF';
  const canNavigate = !!onClick;
  const isLottery = concert.status === '抽選中';

  const displayImage = tourImageUrl || (concert.images && concert.images.length > 0 ? concert.images[0] : null);

  return (
    <div 
      onClick={onClick}
      style={{
        background: 'white',
        borderRadius: '28px',
        padding: '16px 20px',
        border: '1px solid rgba(0, 0, 0, 0.04)',
        boxShadow: '0 4px 12px rgba(0,0,0,0.03)',
        display: 'flex',
        gap: '16px',
        alignItems: 'center',
        cursor: canNavigate ? 'pointer' : 'default',
        position: 'relative'
      }}
    >
      <div style={{
        width: '52px',
        height: '52px',
        borderRadius: '16px',
        background: '#F3F4F6',
        flexShrink: 0,
        overflow: 'hidden',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        border: '1px solid rgba(0,0,0,0.05)'
      }}>
