export const ArtistDetailPage: React.FC<Props> = ({ 
  artistId, 
  artist, 
  settings, 
  onOpenArtistEditor, 
  onOpenConcertEditor, 
  onOpenConcertHome,
  onChangeSettings,
  onBack 
}) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const status = calcArtistStatus(artist);

