            height: '96px', 
            borderRadius: '50%', 
            background: '#F3F4F6', 
            border: '3px solid white', 
            boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
            overflow: 'hidden',
            flexShrink: 0,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center'
