          </div>
          <div style={{ minWidth: 0 }}>
            <h1 style={{ fontSize: '32px', fontWeight: '900', margin: 0, letterSpacing: '-0.02em', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
              {artist.name}
            </h1>

            <div style={{ 
              marginTop: '8px',
              display: 'inline-flex',
              alignItems: 'center',
              gap: '8px',
              background: 'white',
              padding: '6px 16px',
              borderRadius: '9999px',
              border: '1px solid #F1F5F9',
              boxShadow: '0 1px 2px 0 rgba(0, 0, 0, 0.05)'
