import { calcArtistStatus, sortArtistsForDisplay } from '../domain/logic';

interface Props {
  artists: Artist[];
  onOpenArtist: (artistId: string) => void;
  onOpenArtistEditor: () => void;
  onRefreshAll: () => void;
  onImportData: (data: Artist[]) => void;
}

const ArtistRowCard = ({ artist, onClick }: { artist: Artist; onClick: () => void }) => {
  const [isHovered, setIsHovered] = useState(false);

  const status = calcArtistStatus(artist);
  const isTouring = status.main === 'ツアー中';
  const dotColor = isTouring ? theme.colors.primary : theme.colors.textLabel;

  return (
    <div
      onClick={onClick}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      style={{
        background: 'white',
        borderRadius: theme.radius.card,
        border: '1px solid rgba(0, 0, 0, 0.04)',
        padding: '20px 24px',
        display: 'flex',
        alignItems: 'center',
        gap: '20px',
        cursor: 'pointer',
        boxShadow: isHovered 
          ? '0 10px 20px -5px rgba(0, 0, 0, 0.06)' 
          : '0 4px 12px -2px rgba(0, 0, 0, 0.03)',
        transform: isHovered ? 'scale(1.015)' : 'scale(1)',
        transition: 'all 0.3s cubic-bezier(0.16, 1, 0.3, 1)',
      }}
    >
      <div style={{
        width: '68px',
        height: '68px',
        borderRadius: '50%',
        background: '#F3F4F6',
        flexShrink: 0,
        border: '3px solid white',
        boxShadow: '0 2px 8px rgba(0,0,0,0.08)',
        overflow: 'hidden',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center'
      }}>
        {artist.imageUrl ? (
          <img src={artist.imageUrl} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
        ) : (
          <span style={{ fontSize: '24px', opacity: 0.2 }}>👤</span>
        )}
      </div>

      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{
          fontWeight: '800',
          fontSize: '19px',
          color: isHovered ? theme.colors.primary : theme.colors.text,
          marginBottom: '6px',
          transition: 'color 0.2s ease'
        }}>
          {artist.name}
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
          <div style={{
            width: '8px',
            height: '8px',
            borderRadius: '50%',
            background: dotColor,
          }} />
          <div style={{
            fontSize: '11px',
            fontWeight: '600',
            color: theme.colors.textSecondary,
            letterSpacing: '0.05em',
            textTransform: 'uppercase'
          }}>
            {status.main}
            {status.sub && (
              <span style={{ color: theme.colors.textWeak, marginLeft: '8px', fontWeight: '400' }}>
                / {status.sub}
              </span>
            )}
          </div>
        </div>
      </div>

      <div style={{ color: theme.colors.textLabel }}>
        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <polyline points="9 18 15 12 9 6"></polyline>
        </svg>
      </div>
    </div>
  );
};

export const ArtistListPage: React.FC<Props> = ({ 
  artists, 
  onOpenArtist, 
  onOpenArtistEditor, 
  onRefreshAll,
  onImportData
}) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isImportConfirmOpen, setIsImportConfirmOpen] = useState(false);
  const [sortMode, setSortMode] = useState<'manual' | 'status'>('status');
  const [stagedImportData, setStagedImportData] = useState<Artist[] | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const sortedArtists = useMemo(() => {
    if (sortMode === 'manual') {
      return [...artists].sort((a, b) => (a.order ?? 0) - (b.order ?? 0));
    }
    return sortArtistsForDisplay(artists, sortMode);
  }, [artists, sortMode]);

  const handleExport = () => {
    try {
      const dataStr = JSON.stringify(artists, null, 2);
      const blob = new Blob([dataStr], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      const date = new Date().toISOString().split('T')[0];
      link.href = url;
      link.download = `LiveTrack_JP_Backup_${date}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
      setIsMenuOpen(false);
    } catch (error) {
      console.error('Export failed:', error);
      alert('エクスポートに失敗しました。');
    }
  };

  const handleImportClick = () => {
    setIsMenuOpen(false);
    fileInputRef.current?.click();
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = JSON.parse(e.target?.result as string);
        if (Array.isArray(json)) {
          setStagedImportData(json);
          setIsImportConfirmOpen(true);
        } else {
          alert('不正な形式のファイルです。');
        }
      } catch (err) {
        console.error('Import failed:', err);
        alert('ファイルの読み込みに失敗しました。');
      }
      // Reset input so the same file can be picked again if needed
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  const executeImport = () => {
    if (stagedImportData) {
      onImportData(stagedImportData);
      setStagedImportData(null);
    }
    setIsImportConfirmOpen(false);
  };

  return (
    <PageShell
      header={
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingBottom: '8px' }}>
          <h1 style={{ fontSize: '32px', fontWeight: '900', color: '#111827', margin: 0, letterSpacing: '-0.025em' }}>
            LiveTrack <span style={{ color: '#53BEE8' }}>JP</span>
          </h1>
          <button 
            onClick={onRefreshAll} 
            style={{ 
              padding: '12px', 
              borderRadius: '9999px', 
              background: 'white', 
              border: '1px solid #F3F4F6', 
              color: '#9CA3AF', 
              boxShadow: '0 1px 2px 0 rgba(0, 0, 0, 0.05)', 
              cursor: 'pointer', 
              outline: 'none',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center'
            }}
          >
            <Icons.Refresh />
          </button>
        </div>
      }
    >
      <input 
        type="file" 
        ref={fileInputRef} 
        style={{ display: 'none' }} 
        accept=".json" 
        onChange={handleFileChange} 
      />

      <div style={{ display: 'flex', flexDirection: 'column', gap: '16px', paddingBottom: '120px' }}>
        {sortedArtists.length === 0 ? (
          <div style={{ 
            padding: '80px 20px', 
            textAlign: 'center', 
            color: theme.colors.textWeak,
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            gap: '24px'
          }}>
            <div style={{ fontSize: '48px', opacity: 0.5 }}>👤</div>
            <div style={{ fontSize: '15px', fontWeight: '600' }}>まだアーティストが登録されていません</div>
            <button 
              onClick={onOpenArtistEditor}
              style={{
                padding: '12px 24px',
                borderRadius: '12px',
                background: theme.colors.primary,
                color: 'white',
                border: 'none',
                fontWeight: 'bold',
                cursor: 'pointer'
              }}
            >
              ＋ アーティストを追加
            </button>
          </div>
        ) : (
          sortedArtists.map((artist) => (
            <ArtistRowCard key={artist.id} artist={artist} onClick={() => onOpenArtist(artist.id)} />
          ))
        )}
      </div>

      <IconButton 
        icon={isMenuOpen ? <Icons.X /> : <Icons.Plus />} 
        primary 
        size={64} 
        onClick={() => setIsMenuOpen(!isMenuOpen)} 
        style={{ 
          position: 'fixed', 
          right: '16px', 
          bottom: 'calc(16px + env(safe-area-inset-bottom))', 
          zIndex: 110,
          boxShadow: '0 8px 24px -6px rgba(83, 190, 232, 0.5)'
        }} 
      />

      <BottomMenu 
        isOpen={isMenuOpen} 
        onClose={() => setIsMenuOpen(false)} 
        onAddArtist={onOpenArtistEditor}
        onExport={handleExport} 
        onImport={handleImportClick}
        currentSort={sortMode}
        onSetSort={setSortMode}
      />
      <ConfirmDialog 
        isOpen={isImportConfirmOpen} 
        title="データをインポート" 
        message="選択されたファイルで現在のすべてのデータが上書きされます。よろしいですか？" 
        confirmLabel="上書きする" 
        isDestructive 
        onClose={() => { setIsImportConfirmOpen(false); setStagedImportData(null); }} 
        onConfirm={executeImport} 
      />
    </PageShell>
  );
};

import React, { useState, useMemo } from 'react';
import { PageId, Artist, Tour, DisplaySettings, Status } from './domain/types';
import { Layout } from './components/Layout';
import { ArtistListPage } from './pages/ArtistListPage';
import { ConcertListPage } from './pages/ConcertListPage';
import { CalendarPage } from './pages/CalendarPage';
import { ArtistDetailPage } from './pages/ArtistDetailPage';
import { ConcertHomePage } from './pages/ConcertHomePage';
import { ArtistEditorPage } from './pages/ArtistEditorPage';
import { ConcertEditorPage } from './pages/ConcertEditorPage';
import { GlassCard } from './ui/GlassCard';
import { theme } from './ui/theme';

// Requirement 1: Unified Navigation Context
type NavContext = {
  path: PageId;
  artistId?: string;
  tourId?: string;
  concertId?: string;
};

export default function App() {
  const [nav, setNav] = useState<NavContext>({ path: 'ARTIST_LIST' });
  const [isArtistPickerOpen, setIsArtistPickerOpen] = useState(false);

  // Global display settings
  const [displaySettings, setDisplaySettings] = useState<DisplaySettings>({
    showAttended: true,
    showSkipped: true,
  });

  // Requirement 2: Single Data Source
  const [artists, setArtists] = useState<Artist[]>([
    { 
      id: '1', name: 'アーティスト A', imageUrl: '', links: [], autoTrackConcerts: true, autoTrackTickets: true, order: 0,
      tours: [{ id: 't1', name: 'Tour A', imageUrl: 'https://images.unsplash.com/photo-1470225620780-dba8ba36b745', memo: 'メモ', concerts: [{ id: 'c1', status: '参戦予定', date: '2024-10-01', venue: 'TOKYO DOME', price: 0, saleLink: '', isParticipated: false, images: ['https://images.unsplash.com/photo-1459749411177-042180ce673c'] }] }]
    },
    { 
      id: '2', name: 'アーティスト B', imageUrl: '', links: [], autoTrackConcerts: false, autoTrackTickets: true, order: 1,
      tours: [{ id: 't2', name: 'Tour B', imageUrl: '', concerts: [{ id: 'c2', status: '参戦済み', date: '2023-01-01', venue: 'OSAKA HALL', price: 0, saleLink: '', isParticipated: false, images: [] }] }]
    },
  ]);

  // --- Navigation Handlers ---

  const navigateToArtistList = () => setNav({ path: 'ARTIST_LIST' });

  const navigateToArtistDetail = (artistId: string) => 
    setNav({ path: 'ARTIST_DETAIL', artistId });

  const navigateToArtistEditor = (artistId?: string) => 
    setNav({ path: 'ARTIST_EDITOR', artistId });

  const navigateToConcertEditor = (artistId: string, tourId?: string) => 
    setNav({ path: 'CONCERT_EDITOR', artistId, tourId });

  const navigateToConcertHome = (artistId: string, tourId: string, concertId: string) => {
    // Requirement 5: Guard for status access
    const artist = artists.find(a => a.id === artistId);
    const tour = artist?.tours.find(t => t.id === tourId);
    const concert = tour?.concerts.find(c => c.id === concertId);

    if (concert && (concert.status === '参戦予定' || concert.status === '参戦済み')) {
      setNav({ path: 'CONCERT_HOME', artistId, tourId, concertId });
    } else {
      navigateToArtistDetail(artistId);
    }
  };

  // --- CRUD API (Unified) ---

  const upsertArtist = (updated: Artist) => {
    setArtists(prev => {
      const exists = prev.some(a => a.id === updated.id);
      return exists ? prev.map(a => a.id === updated.id ? updated : a) : [...prev, updated];
    });
    navigateToArtistDetail(updated.id);
  };

  const deleteArtist = (artistId: string) => {
    setArtists(prev => prev.filter(a => a.id !== artistId));
    navigateToArtistList();
  };

  const upsertTour = (artistId: string, updatedTour: Tour) => {
    setArtists(prev => prev.map(artist => {
      if (artist.id !== artistId) return artist;
      const tourExists = artist.tours.some(t => t.id === updatedTour.id);
      return {
        ...artist,
        tours: tourExists 
          ? artist.tours.map(t => t.id === updatedTour.id ? updatedTour : t)
          : [...artist.tours, updatedTour]
      };
    }));
    navigateToArtistDetail(artistId);
  };

  const deleteTour = (artistId: string, tourId: string) => {
    setArtists(prev => prev.map(artist => {
      if (artist.id !== artistId) return artist;
      return { ...artist, tours: artist.tours.filter(t => t.id !== tourId) };
    }));
    navigateToArtistDetail(artistId);
  };

  const updateConcertAlbum = (artistId: string, tourId: string, concertId: string, images: string[]) => {
    setArtists(prev => prev.map(artist => {
      if (artist.id !== artistId) return artist;
      return {
        ...artist,
        tours: artist.tours.map(tour => {
          if (tour.id !== tourId) return tour;
          return {
            ...tour,
            concerts: tour.concerts.map(concert => 
              concert.id === concertId ? { ...concert, images } : concert
            )
          };
        })
      };
    }));
  };

  // --- External Actions ---

  const handleRefreshAll = () => {
    console.log('Refreshing data...');
  };

  // Requirement 6: Reset logic for import
  const handleImportData = (newArtists: Artist[]) => {
    setArtists(newArtists);
    setNav({ path: 'ARTIST_LIST' });
  };

  const handleUpdateDisplaySettings = (updates: Partial<DisplaySettings>) => {
    setDisplaySettings(prev => ({ ...prev, ...updates }));
  };

  // Requirement 4: Artist Selection for Global "+" 
  const openGlobalConcertPicker = () => setIsArtistPickerOpen(true);

  // --- Page Rendering ---

  const renderPage = () => {
    switch (nav.path) {
      case 'ARTIST_LIST':
        return (
          <ArtistListPage 
            artists={artists}
            onOpenArtist={navigateToArtistDetail} 
            onOpenArtistEditor={() => navigateToArtistEditor()}
            onRefreshAll={handleRefreshAll}
            onImportData={handleImportData}
          />
        );
      case 'CONCERT_LIST':
        return (
          <ConcertListPage 
            artists={artists}
            onOpenArtist={navigateToArtistDetail}
            onOpenConcert={navigateToConcertHome}
            onCreateConcert={openGlobalConcertPicker}
            onRefreshAll={handleRefreshAll} 
          />
        );
      case 'CALENDAR':
        return (
          <CalendarPage 
            artists={artists}
            onOpenArtist={navigateToArtistDetail}
            onOpenConcert={navigateToConcertHome}
            onRefreshAll={handleRefreshAll}
          />
        );
      case 'ARTIST_DETAIL': {
        const artist = artists.find(a => a.id === nav.artistId);
        if (!artist) return null;
        return (
          <ArtistDetailPage 
            artistId={nav.artistId!} 
            artist={artist}
            settings={displaySettings}
            onOpenArtistEditor={navigateToArtistEditor}
            onOpenConcertEditor={(aid) => navigateToConcertEditor(aid)}
            onOpenConcertHome={navigateToConcertHome}
            onChangeSettings={handleUpdateDisplaySettings}
            onBack={navigateToArtistList} 
          />
        );
      }
      case 'CONCERT_HOME': {
        const artist = artists.find(a => a.id === nav.artistId);
        const tour = artist?.tours.find(t => t.id === nav.tourId);
        const concert = tour?.concerts.find(c => c.id === nav.concertId);

        if (!artist || !tour || !concert) {
          // Guard redirect
          navigateToArtistList();
          return null;
        }

        return (
          <ConcertHomePage 
            artistId={artist.id}
            concertId={concert.id}
            artist={artist}
            tour={tour}
            concert={concert}
            onBack={() => navigateToArtistDetail(artist.id)}
            onOpenConcertEditor={navigateToConcertEditor}
            onUpdateConcertAlbum={updateConcertAlbum}
          />
        );
      }
      case 'ARTIST_EDITOR': {
        const artist = artists.find(a => a.id === nav.artistId);
        return (
          <ArtistEditorPage 
            artistId={nav.artistId}
            artist={artist}
            onSave={upsertArtist}
            onCancel={() => nav.artistId ? navigateToArtistDetail(nav.artistId) : navigateToArtistList()}
            onOpenConcertEditor={navigateToConcertEditor}
            onDeleteArtist={deleteArtist}
          />
        );
      }
      case 'CONCERT_EDITOR': {
        const artist = artists.find(a => a.id === nav.artistId);
        if (!artist) return null;
        const tour = artist.tours.find(t => t.id === nav.tourId);
        return (
          <ConcertEditorPage 
            artistId={artist.id}
            tourId={nav.tourId}
            tour={tour}
            allArtists={artists}
            onSave={(updated) => upsertTour(artist.id, updated)}
            onCancel={() => navigateToArtistDetail(artist.id)}
            onDeleteTour={deleteTour}
          />
        );
      }
      default:
        return null;
    }
  };

  return (
    <div className="app-root">
      <Layout currentPath={nav.path} onNavigate={(path) => setNav({ path })}>
        {renderPage()}
      </Layout>

      {/* Requirement 4: Global Artist Picker Sheet */}
      {isArtistPickerOpen && (
        <div style={overlayStyle}>
          <div style={backdropStyle} onClick={() => setIsArtistPickerOpen(false)} />
          <GlassCard padding="24px" style={pickerCardStyle}>
            <h3 style={{ margin: 0, fontSize: '18px', fontWeight: '800' }}>公演を追加するアーティストを選択</h3>
            <div style={pickerListStyle}>
              {artists.length === 0 ? (
                <div style={emptyPickerStyle}>
                  アーティストを先に登録してください
                </div>
              ) : (
                artists.map(artist => (
                  <button 
                    key={artist.id}
                    onClick={() => {
                      navigateToConcertEditor(artist.id);
                      setIsArtistPickerOpen(false);
                    }}
                    style={pickerButtonStyle}
                  >
                    {artist.name}
                  </button>
                ))
              )}
            </div>
            <button onClick={() => setIsArtistPickerOpen(false)} style={closeButtonStyle}>
              閉じる
            </button>
          </GlassCard>
        </div>
      )}
    </div>
  );
}

// --- Styles ---
const overlayStyle: React.CSSProperties = { position: 'fixed', inset: 0, zIndex: 2000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '24px' };
const backdropStyle: React.CSSProperties = { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)', backdropFilter: 'blur(8px)' };
const pickerCardStyle: React.CSSProperties = { width: '100%', maxWidth: '360px', position: 'relative', display: 'flex', flexDirection: 'column', gap: '20px' };
const pickerListStyle: React.CSSProperties = { display: 'flex', flexDirection: 'column', gap: '10px', maxHeight: '300px', overflowY: 'auto' };
const emptyPickerStyle: React.CSSProperties = { fontSize: '13px', color: theme.colors.textSecondary, textAlign: 'center', padding: '20px' };
const pickerButtonStyle: React.CSSProperties = { padding: '16px', borderRadius: '16px', border: '1px solid rgba(0,0,0,0.05)', background: 'white', textAlign: 'left', fontWeight: '700', fontSize: '15px', cursor: 'pointer' };
const closeButtonStyle: React.CSSProperties = { padding: '12px', borderRadius: '12px', border: 'none', background: 'rgba(0,0,0,0.05)', fontWeight: '700', cursor: 'pointer' };

import React, { useState, useMemo, useEffect } from 'react';
import { PageShell } from '../ui/PageShell';
import { theme } from '../ui/theme';
import { PageId, Status, Artist, Concert } from '../domain/types';
import { CalendarMenu } from '../components/CalendarMenu';
import { 
  getBestStatusForDay, 
  sortPerformancesForDisplay, 
} from '../domain/logic';
import { Icons, IconButton } from '../ui/IconButton';

interface Props {
  artists: Artist[];
  onOpenArtist: (artistId: string) => void;
  onOpenConcert: (artistId: string, tourId: string, concertId: string) => void;
  onRefreshAll: () => void;
}

const colorMap: Record<Status, string> = {
  '参戦予定': theme.colors.status['参戦予定'],
  '抽選中': theme.colors.status['抽選中'],
  '検討中': theme.colors.status['検討中'],
  '発売前': theme.colors.status['発売前'],
  '参戦済み': theme.colors.status['参戦済み'],
  '見送': theme.colors.status['見送'],
};

interface ConcertWithMetadata extends Concert {
  artistName: string;
  artistId: string;
  tourName: string;
  tourId: string;
}

export const CalendarPage: React.FC<Props> = ({ artists, onOpenArtist, onOpenConcert, onRefreshAll }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<string | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [weekStart, setWeekStart] = useState<'sun' | 'mon'>('sun');

  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);

  useEffect(() => {
    setSelectedDate(null);
  }, [currentDate.getFullYear(), currentDate.getMonth()]);

  const allConcerts = useMemo(() => {
    const list: ConcertWithMetadata[] = [];
    artists.forEach(artist => {
      artist.tours.forEach(tour => {
        tour.concerts.forEach(concert => {
          list.push({
            ...concert,
            artistName: artist.name,
            artistId: artist.id,
            tourName: tour.name,
            tourId: tour.id
          });
        });
      });
    });
    return list;
  }, [artists]);

  const visibleConcerts = useMemo(() => {
    return allConcerts.filter(c => {
      if (c.date === 'TBD') return false;
      if (!showAttended && c.status === '参戦済み') return false;
      if (!showSkipped && c.status === '見送') return false;
      return true;
    });
  }, [allConcerts, showAttended, showSkipped]);

  const daysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
  const firstDayOfMonth = (year: number, month: number) => new Date(year, month, 1).getDay();

  const calendarDays = useMemo(() => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const count = daysInMonth(year, month);
    let startDay = firstDayOfMonth(year, month);
    if (weekStart === 'mon') startDay = startDay === 0 ? 6 : startDay - 1;
    const days = [];
    for (let i = 0; i < startDay; i++) days.push(null);
    for (let i = 1; i <= count; i++) days.push(i);
    return days;
  }, [currentDate, weekStart]);

  const getDayConcerts = (day: number) => {
    const dateStr = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    return visibleConcerts.filter(c => c.date === dateStr);
  };

  const handleDayClick = (day: number) => {
    const dateStr = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSelectedDate(dateStr === selectedDate ? null : dateStr);
  };

  const handleConcertClick = (concert: ConcertWithMetadata) => {
    if (concert.status === '参戦予定' || concert.status === '参戦済み') {
      onOpenConcert(concert.artistId, concert.tourId, concert.id);
    } else {
      onOpenArtist(concert.artistId);
    }
  };

  const dayConcerts = useMemo(() => {
    if (!selectedDate) return [];
    const filtered = visibleConcerts.filter(c => c.date === selectedDate);
    return sortPerformancesForDisplay(filtered as any) as ConcertWithMetadata[];
