import { Artist, Concert, Status, TICKET_TRACK_STATUSES, TOUR_ACTIVE_STATUSES, PageId } from './types';

/**
 * ===== Artist status (for Artist List) =====
 */

const ARTIST_SUB_STATUS_ORDER: Status[] = [
  '発売前',
  '検討中',
  '抽選中',
  '参戦予定',
  '参戦済み',
  '見送',
];

const ARTIST_SUB_STATUS_PRIORITY: Record<Status, number> = {
  '発売前': 0,
  '検討中': 1,
  '抽選中': 2,
  '参戦予定': 3,
  '参戦済み': 4,
  '見送': 5,
};

const pickArtistSubStatus = (concerts: Concert[]): Status | null => {
  const candidates = concerts
    .map(c => c.status)
    .filter((s): s is Status => ARTIST_SUB_STATUS_ORDER.includes(s));

  if (candidates.length === 0) return null;

  candidates.sort((a, b) => ARTIST_SUB_STATUS_PRIORITY[a] - ARTIST_SUB_STATUS_PRIORITY[b]);
  return candidates[0] ?? null;
};

export const calcArtistStatus = (artist: Artist): {
  main: 'ツアー中' | '公演追跡中' | '未追跡';
  sub: Status | null;
} => {
  const allConcerts = artist.tours.flatMap(t => t.concerts);
  const hasActiveTour = allConcerts.some(c => TOUR_ACTIVE_STATUSES.includes(c.status));

  let main: 'ツアー中' | '公演追跡中' | '未追跡' = '未追跡';
  if (hasActiveTour) {
    main = 'ツアー中';
  } else if (artist.autoTrackConcerts) {
    main = '公演追跡中';
  } else {
    main = '未追跡';
  }

  const sub = main === 'ツアー中' ? pickArtistSubStatus(allConcerts) : null;
  return { main, sub };
};

const getArtistPriority = (artist: Artist): { main: number; sub: number } => {
  const status = calcArtistStatus(artist);
  if (status.main === 'ツアー中') {
    return {
      main: 1,
      sub: status.sub ? ARTIST_SUB_STATUS_PRIORITY[status.sub] : 99,
    };
  }
  if (status.main === '公演追跡中') return { main: 2, sub: 0 };
  return { main: 3, sub: 0 };
};

export const sortArtistsForDisplay = (artists: Artist[], sortMode: 'manual' | 'status'): Artist[] => {
  if (sortMode === 'manual') {
    return [...artists];
  }
  return [...artists].sort((a, b) => {
    const prioA = getArtistPriority(a);
    const prioB = getArtistPriority(b);
    if (prioA.main !== prioB.main) return prioA.main - prioB.main;
    if (prioA.sub !== prioB.sub) return prioA.sub - prioB.sub;
    return a.name.localeCompare(b.name);
  });
};

/**
 * ===== Concert sorting / calendar logic =====
 */

const getConcertStatusPriority = (status: Status): number => {
  if (TICKET_TRACK_STATUSES.includes(status)) return 1;
  if (status === '参戦予定') return 2;
  if (status === '参戦済み') return 3;
  if (status === '見送') return 4;
  return 99;
};

const getCalendarStatusWeight = (status: Status): number => {
  switch (status) {
    case '参戦予定': return 100;
    case '抽選中': return 90;
    case '検討中': return 80;
    case '発売前': return 70;
    case '参戦済み': return 60;
    case '見送': return 50;
    default: return 0;
  }
};

export const getBestStatusForDay = (concerts: Concert[]): Status | null => {
  const dated = concerts.filter(c => c.date !== 'TBD');
  if (dated.length === 0) return null;
  return [...dated].sort((a, b) => getCalendarStatusWeight(b.status) - getCalendarStatusWeight(a.status))[0].status;
};

export const getConcertNavigationTarget = (status: Status): PageId => {
  if (status === '参戦予定' || status === '参戦済み') return 'CONCERT_HOME';
  return 'ARTIST_DETAIL';
};

export const sortPerformancesForDisplay = (concerts: Concert[]): Concert[] => {
  return [...concerts].sort((a, b) => {
    const prioA = getConcertStatusPriority(a.status);
    const prioB = getConcertStatusPriority(b.status);
    if (prioA !== prioB) return prioA - prioB;
    if (a.date !== 'TBD' && b.date === 'TBD') return -1;
    if (a.date === 'TBD' && b.date !== 'TBD') return 1;
    if (a.date !== 'TBD' && b.date !== 'TBD') return a.date.localeCompare(b.date);
    return 0;
  });
};

export const sortPerformancesByLotteryDate = (concerts: Concert[]): Concert[] => {
  const targets: Status[] = ['抽選中', '参戦予定', '見送'];
  return [...concerts].sort((a, b) => {
    const isTargetA = targets.includes(a.status) && !!a.lotteryResultDate;
    const isTargetB = targets.includes(b.status) && !!b.lotteryResultDate;
    if (isTargetA && !isTargetB) return -1;
    if (!isTargetA && isTargetB) return 1;
    if (isTargetA && isTargetB) {
      return (a.lotteryResultDate || '').localeCompare(b.lotteryResultDate || '');
    }
    return 0;
  });
};

/**
 * Checks for date conflicts globally across all artists, regardless of status.
 */
export const checkGlobalDateConflicts = (
  allArtists: Artist[],
  currentTourId: string,
  formConcerts: Concert[]
): string[] => {
  // 1) Collect all existing dates from other artists/tours
  const otherDates = new Set<string>();
  allArtists.forEach(artist => {
    artist.tours.forEach(tour => {
      if (tour.id === currentTourId) return;
      tour.concerts.forEach(concert => {
        if (concert.date !== 'TBD' && concert.date) {
          otherDates.add(concert.date);
        }
      });
    });
  });

  // 2) Check current form concerts for conflicts with others and internal duplicates
  const conflicts = new Set<string>();
  const currentDatesInForm = new Set<string>();

  formConcerts.forEach(c => {
    if (c.date === 'TBD' || !c.date) return;

    // Check against other tours
    if (otherDates.has(c.date)) {
      conflicts.add(c.date);
    }

    // Check against internal form duplicates
    if (currentDatesInForm.has(c.date)) {
      conflicts.add(c.date);
    }

    currentDatesInForm.add(c.date);
  });

  return Array.from(conflicts);
};

export const checkDateConflicts = (concerts: Concert[]): string[] => {
  const dated = concerts.filter(c => c.date !== 'TBD' && c.date);
  const dates = dated.map(c => c.date);
  const conflicts = dates.filter((date, index) => dates.indexOf(date) !== index);
  return Array.from(new Set(conflicts));
};

