import { Artist, Concert, Status, TICKET_TRACK_STATUSES, TOUR_ACTIVE_STATUSES, PageId, GlobalSettings } from './types';

/**
 * ===== Artist status (for Artist List) =====
 */

const ARTIST_SUB_STATUS_ORDER: Status[] = [
  '発売前',
  '検討中',
  '抽選中',
  '参戦予定',
  '参戦済み',
  '見送',
];

const ARTIST_SUB_STATUS_PRIORITY: Record<Status, number> = {
  '発売前': 0,
  '検討中': 1,
  '抽選中': 2,
  '参戦予定': 3,
  '参戦済み': 4,
  '見送': 5,
};

const pickArtistSubStatus = (concerts: Concert[]): Status | null => {
  const candidates = concerts
    .map(c => c.status)
    .filter((s): s is Status => ARTIST_SUB_STATUS_ORDER.includes(s));

  if (candidates.length === 0) return null;

  candidates.sort((a, b) => ARTIST_SUB_STATUS_PRIORITY[a] - ARTIST_SUB_STATUS_PRIORITY[b]);
  return candidates[0] ?? null;
};

export const calcArtistStatus = (artist: Artist): {
  main: 'ツアー中' | '公演追跡中' | '未追跡';
  sub: Status | null;
} => {
  const allConcerts = artist.tours.flatMap(t => t.concerts);
  const hasActiveTour = allConcerts.some(c => TOUR_ACTIVE_STATUSES.includes(c.status));

  let main: 'ツアー中' | '公演追跡中' | '未追跡' = '未追跡';
  if (hasActiveTour) {
    main = 'ツアー中';
  } else if (artist.autoTrackConcerts) {
    main = '公演追跡中';
  } else {
    main = '未追跡';
  }

  const sub = main === 'ツアー中' ? pickArtistSubStatus(allConcerts) : null;
  return { main, sub };
};

const getArtistPriority = (artist: Artist): { main: number; sub: number } => {
  const status = calcArtistStatus(artist);
  if (status.main === 'ツアー中') {
    return {
      main: 1,
      sub: status.sub ? ARTIST_SUB_STATUS_PRIORITY[status.sub] : 99,
    };
  }
  if (status.main === '公演追跡中') return { main: 2, sub: 0 };
  return { main: 3, sub: 0 };
};

export const sortArtistsForDisplay = (artists: Artist[], sortMode: 'manual' | 'status'): Artist[] => {
  if (sortMode === 'manual') {
    return [...artists];
  }
  return [...artists].sort((a, b) => {
    const prioA = getArtistPriority(a);
    const prioB = getArtistPriority(b);
    if (prioA.main !== prioB.main) return prioA.main - prioB.main;
    if (prioA.sub !== prioB.sub) return prioA.sub - prioB.sub;
    return a.name.localeCompare(b.name);
  });
};

/**
 * ===== Concert sorting / calendar logic =====
 */

const getConcertStatusPriority = (status: Status): number => {
  if (TICKET_TRACK_STATUSES.includes(status)) return 1;
  if (status === '参戦予定') return 2;
  if (status === '参戦済み') return 3;
  if (status === '見送') return 4;
  return 99;
};

const getCalendarStatusWeight = (status: Status): number => {
  switch (status) {
    case '参戦予定': return 100;
    case '抽選中': return 90;
    case '検討中': return 80;
    case '発売前': return 70;
    case '参戦済み': return 60;
    case '見送': return 50;
    default: return 0;
  }
};

export const getBestStatusForDay = (concerts: Concert[]): Status | null => {
  const dated = concerts.filter(c => c.date !== 'TBD');
  if (dated.length === 0) return null;
  return [...dated].sort((a, b) => getCalendarStatusWeight(b.status) - getCalendarStatusWeight(a.status))[0].status;
};

export const getConcertNavigationTarget = (status: Status): PageId => {
  if (status === '参戦予定' || status === '参戦済み') return 'CONCERT_HOME';
  return 'ARTIST_DETAIL';
};

export const sortPerformancesForDisplay = (concerts: Concert[]): Concert[] => {
  return [...concerts].sort((a, b) => {
    const prioA = getConcertStatusPriority(a.status);
    const prioB = getConcertStatusPriority(b.status);
    if (prioA !== prioB) return prioA - prioB;
    if (a.date !== 'TBD' && b.date === 'TBD') return -1;
    if (a.date === 'TBD' && b.date !== 'TBD') return 1;
    if (a.date !== 'TBD' && b.date !== 'TBD') return a.date.localeCompare(b.date);
    return 0;
  });
};

export const sortPerformancesByLotteryDate = (concerts: Concert[]): Concert[] => {
  const targets: Status[] = ['抽選中', '参戦予定', '見送'];
  return [...concerts].sort((a, b) => {
    const isTargetA = targets.includes(a.status) && !!a.lotteryResultDate;
    const isTargetB = targets.includes(b.status) && !!b.lotteryResultDate;
    if (isTargetA && !isTargetB) return -1;
    if (!isTargetA && isTargetB) return 1;
    if (isTargetA && isTargetB) {
      return (a.lotteryResultDate || '').localeCompare(b.lotteryResultDate || '');
    }
    return 0;
  });
};

/**
 * Checks for date conflicts globally across all artists, regardless of status.
 */
export const checkGlobalDateConflicts = (
  allArtists: Artist[],
  currentTourId: string,
  formConcerts: Concert[]
): string[] => {
  const otherDates = new Set<string>();
  allArtists.forEach(artist => {
    artist.tours.forEach(tour => {
      if (tour.id === currentTourId) return;
      tour.concerts.forEach(concert => {
        if (concert.date !== 'TBD' && concert.date) {
          otherDates.add(concert.date);
        }
      });
    });
  });

  const conflicts = new Set<string>();
  const currentDatesInForm = new Set<string>();

  formConcerts.forEach(c => {
    if (c.date === 'TBD' || !c.date) return;
    if (otherDates.has(c.date)) {
      conflicts.add(c.date);
    }
    if (currentDatesInForm.has(c.date)) {
      conflicts.add(c.date);
    }
    currentDatesInForm.add(c.date);
  });

  return Array.from(conflicts);
};

/**
 * ===== Tracking Logic (Requirement 7) =====
 */

export const getTrackTargetConcerts = (
  artist: Artist,
  settings: GlobalSettings,
  now: Date = new Date()
): Concert[] => {
  const n = settings.autoTrackIntervalDays;
  const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const limitStart = new Date(todayStart.getTime() - n * 24 * 60 * 60 * 1000);

  return artist.tours.flatMap(tour => tour.concerts).filter(concert => {
    // 1. Status Check
    if (!TICKET_TRACK_STATUSES.includes(concert.status)) return false;

    // 2. Date Check (Requirement 4)
    if (concert.date === 'TBD' || !concert.date) return false;

    const concertDate = new Date(concert.date);
    // Range: Today - N to Today (Requirement 3)
    return concertDate >= limitStart && concertDate <= todayStart;
  });
};

export const shouldTriggerAutoTrack = (
  lastCheckedAt: string | undefined,
  settings: GlobalSettings,
  now: Date = new Date()
): boolean => {
  if (!lastCheckedAt) return true;
  const lastDate = new Date(lastCheckedAt);
  const diffTime = now.getTime() - lastDate.getTime();
  const diffDays = diffTime / (1000 * 60 * 60 * 24);
  return diffDays >= settings.autoTrackIntervalDays;
};

import React, { useState, useMemo, useCallback } from 'react';
import { PageId, Artist, Tour, DisplaySettings, Status, GlobalSettings, SiteLink, TrackingStatus, TrackingErrorType } from './domain/types';
import { Layout } from './components/Layout';
import { ArtistListPage } from './pages/ArtistListPage';
import { ConcertListPage } from './pages/ConcertListPage';
import { CalendarPage } from './pages/CalendarPage';
import { ArtistDetailPage } from './pages/ArtistDetailPage';
import { ConcertHomePage } from './pages/ConcertHomePage';
import { ArtistEditorPage } from './pages/ArtistEditorPage';
import { ConcertEditorPage } from './pages/ConcertEditorPage';
import { GlassCard } from './ui/GlassCard';
import { theme } from './ui/theme';
import { shouldTriggerAutoTrack, getTrackTargetConcerts } from './domain/logic';

type NavContext = {
  path: PageId;
  artistId?: string;
  tourId?: string;
  concertId?: string;
};

// Simulation of network tracking
const performTrackingSimulation = async (url: string): Promise<{ status: TrackingStatus; error?: TrackingErrorType }> => {
  // Simulate delay
  await new Promise(resolve => setTimeout(resolve, 800));
  // 15% failure rate for simulation
  const isFailed = Math.random() < 0.15;
  if (isFailed) {
    const errors: TrackingErrorType[] = [
      '接続できませんでした',
      'ページの内容が変わりました',
      'アクセスが制限されています',
      '情報を取得できませんでした'
    ];
    return { status: 'failed', error: errors[Math.floor(Math.random() * errors.length)] };
  }
  return { status: 'success' };
};

export default function App() {
  const [nav, setNav] = useState<NavContext>({ path: 'ARTIST_LIST' });
  const [isArtistPickerOpen, setIsArtistPickerOpen] = useState(false);
  const [isTracking, setIsTracking] = useState(false);

  // Requirement: Global Settings
  const [globalSettings, setGlobalSettings] = useState<GlobalSettings>({
    autoTrackIntervalDays: 7
  });

  const [displaySettings, setDisplaySettings] = useState<DisplaySettings>({
    showAttended: true,
    showSkipped: true,
  });

  const [artists, setArtists] = useState<Artist[]>([
    { 
      id: '1', name: 'アーティスト A', imageUrl: '', links: [{ name: '公式サイト', url: 'https://example.com', autoTrack: true }], autoTrackConcerts: true, autoTrackTickets: true, order: 0,
      tours: [{ id: 't1', name: 'Tour A', imageUrl: 'https://images.unsplash.com/photo-1470225620780-dba8ba36b745', memo: 'メモ', concerts: [{ id: 'c1', status: '発売前', date: new Date().toISOString().split('T')[0], venue: 'TOKYO DOME', price: 0, saleLink: '', isParticipated: false, images: [] }] }]
    },
    { 
      id: '2', name: 'アーティスト B', imageUrl: '', links: [], autoTrackConcerts: false, autoTrackTickets: true, order: 1,
      tours: [{ id: 't2', name: 'Tour B', imageUrl: '', concerts: [{ id: 'c2', status: '参戦済み', date: '2023-01-01', venue: 'OSAKA HALL', price: 0, saleLink: '', isParticipated: false, images: [] }] }]
    },
  ]);

  // --- Navigation Handlers ---

  const navigateToArtistList = () => setNav({ path: 'ARTIST_LIST' });
  const navigateToArtistDetail = (artistId: string) => setNav({ path: 'ARTIST_DETAIL', artistId });
  const navigateToArtistEditor = (artistId?: string) => setNav({ path: 'ARTIST_EDITOR', artistId });
  const navigateToConcertEditor = (artistId: string, tourId?: string) => setNav({ path: 'CONCERT_EDITOR', artistId, tourId });
  const navigateToConcertHome = (artistId: string, tourId: string, concertId: string) => {
    const artist = artists.find(a => a.id === artistId);
    const tour = artist?.tours.find(t => t.id === tourId);
    const concert = tour?.concerts.find(c => c.id === concertId);
    if (concert && (concert.status === '参戦予定' || concert.status === '参戦済み')) {
      setNav({ path: 'CONCERT_HOME', artistId, tourId, concertId });
    } else {
      navigateToArtistDetail(artistId);
    }
  };

  // --- CRUD API ---

  const upsertArtist = (updated: Artist) => {
    setArtists(prev => {
      const exists = prev.some(a => a.id === updated.id);
      return exists ? prev.map(a => a.id === updated.id ? updated : a) : [...prev, updated];
    });
    navigateToArtistDetail(updated.id);
  };

  const deleteArtist = (artistId: string) => {
    setArtists(prev => prev.filter(a => a.id !== artistId));
    navigateToArtistList();
  };

  const upsertTour = (artistId: string, updatedTour: Tour) => {
    setArtists(prev => prev.map(artist => {
      if (artist.id !== artistId) return artist;
      const tourExists = artist.tours.some(t => t.id === updatedTour.id);
      return {
        ...artist,
        tours: tourExists 
          ? artist.tours.map(t => t.id === updatedTour.id ? updatedTour : t)
          : [...artist.tours, updatedTour]
      };
    }));
    navigateToArtistDetail(artistId);
  };

  const deleteTour = (artistId: string, tourId: string) => {
    setArtists(prev => prev.map(artist => {
      if (artist.id !== artistId) return artist;
      return { ...artist, tours: artist.tours.filter(t => t.id !== tourId) };
    }));
    navigateToArtistDetail(artistId);
  };

  const updateConcertAlbum = (artistId: string, tourId: string, concertId: string, images: string[]) => {
    setArtists(prev => prev.map(artist => {
      if (artist.id !== artistId) return artist;
      return {
        ...artist,
        tours: artist.tours.map(tour => {
          if (tour.id !== tourId) return tour;
          return {
            ...tour,
            concerts: tour.concerts.map(concert => 
              concert.id === concertId ? { ...concert, images } : concert
            )
          };
        })
      };
    }));
  };

  // --- Requirement 8: Tracking Execution ---

  const handleRefreshAll = useCallback(async (isManual: boolean = true) => {
    if (isTracking) return;
    setIsTracking(true);
    const now = new Date();
    const nowStr = now.toISOString();

    const newArtists = [...artists];
    let changed = false;

    for (let i = 0; i < newArtists.length; i++) {
      const artist = newArtists[i];
      let artistChanged = false;

      // Filter concerts to track based on Requirement 4 & 7
      const targets = getTrackTargetConcerts(artist, globalSettings, now);
      if (targets.length === 0 && !isManual) continue;

      const newLinks = artist.links.map(link => {
        // Requirement 2: Condition check
        const shouldRun = isManual || (link.autoTrack && shouldTriggerAutoTrack(link.lastCheckedAt, globalSettings, now));

        if (shouldRun) {
          // Simulation (Requirement 6 & 8)
          console.log(`Tracking ${artist.name} via ${link.name}... Range: -${globalSettings.autoTrackIntervalDays} days`);
          artistChanged = true;
          changed = true;

          return { ...link }; // We will update this after await in a real scenario
        }
        return link;
      });

      if (artistChanged) {
        // Since we are simulating, we do a batch update for the artist
        for (let j = 0; j < artist.links.length; j++) {
          const link = artist.links[j];
          if (isManual || (link.autoTrack && shouldTriggerAutoTrack(link.lastCheckedAt, globalSettings, now))) {
             const result = await performTrackingSimulation(link.url);
             newLinks[j] = {
               ...newLinks[j],
               lastCheckedAt: nowStr,
               trackingStatus: result.status,
               errorMessage: result.error,
               lastSuccessAt: result.status === 'success' ? nowStr : newLinks[j].lastSuccessAt
             };
          }
        }
        newArtists[i] = { ...artist, links: newLinks };
      }
    }

    if (changed) setArtists(newArtists);
    setIsTracking(false);
  }, [artists, globalSettings, isTracking]);

  const handleImportData = (newArtists: Artist[]) => {
    setArtists(newArtists);
    setNav({ path: 'ARTIST_LIST' });
  };

  const handleUpdateDisplaySettings = (updates: Partial<DisplaySettings>) => {
    setDisplaySettings(prev => ({ ...prev, ...updates }));
  };

  const openGlobalConcertPicker = () => setIsArtistPickerOpen(true);

  // --- Page Rendering ---

  const renderPage = () => {
    switch (nav.path) {
      case 'ARTIST_LIST':
        return (
          <ArtistListPage 
            artists={artists}
            onOpenArtist={navigateToArtistDetail} 
            onOpenArtistEditor={() => navigateToArtistEditor()}
            onRefreshAll={() => handleRefreshAll(true)}
            onImportData={handleImportData}
          />
        );
      case 'CONCERT_LIST':
        return (
          <ConcertListPage 
            artists={artists}
            onOpenArtist={navigateToArtistDetail}
            onOpenConcert={navigateToConcertHome}
            onCreateConcert={openGlobalConcertPicker}
            onRefreshAll={() => handleRefreshAll(true)} 
          />
        );
      case 'CALENDAR':
        return (
          <CalendarPage 
            artists={artists}
            onOpenArtist={navigateToArtistDetail}
            onOpenConcert={navigateToConcertHome}
            onRefreshAll={() => handleRefreshAll(true)}
          />
        );
      case 'ARTIST_DETAIL': {
        const artist = artists.find(a => a.id === nav.artistId);
        if (!artist) return null;
        return (
          <ArtistDetailPage 
            artistId={nav.artistId!} 
            artist={artist}
            settings={displaySettings}
            onOpenArtistEditor={navigateToArtistEditor}
            onOpenConcertEditor={(aid) => navigateToConcertEditor(aid)}
            onOpenConcertHome={navigateToConcertHome}
            onChangeSettings={handleUpdateDisplaySettings}
            onBack={navigateToArtistList} 
          />
        );
      }
      case 'CONCERT_HOME': {
        const artist = artists.find(a => a.id === nav.artistId);
        const tour = artist?.tours.find(t => t.id === nav.tourId);
        const concert = tour?.concerts.find(c => c.id === nav.concertId);
        if (!artist || !tour || !concert) {
          navigateToArtistList();
          return null;
        }
        return (
          <ConcertHomePage 
            artistId={artist.id}
            concertId={concert.id}
            artist={artist}
            tour={tour}
            concert={concert}
            onBack={() => navigateToArtistDetail(artist.id)}
            onOpenConcertEditor={navigateToConcertEditor}
            onUpdateConcertAlbum={updateConcertAlbum}
          />
        );
      }
      case 'ARTIST_EDITOR': {
        const artist = artists.find(a => a.id === nav.artistId);
        return (
          <ArtistEditorPage 
            artistId={nav.artistId}
            artist={artist}
            onSave={upsertArtist}
            onCancel={() => nav.artistId ? navigateToArtistDetail(nav.artistId) : navigateToArtistList()}
            onOpenConcertEditor={navigateToConcertEditor}
            onDeleteArtist={deleteArtist}
          />
        );
      }
      case 'CONCERT_EDITOR': {
        const artist = artists.find(a => a.id === nav.artistId);
        if (!artist) return null;
        const tour = artist.tours.find(t => t.id === nav.tourId);
        return (
          <ConcertEditorPage 
            artistId={artist.id}
            tourId={nav.tourId}
            tour={tour}
            allArtists={artists}
            onSave={(updated) => upsertTour(artist.id, updated)}
            onCancel={() => navigateToArtistDetail(artist.id)}
            onDeleteTour={deleteTour}
          />
        );
      }
      default:
        return null;
    }
  };

  return (
    <div className="app-root">
      <Layout currentPath={nav.path} onNavigate={(path) => setNav({ path })}>
        {renderPage()}
      </Layout>

      {isArtistPickerOpen && (
        <div style={overlayStyle}>
          <div style={backdropStyle} onClick={() => setIsArtistPickerOpen(false)} />
          <GlassCard padding="24px" style={pickerCardStyle}>
            <h3 style={{ margin: 0, fontSize: '18px', fontWeight: '800' }}>公演を追加するアーティストを選択</h3>
            <div style={pickerListStyle}>
              {artists.length === 0 ? (
                <div style={emptyPickerStyle}>アーティストを先に登録してください</div>
              ) : (
                artists.map(artist => (
                  <button key={artist.id} onClick={() => { navigateToConcertEditor(artist.id); setIsArtistPickerOpen(false); }} style={pickerButtonStyle}>{artist.name}</button>
                ))
              )}
            </div>
            <button onClick={() => setIsArtistPickerOpen(false)} style={closeButtonStyle}>閉じる</button>
          </GlassCard>
        </div>
      )}

      {isTracking && (
        <div style={{ position: 'fixed', top: '24px', left: '50%', transform: 'translateX(-50%)', zIndex: 9999 }}>
          <GlassCard padding="12px 24px" style={{ borderRadius: '999px', boxShadow: '0 10px 25px rgba(0,0,0,0.1)' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px', fontSize: '14px', fontWeight: 'bold', color: theme.colors.primary }}>
               <div className="spinning" style={{ width: '16px', height: '16px', border: `2px solid ${theme.colors.primary}`, borderTopColor: 'transparent', borderRadius: '50%' }} />
               追跡実行中...
            </div>
          </GlassCard>
        </div>
      )}

      <style>{`
        @keyframes spin { to { transform: rotate(360deg); } }
        .spinning { animation: spin 0.8s linear infinite; }
      `}</style>
    </div>
  );
}

