  );
};

const navBtnStyle = { width: '40px', height: '40px', borderRadius: '50%', border: 'none', background: '#F3F4F6', cursor: 'pointer', fontWeight: 'bold' };
const weekLabelStyle = { textAlign: 'center', fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary, paddingBottom: '8px' };
const dayCellStyle: React.CSSProperties = { 
  minHeight: '52px', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', borderRadius: '12px', cursor: 'pointer', position: 'relative', transition: 'all 0.1s ease', padding: '4px 0' 
};
const eventCardStyle: React.CSSProperties = { 
  background: 'white', borderRadius: '24px', padding: '12px 16px', border: '1px solid rgba(0,0,0,0.04)', boxShadow: '0 4px 12px rgba(0,0,0,0.03)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', cursor: 'pointer' 
};

import { Artist, Concert, Status, TICKET_TRACK_STATUSES, TOUR_ACTIVE_STATUSES, PageId, GlobalSettings, DueAction, CalendarEvent, CalendarEventType } from './types';

/**
 * ===== Date Parsing Rules =====
 */
export const parseConcertDate = (dateStr: string | null | undefined, type: 'CONCERT' | 'NORMAL'): Date | null => {
  if (!dateStr || dateStr === 'TBD') return null;

  // If it has a time part
  if (dateStr.includes(' ')) {
    const d = new Date(dateStr);
    return isNaN(d.getTime()) ? null : d;
  }

  // Date only YYYY-MM-DD
  const [y, m, d] = dateStr.split('-').map(Number);
  if (type === 'CONCERT') {
    return new Date(y, m - 1, d, 21, 0, 0); // Rule: 21:00 for concert
  }
  return new Date(y, m - 1, d, 12, 0, 0); // Rule: 12:00 for sale/deadline/result
};

/**
 * ===== Calendar Logic (New Specification) =====
 */

export const EVENT_PRIORITY: Record<CalendarEventType, number> = {
  '公演': 1,
  '抽選結果': 2,
  '申込締切': 3,
  '発売開始': 4,
};

const extractDateAndTime = (str: string | null | undefined): { date: string; time?: string } | null => {
  if (!str || str === 'TBD') return null;
  const [date, time] = str.split(' ');
  return { date, time: time ? time.substring(0, 5) : undefined };
};

export const buildCalendarEvents = (artists: Artist[], settings: { showAttended: boolean; showSkipped: boolean }): CalendarEvent[] => {
  const events: CalendarEvent[] = [];

  artists.forEach(artist => {
    artist.tours.forEach(tour => {
      tour.concerts.forEach(concert => {
        // Skip based on global visibility settings
        if (!settings.showAttended && concert.status === '参戦済み') return;
        if (!settings.showSkipped && concert.status === '見送') return;

        const title = `${artist.name} / ${tour.name}`;

        // A) 公演
        const cInfo = extractDateAndTime(concert.concertAt || concert.date);
        if (cInfo) {
          events.push({
            dateKey: cInfo.date,
            timeLabel: cInfo.time,
            type: '公演',
            artistId: artist.id,
            tourId: tour.id,
            concertId: concert.id,
            title,
            status: concert.status,
          });
        }

        // B) 抽選結果
        if (concert.status === '抽選中') {
          const rInfo = extractDateAndTime(concert.resultAt);
          if (rInfo) {
            events.push({
              dateKey: rInfo.date,
              timeLabel: rInfo.time,
              type: '抽選結果',
              artistId: artist.id,
              tourId: tour.id,
              concertId: concert.id,
              title,
              status: concert.status,
            });
          }
        }

        // C) 発売開始
        if (concert.status === '発売前') {
          const sInfo = extractDateAndTime(concert.saleAt);
          if (sInfo) {
            events.push({
              dateKey: sInfo.date,
              timeLabel: sInfo.time,
              type: '発売開始',
              artistId: artist.id,
              tourId: tour.id,
              concertId: concert.id,
              title,
              status: concert.status,
            });
          }
        }

        // D) 申込締切
        if (concert.status === '検討中') {
          const dInfo = extractDateAndTime(concert.deadlineAt);
          if (dInfo) {
            events.push({
              dateKey: dInfo.date,
              timeLabel: dInfo.time,
              type: '申込締切',
              artistId: artist.id,
              tourId: tour.id,
              concertId: concert.id,
              title,
              status: concert.status,
            });
          }
        }
      });
    });
  });

  return events;
};

/**
 * ===== DueAction Determination Logic =====
 */
export const getDueAction = (concert: Concert, now: Date = new Date()): DueAction | null => {
  const saleTime = parseConcertDate(concert.saleAt, 'NORMAL');
  const deadlineTime = parseConcertDate(concert.deadlineAt, 'NORMAL');
  const resultTime = parseConcertDate(concert.resultAt, 'NORMAL');
  const concertTime = parseConcertDate(concert.concertAt, 'CONCERT');

  switch (concert.status) {
    case '発売前':
      if (saleTime && now >= saleTime) return 'ASK_BUY_AT_SALE';
      return null;

    case '検討中':
      if (deadlineTime && now >= deadlineTime) return 'ASK_BUY_AT_DEADLINE';
      if (!deadlineTime) return 'NEED_SET_DEADLINE_AT';
      return null;

    case '抽選中':
      if (resultTime && now >= resultTime) return 'ASK_RESULT';
      if (!resultTime) return 'NEED_SET_RESULT_AT';
      return null;

    case '参戦予定':
      if (!concertTime) return 'NEED_SET_CONCERT_AT';
      return null;

    default:
      return null;
  }
};

/**
 * ===== Automatic Advancement (Requirement 6) =====
 */
export const autoAdvanceConcertStatus = (concert: Concert, now: Date = new Date()): Concert => {
  if (concert.status === '参戦予定') {
    const concertTime = parseConcertDate(concert.concertAt, 'CONCERT');
    if (concertTime && now >= concertTime) {
      return { ...concert, status: '参戦済み' };
    }
  }
  return concert;
};

/**
 * ===== Decision Application (Requirement 5) =====
 */
export const applyDecision = (
  concert: Concert, 
  decision: 'BUY' | 'CONSIDER' | 'SKIP' | 'WON' | 'LOST', 
  payload?: { lotteryName?: string; resultAt?: string; concertAt?: string }
): Concert => {
  switch (decision) {
    case 'BUY':
      return { 
        ...concert, 
        status: '抽選中', 
        lotteryName: payload?.lotteryName ?? concert.lotteryName,
        resultAt: payload?.resultAt ?? concert.resultAt 
      };
    case 'CONSIDER':
      return { ...concert, status: '検討中' };
    case 'SKIP':
      return { ...concert, status: '見送', lotteryResult: null };
    case 'WON':
      return { 
        ...concert, 
        status: '参戦予定', 
        lotteryResult: 'WON',
        concertAt: payload?.concertAt ?? (concert.concertAt || concert.date)
      };
    case 'LOST':
      return { ...concert, status: '見送', lotteryResult: 'LOST' };
    default:
      return concert;
  }
};

/**
 * ===== Artist status logic =====
 */
const ARTIST_SUB_STATUS_ORDER: Status[] = ['発売前', '検討中', '抽選中', '参戦予定', '参戦済み', '見送'];
const ARTIST_SUB_STATUS_PRIORITY: Record<Status, number> = {
  '発売前': 0, '検討中': 1, '抽選中': 2, '参戦予定': 3, '参戦済み': 4, '見送': 5,
};

const pickArtistSubStatus = (concerts: Concert[]): Status | null => {
  const candidates = concerts
    .map(c => c.status)
    .filter((s): s is Status => ARTIST_SUB_STATUS_ORDER.includes(s));
  if (candidates.length === 0) return null;
  candidates.sort((a, b) => ARTIST_SUB_STATUS_PRIORITY[a] - ARTIST_SUB_STATUS_PRIORITY[b]);
  return candidates[0] ?? null;
};

export const calcArtistStatus = (artist: Artist): {
  main: 'ツアー中' | '公演追跡中' | '未追跡';
  sub: Status | null;
} => {
  const allConcerts = artist.tours.flatMap(t => t.concerts);
  const hasActiveTour = allConcerts.some(c => TOUR_ACTIVE_STATUSES.includes(c.status));
  let main: 'ツアー中' | '公演追跡中' | '未追跡' = '未追跡';
  if (hasActiveTour) main = 'ツアー中';
  else if (artist.autoTrackConcerts) main = '公演追跡中';
  const sub = main === 'ツアー中' ? pickArtistSubStatus(allConcerts) : null;
  return { main, sub };
};

export const sortArtistsForDisplay = (artists: Artist[], sortMode: 'manual' | 'status'): Artist[] => {
  if (sortMode === 'manual') return [...artists];
  return [...artists].sort((a, b) => {
    const prioA = getArtistPriority(a);
    const prioB = getArtistPriority(b);
    if (prioA.main !== prioB.main) return prioA.main - prioB.main;
    if (prioA.sub !== prioB.sub) return prioA.sub - prioB.sub;
    return a.name.localeCompare(b.name);
  });
};

const getArtistPriority = (artist: Artist) => {
  const status = calcArtistStatus(artist);
  if (status.main === 'ツアー中') return { main: 1, sub: status.sub ? ARTIST_SUB_STATUS_PRIORITY[status.sub] : 99 };
  if (status.main === '公演追跡中') return { main: 2, sub: 0 };
  return { main: 3, sub: 0 };
};

/**
 * ===== Concert sorting logic =====
 */
const getConcertStatusPriority = (status: Status): number => {
  if (TICKET_TRACK_STATUSES.includes(status)) return 1;
  if (status === '参戦予定') return 2;
  if (status === '参戦済み') return 3;
  if (status === '見送') return 4;
  return 99;
};

export const getBestStatusForDay = (concerts: Concert[]): Status | null => {
  const dated = concerts.filter(c => c.date !== 'TBD' || c.concertAt);
  if (dated.length === 0) return null;
  return [...dated].sort((a, b) => getCalendarStatusWeight(b.status) - getCalendarStatusWeight(a.status))[0].status;
};

const getCalendarStatusWeight = (status: Status): number => {
  switch (status) {
    case '参戦予定': return 100;
    case '抽選中': return 90;
    case '検討中': return 80;
    case '発売前': return 70;
    case '参戦済み': return 60;
    case '見送': return 50;
    default: return 0;
  }
};

export const sortPerformancesForDisplay = (concerts: Concert[]): Concert[] => {
  return [...concerts].sort((a, b) => {
    const prioA = getConcertStatusPriority(a.status);
    const prioB = getConcertStatusPriority(b.status);
    if (prioA !== prioB) return prioA - prioB;
    const dateA = a.concertAt || a.date;
    const dateB = b.concertAt || b.date;
    if (dateA !== 'TBD' && dateB === 'TBD') return -1;
    if (dateA === 'TBD' && dateB !== 'TBD') return 1;
    if (dateA !== 'TBD' && dateB !== 'TBD') return dateA.localeCompare(dateB);
    return 0;
  });
};

export const sortPerformancesByLotteryDate = (concerts: Concert[]): Concert[] => {
  const getMilestoneDate = (c: Concert) => {
    if (c.status === '抽選中') return c.resultAt;
    if (c.status === '検討中') return c.deadlineAt;
    if (c.status === '発売前') return c.saleAt;
    return null;
  };

  return [...concerts].sort((a, b) => {
    const dateA = getMilestoneDate(a);
    const dateB = getMilestoneDate(b);

    // Items with milestone dates come first
    if (dateA && !dateB) return -1;
    if (!dateA && dateB) return 1;
    if (dateA && dateB) return dateA.localeCompare(dateB);

    // Fallback to concert date
    const cA = a.concertAt || a.date;
    const cB = b.concertAt || b.date;
    if (cA !== 'TBD' && cB !== 'TBD') return cA.localeCompare(cB);
    if (cA !== 'TBD') return -1;
    if (cB !== 'TBD') return 1;
    return 0;
  });
};

export const checkGlobalDateConflicts = (allArtists: Artist[], currentTourId: string, formConcerts: Concert[]): string[] => {
  const otherDates = new Set<string>();
  allArtists.forEach(artist => artist.tours.forEach(tour => {
    if (tour.id === currentTourId) return;
    tour.concerts.forEach(concert => {
      const d = concert.concertAt || concert.date;
      if (d !== 'TBD' && d) otherDates.add(d.split(' ')[0]);
    });
  }));
  const conflicts = new Set<string>();
  const currentDatesInForm = new Set<string>();
  formConcerts.forEach(c => {
    const d = c.concertAt || c.date;
    if (d === 'TBD' || !d) return;
    const dateOnly = d.split(' ')[0];
    if (otherDates.has(dateOnly) || currentDatesInForm.has(dateOnly)) conflicts.add(dateOnly);
    currentDatesInForm.add(dateOnly);
  });
  return Array.from(conflicts);
};

export const getTrackTargetConcerts = (artist: Artist, settings: GlobalSettings, now: Date = new Date()): Concert[] => {
  const n = settings.autoTrackIntervalDays;
  const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const limitStart = new Date(todayStart.getTime() - n * 24 * 60 * 60 * 1000);
  return artist.tours.flatMap(tour => tour.concerts).filter(concert => {
    if (!TICKET_TRACK_STATUSES.includes(concert.status)) return false;
    const d = concert.concertAt || concert.date;
    if (d === 'TBD' || !d) return false;
    const concertDate = new Date(d);
    return concertDate >= limitStart && concertDate <= todayStart;
  });
};

export const shouldTriggerAutoTrack = (lastCheckedAt: string | undefined, settings: GlobalSettings, now: Date = new Date()): boolean => {
  if (!lastCheckedAt) return true;
  const diffDays = (now.getTime() - new Date(lastCheckedAt).getTime()) / (1000 * 60 * 60 * 24);
  return diffDays >= settings.autoTrackIntervalDays;
};

import React, { useState, useMemo } from 'react';
import { PageShell } from '../ui/PageShell';
import { IconButton, Icons } from '../ui/IconButton';
import { theme } from '../ui/theme';
import { PageId, Concert, Status, Artist, DueAction } from '../domain/types';
import { ConcertMenu } from '../components/ConcertMenu';
import { sortPerformancesForDisplay, sortPerformancesByLotteryDate, getDueAction, applyDecision } from '../domain/logic';
import { GlassCard } from '../ui/GlassCard';

interface Props {
  artists: Artist[];
  onOpenArtist: (artistId: string) => void;
  onOpenConcert: (artistId: string, tourId: string, concertId: string) => void;
  onCreateConcert: () => void;
  onRefreshAll: () => void;
  onUpdateConcert: (artistId: string, tourId: string, concertId: string, updates: Partial<Concert>) => void;
}

interface ConcertWithMetadata extends Concert {
  artistName: string;
  artistId: string;
  artistImageUrl: string;
  tourName: string;
  tourId: string;
  tourImageUrl: string;
  tourOfficialUrl?: string;
}

const ActionPanel: React.FC<{ 
  concert: ConcertWithMetadata; 
  dueAction: DueAction; 
  onAction: (decision: 'BUY' | 'CONSIDER' | 'SKIP' | 'WON' | 'LOST', payload?: any) => void;
  onOpenEditor: () => void;
}> = ({ concert, dueAction, onAction, onOpenEditor }) => {
  const [lotteryName, setLotteryName] = useState(concert.lotteryName || '');
  const [resultAt, setResultAt] = useState(concert.resultAt || '');
  const [concertAt, setConcertAt] = useState(concert.concertAt || '');

  const renderContent = () => {
    switch (dueAction) {
      case 'ASK_BUY_AT_SALE':
      case 'ASK_BUY_AT_DEADLINE':
        return (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
            <div style={{ fontSize: '13px', fontWeight: 'bold', color: theme.colors.error }}>チケット販売・締切期間です</div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px' }}>
              <input type="text" placeholder="抽選名 (FC先行等)" value={lotteryName} onChange={e => setLotteryName(e.target.value)} style={smallInputStyle} />
              <input type="date" value={resultAt} onChange={e => setResultAt(e.target.value)} style={smallInputStyle} />
            </div>
            <div style={{ display: 'flex', gap: '8px' }}>
              <button onClick={() => onAction('BUY', { lotteryName, resultAt })} style={primaryBtnStyle}>購入・申込</button>
              {dueAction === 'ASK_BUY_AT_SALE' && <button onClick={() => onAction('CONSIDER')} style={secondaryBtnStyle}>検討</button>}
              <button onClick={() => onAction('SKIP')} style={dangerBtnStyle}>見送</button>
            </div>
          </div>
        );
      case 'ASK_RESULT':
        return (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
            <div style={{ fontSize: '13px', fontWeight: 'bold', color: theme.colors.error }}>抽選結果が出ている時間です</div>
            {!concert.concertAt && <input type="date" value={concertAt} onChange={e => setConcertAt(e.target.value)} style={smallInputStyle} placeholder="公演日時" />}
            <div style={{ display: 'flex', gap: '8px' }}>
              <button onClick={() => onAction('WON', { concertAt: concertAt || concert.date })} style={primaryBtnStyle}>当選</button>
              <button onClick={() => onAction('LOST')} style={dangerBtnStyle}>落選</button>
            </div>
          </div>
        );
      case 'NEED_SET_DEADLINE_AT':
      case 'NEED_SET_RESULT_AT':
      case 'NEED_SET_CONCERT_AT':
        return (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
            <div style={{ fontSize: '13px', fontWeight: 'bold', color: theme.colors.textSecondary }}>日時の設定が必要です</div>
            <button onClick={onOpenEditor} style={secondaryBtnStyle}>詳細編集を開く</button>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div style={{ marginTop: '16px', paddingTop: '16px', borderTop: '1px solid rgba(0,0,0,0.05)' }} onClick={e => e.stopPropagation()}>
      {renderContent()}
    </div>
  );
};

const smallInputStyle = { padding: '8px', borderRadius: '8px', border: '1px solid rgba(0,0,0,0.1)', fontSize: '13px', outline: 'none' };
const primaryBtnStyle = { flex: 1, padding: '10px', borderRadius: '10px', background: theme.colors.primary, color: 'white', border: 'none', fontWeight: 'bold', fontSize: '13px', cursor: 'pointer' };
const secondaryBtnStyle = { flex: 1, padding: '10px', borderRadius: '10px', background: 'rgba(0,0,0,0.05)', border: 'none', fontWeight: 'bold', fontSize: '13px', cursor: 'pointer' };
const dangerBtnStyle = { flex: 1, padding: '10px', borderRadius: '10px', background: 'rgba(247, 137, 63, 0.1)', color: theme.colors.error, border: 'none', fontWeight: 'bold', fontSize: '13px', cursor: 'pointer' };

const ConcertRowCard: React.FC<{ 
  concert: ConcertWithMetadata; 
  onClick: () => void;
  onUpdate: (updates: Partial<Concert>) => void;
  onOpenEditor: () => void;
  sortMode: 'status' | 'lottery';
}> = ({ concert, onClick, onUpdate, onOpenEditor, sortMode }) => {
  const [isHovered, setIsHovered] = useState(false);
  const [imgError, setImgError] = useState(false);
  const dueAction = getDueAction(concert);

  const statusColor = theme.colors.status[concert.status as Status] || theme.colors.primary;
  const displayImage = concert.tourImageUrl || (concert.images && concert.images.length > 0 ? concert.images[0] : null) || concert.artistImageUrl;

  const handleAction = (decision: any, payload: any) => {
    const updated = applyDecision(concert, decision, payload);
    onUpdate(updated);
  };

  const displayDateInfo = useMemo(() => {
    if (sortMode !== 'lottery') {
      return { label: '', value: concert.concertAt || concert.date };
    }

    switch (concert.status) {
      case '抽選中':
        return { label: '抽選結果: ', value: concert.resultAt || '未設定' };
      case '検討中':
        return { label: '申込締切: ', value: concert.deadlineAt || '未設定' };
      case '発売前':
        return { label: '発売開始: ', value: concert.saleAt || '未設定' };
      default:
        return { label: '', value: concert.concertAt || concert.date };
    }
  }, [concert, sortMode]);

  return (
    <div
      onClick={onClick}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      style={{
        background: 'white',
        borderRadius: theme.radius.card,
        border: dueAction ? `2px solid ${theme.colors.error}` : '1px solid rgba(0, 0, 0, 0.04)',
        padding: '20px 24px',
        display: 'flex',
        flexDirection: 'column',
        gap: '4px',
        cursor: 'pointer',
        boxShadow: isHovered 
          ? '0 10px 20px -5px rgba(0, 0, 0, 0.06)' 
          : '0 4px 12px -2px rgba(0, 0, 0, 0.03)',
        transform: isHovered ? 'scale(1.01)' : 'scale(1)',
        transition: 'all 0.3s cubic-bezier(0.16, 1, 0.3, 1)',
      }}
    >
      <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
        <div style={{
          width: '68px', height: '68px', borderRadius: '50%', background: '#F3F4F6', flexShrink: 0, border: '3px solid white', boxShadow: '0 2px 8px rgba(0,0,0,0.08)', overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'center'
        }}>
          {displayImage && !imgError ? (
            <img src={displayImage} referrerPolicy="no-referrer" alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} onError={() => setImgError(true)} />
          ) : (
            <span style={{ fontSize: '24px', opacity: 0.2 }}>🎟️</span>
          )}
        </div>

        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: '700', letterSpacing: '0.05em', marginBottom: '2px', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{concert.artistName}</div>
          <div style={{ fontWeight: '800', fontSize: '18px', color: isHovered ? theme.colors.primary : theme.colors.text, transition: 'color 0.2s', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', marginBottom: '4px' }}>{concert.tourName}</div>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <div style={{ fontSize: '13px', color: theme.colors.textSecondary, display: 'flex', alignItems: 'center', gap: '2px' }}>
              {displayDateInfo.label && <span style={{ fontWeight: '800', color: theme.colors.textMain }}>{displayDateInfo.label}</span>}
              <span>{displayDateInfo.value}</span>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
              <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: statusColor }} />
              <div style={{ fontSize: '11px', fontWeight: '800', color: statusColor, textTransform: 'uppercase' }}>
                {concert.status === '見送' && concert.lotteryResult === 'LOST' ? '落選' : concert.status}
              </div>
            </div>
          </div>
        </div>
      </div>

      {dueAction && (
        <ActionPanel 
          concert={concert} 
          dueAction={dueAction} 
          onAction={handleAction} 
          onOpenEditor={onOpenEditor} 
        />
      )}
    </div>
  );
};

export const ConcertListPage: React.FC<Props> = ({ artists, onOpenArtist, onOpenConcert, onCreateConcert, onRefreshAll, onUpdateConcert }) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [showAttended, setShowAttended] = useState(true);
  const [showSkipped, setShowSkipped] = useState(true);
  const [sortMode, setSortMode] = useState<'status' | 'lottery'>('status');

  const allConcerts = useMemo(() => {
    const list: ConcertWithMetadata[] = [];
    artists.forEach(artist => artist.tours.forEach(tour => tour.concerts.forEach(concert => {
      list.push({ ...concert, artistName: artist.name, artistId: artist.id, artistImageUrl: artist.imageUrl || '', tourName: tour.name, tourId: tour.id, tourImageUrl: tour.imageUrl || '', tourOfficialUrl: tour.officialUrl });
    })));
    return list;
  }, [artists]);

  const processedConcerts = useMemo(() => {
    let list = allConcerts.filter(c => {
      if (!showAttended && c.status === '参戦済み') return false;
      if (!showSkipped && c.status === '見送') return false;
      return true;
    });
    return sortMode === 'lottery' ? sortPerformancesByLotteryDate(list as any) as ConcertWithMetadata[] : sortPerformancesForDisplay(list as any) as ConcertWithMetadata[];
  }, [allConcerts, showAttended, showSkipped, sortMode]);

  return (
    <PageShell header={
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingBottom: '8px' }}>
        <h1 style={{ fontSize: '32px', fontWeight: '900', color: '#111827', margin: 0, letterSpacing: '-0.025em' }}>LiveTrack <span style={{ color: '#53BEE8' }}>JP</span></h1>
        <button onClick={onRefreshAll} style={{ padding: '12px', borderRadius: '9999px', background: 'white', border: '1px solid #F3F4F6', color: '#9CA3AF', cursor: 'pointer', outline: 'none', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><Icons.Refresh /></button>
      </div>
    }>
      <div style={{ display: 'flex', flexDirection: 'column', gap: '16px', paddingBottom: '120px' }}>
        {processedConcerts.length === 0 ? (
          <div style={{ padding: '80px 20px', textAlign: 'center', color: theme.colors.textWeak, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '24px' }}>
            <div style={{ fontSize: '48px', opacity: 0.5 }}>🎟️</div>
            <div style={{ fontSize: '15px', fontWeight: '600' }}>表示可能な公演がありません</div>
            <button onClick={onCreateConcert} style={{ padding: '12px 24px', borderRadius: '12px', background: theme.colors.primary, color: 'white', border: 'none', fontWeight: 'bold', cursor: 'pointer' }}>＋ 公演を追加</button>
          </div>
        ) : (
          processedConcerts.map((concert) => (
            <ConcertRowCard 
              key={concert.id} 
              concert={concert} 
              sortMode={sortMode}
              onClick={() => {
                if (!getDueAction(concert)) {
                  if (concert.status === '参戦予定' || concert.status === '参戦済み') onOpenConcert(concert.artistId, concert.tourId, concert.id);
                  else onOpenArtist(concert.artistId);
                }
              }} 
              onUpdate={(updates) => onUpdateConcert(concert.artistId, concert.tourId, concert.id, updates)}
              onOpenEditor={() => onOpenArtist(concert.artistId)}
            />
          ))
        )}
      </div>
      <IconButton icon={isMenuOpen ? <Icons.X /> : <Icons.Plus />} primary size={64} onClick={() => setIsMenuOpen(!isMenuOpen)} style={{ position: 'fixed', right: '16px', bottom: 'calc(16px + env(safe-area-inset-bottom))', zIndex: 110, boxShadow: '0 8px 24px -6px rgba(83, 190, 232, 0.5)' }} />
      <ConcertMenu isOpen={isMenuOpen} onClose={() => setIsMenuOpen(false)} onAddConcert={onCreateConcert} showAttended={showAttended} onToggleAttended={() => setShowAttended(!showAttended)} showSkipped={showSkipped} onToggleSkipped={() => setShowSkipped(!showSkipped)} sortMode={sortMode} onSetSort={setSortMode} />
    </PageShell>
  );
};

import React, { useState, useMemo, useCallback, useEffect } from 'react';
import { PageId, Artist, Tour, DisplaySettings, Status, GlobalSettings, SiteLink, TrackingStatus, TrackingErrorType, Concert } from './domain/types';
import { Layout } from './components/Layout';
import { ArtistListPage } from './pages/ArtistListPage';
import { ConcertListPage } from './pages/ConcertListPage';
import { CalendarPage } from './pages/CalendarPage';
import { ArtistDetailPage } from './pages/ArtistDetailPage';
import { ConcertHomePage } from './pages/ConcertHomePage';
import { ArtistEditorPage } from './pages/ArtistEditorPage';
import { ConcertEditorPage } from './pages/ConcertEditorPage';
import { GlassCard } from './ui/GlassCard';
import { theme } from './ui/theme';
import { shouldTriggerAutoTrack, getTrackTargetConcerts, getDueAction, autoAdvanceConcertStatus } from './domain/logic';

type NavContext = { path: PageId; artistId?: string; tourId?: string; concertId?: string; };

export default function App() {
  const [nav, setNav] = useState<NavContext>({ path: 'ARTIST_LIST' });
  const [isArtistPickerOpen, setIsArtistPickerOpen] = useState(false);
  const [globalSettings, setGlobalSettings] = useState<GlobalSettings>({ autoTrackIntervalDays: 7 });
  const [displaySettings, setDisplaySettings] = useState<DisplaySettings>({ showAttended: true, showSkipped: true });

  // Persistence: Elevated sort modes
  const [artistSortMode, setArtistSortMode] = useState<'manual' | 'status'>('status');
  const [concertSortMode, setConcertSortMode] = useState<'status' | 'lottery'>('status');

  const [artists, setArtists] = useState<Artist[]>([]);

  // Requirement: Global Alert calculation for Nav Red Dot
  const hasGlobalConcertAlert = useMemo(() => {
    const now = new Date();
    return artists.some(a => a.tours.some(t => t.concerts.some(c => !!getDueAction(c, now))));
  }, [artists]);

  // Requirement 6: Automatic advancement runner
  const runAutoAdvance = useCallback(() => {
    const now = new Date();
    setArtists(prev => prev.map(a => ({
      ...a,
      tours: a.tours.map(t => ({
        ...t,
        concerts: t.concerts.map(c => autoAdvanceConcertStatus(c, now))
      }))
    })));
  }, []);

  useEffect(() => {
    runAutoAdvance();
  }, [nav.path]); // Run when switching pages

  const navigateToArtistList = () => setNav({ path: 'ARTIST_LIST' });
  const navigateToArtistDetail = (artistId: string) => setNav({ path: 'ARTIST_DETAIL', artistId });
  const navigateToArtistEditor = (artistId?: string) => setNav({ path: 'ARTIST_EDITOR', artistId });
  const navigateToConcertEditor = (artistId: string, tourId?: string) => setNav({ path: 'CONCERT_EDITOR', artistId, tourId });
  const navigateToConcertHome = (artistId: string, tourId: string, concertId: string) => setNav({ path: 'CONCERT_HOME', artistId, tourId, concertId });

  const upsertArtist = (updated: Artist) => {
    setArtists(prev => {
      const exists = prev.some(a => a.id === updated.id);
      return exists ? prev.map(a => a.id === updated.id ? updated : a) : [...prev, updated];
    });
    navigateToArtistDetail(updated.id);
  };

  const handleUpdateArtistOrder = (newArtists: Artist[]) => {
    setArtists(newArtists.map((a, i) => ({ ...a, order: i })));
  };

  const updateConcert = (artistId: string, tourId: string, concertId: string, updates: Partial<Concert>) => {
    setArtists(prev => prev.map(a => {
      if (a.id !== artistId) return a;
      return {
        ...a,
        tours: a.tours.map(t => {
          if (t.id !== tourId) return t;
          return {
            ...t,
            concerts: t.concerts.map(c => c.id === concertId ? { ...c, ...updates } : c)
          };
        })
      };
    }));
  };

  const upsertTour = (artistId: string, updatedTour: Tour) => {
    setArtists(prev => prev.map(artist => {
      if (artist.id !== artistId) return artist;
      const tourExists = artist.tours.some(t => t.id === updatedTour.id);
      return { ...artist, tours: tourExists ? artist.tours.map(t => t.id === updatedTour.id ? updatedTour : t) : [...artist.tours, updatedTour] };
    }));
    navigateToArtistDetail(artistId);
  };

  const deleteTour = (artistId: string, tourId: string) => {
    setArtists(prev => prev.map(artist => artist.id !== artistId ? artist : { ...artist, tours: artist.tours.filter(t => t.id !== tourId) }));
    navigateToArtistDetail(artistId);
  };

  const renderPage = () => {
    switch (nav.path) {
      case 'ARTIST_LIST': 
        return (
          <ArtistListPage 
            artists={artists} 
            onOpenArtist={navigateToArtistDetail} 
            onOpenArtistEditor={() => navigateToArtistEditor()} 
            onRefreshAll={() => {}} 
            onImportData={setArtists} 
            globalSettings={globalSettings} 
            onUpdateGlobalSettings={setGlobalSettings}
            sortMode={artistSortMode}
            onSetSort={setArtistSortMode}
            onUpdateOrder={handleUpdateArtistOrder}
          />
        );
      case 'CONCERT_LIST': 
        return (
          <ConcertListPage 
            artists={artists} 
            onOpenArtist={navigateToArtistDetail} 
            onOpenConcert={navigateToConcertHome} 
            onCreateConcert={() => setIsArtistPickerOpen(true)} 
            onRefreshAll={runAutoAdvance} 
            onUpdateConcert={updateConcert} 
            sortMode={concertSortMode}
            onSetSort={setConcertSortMode}
          />
        );
      case 'CALENDAR': 
        return <CalendarPage artists={artists} onOpenArtist={navigateToArtistDetail} onOpenConcert={navigateToConcertHome} onRefreshAll={runAutoAdvance} />;
      case 'ARTIST_DETAIL': {
        const artist = artists.find(a => a.id === nav.artistId);
        if (!artist) return null;
        return <ArtistDetailPage artistId={nav.artistId!} artist={artist} settings={displaySettings} onOpenArtistEditor={navigateToArtistEditor} onOpenConcertEditor={navigateToConcertEditor} onOpenConcertHome={navigateToConcertHome} onChangeSettings={s => setDisplaySettings(p => ({...p, ...s}))} onBack={navigateToArtistList} />;
      }
      case 'CONCERT_HOME': {
        const artist = artists.find(a => a.id === nav.artistId);
        const tour = artist?.tours.find(t => t.id === nav.tourId);
        const concert = tour?.concerts.find(c => c.id === nav.concertId);
        if (!artist || !tour || !concert) return null;
        return <ConcertHomePage artistId={artist.id} concertId={concert.id} artist={artist} tour={tour} concert={concert} onBack={() => navigateToArtistDetail(artist.id)} onOpenConcertEditor={navigateToConcertEditor} onUpdateConcertAlbum={(aid, tid, cid, imgs) => updateConcert(aid, tid, cid, { images: imgs })} />;
      }
      case 'ARTIST_EDITOR': return <ArtistEditorPage artistId={nav.artistId} artist={artists.find(a => a.id === nav.artistId)} onSave={upsertArtist} onCancel={navigateToArtistList} onOpenConcertEditor={navigateToConcertEditor} onDeleteArtist={id => { setArtists(p => p.filter(a => a.id !== id)); navigateToArtistList(); }} />;
      case 'CONCERT_EDITOR': {
        const artist = artists.find(a => a.id === nav.artistId);
        if (!artist) return null;
        return <ConcertEditorPage artistId={artist.id} tourId={nav.tourId} tour={artist.tours.find(t => t.id === nav.tourId)} allArtists={artists} onSave={t => upsertTour(artist.id, t)} onCancel={() => navigateToArtistDetail(artist.id)} onDeleteTour={deleteTour} />;
      }
      default: return null;
    }
  };

  return (
    <div className="app-root">
      <Layout currentPath={nav.path} onNavigate={p => setNav({ path: p })} hasConcertAlert={hasGlobalConcertAlert}>
        {renderPage()}
      </Layout>
      {isArtistPickerOpen && (
        <div style={overlayStyle}>
          <div style={backdropStyle} onClick={() => setIsArtistPickerOpen(false)} />
          <GlassCard padding="24px" style={pickerCardStyle}>
            <h3>アーティストを選択</h3>
            <div style={pickerListStyle}>{artists.map(a => <button key={a.id} onClick={() => { navigateToConcertEditor(a.id); setIsArtistPickerOpen(false); }} style={pickerButtonStyle}>{a.name}</button>)}</div>
            <button onClick={() => setIsArtistPickerOpen(false)} style={closeButtonStyle}>閉じる</button>
          </GlassCard>
        </div>
      )}
    </div>
  );
}

