  const intervals: (3 | 7 | 14 | 21 | 30)[] = [3, 7, 14, 21, 30];

  return (
    <div style={{
      position: 'fixed',
      bottom: '100px',
      right: '16px',
      zIndex: 1000,
      width: '260px',
    }}>
      <div 
        style={{ position: 'fixed', inset: 0, background: 'transparent' }} 
