                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                    <h3 style={{ fontSize: '18px', fontWeight: '900', margin: 0, lineHeight: '1.2' }}>{tour.name}</h3>
                    {tour.officialUrl && (
                      <a 
                        href={tour.officialUrl} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        onClick={(e) => e.stopPropagation()}
                        style={{ 
                          display: 'flex', 
                          color: theme.colors.primary, 
                          padding: '6px',
                          borderRadius: '8px',
                          background: 'rgba(83, 190, 232, 0.08)',
                          marginLeft: '8px'
                        }}
                        title="ツアー公式サイト"
                      >
                        <Icons.Globe />
                      </a>
                    )}
                  </div>
                  <div style={{ marginTop: '6px', display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <span style={{ fontSize: '11px', fontWeight: '800', color: theme.colors.textWeak, background: '#F1F5F9', padding: '2px 8px', borderRadius: '6px' }}>
                      {tour.concerts.length}公演
                    </span>
                  </div>
                </div>
              </div>

              {/* 场次列表 */}
              <div style={{ display: 'flex', flexDirection: 'column' }}>
                {tour.concerts.map((c, idx) => {
                  const isNavigable = c.status === '参戦予定' || c.status === '参戦済み';
                  return (
                    <InstanceRow 
                      key={c.id} 
                      concert={c} 
                      tourOfficialUrl={tour.officialUrl}
                      isLast={idx === tour.concerts.length - 1}
                      onClick={isNavigable ? () => onOpenConcertHome(artistId, tour.id, c.id) : undefined} 
                    />
                  );
                })}
              </div>
            </GlassCard>
          ))
        )}
      </div>

      {/* 浮动操作按钮 */}
      <IconButton 
        icon={isMenuOpen ? <Icons.X /> : <Icons.Plus />} 
        primary 
        size={64} 
        onClick={() => setIsMenuOpen(!isMenuOpen)} 
        style={{ 
          position: 'fixed', 
          right: '16px', 
          bottom: 'calc(16px + env(safe-area-inset-bottom))', 
          zIndex: 110,
          boxShadow: '0 8px 24px -6px rgba(83, 190, 232, 0.5)'
        }} 
      />

      <ArtistDetailMenu 
        isOpen={isMenuOpen} 
        onClose={() => setIsMenuOpen(false)}
        onAddConcert={() => onOpenConcertEditor(artistId)}
        settings={settings}
        onChangeSettings={onChangeSettings}
      />
    </div>
  );
};

import React, { useState, useMemo, useCallback, useEffect } from 'react';
import { PageId, Artist, Tour, DisplaySettings, Status, GlobalSettings, SiteLink, TrackingStatus, TrackingErrorType, Concert } from './domain/types';
import { Layout } from './components/Layout';
import { ArtistListPage } from './pages/ArtistListPage';
import { ConcertListPage } from './pages/ConcertListPage';
import { CalendarPage } from './pages/CalendarPage';
import { ArtistDetailPage } from './pages/ArtistDetailPage';
import { ConcertHomePage } from './pages/ConcertHomePage';
import { ArtistEditorPage } from './pages/ArtistEditorPage';
import { ConcertEditorPage } from './pages/ConcertEditorPage';
import { GlassCard } from './ui/GlassCard';
import { theme } from './ui/theme';
import { shouldTriggerAutoTrack, getTrackTargetConcerts, getDueAction, autoAdvanceConcertStatus } from './domain/logic';

type NavContext = { path: PageId; artistId?: string; tourId?: string; concertId?: string; };

export default function App() {
  const [nav, setNav] = useState<NavContext>({ path: 'ARTIST_LIST' });
  const [isArtistPickerOpen, setIsArtistPickerOpen] = useState(false);
  const [globalSettings, setGlobalSettings] = useState<GlobalSettings>({ autoTrackIntervalDays: 7 });
  const [displaySettings, setDisplaySettings] = useState<DisplaySettings>({ showAttended: true, showSkipped: true });

  // Persistence: Elevated sort modes
  const [artistSortMode, setArtistSortMode] = useState<'manual' | 'status'>('status');
  const [concertSortMode, setConcertSortMode] = useState<'status' | 'lottery'>('status');

  const [artists, setArtists] = useState<Artist[]>([]);

  // Requirement: Global Alert calculation for Nav Red Dot
  const hasGlobalConcertAlert = useMemo(() => {
    const now = new Date();
    return artists.some(a => a.tours.some(t => t.concerts.some(c => !!getDueAction(c, now))));
  }, [artists]);

  // Requirement 6: Automatic advancement runner
  const runAutoAdvance = useCallback(() => {
    const now = new Date();
    setArtists(prev => prev.map(a => ({
      ...a,
      tours: a.tours.map(t => ({
        ...t,
        concerts: t.concerts.map(c => autoAdvanceConcertStatus(c, now))
      }))
    })));
  }, []);

  useEffect(() => {
    runAutoAdvance();
  }, [nav.path, runAutoAdvance]); // Run when switching pages

  const navigateToArtistList = () => setNav({ path: 'ARTIST_LIST' });
  const navigateToArtistDetail = (artistId: string) => setNav({ path: 'ARTIST_DETAIL', artistId });
  const navigateToArtistEditor = (artistId?: string) => setNav({ path: 'ARTIST_EDITOR', artistId });
  const navigateToConcertEditor = (artistId: string, tourId?: string) => setNav({ path: 'CONCERT_EDITOR', artistId, tourId });
  const navigateToConcertHome = (artistId: string, tourId: string, concertId: string) => setNav({ path: 'CONCERT_HOME', artistId, tourId, concertId });

  const upsertArtist = (updated: Artist) => {
    setArtists(prev => {
      const exists = prev.some(a => a.id === updated.id);
      return exists ? prev.map(a => a.id === updated.id ? updated : a) : [...prev, updated];
    });
    navigateToArtistDetail(updated.id);
  };

  const handleUpdateArtistOrder = (newArtists: Artist[]) => {
    setArtists(newArtists.map((a, i) => ({ ...a, order: i })));
  };

  const updateConcert = (artistId: string, tourId: string, concertId: string, updates: Partial<Concert>) => {
    setArtists(prev => prev.map(a => {
      if (a.id !== artistId) return a;
      return {
        ...a,
        tours: a.tours.map(t => {
          if (t.id !== tourId) return t;
          return {
            ...t,
            concerts: t.concerts.map(c => c.id === concertId ? { ...c, ...updates } : c)
          };
        })
      };
    }));
  };

  const upsertTour = (artistId: string, updatedTour: Tour) => {
    setArtists(prev => prev.map(artist => {
      if (artist.id !== artistId) return artist;
      const tourExists = artist.tours.some(t => t.id === updatedTour.id);
      return { ...artist, tours: tourExists ? artist.tours.map(t => t.id === updatedTour.id ? updatedTour : t) : [...artist.tours, updatedTour] };
    }));
    navigateToArtistDetail(artistId);
  };

  const deleteTour = (artistId: string, tourId: string) => {
    setArtists(prev => prev.map(artist => artist.id !== artistId ? artist : { ...artist, tours: artist.tours.filter(t => t.id !== tourId) }));
    navigateToArtistDetail(artistId);
  };

  const renderPage = () => {
    switch (nav.path) {
      case 'ARTIST_LIST': 
        return (
          <ArtistListPage 
            artists={artists} 
            onOpenArtist={navigateToArtistDetail} 
            onOpenArtistEditor={() => navigateToArtistEditor()} 
            onRefreshAll={runAutoAdvance} 
            onImportData={setArtists} 
            globalSettings={globalSettings} 
            onUpdateGlobalSettings={setGlobalSettings}
            sortMode={artistSortMode}
            onSetSort={setArtistSortMode}
            onUpdateOrder={handleUpdateArtistOrder}
          />
        );
      case 'CONCERT_LIST': 
        return (
          <ConcertListPage 
            artists={artists} 
            onOpenArtist={navigateToArtistDetail} 
            onOpenConcert={navigateToConcertHome} 
            onCreateConcert={() => setIsArtistPickerOpen(true)} 
            onRefreshAll={runAutoAdvance} 
            onUpdateConcert={updateConcert} 
            sortMode={concertSortMode}
            onSetSort={setConcertSortMode}
          />
        );
      case 'CALENDAR': 
        return <CalendarPage artists={artists} onOpenArtist={navigateToArtistDetail} onOpenConcert={navigateToConcertHome} onRefreshAll={runAutoAdvance} />;
      case 'ARTIST_DETAIL': {
        const artist = artists.find(a => a.id === nav.artistId);
        if (!artist) return null;
        return <ArtistDetailPage artistId={nav.artistId!} artist={artist} settings={displaySettings} onOpenArtistEditor={navigateToArtistEditor} onOpenConcertEditor={navigateToConcertEditor} onOpenConcertHome={navigateToConcertHome} onChangeSettings={s => setDisplaySettings(p => ({...p, ...s}))} onBack={navigateToArtistList} />;
      }
      case 'CONCERT_HOME': {
        const artist = artists.find(a => a.id === nav.artistId);
        const tour = artist?.tours.find(t => t.id === nav.tourId);
        const concert = tour?.concerts.find(c => c.id === nav.concertId);
        if (!artist || !tour || !concert) return null;
        return <ConcertHomePage artistId={artist.id} concertId={concert.id} artist={artist} tour={tour} concert={concert} onBack={() => navigateToArtistDetail(artist.id)} onOpenConcertEditor={navigateToConcertEditor} onUpdateConcertAlbum={(aid, tid, cid, imgs) => updateConcert(aid, tid, cid, { images: imgs })} />;
      }
      case 'ARTIST_EDITOR': return <ArtistEditorPage artistId={nav.artistId} artist={artists.find(a => a.id === nav.artistId)} onSave={upsertArtist} onCancel={navigateToArtistList} onOpenConcertEditor={navigateToConcertEditor} onDeleteArtist={id => { setArtists(p => p.filter(a => a.id !== id)); navigateToArtistList(); }} />;
      case 'CONCERT_EDITOR': {
        const artist = artists.find(a => a.id === nav.artistId);
        if (!artist) return null;
        return <ConcertEditorPage artistId={artist.id} tourId={nav.tourId} tour={artist.tours.find(t => t.id === nav.tourId)} allArtists={artists} onSave={t => upsertTour(artist.id, t)} onCancel={() => navigateToArtistDetail(artist.id)} onDeleteTour={deleteTour} />;
      }
      default: return null;
    }
  };

  return (
    <div className="app-root">
      <Layout currentPath={nav.path} onNavigate={p => setNav({ path: p })} hasConcertAlert={hasGlobalConcertAlert}>
        {renderPage()}
      </Layout>
      {isArtistPickerOpen && (
        <div style={overlayStyle}>
          <div style={backdropStyle} onClick={() => setIsArtistPickerOpen(false)} />
          <GlassCard padding="24px" style={pickerCardStyle}>
            <h3>アーティストを選択</h3>
            <div style={pickerListStyle}>{artists.map(a => <button key={a.id} onClick={() => { navigateToConcertEditor(a.id); setIsArtistPickerOpen(false); }} style={pickerButtonStyle}>{a.name}</button>)}</div>
            <button onClick={() => setIsArtistPickerOpen(false)} style={closeButtonStyle}>閉じる</button>
          </GlassCard>
        </div>
      )}
    </div>
  );
}

const overlayStyle: React.CSSProperties = { position: 'fixed', inset: 0, zIndex: 2000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '24px' };
const backdropStyle: React.CSSProperties = { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)', backdropFilter: 'blur(8px)' };
const pickerCardStyle: React.CSSProperties = { width: '100%', maxWidth: '360px', position: 'relative' };
const pickerListStyle: React.CSSProperties = { display: 'flex', flexDirection: 'column', gap: '10px', maxHeight: '300px', overflowY: 'auto' };
const pickerButtonStyle: React.CSSProperties = { padding: '16px', borderRadius: '16px', border: '1px solid rgba(0,0,0,0.05)', background: 'white', textAlign: 'left', fontWeight: '700', fontSize: '15px', cursor: 'pointer' };
const closeButtonStyle: React.CSSProperties = { padding: '12px', borderRadius: '12px', border: 'none', background: 'rgba(0,0,0,0.05)', fontWeight: '700', cursor: 'pointer', marginTop: '16px', width: '100%' };

import React, { useState, useMemo, useRef } from 'react';
import { BottomMenu } from '../components/BottomMenu';
import { ConfirmDialog } from '../components/ConfirmDialog';
import { IconButton, Icons } from '../ui/IconButton';
import { PageShell } from '../ui/PageShell';
import { theme } from '../ui/theme';
import { TEXT } from '../ui/constants';
import { PageId, Artist, GlobalSettings, Status } from '../domain/types';
import { calcArtistStatus, sortArtistsForDisplay } from '../domain/logic';

interface Props {
  artists: Artist[];
  onOpenArtist: (artistId: string) => void;
  onOpenArtistEditor: () => void;
  onRefreshAll: () => void;
  onImportData: (data: Artist[]) => void;
  globalSettings: GlobalSettings;
  onUpdateGlobalSettings: (settings: GlobalSettings) => void;
  sortMode: 'manual' | 'status';
  onSetSort: (mode: 'manual' | 'status') => void;
  onUpdateOrder: (newArtists: Artist[]) => void;
}

const ArtistRowCard: React.FC<{ 
  artist: Artist; 
  onClick: () => void; 
  draggable?: boolean;
  onDragStart?: () => void;
  onDragEnter?: () => void;
  onDragEnd?: () => void;
}> = ({ artist, onClick, draggable, onDragStart, onDragEnter, onDragEnd }) => {
  const [isHovered, setIsHovered] = useState(false);

  const status = calcArtistStatus(artist);

  const dotColor = useMemo(() => {
    if (status.main === TEXT.ARTIST_STATUS.MAIN_TOURING && status.sub) {
      return theme.colors.status[status.sub as Status] || theme.colors.primary;
    }
    if (status.main === TEXT.ARTIST_STATUS.MAIN_TRACKING) {
      return '#00ffff';
    }
    return theme.colors.textLabel;
  }, [status]);

  return (
    <div
      onClick={onClick}
      draggable={draggable}
      onDragStart={onDragStart}
      onDragEnter={onDragEnter}
      onDragEnd={onDragEnd}
      onDragOver={(e) => draggable && e.preventDefault()}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      style={{
        background: 'white',
        borderRadius: theme.radius.card,
        border: '1px solid rgba(0, 0, 0, 0.04)',
        padding: '20px 24px',
        display: 'flex',
        alignItems: 'center',
        gap: '20px',
        cursor: draggable ? 'grabbing' : 'pointer',
        boxShadow: isHovered 
          ? '0 10px 20px -5px rgba(0, 0, 0, 0.06)' 
          : '0 4px 12px -2px rgba(0, 0, 0, 0.03)',
        transform: isHovered ? 'scale(1.015)' : 'scale(1)',
        transition: 'all 0.3s cubic-bezier(0.16, 1, 0.3, 1)',
        opacity: draggable && isHovered ? 0.7 : 1
      }}
    >
      <div style={{
        width: '68px',
        height: '68px',
        borderRadius: '50%',
        background: '#F3F4F6',
        flexShrink: 0,
        border: '3px solid white',
        boxShadow: '0 2px 8px rgba(0,0,0,0.08)',
        overflow: 'hidden',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center'
      }}>
        {artist.imageUrl ? (
          <img src={artist.imageUrl} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
        ) : (
          <span style={{ fontSize: '24px', opacity: 0.2 }}>👤</span>
        )}
      </div>

      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{
          fontWeight: '800',
          fontSize: '19px',
          color: isHovered ? theme.colors.primary : theme.colors.text,
          marginBottom: '6px',
          transition: 'color 0.2s ease'
        }}>
          {artist.name}
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
          <div style={{
            width: '8px',
            height: '8px',
            borderRadius: '50%',
            background: dotColor,
          }} />
          <div style={{
            fontSize: '11px',
            fontWeight: '600',
            color: theme.colors.textSecondary,
            letterSpacing: '0.05em',
            textTransform: 'uppercase'
          }}>
            {status.main}
            {status.sub && (
              <span style={{ color: theme.colors.textWeak, marginLeft: '8px', fontWeight: '400' }}>
                / {TEXT.STATUS[status.sub]}
              </span>
            )}
          </div>
        </div>
      </div>

      <div style={{ color: theme.colors.textLabel, display: 'flex', alignItems: 'center', gap: '8px' }}>
        {draggable && (
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ opacity: 0.5 }}>
            <line x1="8" y1="9" x2="16" y2="9"></line>
            <line x1="8" y1="15" x2="16" y2="15"></line>
          </svg>
        )}
        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <polyline points="9 18 15 12 9 6"></polyline>
        </svg>
      </div>
    </div>
  );
};

export const ArtistListPage: React.FC<Props> = ({ 
  artists, 
  onOpenArtist, 
  onOpenArtistEditor, 
  onRefreshAll,
  onImportData,
  globalSettings,
  onUpdateGlobalSettings,
  sortMode,
  onSetSort,
  onUpdateOrder
}) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isImportConfirmOpen, setIsImportConfirmOpen] = useState(false);
  const [stagedImportData, setStagedImportData] = useState<Artist[] | null>(null);
  const [refreshState, setRefreshState] = useState<'idle' | 'refreshing' | 'completed'>('idle');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);

  const sortedArtists = useMemo(() => {
    if (sortMode === 'manual') {
      return [...artists].sort((a, b) => (a.order ?? 0) - (b.order ?? 0));
    }
    return sortArtistsForDisplay(artists, sortMode);
  }, [artists, sortMode]);

  const handleRefresh = () => {
    if (refreshState !== 'idle') return;

    setRefreshState('refreshing');
    onRefreshAll();

    // Duration of spin animation
    setTimeout(() => {
      setRefreshState('completed');
      // Duration of showing the checkmark
      setTimeout(() => {
        setRefreshState('idle');
      }, 1200);
    }, 800);
  };

  const handleDragStart = (index: number) => {
    dragItem.current = index;
  };

  const handleDragEnter = (index: number) => {
    dragOverItem.current = index;
  };

  const handleDragEnd = () => {
    if (dragItem.current !== null && dragOverItem.current !== null && dragItem.current !== dragOverItem.current) {
      const newList = [...sortedArtists];
      const draggedItemContent = newList[dragItem.current];
      newList.splice(dragItem.current, 1);
      newList.splice(dragOverItem.current, 0, draggedItemContent);
      onUpdateOrder(newList);
    }
    dragItem.current = null;
    dragOverItem.current = null;
  };

  const handleExport = () => {
    try {
      const dataStr = JSON.stringify(artists, null, 2);
      const blob = new Blob([dataStr], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      const date = new Date().toISOString().split('T')[0];
      link.href = url;
      link.download = `LiveTrack_JP_Backup_${date}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
      setIsMenuOpen(false);
    } catch (error) {
      console.error('Export failed:', error);
    }
  };

  const handleImportClick = () => {
    setIsMenuOpen(false);
    fileInputRef.current?.click();
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = JSON.parse(e.target?.result as string);
        if (Array.isArray(json)) {
          setStagedImportData(json);
          setIsImportConfirmOpen(true);
        }
      } catch (err) {
        console.error('Import failed:', err);
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  const executeImport = () => {
    if (stagedImportData) {
      onImportData(stagedImportData);
      setStagedImportData(null);
    }
    setIsImportConfirmOpen(false);
  };

  return (
    <PageShell
      header={
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingBottom: '8px' }}>
          <h1 style={{ fontSize: '32px', fontWeight: '900', color: '#111827', margin: 0, letterSpacing: '-0.025em' }}>
            {TEXT.GLOBAL.APP_TITLE} <span style={{ color: '#53BEE8' }}>JP</span>
          </h1>
          <button 
            onClick={handleRefresh} 
            disabled={refreshState !== 'idle'}
            style={{ 
              padding: '12px', 
              borderRadius: '9999px', 
              background: 'white', 
              border: refreshState === 'completed' ? `1px solid ${theme.colors.success}` : '1px solid #F3F4F6', 
              color: refreshState === 'completed' ? theme.colors.success : (refreshState === 'refreshing' ? theme.colors.primary : '#9CA3AF'), 
              boxShadow: '0 1px 2px 0 rgba(0, 0, 0, 0.05)', 
              cursor: refreshState === 'idle' ? 'pointer' : 'default', 
              outline: 'none',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              transition: 'all 0.3s ease'
            }}
          >
            {refreshState === 'completed' ? (
              <Icons.Check className="animate-pop-in" />
            ) : (
              <Icons.Refresh className={refreshState === 'refreshing' ? 'animate-spin' : ''} />
            )}
          </button>
        </div>
      }
    >
      <input 
        type="file" 
        ref={fileInputRef} 
        style={{ display: 'none' }} 
        accept=".json" 
        onChange={handleFileChange} 
      />

      <div style={{ display: 'flex', flexDirection: 'column', gap: '16px', paddingBottom: '120px' }}>
        {sortedArtists.length === 0 ? (
          <div style={{ 
            padding: '80px 20px', 
            textAlign: 'center', 
            color: theme.colors.textWeak,
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            gap: '24px'
          }}>
            <div style={{ fontSize: '48px', opacity: 0.5 }}>👤</div>
            <div style={{ fontSize: '15px', fontWeight: '600' }}>{TEXT.GLOBAL.APP_SUBTITLE}</div>
            <button 
              onClick={onOpenArtistEditor}
              style={{
                padding: '12px 24px',
                borderRadius: '12px',
                background: theme.colors.primary,
                color: 'white',
                border: 'none',
                fontWeight: 'bold',
                cursor: 'pointer'
              }}
            >
              ＋ {TEXT.BUTTONS.ADD}
            </button>
          </div>
        ) : (
          sortedArtists.map((artist, index) => (
            <ArtistRowCard 
              key={artist.id} 
              artist={artist} 
              onClick={() => onOpenArtist(artist.id)} 
              draggable={sortMode === 'manual'}
              onDragStart={() => handleDragStart(index)}
              onDragEnter={() => handleDragEnter(index)}
              onDragEnd={handleDragEnd}
            />
          ))
        )}
      </div>

      <IconButton 
        icon={isMenuOpen ? <Icons.X /> : <Icons.Plus />} 
        primary 
        size={64} 
        onClick={() => setIsMenuOpen(!isMenuOpen)} 
        style={{ 
          position: 'fixed', 
          right: '16px', 
          bottom: 'calc(16px + env(safe-area-inset-bottom))', 
          zIndex: 110,
          boxShadow: '0 8px 24px -6px rgba(83, 190, 232, 0.5)'
        }} 
      />

      <BottomMenu 
        isOpen={isMenuOpen} 
        onClose={() => setIsMenuOpen(false)} 
        onAddArtist={onOpenArtistEditor}
        onExport={handleExport} 
        onImport={handleImportClick}
        currentSort={sortMode}
        onSetSort={onSetSort}
        globalSettings={globalSettings}
        onUpdateGlobalSettings={onUpdateGlobalSettings}
      />
      <ConfirmDialog 
        isOpen={isImportConfirmOpen} 
        title={TEXT.ALERTS.IMPORT_CONFIRM_TITLE} 
        message={TEXT.ALERTS.IMPORT_CONFIRM_MSG} 
        confirmLabel={TEXT.BUTTONS.IMPORT} 
        isDestructive 
        onClose={() => { setIsImportConfirmOpen(false); setStagedImportData(null); }} 
        onConfirm={executeImport} 
      />
    </PageShell>
  );
};

