          <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: current.color }} />
          {current.label}
        </div>
        <span style={{ fontSize: '10px', opacity: 0.5 }}>{isOpen ? '▲' : '▼'}</span>
      </div>
      {isOpen && (
        <><div style={{ position: 'fixed', inset: 0, zIndex: 100 }} onClick={() => setIsOpen(false)} />
