              <div style={{ fontSize: '48px', marginBottom: '16px', opacity: 0.3 }}>🎪</div>
              <div style={{ fontWeight: '600' }}>表示可能な公演がありません</div>
            </div>
          ) : (
            processedTours.map(tour => (
