import React, { useState, useEffect, useRef } from 'react';
import { theme } from '../ui/theme';
import { TEXT } from '../ui/constants';
import { GlassCard } from '../ui/GlassCard';
import { ConfirmDialog } from '../components/ConfirmDialog';
import { Artist, SiteLink } from '../domain/types';
import { Icons, IconButton } from '../ui/IconButton';
import { PageShell } from '../ui/PageShell';

interface Props {
  artistId?: string;
  artist?: Artist;
  onSave: (updated: Artist) => void;
  onCancel: () => void;
  onDeleteArtist: (artistId: string) => void;
}

const generateId = () => Math.random().toString(36).substr(2, 9);

const normalizeLink = (link: Partial<SiteLink> | undefined | null): SiteLink => {
  const safeName = typeof link?.name === 'string' ? link!.name : '';
  const safeUrl = typeof link?.url === 'string' ? link!.url : '';
  const safeAutoTrack = typeof link?.autoTrack === 'boolean' ? link!.autoTrack : false;
  return {
    name: safeName,
    url: safeUrl,
    autoTrack: safeAutoTrack,
    lastCheckedAt: link?.lastCheckedAt,
    lastSuccessAt: link?.lastSuccessAt,
    trackingStatus: link?.trackingStatus,
    errorMessage: link?.errorMessage,
  };
};

export const ArtistEditorPage: React.FC<Props> = ({
  artistId,
  artist,
  onSave,
  onCancel,
  onDeleteArtist,
}) => {
  const createNewArtist = (): Artist => ({
    id: generateId(),
    name: '',
    imageUrl: '',
    links: [],
    autoTrackConcerts: true,
    autoTrackTickets: true,
    tours: [],
    order: 0,
  });

  const [formData, setFormData] = useState<Artist>(artist ? { ...artist } : createNewArtist());
  const initialSnapshotRef = useRef<string>(JSON.stringify(artist ? { ...artist } : formData));
  const [imageUrlDraft, setImageUrlDraft] = useState(formData.imageUrl);
  const [hasChanges, setHasChanges] = useState(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [isBackConfirmOpen, setIsBackConfirmOpen] = useState(false);

  useEffect(() => {
    if (artist) {
      setFormData({ ...artist });
      setImageUrlDraft(artist.imageUrl);
      initialSnapshotRef.current = JSON.stringify(artist);
    }
  }, [artistId, artist]);

  useEffect(() => {
    setHasChanges(JSON.stringify(formData) !== initialSnapshotRef.current);
  }, [formData]);

  const handleUpdateField = (field: keyof Artist, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  const handleLoadImage = () => {
    if (imageUrlDraft.trim()) {
      handleUpdateField('imageUrl', imageUrlDraft.trim());
    }
  };

  const handleBack = () => {
    if (hasChanges) {
      setIsBackConfirmOpen(true);
    } else {
      onCancel();
    }
  };

  const setLinks = (updater: (prev: SiteLink[]) => SiteLink[]) => {
    setFormData((prev) => {
      const current = Array.isArray(prev.links) ? prev.links : [];
      return { ...prev, links: updater(current) };
    });
  };

  const addLink = () => {
    setLinks((prev) => [...prev, { name: '', url: '', autoTrack: false }]);
  };

  const updateLink = (index: number, patch: Partial<SiteLink>) => {
    setLinks((prev) =>
      prev.map((l, i) => i !== index ? l : { ...normalizeLink(l), ...patch })
    );
  };

  const removeLink = (index: number) => {
    setLinks((prev) => prev.filter((_, i) => i !== index));
  };

  return (
    <PageShell
      header={
        <header style={headerStyle}>
          <IconButton
            icon={<Icons.X />}
            onClick={handleBack}
            size={40}
            style={{ color: theme.colors.textSecondary, borderColor: 'transparent', background: 'transparent', boxShadow: 'none' }}
          />
          <h2 style={{ fontSize: '17px', margin: 0, fontWeight: 'bold' }}>
            {artistId ? 'アーティスト編集' : 'アーティスト追加'}
          </h2>
          {artistId ? (
            <IconButton
              icon={<Icons.Trash />}
              onClick={() => setIsDeleteModalOpen(true)}
              size={40}
              style={{ color: theme.colors.error, borderColor: 'transparent', background: 'transparent', boxShadow: 'none' }}
            />
          ) : (
            <div style={{ width: 40 }} />
          )}
        </header>
      }
    >
      <div style={{ paddingBottom: '160px' }}>
        <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '24px' }}>
          <div style={{ width: '100px', height: '100px', borderRadius: '50%', background: '#F3F4F6', border: '4px solid white', boxShadow: '0 4px 12px rgba(0,0,0,0.1)', overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            {formData.imageUrl ? (
              <img src={formData.imageUrl} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
            ) : (
              <span style={{ fontSize: '32px', opacity: 0.2 }}>👤</span>
            )}
          </div>
        </div>

        <section style={{ marginBottom: theme.spacing.xl }}>
          <h3 style={sectionTitleStyle}>基本情報</h3>
          <GlassCard padding={theme.spacing.md}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.md }}>
              <Field label="アーティスト名 (必须)">
                <input type="text" value={formData.name} onChange={(e) => handleUpdateField('name', e.target.value)} placeholder="名称を入力" style={inputStyle} />
              </Field>
              <Field label="画像URL">
                <div style={{ display: 'flex', gap: '8px' }}>
                  <input type="url" value={imageUrlDraft} onChange={(e) => setImageUrlDraft(e.target.value)} placeholder="https://..." style={inputStyle} />
                  <button onClick={handleLoadImage} style={loadButtonStyle}>読み込み</button>
                </div>
              </Field>
            </div>
          </GlassCard>
        </section>

        <section style={{ marginBottom: theme.spacing.xl }}>
          <h3 style={sectionTitleStyle}>追跡設定</h3>
          <GlassCard padding={theme.spacing.md}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.lg }}>
              <ToggleRow label="公演自動追跡" subLabel="新規ツアー・公演情報を自動取得します" active={formData.autoTrackConcerts} onToggle={() => handleUpdateField('autoTrackConcerts', !formData.autoTrackConcerts)} />
              <ToggleRow label="チケット自動追跡" subLabel="販売・抽選情報を自动更新します" active={formData.autoTrackTickets} onToggle={() => handleUpdateField('autoTrackTickets', !formData.autoTrackTickets)} />
            </div>
          </GlassCard>
        </section>

        <section style={{ marginBottom: theme.spacing.xl }}>
          <h3 style={sectionTitleStyle}>公式サイト・リンク</h3>
          <GlassCard padding={theme.spacing.md}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.md }}>
              {formData.links.map((link, idx) => {
                const safe = normalizeLink(link);
                return (
                  <div key={idx} style={linkBoxStyle}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px' }}>
                      <span style={{ fontSize: '12px', color: theme.colors.textSecondary, fontWeight: 800 }}>サイト {idx + 1}</span>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                        <Toggle active={safe.autoTrack} onToggle={() => updateLink(idx, { autoTrack: !safe.autoTrack })} />
                        <button onClick={() => removeLink(idx)} style={iconBtnStyle}><Icons.Trash /></button>
                      </div>
                    </div>
                    <Field label="サイト名">
                      <input type="text" value={safe.name} onChange={(e) => updateLink(idx, { name: e.target.value })} placeholder="公式サイト等" style={inputStyle} />
                    </Field>
                    <div style={{ height: '8px' }} />
                    <Field label="URL">
                      <input type="url" value={safe.url} onChange={(e) => updateLink(idx, { url: e.target.value })} placeholder="https://..." style={inputStyle} />
                    </Field>
                  </div>
                );
              })}
              <button onClick={addLink} style={addLinkButtonStyle}>＋ サイトを追加</button>
            </div>
          </GlassCard>
        </section>

        <button
          disabled={!hasChanges || !formData.name}
          onClick={() => onSave(formData)}
          style={{
            width: '100%', padding: '16px', borderRadius: theme.radius.button, fontWeight: 'bold', fontSize: '16px', cursor: 'pointer', border: 'none', color: 'white',
            background: !hasChanges || !formData.name ? 'rgba(0,0,0,0.05)' : theme.colors.primary,
          }}
        >
          {TEXT.BUTTONS.SAVE}
        </button>

        <ConfirmDialog isOpen={isDeleteModalOpen} title={TEXT.ALERTS.DELETE_ARTIST_TITLE} message={TEXT.ALERTS.DELETE_ARTIST_MSG} confirmLabel={TEXT.BUTTONS.DELETE} isDestructive onClose={() => setIsDeleteModalOpen(false)} onConfirm={() => onDeleteArtist(formData.id)} />
        <ConfirmDialog isOpen={isBackConfirmOpen} title="変更を破棄しますか？" message="編集した内容は保存されません。戻りますか？" confirmLabel="戻る" onClose={() => setIsBackConfirmOpen(false)} onConfirm={onCancel} />
      </div>
    </PageShell>
  );
};

const headerStyle: React.CSSProperties = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', position: 'sticky', top: 0, zIndex: 100, background: theme.colors.background, padding: `${theme.spacing.sm} 0` };
const sectionTitleStyle: React.CSSProperties = { fontSize: '13px', color: theme.colors.textSecondary, fontWeight: 'bold', marginBottom: theme.spacing.sm, paddingLeft: '4px' };
const inputStyle: React.CSSProperties = { width: '100%', padding: '10px 12px', borderRadius: '10px', border: '1px solid rgba(0,0,0,0.08)', background: 'rgba(255,255,255,0.4)', fontSize: '15px', outline: 'none' };
const loadButtonStyle: React.CSSProperties = { padding: '0 16px', borderRadius: '12px', border: '1px solid rgba(0,0,0,0.08)', background: 'white', color: theme.colors.textSecondary, fontSize: '13px', fontWeight: 'bold', cursor: 'pointer', whiteSpace: 'nowrap' };
const addLinkButtonStyle: React.CSSProperties = { padding: '12px', borderRadius: '14px', border: '1px dashed rgba(0,0,0,0.12)', background: 'rgba(255,255,255,0.25)', color: theme.colors.primary, fontWeight: 900, fontSize: '13px', cursor: 'pointer' };
const linkBoxStyle: React.CSSProperties = { border: '1px solid rgba(0,0,0,0.06)', background: 'rgba(255,255,255,0.35)', borderRadius: '16px', padding: '12px' };
const iconBtnStyle: React.CSSProperties = { border: 'none', background: 'transparent', color: theme.colors.textSecondary, cursor: 'pointer', padding: '6px' };

const Field = ({ label, children }: any) => (
  <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
    <label style={{ fontSize: '12px', color: theme.colors.textSecondary, marginLeft: '4px' }}>{label}</label>
    {children}
  </div>
);

const ToggleRow = ({ label, subLabel, active, onToggle }: any) => (
  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
    <div>
      <div style={{ fontWeight: '600', fontSize: '15px' }}>{label}</div>
      <div style={{ fontSize: '12px', color: theme.colors.textSecondary }}>{subLabel}</div>
    </div>
    <Toggle active={active} onToggle={onToggle} />
  </div>
);

const Toggle = ({ active, onToggle }: any) => (
  <div onClick={onToggle} style={{ width: '46px', height: '26px', borderRadius: '13px', background: active ? theme.colors.primary : '#E9E9EB', position: 'relative', cursor: 'pointer' }}>
    <div style={{ position: 'absolute', top: '2px', left: active ? '22px' : '2px', width: '22px', height: '22px', borderRadius: '11px', background: 'white', transition: 'left 0.2s' }} />
  </div>
);

import React, { useState, useMemo, useCallback, useEffect } from 'react';
import { PageId, Artist, Tour, DisplaySettings, Status, GlobalSettings, SiteLink, TrackingStatus, TrackingErrorType, Concert } from './domain/types';
import { Layout } from './components/Layout';
import { ArtistListPage } from './pages/ArtistListPage';
import { ConcertListPage } from './pages/ConcertListPage';
import { CalendarPage } from './pages/CalendarPage';
import { ArtistDetailPage } from './pages/ArtistDetailPage';
import { ConcertHomePage } from './pages/ConcertHomePage';
import { ArtistEditorPage } from './pages/ArtistEditorPage';
import { ConcertEditorPage } from './pages/ConcertEditorPage';
import { GlassCard } from './ui/GlassCard';
import { theme } from './ui/theme';
import { shouldTriggerAutoTrack, getTrackTargetConcerts, getDueAction, autoAdvanceConcertStatus } from './domain/logic';

type NavContext = { path: PageId; artistId?: string; tourId?: string; concertId?: string; };

export default function App() {
  const [nav, setNav] = useState<NavContext>({ path: 'ARTIST_LIST' });
  const [isArtistPickerOpen, setIsArtistPickerOpen] = useState(false);
  const [globalSettings, setGlobalSettings] = useState<GlobalSettings>({ autoTrackIntervalDays: 7 });
  const [displaySettings, setDisplaySettings] = useState<DisplaySettings>({ showAttended: true, showSkipped: true });

  // Persistence: Elevated sort modes
  const [artistSortMode, setArtistSortMode] = useState<'manual' | 'status'>('status');
  const [concertSortMode, setConcertSortMode] = useState<'status' | 'lottery'>('status');

  const [artists, setArtists] = useState<Artist[]>([]);

  // Requirement: Global Alert calculation for Nav Red Dot
  const hasGlobalConcertAlert = useMemo(() => {
    const now = new Date();
    return artists.some(a => a.tours.some(t => t.concerts.some(c => !!getDueAction(c, now))));
  }, [artists]);

  // Requirement 6: Automatic advancement runner
  const runAutoAdvance = useCallback(() => {
    const now = new Date();
    setArtists(prev => prev.map(a => ({
      ...a,
      tours: a.tours.map(t => ({
        ...t,
        concerts: t.concerts.map(c => autoAdvanceConcertStatus(c, now))
      }))
    })));
  }, []);

  useEffect(() => {
    runAutoAdvance();
  }, [nav.path, runAutoAdvance]); // Run when switching pages

  const navigateToArtistList = () => setNav({ path: 'ARTIST_LIST' });
  const navigateToArtistDetail = (artistId: string) => setNav({ path: 'ARTIST_DETAIL', artistId });
  const navigateToArtistEditor = (artistId?: string) => setNav({ path: 'ARTIST_EDITOR', artistId });
  const navigateToConcertEditor = (artistId: string, tourId?: string) => setNav({ path: 'CONCERT_EDITOR', artistId, tourId });
  const navigateToConcertHome = (artistId: string, tourId: string, concertId: string) => setNav({ path: 'CONCERT_HOME', artistId, tourId, concertId });

  const upsertArtist = (updated: Artist) => {
    setArtists(prev => {
      const exists = prev.some(a => a.id === updated.id);
      return exists ? prev.map(a => a.id === updated.id ? updated : a) : [...prev, updated];
    });
    navigateToArtistDetail(updated.id);
  };

  const handleUpdateArtistOrder = (newArtists: Artist[]) => {
    setArtists(newArtists.map((a, i) => ({ ...a, order: i })));
  };

  const updateConcert = (artistId: string, tourId: string, concertId: string, updates: Partial<Concert>) => {
    setArtists(prev => prev.map(a => {
      if (a.id !== artistId) return a;
      return {
        ...a,
        tours: a.tours.map(t => {
          if (t.id !== tourId) return t;
          return {
            ...t,
            concerts: t.concerts.map(c => c.id === concertId ? { ...c, ...updates } : c)
          };
        })
      };
    }));
  };

  const upsertTour = (artistId: string, updatedTour: Tour) => {
    setArtists(prev => prev.map(artist => {
      if (artist.id !== artistId) return artist;
      const tourExists = artist.tours.some(t => t.id === updatedTour.id);
      return { ...artist, tours: tourExists ? artist.tours.map(t => t.id === updatedTour.id ? updatedTour : t) : [...artist.tours, updatedTour] };
    }));
    navigateToArtistDetail(artistId);
  };

  const deleteTour = (artistId: string, tourId: string) => {
    setArtists(prev => prev.map(artist => artist.id !== artistId ? artist : { ...artist, tours: artist.tours.filter(t => t.id !== tourId) }));
    navigateToArtistDetail(artistId);
  };

  const renderPage = () => {
    switch (nav.path) {
      case 'ARTIST_LIST': 
        return (
          <ArtistListPage 
            artists={artists} 
            onOpenArtist={navigateToArtistDetail} 
            onOpenArtistEditor={() => navigateToArtistEditor()} 
            onRefreshAll={runAutoAdvance} 
            onImportData={setArtists} 
            globalSettings={globalSettings} 
            onUpdateGlobalSettings={setGlobalSettings}
            sortMode={artistSortMode}
            onSetSort={setArtistSortMode}
            onUpdateOrder={handleUpdateArtistOrder}
          />
        );
      case 'CONCERT_LIST': 
        return (
          <ConcertListPage 
            artists={artists} 
            onOpenArtist={navigateToArtistDetail} 
            onOpenConcert={navigateToConcertHome} 
            onCreateConcert={() => setIsArtistPickerOpen(true)} 
            onRefreshAll={runAutoAdvance} 
            onUpdateConcert={updateConcert} 
            sortMode={concertSortMode}
            onSetSort={setConcertSortMode}
          />
        );
      case 'CALENDAR': 
        return <CalendarPage artists={artists} onOpenArtist={navigateToArtistDetail} onOpenConcert={navigateToConcertHome} onRefreshAll={runAutoAdvance} />;
      case 'ARTIST_DETAIL': {
        const artist = artists.find(a => a.id === nav.artistId);
        if (!artist) return null;
        return <ArtistDetailPage artistId={nav.artistId!} artist={artist} settings={displaySettings} onOpenArtistEditor={navigateToArtistEditor} onOpenConcertEditor={navigateToConcertEditor} onOpenConcertHome={navigateToConcertHome} onChangeSettings={s => setDisplaySettings(p => ({...p, ...s}))} onBack={navigateToArtistList} />;
      }
      case 'CONCERT_HOME': {
        const artist = artists.find(a => a.id === nav.artistId);
        const tour = artist?.tours.find(t => t.id === nav.tourId);
        const concert = tour?.concerts.find(c => c.id === nav.concertId);
        if (!artist || !tour || !concert) return null;
        return <ConcertHomePage artistId={artist.id} concertId={concert.id} artist={artist} tour={tour} concert={concert} onBack={() => navigateToArtistDetail(artist.id)} onOpenConcertEditor={navigateToConcertEditor} onUpdateConcertAlbum={(aid, tid, cid, imgs) => updateConcert(aid, tid, cid, { images: imgs })} />;
      }
      case 'ARTIST_EDITOR': return (
        <ArtistEditorPage 
          artistId={nav.artistId} 
          artist={artists.find(a => a.id === nav.artistId)} 
          onSave={upsertArtist} 
          onCancel={() => {
            if (nav.artistId) {
              navigateToArtistDetail(nav.artistId);
            } else {
              navigateToArtistList();
            }
          }} 
          // Fixed: Removed onOpenConcertEditor as it is not used in ArtistEditorPage component or props.
          onDeleteArtist={id => { 
            setArtists(p => p.filter(a => a.id !== id)); 
            navigateToArtistList(); 
          }} 
        />
      );
      case 'CONCERT_EDITOR': {
        const artist = artists.find(a => a.id === nav.artistId);
        if (!artist) return null;
        return <ConcertEditorPage artistId={artist.id} tourId={nav.tourId} tour={artist.tours.find(t => t.id === nav.tourId)} allArtists={artists} onSave={t => upsertTour(artist.id, t)} onCancel={() => navigateToArtistDetail(artist.id)} onDeleteTour={deleteTour} />;
      }
      default: return null;
    }
  };

  return (
    <div className="app-root">
      <Layout currentPath={nav.path} onNavigate={p => setNav({ path: p })} hasConcertAlert={hasGlobalConcertAlert}>
        {renderPage()}
      </Layout>
      {isArtistPickerOpen && (
        <div style={overlayStyle}>
          <div style={backdropStyle} onClick={() => setIsArtistPickerOpen(false)} />
          <GlassCard padding="24px" style={pickerCardStyle}>
            <h3>アーティストを選択</h3>
            <div style={pickerListStyle}>{artists.map(a => <button key={a.id} onClick={() => { navigateToConcertEditor(a.id); setIsArtistPickerOpen(false); }} style={pickerButtonStyle}>{a.name}</button>)}</div>
            <button onClick={() => setIsArtistPickerOpen(false)} style={closeButtonStyle}>閉じる</button>
          </GlassCard>
        </div>
      )}
    </div>
  );
}

const overlayStyle: React.CSSProperties = { position: 'fixed', inset: 0, zIndex: 2000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '24px' };
const backdropStyle: React.CSSProperties = { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)', backdropFilter: 'blur(8px)' };
const pickerCardStyle: React.CSSProperties = { width: '100%', maxWidth: '360px', position: 'relative' };
const pickerListStyle: React.CSSProperties = { display: 'flex', flexDirection: 'column', gap: '10px', maxHeight: '300px', overflowY: 'auto' };
const pickerButtonStyle: React.CSSProperties = { padding: '16px', borderRadius: '16px', border: '1px solid rgba(0,0,0,0.05)', background: 'white', textAlign: 'left', fontWeight: '700', fontSize: '15px', cursor: 'pointer' };
const closeButtonStyle: React.CSSProperties = { padding: '12px', borderRadius: '12px', border: 'none', background: 'rgba(0,0,0,0.05)', fontWeight: '700', cursor: 'pointer', marginTop: '16px', width: '100%' };

import React, { useState, useMemo } from 'react';
import { PageShell } from '../ui/PageShell';
import { theme } from '../ui/theme';
import { IconButton, Icons } from '../ui/IconButton';
import { GlassCard } from '../ui/GlassCard';
import { Artist, Concert, DisplaySettings, Status } from '../domain/types';
import { calcArtistStatus, sortPerformancesForDisplay } from '../domain/logic';
import { TEXT } from '../ui/constants';

interface Props {
  artistId: string;
  artist: Artist;
  settings: DisplaySettings;
  onOpenArtistEditor: (artistId: string) => void;
  onOpenConcertEditor: (artistId: string, tourId?: string) => void;
  onOpenConcertHome: (artistId: string, tourId: string, concertId: string) => void;
  onChangeSettings: (settings: Partial<DisplaySettings>) => void;
  onBack: () => void;
}

const InstanceRow: React.FC<{ 
  concert: Concert; 
  isLast: boolean;
  onClick?: () => void;
  disabled?: boolean;
}> = ({ concert, isLast, onClick, disabled }) => {
  const isSpecial = concert.status === '参戦予定' || concert.status === '参戦済み';
  const dotColor = isSpecial ? theme.colors.primary : '#9CA3AF';

  const handleLinkClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (concert.saleLink) {
      window.open(concert.saleLink, '_blank', 'noopener,noreferrer');
    }
  };

  return (
    <div 
      onClick={disabled ? undefined : onClick}
      style={{
        padding: '16px 20px',
        display: 'flex',
        gap: '12px',
        alignItems: 'center',
        cursor: (disabled || !onClick) ? 'default' : 'pointer',
        borderBottom: isLast ? 'none' : '1px solid rgba(0, 0, 0, 0.05)',
        transition: 'background 0.2s',
        opacity: disabled ? 0.6 : 1,
      }}
    >
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
          <span style={{ fontWeight: '800', fontSize: '15px' }}>{concert.date}</span>
          <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
            <div style={{ width: '6px', height: '6px', borderRadius: '50%', background: dotColor }} />
            <span style={{ fontSize: '11px', fontWeight: '700', color: theme.colors.textSecondary }}>{concert.status}</span>
          </div>
        </div>
        <div style={{ fontSize: '13px', color: theme.colors.textSecondary, marginTop: '2px', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
          {concert.venue || '会場未定'}
        </div>
      </div>

      <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
        {concert.saleLink && (
          <button 
            onClick={handleLinkClick}
            style={{ 
              border: 'none', 
              background: 'rgba(83, 190, 232, 0.1)', 
              color: theme.colors.primary, 
              padding: '8px', 
              borderRadius: '10px', 
              cursor: 'pointer',
              display: 'flex',
              alignItems: 'center'
            }}
          >
            <Icons.ExternalLink style={{ width: 16, height: 16 }} />
          </button>
        )}
        {onClick && !disabled && (
          <div style={{ color: '#D1D5DB' }}>
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <polyline points="9 18 15 12 9 6"></polyline>
            </svg>
          </div>
        )}
      </div>
    </div>
  );
};

export const ArtistDetailPage: React.FC<Props> = ({ 
  artistId, 
  artist, 
  settings, 
  onOpenArtistEditor, 
  onOpenConcertEditor, 
  onOpenConcertHome,
  onBack 
}) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isSelectionMode, setIsSelectionMode] = useState(false);
  const [imgErrors, setImgErrors] = useState<Record<string, boolean>>({});

  const status = calcArtistStatus(artist);

  const dotColor = useMemo(() => {
    if (status.main === TEXT.ARTIST_STATUS.MAIN_TOURING && status.sub) {
      return theme.colors.status[status.sub as Status] || theme.colors.primary;
    }
    if (status.main === TEXT.ARTIST_STATUS.MAIN_TRACKING) {
      return '#00E0FF';
    }
    return '#E2E8F0';
  }, [status]);

  const processedTours = useMemo(() => {
    return artist.tours
      .map(tour => ({
        ...tour,
        concerts: sortPerformancesForDisplay(tour.concerts.filter(c => {
          if (!settings.showAttended && c.status === '参戦済み') return false;
          if (!settings.showSkipped && c.status === '見送') return false;
          return true;
        }))
      }))
      .filter(tour => tour.concerts.length > 0 || isSelectionMode);
  }, [artist.tours, settings, isSelectionMode]);

  const handleEditConcertClick = () => {
    setIsMenuOpen(false);
    if (artist.tours.length === 0) {
      onOpenConcertEditor(artistId);
    } else if (artist.tours.length === 1) {
      onOpenConcertEditor(artistId, artist.tours[0].id);
    } else {
      setIsSelectionMode(true);
    }
  };

  return (
    <PageShell
      header={
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', minHeight: '44px' }}>
          {!isSelectionMode ? (
            <button 
              onClick={onBack} 
              style={{ border: 'none', background: 'none', color: '#9CA3AF', cursor: 'pointer', padding: '8px', display: 'flex', alignItems: 'center' }}
            >
              <Icons.ChevronLeft />
            </button>
          ) : (
            <div style={{ flex: 1, paddingRight: '16px' }}>
              <h2 style={{ fontSize: '15px', fontWeight: '800', color: theme.colors.primary, margin: 0 }}>
                編集するツアーを選択してください
              </h2>
            </div>
          )}

          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            {isSelectionMode ? (
              <button 
                onClick={() => setIsSelectionMode(false)}
                style={{
                  border: 'none',
                  background: 'rgba(0,0,0,0.05)',
                  color: theme.colors.textSecondary,
                  padding: '8px 16px',
                  borderRadius: '12px',
                  fontSize: '13px',
                  fontWeight: '800',
                  cursor: 'pointer'
                }}
              >
                キャンセル
              </button>
            ) : (
              <div style={{ position: 'relative' }}>
                <IconButton 
                  icon={<Icons.Edit />} 
                  onClick={() => setIsMenuOpen(!isMenuOpen)}
                  size={40}
                  style={{ 
                    borderRadius: '16px', 
                    color: theme.colors.primary, 
                    borderColor: isMenuOpen ? theme.colors.primary : '#F3F4F6' 
                  }}
                />

                {isMenuOpen && (
                  <div style={{ position: 'absolute', top: '48px', right: 0, zIndex: 1000, width: '220px' }}>
                    <div style={{ position: 'fixed', inset: 0 }} onClick={() => setIsMenuOpen(false)} />
                    <GlassCard padding="8px" className="fade-in" style={{ boxShadow: theme.shadows.pop }}>
                      <MenuOption 
                        label="アーティスト編集" 
                        icon={<Icons.Edit style={{ width: 16 }} />} 
                        onClick={() => { onOpenArtistEditor(artistId); setIsMenuOpen(false); }} 
                      />
                      <MenuOption 
                        label="ツアー・公演編集" 
                        icon={<Icons.Calendar style={{ width: 16 }} />} 
                        onClick={handleEditConcertClick} 
                      />
                    </GlassCard>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      }
    >
      <div style={{ paddingBottom: '120px' }}>
        {/* Profile Info */}
        <div style={{ display: 'flex', alignItems: 'center', gap: '24px', marginBottom: '32px', opacity: isSelectionMode ? 0.3 : 1, transition: 'opacity 0.3s' }}>
          <div style={{ 
            width: '96px', height: '96px', borderRadius: '50%', background: '#F3F4F6', border: '3px solid white', boxShadow: '0 4px 12px rgba(0,0,0,0.1)', overflow: 'hidden', flexShrink: 0, display: 'flex', alignItems: 'center', justifyContent: 'center'
          }}>
            {artist.imageUrl ? (
              <img src={artist.imageUrl} referrerPolicy="no-referrer" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
            ) : (
              <span style={{ fontSize: '32px', opacity: 0.2 }}>👤</span>
            )}
          </div>
          <div style={{ minWidth: 0 }}>
            <h1 style={{ fontSize: '32px', fontWeight: '900', margin: 0, letterSpacing: '-0.02em', lineHeight: '1.2' }}>{artist.name}</h1>
            <div style={{ marginTop: '8px', display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
              <div style={{ display: 'inline-flex', alignItems: 'center', gap: '8px', background: 'white', padding: '6px 14px', borderRadius: '9999px', border: '1px solid #F1F5F9' }}>
                <div
                  style={{
                    width: '8px',
                    height: '8px',
                    borderRadius: '50%',
                    background: dotColor,
                    boxShadow: `0 0 12px ${dotColor}99`,
                    filter: 'blur(1px)'
                  }}
                />
                <span style={{ fontSize: '13px', fontWeight: '800', color: theme.colors.textMain }}>{status.main}</span>
              </div>
            </div>
          </div>
        </div>

        {/* Artist Links Section */}
        {artist.links && artist.links.length > 0 && !isSelectionMode && (
          <div style={{ 
            display: 'flex', 
            gap: '8px', 
            overflowX: 'auto', 
            paddingBottom: '8px', 
            marginBottom: '40px',
            msOverflowStyle: 'none',
            scrollbarWidth: 'none'
          }} className="hide-scrollbar">
            {artist.links.map((link, idx) => (
              <button
                key={idx}
                onClick={() => window.open(link.url, '_blank', 'noopener,noreferrer')}
                style={{
                  whiteSpace: 'nowrap',
                  padding: '8px 16px',
                  borderRadius: '14px',
                  background: 'rgba(255,255,255,0.8)',
                  border: '1px solid rgba(0,0,0,0.04)',
                  fontSize: '13px',
                  fontWeight: '700',
                  color: theme.colors.textSecondary,
                  cursor: 'pointer',
                  boxShadow: '0 2px 4px rgba(0,0,0,0.02)',
                  transition: 'all 0.2s'
                }}
                onMouseEnter={e => e.currentTarget.style.borderColor = theme.colors.primary}
                onMouseLeave={e => e.currentTarget.style.borderColor = 'rgba(0,0,0,0.04)'}
              >
                {link.name || '外部リンク'}
              </button>
            ))}
          </div>
        )}

        {/* Tours List */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
          {processedTours.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '60px 40px', color: theme.colors.textWeak }}>
              <div style={{ fontSize: '48px', marginBottom: '16px', opacity: 0.3 }}>🎪</div>
              <div style={{ fontWeight: '600' }}>表示可能な公演がありません</div>
            </div>
          ) : (
            processedTours.map(tour => (
              <div key={tour.id} style={{ transition: 'all 0.3s cubic-bezier(0.16, 1, 0.3, 1)', transform: isSelectionMode ? 'scale(1.02)' : 'scale(1)' }}>
                <GlassCard 
                  padding="0" 
                  onClick={isSelectionMode ? () => onOpenConcertEditor(artistId, tour.id) : undefined}
                  style={{ 
                    overflow: 'hidden',
                    border: isSelectionMode ? `2.5px solid ${theme.colors.primary}` : theme.glass.border,
                    boxShadow: isSelectionMode ? theme.shadows.pop : theme.shadows.card,
                    position: 'relative'
                  }}
                >
                  <div style={{ 
                    display: 'flex', 
                    gap: '16px', 
                    padding: '20px', 
                    background: isSelectionMode ? 'rgba(83, 190, 232, 0.05)' : 'linear-gradient(to bottom right, rgba(255,255,255,0.8), rgba(255,255,255,0.4))', 
                    borderBottom: '1px solid rgba(0,0,0,0.03)' 
                  }}>
                    <div style={{ width: '60px', height: '80px', borderRadius: '12px', background: '#F3F4F6', flexShrink: 0, overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                      {tour.imageUrl && !imgErrors[tour.id] ? (
                        <img src={tour.imageUrl} referrerPolicy="no-referrer" style={{ width: '100%', height: '100%', objectFit: 'cover' }} onError={() => setImgErrors(p => ({ ...p, [tour.id]: true }))} />
                      ) : (
                        <span style={{ fontSize: '24px', opacity: 0.2 }}>🎸</span>
                      )}
                    </div>
                    <div style={{ flex: 1, minWidth: 0, display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <h3 style={{ fontSize: '18px', fontWeight: '900', margin: 0, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{tour.name}</h3>
                        <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                          {tour.officialUrl && !isSelectionMode && (
                            <button 
                              onClick={(e) => { e.stopPropagation(); window.open(tour.officialUrl, '_blank', 'noopener,noreferrer'); }}
                              style={{ border: 'none', background: 'none', cursor: 'pointer', color: theme.colors.textWeak, padding: '4px' }}
                            >
                              <Icons.Globe style={{ width: 18, height: 18 }} />
                            </button>
                          )}
                          {isSelectionMode && (
                            <div style={{ background: theme.colors.primary, color: 'white', padding: '4px', borderRadius: '50%', display: 'flex' }}>
                              <Icons.Edit style={{ width: 14, height: 14 }} />
                            </div>
                          )}
                        </div>
                      </div>
                      <div style={{ marginTop: '6px' }}>
                        <span style={{ fontSize: '11px', fontWeight: '800', color: theme.colors.textWeak, background: '#F1F5F9', padding: '2px 8px', borderRadius: '6px' }}>
                          {tour.concerts.length}公演
                        </span>
                      </div>
                    </div>
                  </div>

                  {!isSelectionMode && (
                    <div style={{ display: 'flex', flexDirection: 'column' }}>
                      {tour.concerts.map((c, idx) => (
                        <InstanceRow 
                          key={c.id} 
                          concert={c} 
                          isLast={idx === tour.concerts.length - 1}
                          onClick={(c.status === '参戦予定' || c.status === '参戦済み') ? () => onOpenConcertHome(artistId, tour.id, c.id) : undefined} 
                        />
                      ))}
                    </div>
                  )}
                </GlassCard>
              </div>
            ))
          )}
        </div>
      </div>

      {!isSelectionMode && (
        <IconButton 
          icon={<Icons.Plus />} 
          primary size={64} 
          onClick={() => onOpenConcertEditor(artistId)} 
          style={{ position: 'fixed', right: '16px', bottom: 'calc(16px + env(safe-area-inset-bottom))', zIndex: 110, boxShadow: theme.shadows.fab }} 
        />
      )}
    </PageShell>
  );
};

const MenuOption = ({ label, icon, onClick }: { label: string; icon: React.ReactNode; onClick: () => void }) => (
  <button 
    onClick={onClick}
    style={{
      width: '100%',
      padding: '12px 16px',
      display: 'flex',
      alignItems: 'center',
      gap: '12px',
      border: 'none',
      background: 'none',
      cursor: 'pointer',
      textAlign: 'left',
      borderRadius: '12px',
      color: theme.colors.text,
      fontSize: '14px',
      fontWeight: '600',
      transition: 'background 0.2s',
    }}
    onMouseEnter={(e) => (e.currentTarget.style.background = 'rgba(0,0,0,0.05)')}
    onMouseLeave={(e) => (e.currentTarget.style.background = 'none')}
  >
    <span style={{ opacity: 0.6 }}>{icon}</span>
    {label}
  </button>
);

import React, { useState, useRef, useEffect } from 'react';
import { theme } from '../ui/theme';
import { ImageDialog } from '../components/ImageDialog';
import { Artist, Tour, Concert } from '../domain/types';
import { Icons, IconButton } from '../ui/IconButton';

interface Props {
  artistId: string;
  concertId: string;
  artist: Artist;
  tour: Tour;
  concert: Concert;
  onBack: () => void;
  onOpenConcertEditor: (artistId: string, tourId: string) => void;
  onUpdateConcertAlbum: (artistId: string, tourId: string, concertId: string, images: string[]) => void;
}

export const ConcertHomePage: React.FC<Props> = ({ 
  artistId, 
  concertId, 
  artist, 
  tour, 
  concert, 
  onBack, 
  onOpenConcertEditor,
  onUpdateConcertAlbum 
}) => {
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingImageUrl, setEditingImageUrl] = useState<{ url: string; index: number } | null>(null);
  const [fullscreenImage, setFullscreenImage] = useState<string | null>(null);
  const [failedImages, setFailedImages] = useState<Set<string>>(new Set());
  const bgCandidates = [tour.imageUrl, artist.imageUrl].filter(Boolean) as string[];
  const [bgIndex, setBgIndex] = useState<number>(0);
  const bgUrl = bgCandidates[bgIndex] || '';

  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);

  const images = concert.images || [];

  useEffect(() => {
    setBgIndex(0);
  }, [tour.imageUrl, artist.imageUrl]);

  const handleBgError = () => {
    setBgIndex((prev) => (prev + 1 < bgCandidates.length ? prev + 1 : prev));
  };

  const handleAddImage = (url: string) => {
    if (editingImageUrl !== null) {
      const newImages = [...images];
      newImages[editingImageUrl.index] = url;
      onUpdateConcertAlbum(artistId, tour.id, concertId, newImages);
      setFailedImages(prev => {
        const next = new Set(prev);
        next.delete(editingImageUrl.url);
        return next;
      });
      setEditingImageUrl(null);
    } else {
      onUpdateConcertAlbum(artistId, tour.id, concertId, [...images, url]);
    }
  };

  const handleImageError = (url: string) => {
    setFailedImages(prev => new Set([...prev, url]));
  };

  const handleRemoveImage = (url: string) => {
    onUpdateConcertAlbum(artistId, tour.id, concertId, images.filter(i => i !== url));
  };

  const handleReplaceImage = (url: string, index: number) => {
    setEditingImageUrl({ url, index });
    setIsDialogOpen(true);
  };

  const handleDragStart = (index: number) => {
    dragItem.current = index;
  };

  const handleDragEnter = (index: number) => {
    dragOverItem.current = index;
  };

  const handleDragEnd = () => {
    if (dragItem.current !== null && dragOverItem.current !== null && dragItem.current !== dragOverItem.current) {
      const newList = [...images];
      const draggedItemContent = newList[dragItem.current];
      newList.splice(dragItem.current, 1);
      newList.splice(dragOverItem.current, 0, draggedItemContent);

      onUpdateConcertAlbum(artistId, tour.id, concertId, newList);
    }
    dragItem.current = null;
    dragOverItem.current = null;
  };

  return (
    <div style={{ minHeight: '100vh', position: 'relative', overflowX: 'hidden' }}>
      <div style={{ 
        position: 'fixed', 
        inset: 0, 
        zIndex: 0, 
        overflow: 'hidden', 
        backgroundColor: '#111',
        pointerEvents: 'none'
      }}>
        {bgUrl && (
          <img 
            src={bgUrl}
            referrerPolicy="no-referrer"
            alt=""
            style={{ 
              width: '100%', 
              height: '100%', 
              objectFit: 'cover',
              filter: 'blur(40px) brightness(0.6)', 
              transform: 'scale(1.2)',
              transition: 'opacity 0.5s ease-in-out'
            }}
            onError={handleBgError}
          />
        )}
      </div>

      <div style={{ position: 'relative', zIndex: 1, padding: `${theme.spacing.lg} ${theme.spacing.md} 140px ${theme.spacing.md}`, maxWidth: '600px', margin: '0 auto' }}>
        <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' }}>
          <button 
            onClick={onBack} 
            style={{ 
              border: 'none', 
              background: 'rgba(255,255,255,0.15)', 
              backdropFilter: 'blur(10px)',
              color: 'white', 
              width: '44px', 
              height: '44px', 
              borderRadius: '22px', 
              display: 'flex', 
              alignItems: 'center', 
              justifyContent: 'center', 
              cursor: 'pointer' 
            }}
          >
            <Icons.ChevronLeft />
          </button>

          <div style={{ display: 'flex', gap: '12px' }}>
            {concert.saleLink && (
              <button 
                onClick={() => window.open(concert.saleLink, '_blank', 'noopener,noreferrer')}
                style={{ 
                  border: 'none', 
                  background: 'rgba(255,255,255,0.15)', 
                  backdropFilter: 'blur(10px)',
                  color: 'white', 
                  width: '44px', 
                  height: '44px', 
                  borderRadius: '22px', 
                  display: 'flex', 
                  alignItems: 'center', 
