        </section>
      </div>

      <IconButton 
        icon={<Icons.Plus />} 
        primary 
        size={64} 
        onClick={() => {
          setEditingImageUrl(null);
          setIsDialogOpen(true);
        }} 
        style={{ 
          position: 'fixed', 
          right: '16px', 
          bottom: 'calc(16px + env(safe-area-inset-bottom))', 
          zIndex: 110,
          boxShadow: '0 8px 24px -6px rgba(83, 190, 232, 0.5)'
        }}
      />

      {fullscreenImage && (
        <div 
          onClick={() => setFullscreenImage(null)} 
