          style={{ 
            position: 'fixed', 
            inset: 0, 
            zIndex: 3000, 
            background: 'rgba(0,0,0,0.95)', 
            display: 'flex', 
            alignItems: 'center', 
            justifyContent: 'center',
            padding: '20px'
