const closeButtonStyle: React.CSSProperties = { padding: '12px', borderRadius: '12px', border: 'none', background: 'rgba(0,0,0,0.05)', fontWeight: '700', cursor: 'pointer', marginTop: '16px', width: '100%' };

import { Artist, Concert, Status, TICKET_TRACK_STATUSES, TOUR_ACTIVE_STATUSES, PageId, GlobalSettings, DueAction, CalendarEvent, CalendarEventType } from './types';
import { TEXT } from '../ui/constants';

/**
 * ===== Date Parsing Rules =====
 * iOS Safari compatibility: replaces '-' with '/' for broad support
 */
export const parseConcertDate = (dateStr: string | null | undefined, type: 'CONCERT' | 'NORMAL'): Date | null => {
  if (!dateStr || dateStr === TEXT.GLOBAL.TBD) return null;

  // Standardize format for iOS: "2023-10-27" -> "2023/10/27"
  const standardizedStr = dateStr.replace(/-/g, '/');

  const d = new Date(standardizedStr);
  if (isNaN(d.getTime())) {
    // Fallback parsing for manual extraction if Date still fails
    try {
      const parts = dateStr.split(' ');
      const dateParts = parts[0].split('-').map(Number);
      if (parts.length > 1) {
        const timeParts = parts[1].split(':').map(Number);
        return new Date(dateParts[0], dateParts[1] - 1, dateParts[2], timeParts[0], timeParts[1] || 0);
      }
      if (type === 'CONCERT') {
        return new Date(dateParts[0], dateParts[1] - 1, dateParts[2], 21, 0, 0);
      }
      return new Date(dateParts[0], dateParts[1] - 1, dateParts[2], 12, 0, 0);
    } catch (e) {
      return null;
    }
  }

  // If input was just date, enforce specific hours
  if (!dateStr.includes(' ')) {
    const y = d.getFullYear();
    const m = d.getMonth();
    const day = d.getDate();
    if (type === 'CONCERT') {
      return new Date(y, m, day, 21, 0, 0);
    }
    return new Date(y, m, day, 12, 0, 0);
  }

  return d;
};

/**
 * ===== Calendar Logic =====
 */

export const EVENT_PRIORITY: Record<CalendarEventType, number> = {
  [TEXT.CALENDAR.EVENT_CONCERT]: 1,
  [TEXT.CALENDAR.EVENT_RESULT]: 2,
  [TEXT.CALENDAR.EVENT_DEADLINE]: 3,
  [TEXT.CALENDAR.EVENT_SALE]: 4,
};

const extractDateAndTime = (str: string | null | undefined): { date: string; time?: string } | null => {
  if (!str || str === TEXT.GLOBAL.TBD) return null;
  const parts = str.split(' ');
  return { date: parts[0], time: parts[1] ? parts[1].substring(0, 5) : undefined };
};

export const buildCalendarEvents = (artists: Artist[], settings: { showAttended: boolean; showSkipped: boolean }): CalendarEvent[] => {
  const events: CalendarEvent[] = [];

  artists.forEach(artist => {
    artist.tours.forEach(tour => {
      tour.concerts.forEach(concert => {
        if (!settings.showAttended && concert.status === '参戦済み') return;
        if (!settings.showSkipped && concert.status === '見送') return;

        const title = `${artist.name} / ${tour.name}`;

        // A) 公演
        const cInfo = extractDateAndTime(concert.concertAt || concert.date);
        if (cInfo) {
          events.push({
            dateKey: cInfo.date,
            timeLabel: cInfo.time,
            type: TEXT.CALENDAR.EVENT_CONCERT as CalendarEventType,
            artistId: artist.id,
            tourId: tour.id,
            concertId: concert.id,
            title,
            status: concert.status,
          });
        }

        // B) 抽選結果
        if (concert.status === '抽選中') {
          const rInfo = extractDateAndTime(concert.resultAt);
          if (rInfo) {
            events.push({
              dateKey: rInfo.date,
              timeLabel: rInfo.time,
              type: TEXT.CALENDAR.EVENT_RESULT as CalendarEventType,
              artistId: artist.id,
              tourId: tour.id,
              concertId: concert.id,
              title,
              status: concert.status,
            });
          }
        }

        // C) 発売開始
        if (concert.status === '発売前') {
          const sInfo = extractDateAndTime(concert.saleAt);
          if (sInfo) {
            events.push({
              dateKey: sInfo.date,
              timeLabel: sInfo.time,
              type: TEXT.CALENDAR.EVENT_SALE as CalendarEventType,
              artistId: artist.id,
              tourId: tour.id,
              concertId: concert.id,
              title,
              status: concert.status,
            });
          }
        }

        // D) 申込締切
        if (concert.status === '検討中') {
          const dInfo = extractDateAndTime(concert.deadlineAt);
          if (dInfo) {
            events.push({
              dateKey: dInfo.date,
              timeLabel: dInfo.time,
              type: TEXT.CALENDAR.EVENT_DEADLINE as CalendarEventType,
              artistId: artist.id,
              tourId: tour.id,
              concertId: concert.id,
              title,
              status: concert.status,
            });
          }
        }
      });
    });
  });

  return events;
};

export const getDueAction = (concert: Concert, now: Date = new Date()): DueAction | null => {
  const saleTime = parseConcertDate(concert.saleAt, 'NORMAL');
  const deadlineTime = parseConcertDate(concert.deadlineAt, 'NORMAL');
  const resultTime = parseConcertDate(concert.resultAt, 'NORMAL');
  const concertTime = parseConcertDate(concert.concertAt, 'CONCERT');

  switch (concert.status) {
    case '発売前':
      if (saleTime && now >= saleTime) return 'ASK_BUY_AT_SALE';
      return null;
    case '検討中':
      if (deadlineTime && now >= deadlineTime) return 'ASK_BUY_AT_DEADLINE';
      if (!deadlineTime) return 'NEED_SET_DEADLINE_AT';
      return null;
    case '抽選中':
      if (resultTime && now >= resultTime) return 'ASK_RESULT';
      if (!resultTime) return 'NEED_SET_RESULT_AT';
      return null;
    case '参戦予定':
      if (!concertTime) return 'NEED_SET_CONCERT_AT';
      return null;
    default:
      return null;
  }
};

export const autoAdvanceConcertStatus = (concert: Concert, now: Date = new Date()): Concert => {
  if (concert.status === '参戦予定') {
    const concertTime = parseConcertDate(concert.concertAt, 'CONCERT');
    if (concertTime && now >= concertTime) {
      return { ...concert, status: '参戦済み' };
    }
  }
  return concert;
};

export const applyDecision = (
  concert: Concert, 
  decision: 'BUY' | 'CONSIDER' | 'SKIP' | 'WON' | 'LOST', 
  payload?: { lotteryName?: string; resultAt?: string; concertAt?: string }
): Concert => {
  switch (decision) {
    case 'BUY':
      return { 
        ...concert, 
        status: '抽選中', 
        lotteryName: payload?.lotteryName ?? concert.lotteryName,
        resultAt: payload?.resultAt ?? concert.resultAt 
      };
    case 'CONSIDER':
      return { ...concert, status: '検討中' };
    case 'SKIP':
      return { ...concert, status: '見送', lotteryResult: null };
    case 'WON':
      return { 
        ...concert, 
        status: '参戦予定', 
        lotteryResult: 'WON',
        concertAt: payload?.concertAt ?? (concert.concertAt || concert.date)
      };
    case 'LOST':
      return { ...concert, status: '見送', lotteryResult: 'LOST' };
    default:
      return concert;
  }
};

const ARTIST_SUB_STATUS_ORDER: Status[] = ['発売前', '検討中', '抽選中', '参戦予定', '参戦済み', '見送'];
const ARTIST_SUB_STATUS_PRIORITY: Record<Status, number> = {
  '発売前': 0, '検討中': 1, '抽選中': 2, '参戦予定': 3, '参戦済み': 4, '見送': 5,
};

const pickArtistSubStatus = (concerts: Concert[]): Status | null => {
  const candidates = concerts
    .map(c => c.status)
    .filter((s): s is Status => ARTIST_SUB_STATUS_ORDER.includes(s));
  if (candidates.length === 0) return null;
  candidates.sort((a, b) => ARTIST_SUB_STATUS_PRIORITY[a] - ARTIST_SUB_STATUS_PRIORITY[b]);
  return candidates[0] ?? null;
};

export const calcArtistStatus = (artist: Artist): {
  main: string;
  sub: Status | null;
} => {
  const allConcerts = artist.tours.flatMap(t => t.concerts);
  const hasActiveTour = allConcerts.some(c => TOUR_ACTIVE_STATUSES.includes(c.status));
  let main: string = TEXT.ARTIST_STATUS.MAIN_NONE;
  if (hasActiveTour) main = TEXT.ARTIST_STATUS.MAIN_TOURING;
  else if (artist.autoTrackConcerts) main = TEXT.ARTIST_STATUS.MAIN_TRACKING;
  const sub = main === TEXT.ARTIST_STATUS.MAIN_TOURING ? pickArtistSubStatus(allConcerts) : null;
  return { main, sub };
};

export const sortArtistsForDisplay = (artists: Artist[], sortMode: 'manual' | 'status'): Artist[] => {
  if (sortMode === 'manual') return [...artists];
  return [...artists].sort((a, b) => {
    const prioA = getArtistPriority(a);
    const prioB = getArtistPriority(b);
    if (prioA.main !== prioB.main) return prioA.main - prioB.main;
    if (prioA.sub !== prioB.sub) return prioA.sub - prioB.sub;
    return a.name.localeCompare(b.name);
  });
};

const getArtistPriority = (artist: Artist) => {
  const status = calcArtistStatus(artist);
  if (status.main === TEXT.ARTIST_STATUS.MAIN_TOURING) return { main: 1, sub: status.sub ? ARTIST_SUB_STATUS_PRIORITY[status.sub] : 99 };
  if (status.main === TEXT.ARTIST_STATUS.MAIN_TRACKING) return { main: 2, sub: 0 };
  return { main: 3, sub: 0 };
};

const getConcertStatusPriority = (status: Status): number => {
  if (TICKET_TRACK_STATUSES.includes(status)) return 1;
  if (status === '参戦予定') return 2;
  if (status === '参戦済み') return 3;
  if (status === '見送') return 4;
  return 99;
};

export const getBestStatusForDay = (concerts: Concert[]): Status | null => {
  const dated = concerts.filter(c => c.date !== TEXT.GLOBAL.TBD || c.concertAt);
  if (dated.length === 0) return null;
  return [...dated].sort((a, b) => getCalendarStatusWeight(b.status) - getCalendarStatusWeight(a.status))[0].status;
};

const getCalendarStatusWeight = (status: Status): number => {
  switch (status) {
    case '参戦予定': return 100;
    case '抽選中': return 90;
    case '検討中': return 80;
    case '発売前': return 70;
    case '参戦済み': return 60;
    case '見送': return 50;
    default: return 0;
  }
};

export const sortPerformancesForDisplay = (concerts: Concert[]): Concert[] => {
  return [...concerts].sort((a, b) => {
    const prioA = getConcertStatusPriority(a.status);
    const prioB = getConcertStatusPriority(b.status);
    if (prioA !== prioB) return prioA - prioB;
    const dateA = a.concertAt || a.date;
    const dateB = b.concertAt || b.date;
    if (dateA !== TEXT.GLOBAL.TBD && dateB === TEXT.GLOBAL.TBD) return -1;
    if (dateA === TEXT.GLOBAL.TBD && dateB !== TEXT.GLOBAL.TBD) return 1;
    if (dateA !== TEXT.GLOBAL.TBD && dateB !== TEXT.GLOBAL.TBD) return dateA.localeCompare(dateB);
    return 0;
  });
};

export const sortPerformancesByLotteryDate = (concerts: Concert[]): Concert[] => {
  const getMilestoneDate = (c: Concert) => {
    if (c.status === '抽選中') return c.resultAt;
    if (c.status === '検討中') return c.deadlineAt;
    if (c.status === '発売前') return c.saleAt;
    return null;
  };

  return [...concerts].sort((a, b) => {
    const dateA = getMilestoneDate(a);
    const dateB = getMilestoneDate(b);
    if (dateA && !dateB) return -1;
    if (!dateA && dateB) return 1;
    if (dateA && dateB) return dateA.localeCompare(dateB);
    const cA = a.concertAt || a.date;
    const cB = b.concertAt || b.date;
    if (cA !== TEXT.GLOBAL.TBD && cB !== TEXT.GLOBAL.TBD) return cA.localeCompare(cB);
    if (cA !== TEXT.GLOBAL.TBD) return -1;
    if (cB !== TEXT.GLOBAL.TBD) return 1;
    return 0;
  });
};

export const checkGlobalDateConflicts = (allArtists: Artist[], currentTourId: string, formConcerts: Concert[]): string[] => {
  const otherDates = new Set<string>();
  allArtists.forEach(artist => artist.tours.forEach(tour => {
    if (tour.id === currentTourId) return;
    tour.concerts.forEach(concert => {
      const d = concert.concertAt || concert.date;
      if (d !== TEXT.GLOBAL.TBD && d) otherDates.add(d.split(' ')[0]);
    });
  }));
  const conflicts = new Set<string>();
  const currentDatesInForm = new Set<string>();
  formConcerts.forEach(c => {
    const d = c.concertAt || c.date;
    if (d === TEXT.GLOBAL.TBD || !d) return;
    const dateOnly = d.split(' ')[0];
    if (otherDates.has(dateOnly) || currentDatesInForm.has(dateOnly)) conflicts.add(dateOnly);
    currentDatesInForm.add(dateOnly);
  });
  return Array.from(conflicts);
};

export const getTrackTargetConcerts = (artist: Artist, settings: GlobalSettings, now: Date = new Date()): Concert[] => {
  const n = settings.autoTrackIntervalDays;
  const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const limitStart = new Date(todayStart.getTime() - n * 24 * 60 * 60 * 1000);
  return artist.tours.flatMap(tour => tour.concerts).filter(concert => {
    if (!TICKET_TRACK_STATUSES.includes(concert.status)) return false;
    const d = concert.concertAt || concert.date;
    if (d === TEXT.GLOBAL.TBD || !d) return false;
    const standardized = d.replace(/-/g, '/');
    const concertDate = new Date(standardized);
    return concertDate >= limitStart && concertDate <= todayStart;
  });
};

export const shouldTriggerAutoTrack = (lastCheckedAt: string | undefined, settings: GlobalSettings, now: Date = new Date()): boolean => {
  if (!lastCheckedAt) return true;
  const diffDays = (now.getTime() - new Date(lastCheckedAt.replace(/-/g, '/')).getTime()) / (1000 * 60 * 60 * 24);
  return diffDays >= settings.autoTrackIntervalDays;
};

import React, { useState, useMemo, useCallback, useEffect } from 'react';
import { PageId, Artist, Tour, DisplaySettings, Status, GlobalSettings, SiteLink, TrackingStatus, TrackingErrorType, Concert } from './domain/types';
import { Layout } from './components/Layout';
import { ArtistListPage } from './pages/ArtistListPage';
import { ConcertListPage } from './pages/ConcertListPage';
import { CalendarPage } from './pages/CalendarPage';
import { ArtistDetailPage } from './pages/ArtistDetailPage';
import { ConcertHomePage } from './pages/ConcertHomePage';
import { ArtistEditorPage } from './pages/ArtistEditorPage';
import { ConcertEditorPage } from './pages/ConcertEditorPage';
import { GlassCard } from './ui/GlassCard';
import { theme } from './ui/theme';
import { shouldTriggerAutoTrack, getTrackTargetConcerts, getDueAction, autoAdvanceConcertStatus } from './domain/logic';

type NavContext = { 
  path: PageId; 
  artistId?: string; 
  tourId?: string; 
  concertId?: string; 
  from?: PageId;
};

const STORAGE_KEYS = {
  ARTISTS: 'livetrack_jp_artists',
  GLOBAL_SETTINGS: 'livetrack_jp_global_settings',
  DISPLAY_SETTINGS: 'livetrack_jp_display_settings',
  ARTIST_SORT: 'livetrack_jp_artist_sort',
  CONCERT_SORT: 'livetrack_jp_concert_sort'
};

/**
 * Robust Persistence Wrapper
 */
const safeSave = (key: string, data: any) => {
  try {
    // Basic Sanitation: Remove potential circular refs or functions
    const serialized = JSON.stringify(data);

    // Quota Awareness: LocalStorage on mobile is usually ~5MB.
    // If saving Artists, check if we're ballooning due to Base64
    if (key === STORAGE_KEYS.ARTISTS && serialized.length > 4 * 1024 * 1024) {
      console.warn("Storage warning: Data size is large. Images might be causing issues.");
    }

    localStorage.setItem(key, serialized);
  } catch (err: any) {
    console.error(`Persistence Error for key [${key}]:`, err);

    let userMsg = "データの保存に失敗しました。";
    if (err.name === 'QuotaExceededError' || err.code === 22) {
      userMsg += "\nストレージ容量が不足しています。アルバムの画像を削除するか、URLでの指定に切り替えてください。";
    } else if (err instanceof TypeError) {
      userMsg += "\nデータの形式に問題があります。";
    } else {
      userMsg += `\nエラー: ${err.message || "不明な理由"}`;
    }

    // UI Feedback is mandatory per requirement
    window.alert(userMsg);
  }
};

export default function App() {
  const [nav, setNav] = useState<NavContext>({ path: 'ARTIST_LIST' });
  const [isArtistPickerOpen, setIsArtistPickerOpen] = useState(false);

  const [globalSettings, setGlobalSettings] = useState<GlobalSettings>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEYS.GLOBAL_SETTINGS);
      return saved ? JSON.parse(saved) : { autoTrackIntervalDays: 7 };
    } catch { return { autoTrackIntervalDays: 7 }; }
  });

  const [displaySettings, setDisplaySettings] = useState<DisplaySettings>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEYS.DISPLAY_SETTINGS);
      return saved ? JSON.parse(saved) : { showAttended: true, showSkipped: true };
    } catch { return { showAttended: true, showSkipped: true }; }
  });

  const [artistSortMode, setArtistSortMode] = useState<'manual' | 'status'>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.ARTIST_SORT);
    return (saved as 'manual' | 'status') || 'status';
  });

  const [concertSortMode, setConcertSortMode] = useState<'status' | 'lottery'>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CONCERT_SORT);
    return (saved as 'status' | 'lottery') || 'status';
  });

  const [artists, setArtists] = useState<Artist[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEYS.ARTISTS);
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  // Effect-based persistence with error handling
  useEffect(() => {
    safeSave(STORAGE_KEYS.ARTISTS, artists);
  }, [artists]);

  useEffect(() => {
    safeSave(STORAGE_KEYS.GLOBAL_SETTINGS, globalSettings);
  }, [globalSettings]);

  useEffect(() => {
    safeSave(STORAGE_KEYS.DISPLAY_SETTINGS, displaySettings);
  }, [displaySettings]);

  useEffect(() => {
    safeSave(STORAGE_KEYS.ARTIST_SORT, artistSortMode);
  }, [artistSortMode]);

  useEffect(() => {
    safeSave(STORAGE_KEYS.CONCERT_SORT, concertSortMode);
  }, [concertSortMode]);

  const hasGlobalConcertAlert = useMemo(() => {
    const now = new Date();
    return artists.some(a => a.tours.some(t => t.concerts.some(c => !!getDueAction(c, now))));
  }, [artists]);

  const runAutoAdvance = useCallback(() => {
    const now = new Date();
    setArtists(prev => prev.map(a => ({
      ...a,
      tours: a.tours.map(t => ({
        ...t,
        concerts: t.concerts.map(c => autoAdvanceConcertStatus(c, now))
      }))
    })));
  }, []);

  useEffect(() => {
    runAutoAdvance();
  }, [nav.path, runAutoAdvance]);

  const navigateToArtistList = () => setNav({ path: 'ARTIST_LIST' });
  const navigateToArtistDetail = (artistId: string, from?: PageId) => setNav({ path: 'ARTIST_DETAIL', artistId, from });
  const navigateToArtistEditor = (artistId?: string) => setNav({ path: 'ARTIST_EDITOR', artistId });
  const navigateToConcertEditor = (artistId: string, tourId?: string) => setNav({ path: 'CONCERT_EDITOR', artistId, tourId });
  const navigateToConcertHome = (artistId: string, tourId: string, concertId: string, from?: PageId) => setNav({ path: 'CONCERT_HOME', artistId, tourId, concertId, from });

  const upsertArtist = (updated: Artist) => {
    setArtists(prev => {
      const exists = prev.some(a => a.id === updated.id);
      return exists ? prev.map(a => a.id === updated.id ? updated : a) : [...prev, updated];
    });
    navigateToArtistDetail(updated.id, nav.from);
  };

  const handleUpdateArtistOrder = (newArtists: Artist[]) => {
    setArtists(newArtists.map((a, i) => ({ ...a, order: i })));
  };

  const updateConcert = (artistId: string, tourId: string, concertId: string, updates: Partial<Concert>) => {
    setArtists(prev => prev.map(a => {
      if (a.id !== artistId) return a;
      return {
        ...a,
        tours: a.tours.map(t => {
          if (t.id !== tourId) return t;
          return {
            ...t,
            concerts: t.concerts.map(c => c.id === concertId ? { ...c, ...updates } : c)
          };
        })
      };
    }));
  };

  const upsertTour = (artistId: string, updatedTour: Tour) => {
    setArtists(prev => prev.map(artist => {
      if (artist.id !== artistId) return artist;
      const tourExists = artist.tours.some(t => t.id === updatedTour.id);
      return { 
        ...artist, 
        tours: tourExists ? artist.tours.map(t => t.id === updatedTour.id ? updatedTour : t) : [...artist.tours, updatedTour] 
      };
    }));
    navigateToArtistDetail(artistId, nav.from);
  };

  const deleteTour = (artistId: string, tourId: string) => {
    setArtists(prev => prev.map(artist => artist.id !== artistId ? artist : { ...artist, tours: artist.tours.filter(t => t.id !== tourId) }));
    navigateToArtistDetail(artistId, nav.from);
  };

  const renderPage = () => {
    switch (nav.path) {
      case 'ARTIST_LIST': 
        return (
          <ArtistListPage 
            artists={artists} 
            onOpenArtist={(id) => navigateToArtistDetail(id, 'ARTIST_LIST')} 
            onOpenArtistEditor={() => navigateToArtistEditor()} 
            onRefreshAll={runAutoAdvance} 
            onImportData={setArtists} 
            globalSettings={globalSettings} 
            onUpdateGlobalSettings={setGlobalSettings}
            sortMode={artistSortMode}
            onSetSort={setArtistSortMode}
            onUpdateOrder={handleUpdateArtistOrder}
          />
        );
      case 'CONCERT_LIST': 
        return (
          <ConcertListPage 
            artists={artists} 
            onOpenArtist={(id) => navigateToArtistDetail(id, 'CONCERT_LIST')} 
            onOpenConcert={(aid, tid, cid) => navigateToConcertHome(aid, tid, cid, 'CONCERT_LIST')} 
            onCreateConcert={() => setIsArtistPickerOpen(true)} 
            onRefreshAll={runAutoAdvance} 
            onUpdateConcert={updateConcert} 
            sortMode={concertSortMode}
            onSetSort={setConcertSortMode}
          />
        );
      case 'CALENDAR': 
        return (
          <CalendarPage 
            artists={artists} 
            onOpenArtist={(id) => navigateToArtistDetail(id, 'CALENDAR')} 
            onOpenConcert={(aid, tid, cid) => navigateToConcertHome(aid, tid, cid, 'CALENDAR')} 
            onRefreshAll={runAutoAdvance} 
          />
        );
      case 'ARTIST_DETAIL': {
        const artist = artists.find(a => a.id === nav.artistId);
        if (!artist) return null;
        return (
          <ArtistDetailPage 
            artistId={nav.artistId!} 
            artist={artist} 
            settings={displaySettings} 
            onOpenArtistEditor={navigateToArtistEditor} 
            onOpenConcertEditor={navigateToConcertEditor} 
            onOpenConcertHome={(aid, tid, cid) => navigateToConcertHome(aid, tid, cid, nav.from)} 
            onChangeSettings={s => setDisplaySettings(p => ({...p, ...s}))} 
            onBack={() => {
              if (nav.from === 'CONCERT_LIST') setNav({ path: 'CONCERT_LIST' });
              else if (nav.from === 'CALENDAR') setNav({ path: 'CALENDAR' });
              else navigateToArtistList();
            }} 
          />
        );
      }
      case 'CONCERT_HOME': {
        const artist = artists.find(a => a.id === nav.artistId);
        const tour = artist?.tours.find(t => t.id === nav.tourId);
        const concert = tour?.concerts.find(c => c.id === nav.concertId);
        if (!artist || !tour || !concert) return null;
        return (
          <ConcertHomePage 
            artistId={artist.id} 
            concertId={concert.id} 
            artist={artist} 
            tour={tour} 
            concert={concert} 
            onBack={() => navigateToArtistDetail(artist.id, nav.from)} 
            onOpenConcertEditor={navigateToConcertEditor} 
            onUpdateConcertAlbum={(aid, tid, cid, imgs) => updateConcert(aid, tid, cid, { images: imgs })} 
          />
        );
      }
      case 'ARTIST_EDITOR': return (
        <ArtistEditorPage 
          artistId={nav.artistId} 
          artist={artists.find(a => a.id === nav.artistId)} 
          onSave={upsertArtist} 
          onCancel={() => {
            if (nav.artistId) {
              navigateToArtistDetail(nav.artistId, nav.from);
            } else {
              navigateToArtistList();
            }
          }} 
          onDeleteArtist={id => { 
            setArtists(p => p.filter(a => a.id !== id)); 
            navigateToArtistList(); 
          }} 
        />
      );
      case 'CONCERT_EDITOR': {
        const artist = artists.find(a => a.id === nav.artistId);
        if (!artist) return null;
        return (
          <ConcertEditorPage 
            artistId={artist.id} 
            tourId={nav.tourId} 
            tour={artist.tours.find(t => t.id === nav.tourId)} 
            allArtists={artists} 
            onSave={t => upsertTour(artist.id, t)} 
            onCancel={() => navigateToArtistDetail(artist.id, nav.from)} 
            onDeleteTour={deleteTour} 
          />
        );
      }
      default: return null;
    }
  };

  return (
    <div className="app-root">
      <Layout currentPath={nav.path} onNavigate={p => setNav({ path: p })} hasConcertAlert={hasGlobalConcertAlert}>
        {renderPage()}
      </Layout>
      {isArtistPickerOpen && (
        <div style={overlayStyle}>
          <div style={backdropStyle} onClick={() => setIsArtistPickerOpen(false)} />
          <GlassCard padding="24px" style={pickerCardStyle}>
            <h3>アーティストを選択</h3>
            <div style={pickerListStyle}>
              {artists.map(a => (
                <button 
                  key={a.id} 
                  type="button"
                  onClick={() => { navigateToConcertEditor(a.id); setIsArtistPickerOpen(false); }} 
                  style={pickerButtonStyle}
                >
                  {a.name}
                </button>
              ))}
            </div>
            <button type="button" onClick={() => setIsArtistPickerOpen(false)} style={closeButtonStyle}>閉じる</button>
          </GlassCard>
        </div>
      )}
    </div>
  );
}

const overlayStyle: React.CSSProperties = { position: 'fixed', inset: 0, zIndex: 2000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '24px' };
const backdropStyle: React.CSSProperties = { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)', backdropFilter: 'blur(8px)' };
const pickerCardStyle: React.CSSProperties = { width: '100%', maxWidth: '360px', position: 'relative' };
const pickerListStyle: React.CSSProperties = { display: 'flex', flexDirection: 'column', gap: '10px', maxHeight: '300px', overflowY: 'auto' };
const pickerButtonStyle: React.CSSProperties = { padding: '16px', borderRadius: '16px', border: '1px solid rgba(0,0,0,0.05)', background: 'white', textAlign: 'left', fontWeight: '700', fontSize: '15px', cursor: 'pointer' };
const closeButtonStyle: React.CSSProperties = { padding: '12px', borderRadius: '12px', border: 'none', background: 'rgba(0,0,0,0.05)', fontWeight: '700', cursor: 'pointer', marginTop: '16px', width: '100%' };

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { theme } from '../ui/theme';
import { GlassCard } from '../ui/GlassCard';
import { ConfirmDialog } from '../components/ConfirmDialog';
import { Artist, Tour, Concert, Status } from '../domain/types';
import { Icons, IconButton } from '../ui/IconButton';
import { sortPerformancesForDisplay, checkGlobalDateConflicts } from '../domain/logic';
import { PageShell } from '../ui/PageShell';

const generateId = () => Math.random().toString(36).substr(2, 9);

const Field: React.FC<{ label: string; description?: string; children: React.ReactNode }> = ({ label, children, description }) => (
  <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
    <label style={{ fontSize: '12px', color: theme.colors.textSecondary, marginLeft: '4px', fontWeight: 'bold' }}>{label}</label>
    {children}
    {description && <div style={{ fontSize: '10px', color: theme.colors.textWeak, marginLeft: '4px' }}>{description}</div>}
  </div>
);

interface Props {
  artistId: string;
  tourId?: string;
  tour?: Tour;
  allArtists: Artist[];
  onSave: (updatedTour: Tour) => void;
  onCancel: () => void;
  onDeleteTour: (artistId: string, tourId: string) => void;
}

const statusOptions: { value: Status; label: string; color: string }[] = [
  { value: '発売前', label: '発売前', color: theme.colors.status['発売前'] },
  { value: '検討中', label: '検討中', color: theme.colors.status['検討中'] },
  { value: '抽選中', label: '抽選中', color: theme.colors.status['抽選中'] },
  { value: '参戦予定', label: '参戦予定', color: theme.colors.status['参戦予定'] },
  { value: '参戦済み', label: '参戦済み', color: theme.colors.status['参戦済み'] },
  { value: '見送', label: '見送', color: theme.colors.status['見送'] },
];

const StatusPicker = ({ value, onChange }: { value: Status; onChange: (s: Status) => void }) => {
  const [isOpen, setIsOpen] = useState(false);
  const current = statusOptions.find(o => o.value === value) || statusOptions[0];
  return (
    <div style={{ position: 'relative' }}>
      <div 
        onClick={() => setIsOpen(!isOpen)} 
        style={{ ...inputStyle, cursor: 'pointer', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
          <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: current.color }} />
          {current.label}
        </div>
        <span style={{ fontSize: '10px', opacity: 0.5 }}>{isOpen ? '▲' : '▼'}</span>
      </div>
      {isOpen && (
        <>
          <div style={{ position: 'fixed', inset: 0, zIndex: 100 }} onClick={() => setIsOpen(false)} />
          <GlassCard padding="8px" style={{ position: 'absolute', top: '100%', left: 0, right: 0, zIndex: 101, marginTop: '4px', display: 'flex', flexDirection: 'column', gap: '2px' }}>
            {statusOptions.map(opt => (
              <div 
                key={opt.value} 
                onClick={() => { onChange(opt.value); setIsOpen(false); }} 
                style={{ 
                  padding: '10px 12px', borderRadius: '8px', fontSize: '14px', fontWeight: '600', cursor: 'pointer', 
                  background: value === opt.value ? 'rgba(83, 190, 232, 0.1)' : 'transparent', 
                  color: value === opt.value ? theme.colors.primary : theme.colors.textMain, 
                  display: 'flex', alignItems: 'center', gap: '8px' 
                }}
              >
                <div style={{ width: '6px', height: '6px', borderRadius: '50%', background: opt.color }} />{opt.label}
              </div>
            ))}
          </GlassCard>
        </>
      )}
    </div>
  );
};

const CustomDatePicker = ({ value, onChange, showTime = false, placeholder }: { value: string | null | undefined; onChange: (val: string) => void; showTime?: boolean; placeholder?: string }) => {
  const [isOpen, setIsOpen] = useState(false);
  const valStr = value || '';
  const initialDateStr = valStr === 'TBD' || !valStr ? '' : valStr.split(' ')[0];
  const initialTimeStr = (showTime && valStr && valStr.includes(' ')) ? valStr.split(' ')[1] : '12:00';
  const [viewDate, setViewDate] = useState(initialDateStr ? new Date(initialDateStr.replace(/-/g, '/')) : new Date());
  const [selectedTime, setSelectedTime] = useState(initialTimeStr);

  const daysInMonth = (y: number, m: number) => new Date(y, m + 1, 0).getDate();
  const firstDay = (y: number, m: number) => new Date(y, m, 1).getDay();

  const calendarDays = useMemo(() => {
    const y = viewDate.getFullYear(); 
    const m = viewDate.getMonth(); 
    const days = []; 
    const first = firstDay(y, m);
    for (let i = 0; i < first; i++) days.push(null);
    for (let i = 1; i <= daysInMonth(y, m); i++) days.push(i);
    return days;
  }, [viewDate]);

  const handleSelectDay = (day: number) => {
    const y = viewDate.getFullYear(); 
    const m = String(viewDate.getMonth() + 1).padStart(2, '0'); 
    const d = String(day).padStart(2, '0');
    const datePart = `${y}-${m}-${d}`;
    if (showTime) onChange(`${datePart} ${selectedTime}`);
    else { onChange(datePart); setIsOpen(false); }
  };

  const hours = Array.from({ length: 24 }, (_, i) => String(i).padStart(2, '0'));
  const minuteOptions = Array.from({ length: 12 }, (_, i) => String(i * 5).padStart(2, '0'));

  return (
    <div style={{ position: 'relative' }}>
      <div onClick={() => setIsOpen(!isOpen)} style={{ ...inputStyle, cursor: 'pointer', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <span style={{ fontSize: '14px', color: !valStr ? theme.colors.textWeak : 'inherit' }}>{valStr || placeholder || '未設定'}</span>
        {showTime ? <Icons.Clock /> : <Icons.Calendar />}
      </div>
      {isOpen && (
        <>
          <div style={{ position: 'fixed', inset: 0, zIndex: 100 }} onClick={() => setIsOpen(false)} />
          <GlassCard padding="16px" style={{ position: 'absolute', top: '100%', left: 0, width: showTime ? '320px' : '280px', zIndex: 101, marginTop: '4px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px' }}>
              <button type="button" onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() - 1, 1))} style={navBtnStyle}>◀</button>
              <div style={{ fontWeight: 'bold', fontSize: '14px' }}>{viewDate.getFullYear()}年 {viewDate.getMonth() + 1}月</div>
              <button type="button" onClick={() => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 1))} style={navBtnStyle}>▶</button>
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: '4px', textAlign: 'center', marginBottom: showTime ? '16px' : '0' }}>
              {['日','月','火','水','木','金','土'].map(d => <div key={d} style={{ fontSize: '10px', color: theme.colors.textWeak }}>{d}</div>)}
              {calendarDays.map((day, i) => {
                const dateKey = `${viewDate.getFullYear()}-${String(viewDate.getMonth()+1).padStart(2,'0')}-${String(day).padStart(2,'0')}`;
                const isSelected = day && initialDateStr === dateKey;
                return (
                  <div 
                    key={i} 
                    onClick={() => day && handleSelectDay(day)} 
                    style={{ 
                      padding: '8px 0', fontSize: '13px', borderRadius: '8px', cursor: day ? 'pointer' : 'default', 
                      background: isSelected ? theme.colors.primary : 'transparent', 
                      color: isSelected ? 'white' : theme.colors.textMain, opacity: day ? 1 : 0 
                    }}
                  >
                    {day}
                  </div>
                );
              })}
            </div>
            {showTime && (
              <div style={{ borderTop: '0.5px solid rgba(0,0,0,0.05)', paddingTop: '16px' }}>
                <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                  <select 
                    value={selectedTime.split(':')[0]} 
                    onChange={e => { 
                      const [h,m] = selectedTime.split(':'); 
                      setSelectedTime(`${e.target.value}:${m}`); 
                      if(initialDateStr) onChange(`${initialDateStr} ${e.target.value}:${m}`); 
                    }} 
                    style={selectTimeStyle}
                  >
                    {hours.map(h => <option key={h} value={h}>{h}時</option>)}
                  </select>
                  <select 
                    value={selectedTime.split(':')[1]} 
                    onChange={e => { 
                      const [h,m] = selectedTime.split(':'); 
                      setSelectedTime(`${h}:${e.target.value}`); 
                      if(initialDateStr) onChange(`${initialDateStr} ${h}:${e.target.value}`); 
                    }} 
                    style={selectTimeStyle}
                  >
                    {minuteOptions.map(m => <option key={m} value={m}>{m}分</option>)}
                  </select>
                </div>
              </div>
            )}
            <div style={{ display: 'flex', gap: '8px', marginTop: '16px' }}>
              <button type="button" onClick={() => { onChange(''); setIsOpen(false); }} style={{ flex: 1, padding: '10px', background: 'rgba(0,0,0,0.05)', borderRadius: '10px', border: 'none', cursor: 'pointer' }}>クリア</button>
              <button type="button" onClick={() => setIsOpen(false)} style={{ flex: 1, padding: '10px', background: theme.colors.primary, color: 'white', borderRadius: '10px', border: 'none', cursor: 'pointer' }}>確定</button>
            </div>
          </GlassCard>
        </>
      )}
    </div>
  );
};

const navBtnStyle = { border: 'none', background: 'none', padding: '4px 8px', cursor: 'pointer' };
const selectTimeStyle = { flex: 1, padding: '8px', borderRadius: '8px', border: '1px solid rgba(0,0,0,0.1)', background: 'white' };

export const ConcertEditorPage: React.FC<Props> = ({ artistId, tourId, tour, allArtists, onSave, onCancel, onDeleteTour }) => {
  const getInitialData = (): Tour => tourId && tour ? { ...tour } : { id: generateId(), name: '', imageUrl: '', memo: '', concerts: [], officialUrl: '' };
  const [formData, setFormData] = useState<Tour>(getInitialData());
  const initialSnapshotRef = useRef<string>(JSON.stringify(getInitialData()));
  const [imageUrlDraft, setImageUrlDraft] = useState(formData.imageUrl);
  const [hasChanges, setHasChanges] = useState(false);
  const [expandedConcertId, setExpandedConcertId] = useState<string | null>(null);
  const [isDeleteTourModalOpen, setIsDeleteTourModalOpen] = useState(false);
  const [isDeleteConcertModalOpen, setIsDeleteConcertModalOpen] = useState<string | null>(null);
  const [conflictDates, setConflictDates] = useState<string[]>([]);

  useEffect(() => { 
    if (tour) { 
      setFormData({ ...tour }); 
      setImageUrlDraft(tour.imageUrl); 
      initialSnapshotRef.current = JSON.stringify(tour); 
    } 
  }, [tourId, tour]);

  useEffect(() => { 
    setHasChanges(JSON.stringify(formData) !== initialSnapshotRef.current); 
  }, [formData]);

  const handleSave = (e?: React.MouseEvent) => {
    if (e) e.preventDefault(); // Safety for touch triggers

    // Explicit Validation
    if (!formData.name.trim()) {
      window.alert("ツアー名を入力してください。");
      return;
    }

    const conflicts = checkGlobalDateConflicts(allArtists, formData.id, formData.concerts);
    if (conflicts.length > 0) { 
      setConflictDates(conflicts); 
      return; 
    }

    onSave(formData);
  };

  const handleAddConcert = () => {
    const nc: Concert = { id: generateId(), date: 'TBD', venue: '', price: 0, saleLink: '', status: '発売前', isParticipated: false, images: [] };
    setFormData(prev => ({ ...prev, concerts: [...prev.concerts, nc] }));
    setExpandedConcertId(nc.id);
  };

  const handleUpdateConcert = (id: string, updates: Partial<Concert>) => setFormData(prev => ({ ...prev, concerts: prev.concerts.map(c => c.id === id ? { ...c, ...updates } : c) }));

  const handleLoadImage = () => {
    if (imageUrlDraft.trim()) {
      setFormData(p => ({ ...p, imageUrl: imageUrlDraft.trim() }));
    }
  };

  return (
    <PageShell header={
      <header style={headerStyle}>
        <IconButton icon={<Icons.X />} onClick={onCancel} size={40} style={{ color: theme.colors.textSecondary, border: 'none', background: 'transparent', boxShadow: 'none' }} />
        <h2 style={{ fontSize: '17px', margin: 0, fontWeight: 'bold' }}>ツアー・公演編集</h2>
        {tourId ? (
          <IconButton icon={<Icons.Trash />} onClick={() => setIsDeleteTourModalOpen(true)} size={40} style={{ color: theme.colors.error, border: 'none', background: 'transparent', boxShadow: 'none' }} />
        ) : (
          <div style={{ width: 40 }} />
        )}
      </header>
    }>
      <div style={{ paddingBottom: '160px' }}>
        <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '24px' }}>
          <div style={{ width: '120px', height: '160px', borderRadius: '16px', background: '#F3F4F6', border: '4px solid white', boxShadow: '0 4px 12px rgba(0,0,0,0.1)', overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            {formData.imageUrl ? <img src={formData.imageUrl} referrerPolicy="no-referrer" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <span style={{ fontSize: '32px', opacity: 0.2 }}>🎸</span>}
          </div>
        </div>
        <section style={{ marginBottom: theme.spacing.xl }}>
          <h3 style={sectionTitleStyle}>ツアー情報</h3>
          <GlassCard padding={theme.spacing.md} style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.md }}>
            <Field label="ツアー名"><input type="text" value={formData.name} onChange={e => setFormData(p => ({ ...p, name: e.target.value }))} style={inputStyle} /></Field>
            <Field label="画像URL">
              <div style={{ display: 'flex', gap: '8px' }}>
                <input 
                  type="url" 
                  value={imageUrlDraft} 
                  onChange={e => setImageUrlDraft(e.target.value)} 
                  style={inputStyle} 
                />
                <button
                  type="button"
                  onClick={handleLoadImage}
                  style={{
                    padding: '0 16px',
                    borderRadius: '12px',
                    border: '1px solid rgba(0,0,0,0.08)',
                    background: 'white',
                    color: theme.colors.textSecondary,
                    fontSize: '13px',
                    fontWeight: 'bold',
                    cursor: 'pointer',
                    whiteSpace: 'nowrap',
                    transition: 'all 0.2s',
                  }}
                >
                  読み込み
                </button>
              </div>
            </Field>
            <Field label="公式サイトURL"><input type="url" value={formData.officialUrl || ''} onChange={e => setFormData(p => ({ ...p, officialUrl: e.target.value }))} style={inputStyle} /></Field>
          </GlassCard>
        </section>
        <section style={{ marginBottom: theme.spacing.xl }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: theme.spacing.sm }}>
            <h3 style={{ ...sectionTitleStyle, marginBottom: 0 }}>公演一覧</h3>
            <button type="button" onClick={handleAddConcert} style={actionButtonStyle}>＋ 公演追加</button>
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: theme.spacing.sm }}>
            {sortPerformancesForDisplay(formData.concerts).map(c => {
              const exp = expandedConcertId === c.id;
              return (
                <GlassCard key={c.id} padding="0" style={{ position: 'relative', zIndex: exp ? 10 : 1 }}>
                  <div onClick={() => setExpandedConcertId(exp ? null : c.id)} style={{ padding: theme.spacing.md, cursor: 'pointer', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <div style={{ flex: 1 }}><div style={{ fontWeight: '700' }}>{c.concertAt || c.date}</div><div style={{ fontSize: '12px', color: theme.colors.textSecondary }}>{c.venue || '会場未入力'}</div></div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}><span style={{ fontSize: '12px', fontWeight: 'bold', color: theme.colors.status[c.status] }}>{c.status}</span><span>{exp ? '▲' : '▼'}</span></div>
                  </div>
                  {exp && (
                    <div style={{ padding: theme.spacing.md, borderTop: '1px solid rgba(0,0,0,0.05)', display: 'flex', flexDirection: 'column', gap: theme.spacing.md }}>
                      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                        <Field label="状态"><StatusPicker value={c.status} onChange={v => handleUpdateConcert(c.id, { status: v })} /></Field>
                        <Field label="会場"><input type="text" value={c.venue} onChange={e => handleUpdateConcert(c.id, { venue: e.target.value })} style={inputStyle} /></Field>
                      </div>
                      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                        {c.status === '発売前' && <Field label="発売日"><CustomDatePicker value={c.saleAt} onChange={v => handleUpdateConcert(c.id, { saleAt: v })} showTime /></Field>}
                        {(c.status === '検討中' || c.status === '発売前') && <Field label="締切日"><CustomDatePicker value={c.deadlineAt} onChange={v => handleUpdateConcert(c.id, { deadlineAt: v })} showTime /></Field>}
                        {c.status === '抽選中' && <Field label="結果日"><CustomDatePicker value={c.resultAt} onChange={v => handleUpdateConcert(c.id, { resultAt: v })} showTime /></Field>}
                        <Field label="公演日"><CustomDatePicker value={c.concertAt || (c.date === 'TBD' ? '' : c.date)} onChange={v => handleUpdateConcert(c.id, { concertAt: v, date: v.split(' ')[0] })} /></Field>
                      </div>
                      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                        <Field label="チケット価格"><input type="number" value={c.price || ''} onChange={e => handleUpdateConcert(c.id, { price: Number(e.target.value) })} style={inputStyle} /></Field>
